window.__QUIZ_SUBJECT__=[{"id": "objective>Literature>2000>1", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short and witty poem is known as", "images": [], "options": {"A": "a ballad", "B": "an epigram", "C": "an epic", "D": "a lyric"}, "answer": "B", "explanation": "The correct answer to the above question is an epigram. The epigram is a short poem or phrase that expresses an idea in a clever or humourous way.     A  ballad is an anonymous narrative passed on from generation by word of mouth to be sung and danced to before a crowd. The ballad forms part of the oral tradition of a particular group of people.  An epic is a long narrative that celebrates real historical events, heroic achievements, heroic figures, civilization, quasi divine figures and such other subjects.  A lyric is a short poem in which a speaker expresses some intense personal feelings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>2", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary work which extols one's virtues and accomplishments is", "images": [], "options": {"A": "a eulogy", "B": "a pastoral", "C": "an elegy", "D": "an allegory"}, "answer": "A", "explanation": "A eulogy is a poem that gives high praise to a person.  A pastoral is a poem which describes the simple life of rural people, especially of shepherds and their love affairs. It is usually set in a   An elegy is poem written to mourn the death of a person.  An allegory is a literary piece in which abstract ideas are personified.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>3", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "George Orwell's Animal Farm is an example of a", "images": [], "options": {"A": "farce", "B": "burlesque", "C": "satire", "D": "lampoon"}, "answer": "C", "explanation": "The text, Animal Farm, by George Orwell is a an example of a satire because it criticizes the Russian Revolution as well as communism. Here, the characters (animals) are allegorical in that they represent the Russian society.    A satire is a literary piece that criticises the ills in the society in a bid to effect a change.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>4", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A poem of lamentation on death is", "images": [], "options": {"A": "a lyric", "B": "a ballad", "C": "an ode", "D": "an elegy"}, "answer": "D", "explanation": "An Elegy is a poem written to mourn the death of a person.  A ballad is an anonymous narrative passed on from generation  by word of mouth to be sung and danced to  before a crowd.  An Ode is a meditative poem which addresses itself to a person or thing in which the good qualities of such a person or object are highlighted and commended.  A lyric is a short poem in which a speaker expresses some intense personal feelings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>5", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The misuse of words that sound somewhat similar is", "images": [], "options": {"A": "malapropism", "B": "metonymy", "C": "onomatopoeia", "D": "pun"}, "answer": "A", "explanation": "Malapropism is the correct answer.  Malapropism is the  misuse of words that sound somewhat similar.   Metonymy is the use of closely-related words to describe a thing. For example, we can use a crown to represent a king.  Onomatopoeia is a sound device. It is the use of the sounds of an object to describe the object.  Pun is a play on words.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>6", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The main character in a literary work is the", "images": [], "options": {"A": "anatagonist", "B": "protagonist", "C": "narrator", "D": "villain"}, "answer": "B", "explanation": "The protagonist is the character that plays the most prominient role in a play or novel, often referred to as hero/heroine or the chief character.  An Antagonist refers to a character in a play or novel who opposes the protagonist rightly or wrongly.  A villain is an extremely wicked character.  The narrator is the voice that tells the story.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>7", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A speech delivered by a character who is alone on the stage is", "images": [], "options": {"A": "a soliloquy", "B": "a chorus", "C": "a dialogue", "D": "an aside"}, "answer": "A", "explanation": "Soliloquy occurs when a character speaks to himself on stage.  A chorus refers to a group of actors in a play whose members act in unison and share same opinion.  An Aside is a terms refers to a speech by the character directed to the audience to the exclusion of fellow characters or actors in drama.  Dialogue is a conversation between characters.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>8", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A sonnet may be divided into an octave and a", "images": [], "options": {"A": "tercet", "B": "quatrain", "C": "sestet", "D": "couplet"}, "answer": "C", "explanation": "A sonnet is a poem of fourteen lines, written in iambic pentameter with a definite rhyme scheme. Examples include Shakespearean and Pertrarchan sonnets. The pertrarchan sonnet is divided into two: an octave and a sestet. It has a rhyme scheme of abba abba cdc cdc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>9", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "''All hands on deck'' is an example of", "images": [], "options": {"A": "personification", "B": "metonymy", "C": "metaphor", "D": "synecdoche"}, "answer": "D", "explanation": "Synecdoche is a figure of speech which substitutes part for a whole. It substitutes a significant part of something for the thing itself. E.g, Many hands make light work.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>10", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In poetry.....consist of four lines", "images": [], "options": {"A": "a sestet", "B": "a quatrain", "C": "an octave", "D": "a tercet"}, "answer": "B", "explanation": "Quatrain is a poem of four lines.  sestet consist of sx lines  octave consist of eight lines  tercet consist of three lines", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>11", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" Soft as he mourned, the streams forgot to flow    She flocks around a dumb compassion show \"    The dominant device used in the lines above is", "images": [], "options": {"A": "oxymoron", "B": "mock-heroic", "C": "pathetic fallacy", "D": "satire"}, "answer": "C", "explanation": "The pathetic fallacy is a sub-type of the personification. It is the projection of human emotions through elements of nature. Here, the streams are attributed to have forgotten how to flow.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>12", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" Soft as he mourned, the streams forgot to flow    She flocks around a dumb compassion show \"  In the above lines, ''flow,'' and ''show''", "images": [], "options": {"A": "alliterate", "B": "contrast", "C": "rhyme", "D": "parallel"}, "answer": "C", "explanation": "Rhyme refers to the sameness of sounds between words in poetry. The most common form is the one between words ending different lines of a poem. Here, FLOW rhymes with SLOW.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>13", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" Soft as he mourned, the streams forgot to flow    She flocks around a dumb compassion show \"  The above lines constitute a", "images": [], "options": {"A": "couplet", "B": "rhythm", "C": "tercet", "D": "rhyme"}, "answer": "A", "explanation": "The given lines form a couplet. A couplet is a pair of successive lines of metre in poetry. The two lines have the same rhythm and often rhyme. In this case, 'flow' and 'show' rhyme, and the rhythm is the same, making it a couplet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>14", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "''I have read Shakespeare' is an example of", "images": [], "options": {"A": "litotes", "B": "paradox", "C": "parody", "D": "metonymy"}, "answer": "D", "explanation": "Metonymy is a figurative event in which the name or attribute of a thing is given as the name of that thing itself.  Litotes is the opposite of hyperbole; it is an understatement. It is the use of two negative words to get as positive meaning. E.g., I am not ungrateful  Paradox is a figure of speech which is built on contrasts as well as a seeming illogicality in the surface meaning.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>15", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Twelfth Night is an example of", "images": [], "options": {"A": "farce", "B": "comedy", "C": "tragi-comedy", "D": "burlesque"}, "answer": "B", "explanation": "Twelfth Night is an example of a comedy because it ends on a happy note. It also has different features of the comedy: mistasken identities, a wedding, laughter, etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>16", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In ''The fair breeze below, the white foam flew, The furrow followed free, the dominant device used is", "images": [], "options": {"A": "metaphor", "B": "personification", "C": "alliteration", "D": "assonance"}, "answer": "C", "explanation": "Alliteration is the systematic repetition of certain consonant sounds at the beginning of words. In the extract, we have \"breeze blew\", where the soubd /b/ alliterates. In \"foam flew, The furrow followed free\", the sound /f/ befins most of the words.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>17", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An address to an object or person not present is", "images": [], "options": {"A": "apostrophe", "B": "synecdoche", "C": "paradox", "D": "epigram"}, "answer": "A", "explanation": "An apostrophe is a device that is used when a direct speech is made to somerthing that is not present as if it were present, e.g., WAEC, why did you do this to me?", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>18", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The expression '' poisonous pleasure of wine'' Illustrates the use of", "images": [], "options": {"A": "metonymy", "B": "synecdoche", "C": "paradox", "D": "oxymoron"}, "answer": "D", "explanation": "An oxymoron is the placement of two contrasting words side by side. Here, \"poisonous\" and \"pleasures\" are placed side by side.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>19", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A non-verbal story-telling by a character on stage is", "images": [], "options": {"A": "imitation", "B": "farce", "C": "mime", "D": "comedy"}, "answer": "C", "explanation": "A non-verbal storytelling by a character on stage is referred to as 'mime'. Mime is a form of silent art that involves acting or communicating using movements, gestures, and facial expressions, without speech. In this case, the character tells a story without using words, hence the term non-verbal storytelling.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>20", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A character that develops with events and situations in a novel is a ......character", "images": [], "options": {"A": "flat", "B": "sound", "C": "minor", "D": "main"}, "answer": "D", "explanation": "A character that develops with events and situations in a novel is main character. Such character is also known as a dynamic character.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2000>21", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem below and answer the question    Now, Joy is born of parents poor,  And Pleasure of our richer kind;  Though Pleasure's free, she cannot sing  As sweet a song as Joy confined.    Pleasure's a moth, that sleeps by day  And dances by false glare at night;  But joy's a Butterfly, that loves  To spread its wings in Nature's light.    The poem says that ''Joy'' is", "images": [], "options": {"A": "for the poor", "B": "natural and satisfying", "C": "artificial and transitory", "D": "for lovers"}, "answer": "B", "explanation": "The poem describes 'Joy' as something that is born of poor parents and is confined, yet it can sing a sweeter song than 'Pleasure'. 'Joy' is also compared to a butterfly that loves to spread its wings in nature's light. This suggests that 'Joy' is natural and satisfying, which aligns with option 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>22", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem below and answer the question    Now, Joy is born of parents poor,  And Pleasure of our richer kind;  Though Pleasure's free, she cannot sing  As sweet a song as Joy confined.    Pleasure's a moth, that sleeps by day  And dances by false glare at night;  But joy's a Butterfly, that loves  To spread its wings in Nature's light.  The dominant device used in presenting ''Joy'' and ''Pleasure'' in the first stanza is", "images": [], "options": {"A": "diction", "B": "oxymoron", "C": "personification", "D": "conceit"}, "answer": "C", "explanation": "Personification is a figurative device which gives the features of human beings to inanimate objects. Here, Joy and Pleasure are abstract concepts that are given human qualities. For example, both of them are said to have the ability to sing: \"Though Pleasure's free, she cannot sing   As sweet a song as Joy confined\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>23", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem below and answer the question    Now, Joy is born of parents poor,  And Pleasure of our richer kind;  Though Pleasure's free, she cannot sing  As sweet a song as Joy confined.    Pleasure's a moth, that sleeps by day  And dances by false glare at night;  But joy's a Butterfly, that loves  To spread its wings in Nature's light.  The feelings associated with ''Joy'' and ''Pleasure'' in the first stanza is", "images": [], "options": {"A": "rhyme", "B": "euphemism", "C": "assonance", "D": "contrast"}, "answer": "D", "explanation": "The feelings associated with 'Joy' and 'Pleasure' in the first stanza are contrasted. The poet describes 'Joy' as being born of poor parents and being confined, yet able to sing a sweet song. On the other hand, 'Pleasure' is described as being of a richer kind and free, but unable to sing as sweet a song as 'Joy'. This is a clear contrast between the two feelings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>24", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem below and answer the question    Now, Joy is born of parents poor,  And Pleasure of our richer kind;  Though Pleasure's free, she cannot sing  As sweet a song as Joy confined.    Pleasure's a moth, that sleeps by day  And dances by false glare at night;  But joy's a Butterfly, that loves  To spread its wings in Nature's light.  ''False glare'' refers to", "images": [], "options": {"A": "man-made light", "B": "nature's light", "C": "the moon's light", "D": "the sun's lig"}, "answer": "A", "explanation": "'False glare' refers to man-made light. In the poem, 'Pleasure' is described as a moth that sleeps by day and dances by false glare at night. Moths are known to be attracted to artificial light or man-made light, hence the term 'false glare'. This is in contrast to 'Joy' which is described as a butterfly that loves to spread its wings in Nature's light.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>25", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem below and answer the question    Now, Joy is born of parents poor,  And Pleasure of our richer kind;  Though Pleasure's free, she cannot sing  As sweet a song as Joy confined.    Pleasure's a moth, that sleeps by day  And dances by false glare at night;  But joy's a Butterfly, that loves  To spread its wings in Nature's light.  ''Pleasure's a moth'' is an example of a (n)", "images": [], "options": {"A": "irony", "B": "hyperbole", "C": "metaphor", "D": "simile"}, "answer": "C", "explanation": "The metaphor is a direct comparison between two things of different nature. Here, Pleasure is directly referred to as a Moth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>26", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the passage below and answer the question:    The long column of misery tended continually to grow longer, as the more robust struggled to get as far as possible from the pursuing French, and as the weaker fell farther and farther behind. There were enough weaklings in all conscience; even in summer they had been badly clothed, and even in victory insufficiently fed, and now it was winter, and Espinosa had been fought and lost, and the route of the retreat lay away from the fertile plains and up into the inhospitable mountains. The rain had fallen upon them in deluges for days and now as they climbed higher it was turning into sleet. and a bitter cold wind blew. Ahead of them they could see the snow lying thick on the mountain passes through which they would have to climb, without food or fuel or rest, and with the terror of the French to urge them on. Disease had come inevitably to complete the work so well begun by hunger, exposure, and the sword    A suitable title for the passage is the", "images": [], "options": {"A": "March of Soldiers", "B": "Agony of War", "C": "Pangs of Hunger", "D": "Dread of Desease"}, "answer": "B", "explanation": "A suitable title for the passage is the Agony of War. The passage depicts the suffering and hardship that happens in war.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>27", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the passage below and answer the question:    The long column of misery tended continually to grow longer, as the more robust struggled to get as far as possible from the pursuing French, and as the weaker fell farther and farther behind. There were enough weaklings in all conscience; even in summer they had been badly clothed, and even in victory insufficiently fed, and now it was winter, and Espinosa had been fought and lost, and the route of the retreat lay away from the fertile plains and up into the inhospitable mountains. The rain had fallen upon them in deluges for days and now as they climbed higher it was turning into sleet. and a bitter cold wind blew. Ahead of them they could see the snow lying thick on the mountain passes through which they would have to climb, without food or fuel or rest, and with the terror of the French to urge them on. Disease had come inevitably to complete the work so well begun by hunger, exposure, and the sword  The writer's mood is one of", "images": [], "options": {"A": "anger", "B": "fear", "C": "pity", "D": "disappointment"}, "answer": "B", "explanation": "The mood of the writer is that of fear. This is seen in the way the retreating soldiers have to brave dire situations such as snowy mountains and hunger in a bid to escape the French army..", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>28", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the passage below and answer the question:    The long column of misery tended continually to grow longer, as the more robust struggled to get as far as possible from the pursuing French, and as the weaker fell farther and farther behind. There were enough weaklings in all conscience; even in summer they had been badly clothed, and even in victory insufficiently fed, and now it was winter, and Espinosa had been fought and lost, and the route of the retreat lay away from the fertile plains and up into the inhospitable mountains. The rain had fallen upon them in deluges for days and now as they climbed higher it was turning into sleet. and a bitter cold wind blew. Ahead of them they could see the snow lying thick on the mountain passes through which they would have to climb, without food or fuel or rest, and with the terror of the French to urge them on. Disease had come inevitably to complete the work so well begun by hunger, exposure, and the sword  The mood is expressed through the use of", "images": [], "options": {"A": "objects", "B": "scenery", "C": "syntax", "D": "diction"}, "answer": "B", "explanation": "The scenery helps to project the mood of fear. Words like winter and inhospitable mountains point this out.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>29", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the passage below and answer the question:    The long column of misery tended continually to grow longer, as the more robust struggled to get as far as possible from the pursuing French, and as the weaker fell farther and farther behind. There were enough weaklings in all conscience; even in summer they had been badly clothed, and even in victory insufficiently fed, and now it was winter, and Espinosa had been fought and lost, and the route of the retreat lay away from the fertile plains and up into the inhospitable mountains. The rain had fallen upon them in deluges for days and now as they climbed higher it was turning into sleet. and a bitter cold wind blew. Ahead of them they could see the snow lying thick on the mountain passes through which they would have to climb, without food or fuel or rest, and with the terror of the French to urge them on. Disease had come inevitably to complete the work so well begun by hunger, exposure, and the sword  The attitude of the survivors is best summed up by the word", "images": [], "options": {"A": "indifference", "B": "persistence", "C": "resignation", "D": "victory"}, "answer": "C", "explanation": "The attitude of the survivors is best summed up by the word \"resignation\", that is, they have accepted their fate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>30", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the passage below and answer the question:    The long column of misery tended continually to grow longer, as the more robust struggled to get as far as possible from the pursuing French, and as the weaker fell farther and farther behind. There were enough weaklings in all conscience; even in summer they had been badly clothed, and even in victory insufficiently fed, and now it was winter, and Espinosa had been fought and lost, and the route of the retreat lay away from the fertile plains and up into the inhospitable mountains. The rain had fallen upon them in deluges for days and now as they climbed higher it was turning into sleet. and a bitter cold wind blew. Ahead of them they could see the snow lying thick on the mountain passes through which they would have to climb, without food or fuel or rest, and with the terror of the French to urge them on. Disease had come inevitably to complete the work so well begun by hunger, exposure, and the sword  The device used in the last sentence is", "images": [], "options": {"A": "climax", "B": "sarcasm", "C": "euphemism", "D": "hyperbole"}, "answer": "A", "explanation": "Climax is the arrangement of an event in an ascending order. In the extract, \"Disease had come inevitably to complete the work so well begun by hunger, exposure, and the sword\", we have an upward movement with regard to level of importance in the words used, that is, hunger-exposure-sword. The sword, of course, represents the highest point of the tension.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>31", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "WILLIAM SHAKESPEARE: Twelfth Night  Read the extract below and answer the question    So please my lord, I might not be admitted;  But from her handmaid to return this answer:  The element itself, till seven years heat,  Shall not behold her face at ample view......  (Act 1 Scene 1)    The speaker is", "images": [], "options": {"A": "Cesario", "B": "Fabian", "C": "Valentine", "D": "Feste"}, "answer": "C", "explanation": "Here, Valentine enters the room with bad news—he wasn't able to deliver Orsino's love note to Olivia because, when he showed up at the Countess's place, her handmaid told him to get lost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>32", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "WILLIAM SHAKESPEARE: Twelfth Night  Read the extract below and answer the question    So please my lord, I might not be admitted;  But from her handmaid to return this answer:  The element itself, till seven years heat,  Shall not behold her face at ample view......  (Act 1 Scene 1)  ''Element'' in the third line refers to the", "images": [], "options": {"A": "sky", "B": "weather", "C": "sun", "D": "cloud"}, "answer": "A", "explanation": "In this context, 'element' refers to the sky. The phrase 'The element itself, till seven years heat, Shall not behold her face at ample view' means that Olivia intends to seclude herself from the world, to the extent that even the sky ('element') will not see her face for seven years. The other options (weather, sun, cloud) do not fit the context of the sentence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>33", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "WILLIAM SHAKESPEARE: Twelfth Night  Read the extract below and answer the question    So please my lord, I might not be admitted;  But from her handmaid to return this answer:  The element itself, till seven years heat,  Shall not behold her face at ample view......  (Act 1 Scene 1)  The report is made to", "images": [], "options": {"A": "Olivia", "B": "Malvolio", "C": "Viola", "D": "Orsino"}, "answer": "D", "explanation": "In the given extract, the speaker is addressing a lord, and in the context of Twelfth Night, this is likely to be Duke Orsino. Therefore, the report is made to Orsino.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>34", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "WILLIAM SHAKESPEARE: Twelfth Night  Read the extract below and answer the question    So please my lord, I might not be admitted;  But from her handmaid to return this answer:  The element itself, till seven years heat,  Shall not behold her face at ample view......  (Act 1 Scene 1)  The one referred to by the speaker is", "images": [], "options": {"A": "Maria", "B": "Olivia", "C": "Sir Tony", "D": "Viola"}, "answer": "B", "explanation": "In the given extract, the speaker is referring to a lady who will not show her face for seven years. In the context of Twelfth Night, this is likely to be Olivia. Therefore, the one referred to by the speaker is Olivia.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>35", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "WILLIAM SHAKESPEARE: Twelfth Night  Read the extract below and answer the question    So please my lord, I might not be admitted;  But from her handmaid to return this answer:  The element itself, till seven years heat,  Shall not behold her face at ample view......  (Act 1 Scene 1)  The message is in connection with", "images": [], "options": {"A": "warfare", "B": "love", "C": "revenge", "D": "shipwreck"}, "answer": "B", "explanation": "The extract is from Shakespeare's Twelfth Night, Act 1 Scene 1. The message being referred to is from Olivia's handmaid, who is conveying Olivia's decision to seclude herself for seven years in mourning for her brother. This is a theme of love, specifically unrequited love, as Duke Orsino is in love with Olivia, but she rejects his advances. Therefore, the correct answer is 'love'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>36", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : Will you stay no longer nor will you not that I go with you?  B : By your patience, no. My stars shine darkly over me; the  Malignancy of my fate might, perhaps, distemper yours; therefore I shall crave of you your leave that I may bear my evils alone  (Act II Scene 1)    The above dialogue is between", "images": [], "options": {"A": "Viola and Captain", "B": "Captain and Sebastian", "C": "Antonio and Sebastian", "D": "Sebastian and Olivia"}, "answer": "C", "explanation": "The dialogue is from Act II Scene 1 of Shakespeare's Twelfth Night. The characters speaking are Antonio and Sebastian. Antonio is offering to accompany Sebastian, but Sebastian declines, fearing that his bad luck might affect Antonio. Therefore, the correct answer is 'Antonio and Sebastian'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>37", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : Will you stay no longer nor will you not that I go with you?  B : By your patience, no. My stars shine darkly over me; the  Malignancy of my fate might, perhaps, distemper yours; therefore I shall crave of you your leave that I may bear my evils alone  (Act II Scene 1)  Speaker B requests Speaker A to", "images": [], "options": {"A": "be patient", "B": "stay behind", "C": "go back home", "D": "pray for his friend"}, "answer": "A", "explanation": "Speaker B requests Speaker A to be patient. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>38", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : Will you stay no longer nor will you not that I go with you?  B : By your patience, no. My stars shine darkly over me; the  Malignancy of my fate might, perhaps, distemper yours; therefore I shall crave of you your leave that I may bear my evils alone  (Act II Scene 1)  The underlined sentence means that my", "images": [], "options": {"A": "faith will rescue you", "B": "malie will destroy you", "C": "ill  - luck may affect you", "D": "bad temper will hurt you"}, "answer": "C", "explanation": "The underlined sentence 'the Malignancy of my fate might, perhaps, distemper yours' means that Speaker B's ill-luck may affect Speaker A. The term 'malignancy of my fate' refers to the bad luck or misfortune of Speaker B and 'distemper yours' suggests that it might negatively affect Speaker A.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>39", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : Will you stay no longer nor will you not that I go with you?  B : By your patience, no. My stars shine darkly over me; the  Malignancy of my fate might, perhaps, distemper yours; therefore I shall crave of you your leave that I may bear my evils alone  (Act II Scene 1)  The scene of his action is", "images": [], "options": {"A": "a street", "B": "the sea-coast", "C": "Orsino's palace", "D": "Olivia's palace"}, "answer": "B", "explanation": "The extract is from Shakespeare's play 'Twelfth Night'. In Act II Scene 1, the scene takes place on the sea-coast. The character is expressing his concern about his fate and doesn't want to affect others with it. The scene is not specifically in a street, Orsino's palace, or Olivia's palace, but on the sea-coast where the character has been shipwrecked.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>40", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : Will you stay no longer nor will you not that I go with you?  B : By your patience, no. My stars shine darkly over me; the  Malignancy of my fate might, perhaps, distemper yours; therefore I shall crave of you your leave that I may bear my evils alone  (Act II Scene 1)  Speaker B is", "images": [], "options": {"A": "grateful", "B": "happy", "C": "angry", "D": "sad"}, "answer": "B", "explanation": "Happy is the correct answer. This is the most accurate answer in relation to the text.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>41", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : How dost thou like this tune?  B : It gives a very echo to the seat  Where Love is throned  A : Thou dost speak masterly  My life upon't , young though thou art, thine eye  Hath stayed upon some favour that it loves;  Hath is not, boy?  B : A little, by your favour (Act ll Scene 4)    Speaker A is", "images": [], "options": {"A": "Sir Toby", "B": "Sir Andrew", "C": "Duke Orsino", "D": "Countess Olivia"}, "answer": "C", "explanation": "The extract is from William Shakespeare's play 'Twelfth Night'. In Act II, Scene 4, the conversation takes place between Duke Orsino and his page, Cesario (Viola in disguise). Duke Orsino is speaker A in the extract. He is talking about love and music, which are recurring themes in his conversations throughout the play.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>42", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : How dost thou like this tune?  B : It gives a very echo to the seat  Where Love is throned  A : Thou dost speak masterly  My life upon't , young though thou art, thine eye  Hath stayed upon some favour that it loves;  Hath is not, boy?  B : A little, by your favour (Act ll Scene 4)  The two speakers are in", "images": [], "options": {"A": "the garden", "B": "a ship", "C": "the Duke's palace", "D": "Olivia's house"}, "answer": "B", "explanation": "The setting of the action is a ship; therefore, the action occurs in the ship.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>43", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : How dost thou like this tune?  B : It gives a very echo to the seat  Where Love is throned  A : Thou dost speak masterly  My life upon't , young though thou art, thine eye  Hath stayed upon some favour that it loves;  Hath is not, boy?  B : A little, by your favour (Act ll Scene 4)  The relationship between speaker A and B is", "images": [], "options": {"A": "master-servant", "B": "brother-sister", "C": "husband-wife", "D": "mistress-steward"}, "answer": "A", "explanation": "The extract is from Shakespeare's play 'Twelfth Night'. In this scene, Duke Orsino is speaking to his page, Cesario (who is actually Viola in disguise). The Duke is the master and Cesario is the servant. The Duke is praising Cesario's understanding of love, suggesting that Cesario must be in love. This is why the correct answer is 'master-servant'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>44", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : How dost thou like this tune?  B : It gives a very echo to the seat  Where Love is throned  A : Thou dost speak masterly  My life upon't , young though thou art, thine eye  Hath stayed upon some favour that it loves;  Hath is not, boy?  B : A little, by your favour (Act ll Scene 4)  The scene reveals", "images": [], "options": {"A": "Orsino's love for Olivia", "B": "Viola's love for Orsino", "C": "Olivia's love for Sebastian", "D": "Olivia's love for Cesario"}, "answer": "B", "explanation": "In this scene, Cesario (Viola in disguise) is speaking to Duke Orsino about love. Cesario's words reflect her own feelings for the Duke, even though she is supposed to be speaking about Olivia's love for him. This is why the correct answer is 'Viola's love for Orsino'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>45", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : How dost thou like this tune?  B : It gives a very echo to the seat  Where Love is throned  A : Thou dost speak masterly  My life upon't , young though thou art, thine eye  Hath stayed upon some favour that it loves;  Hath is not, boy?  B : A little, by your favour (Act ll Scene 4)  The dialogue shows that the characters are", "images": [], "options": {"A": "in love with each other", "B": "truly in love with music", "C": "in love with the same person", "D": "both victims of unreturned love"}, "answer": "D", "explanation": "The dialogue shows that the characters are both victims of unreturned love", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>46", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    I am not weary, and 't is long to night.  I pray you, let us satisfy our eyes  With the memorials and the things of fame  That do renown this city  (Act III Scene 3)    The speaker is", "images": [], "options": {"A": "Malvolio", "B": "Viola", "C": "Antonio", "D": "Sebastian"}, "answer": "D", "explanation": "The speaker is Sebastian. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>47", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    I am not weary, and 't is long to night.  I pray you, let us satisfy our eyes  With the memorials and the things of fame  That do renown this city  (Act III Scene 3)  The speaker is addressing", "images": [], "options": {"A": "Malvolio", "B": "Antonio", "C": "Valentine", "D": "Sebastian"}, "answer": "B", "explanation": "Here, Sebastien is addressing is Antonio. This is the most accurate answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>48", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    I am not weary, and 't is long to night.  I pray you, let us satisfy our eyes  With the memorials and the things of fame  That do renown this city  (Act III Scene 3)  The person addressed responds to the speaker's request by", "images": [], "options": {"A": "declining it", "B": "accepting it", "C": "being undecided", "D": "being angry"}, "answer": "A", "explanation": "The addressed character decline the request of the speaker.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>49", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    She sends him purpose that I may appear stub  born to him ; for she incites me to that in the letter.  ''Cast thy humble slough,''  says she; ''be opposite with a kinsman, surly  with servant;.......    The speaker is", "images": [], "options": {"A": "Malvolio", "B": "Sebastian", "C": "Orsino", "D": "Sir Toby"}, "answer": "A", "explanation": "The speaker in the extract is Malvolio. In the play 'Twelfth Night' by William Shakespeare, Malvolio is the steward of Olivia's household. In this scene, he is reading a letter that he believes is from Olivia, but it is actually a prank letter written by Maria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2000>50", "subject": "Literature", "year": "2000", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    She sends him purpose that I may appear stub  born to him ; for she incites me to that in the letter.  ''Cast thy humble slough,''  says she; ''be opposite with a kinsman, surly  with servant;.......  The letter referred to is from", "images": [], "options": {"A": "Sir Andrew", "B": "Maria", "C": "Olivia", "D": "Cesario"}, "answer": "B", "explanation": "The letter referred to in the extract is from Maria. In the play 'Twelfth Night' by William Shakespeare, Maria writes a prank letter to Malvolio, making him believe it is from Olivia.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>1", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "One of the following plays is based on the mistakes of a night", "images": [], "options": {"A": "The Gods are not to Blame", "B": "The marriage of Anansewa", "C": "Arms and the Man", "D": "She stoops to Conquer"}, "answer": "D", "explanation": "She stoops to Conquer is a based on the mistakes of a night. These mistakes are in the form of mistaken identities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>2", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The genres of Literature are", "images": [], "options": {"A": "dialogue, stage and actng", "B": "prose, tales and verse", "C": "prose, poetry and drama", "D": "drama, actors and poetry"}, "answer": "C", "explanation": "The genres of Literature are traditionally divided into three types: prose, poetry, and drama. Prose is a form of language that has no formal metrical structure. Poetry is a form of literature that uses aesthetic and rhythmic qualities of language. Drama is a mode of fictional representation through dialogue and performance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2001>3", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A seemingly absurd statement is a/an", "images": [], "options": {"A": "climax", "B": "anti-climax", "C": "hyperbole", "D": "paradox"}, "answer": "D", "explanation": "Climax is a figurative device which locates ideas in an ascending order of their significance. It is the highest point of the tension in a literary work.  Anti-climax is the opposite of climax. It arranges events or ideas in desceding order of importance for effect.  Hyperbole refers to an excessive exaggeration that is done for the purpose of emphasis or humour.   A paradox is a figure of speech which is built on contrasts as well as seeming illogicaaly in the surface meaning. Although a paradoxical statements appears self contradictory, there is usually at its core a hidden meaning . Therefore, a seemingly absurd statement is a paradox.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>4", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A play is watched by a/an", "images": [], "options": {"A": "congregation", "B": "group", "C": "audience", "D": "entourage"}, "answer": "C", "explanation": "A play is watched by an audience. An audience is a group of people who participate in a show or encounter a work of art, literature (in which they are called 'readers'), theatre, music (in which they are called 'listeners'), video games (in which they are called 'players'), or academics in any medium. Audience members participate in different ways in different kinds of art; some events invite overt audience participation and others allowing only modest clapping and criticism and reception.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2001>5", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Poetry differs from prose by its use of", "images": [], "options": {"A": "song", "B": "condensed language", "C": "flat character", "D": "rhythm"}, "answer": "B", "explanation": "Poetry differs from other genres of literature in that it makes use of elevated and condensed language. To put simply, poetry says a lot in a few words.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>6", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick out the odd item", "images": [], "options": {"A": "Actors", "B": "Stage", "C": "Dialogue", "D": "Chapters"}, "answer": "D", "explanation": "The odd item in the following is 'chapter'. All other terms except 'chapters' are terminologies used in drama. Chapter is used in prose.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2001>7", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A piece of writing about oneself is a/an", "images": [], "options": {"A": "autobiography", "B": "biography", "C": "autography", "D": "mimeography"}, "answer": "A", "explanation": "An autobiography is a self-written account of one's life. It is a piece of writing about oneself, hence the correct answer. A biography is an account of someone's life written by someone else. Autography is a person's own handwriting or signature, and mimeography is a printing method.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2001>8", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short poem expressing intense emotions and usually sung is a/an", "images": [], "options": {"A": "ode", "B": "pastoral", "C": "elegy", "D": "lyric"}, "answer": "D", "explanation": "A lyric is a short poem in which a speaker expresses some intense personal feeling. It is also a short musical or rythmic poem which expresses a poet's thought and emotions on any matter that interests him or her.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>9", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick out the odd item", "images": [], "options": {"A": "The Gods are not to Blame", "B": "The Concubine", "C": "Things Fall Apart", "D": "The African Child"}, "answer": "A", "explanation": "The Gods are not to Blame is the odd item because it is an African drama.while the rest are works of prose.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2001>10", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In ''Biodun did his best but was first from behind'', first from behind'' is an example of", "images": [], "options": {"A": "sarcasm", "B": "euphemism", "C": "hyperbole", "D": "paradox"}, "answer": "A", "explanation": "Sarcasm is a type of irony, often applied with scorn and contempt for its victim. It is an undisguised expression of anger,an unkind joke as it were , whose aim is to hurt so as to punish. First from behind actually means last; therefore, the speaker is being sarcastic in a bid to mock Biodun.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>11", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary work that ridicules ideas or the follies of people is a/an", "images": [], "options": {"A": "satire", "B": "elegy", "C": "lullaby", "D": "masque"}, "answer": "A", "explanation": "A satire is a literary work that ridicules the ills, vices and follies of a particular society in irder to effect a change.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>12", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In ''the wretched beggar cleaned his nails with dry saliva'' the device used is", "images": [], "options": {"A": "anti-climax", "B": "oxymoron", "C": "anecdote", "D": "antithesis"}, "answer": "B", "explanation": "The expression, \"dry saliva\" is oxymoronic. Saliva cannot be dry: therefore the placement of \"dry\" and \"saliva\" side by side constitutes an oxymoron.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2001>13", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A symbolic representation of ideas, actions and situations in a work of art is a/an", "images": [], "options": {"A": "fable", "B": "allegory", "C": "romance", "D": "parody"}, "answer": "B", "explanation": "An allegory is a play that is filled with figures which represent such ideas as malice, faithfulness, cruelty, envy, despair,contentment, pride,love etc.  It can further be defined as a work of literature where abstract ideas are personified.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>14", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "''The cell is a cruel place; sometimes a haven'', illustrates the use of", "images": [], "options": {"A": "paradox", "B": "sarcasm", "C": "anti-climax", "D": "personification"}, "answer": "A", "explanation": "Paradox is the correct answer. It is used to indicate a statement that seems untrue at first inspection but becomes clearer and factual at a second look.  The fact that the cell which is a cruel place can also be a safe haven is paradoxical .", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2001>15", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An elegy is a poem that usually expresses a state of", "images": [], "options": {"A": "euphoria", "B": "confusion and chaos", "C": "grandeur", "D": "sorrow and grief"}, "answer": "D", "explanation": "An elegy is a form of poetry that typically expresses sorrow or lamentation, usually for someone who has died. Therefore, the correct answer is 'sorrow and grief'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2001>16", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In ''I am so famished, I can devour a whole cow'', the device used is", "images": [], "options": {"A": "hyperbole", "B": "metaphor", "C": "irony", "D": "sarcasm"}, "answer": "A", "explanation": "Hyperbole is an extravagant exaggeration  of fact, often deployed for acute comic effect. Here, the speaker boasts about his ability to devour an entire cow. This of course is an exaggeration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>17", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The repetition of initial consonant sounds in poetry is", "images": [], "options": {"A": "assonance", "B": "rhyme", "C": "alliteration", "D": "oxymoron"}, "answer": "C", "explanation": "Alliteration is the systematic repetition of certain consonant sounds in a poetic line or nearby lines, at the beginning of words, in order to produce a specific sound effect", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>18", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "''Here comes the princess; now heaven walks on earth'', illustrates the use of", "images": [], "options": {"A": "contrast", "B": "metaphor", "C": "metonymy", "D": "meiosis"}, "answer": "B", "explanation": "The phrase ''Here comes the princess; now heaven walks on earth'' is an example of a metaphor. A metaphor is a figure of speech that makes a comparison between two unlike things. In this case, the princess is being compared to heaven, suggesting that her presence is as delightful or wonderful as heaven. The other options (contrast, metonymy, meiosis) do not accurately describe this literary device.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>19", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In the line '' I walk upon the thorns of life'', the metre is", "images": [], "options": {"A": "trochaic", "B": "anapaestic", "C": "iambic", "D": "dactylic"}, "answer": "C", "explanation": "The line is composed in iambic tetrameter, that is, four iambic feet: i WALK/ uPON/ the THORNS/ of LIFE/  The iambic meter is a combination of two syllables, following the pattern: unstressed syllable + stressed syllable.   NOTE THAT THE STRESSED SYLLABLE IS USUALLY CAPITALISED.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2001>20", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An ode is usually a poem written for", "images": [], "options": {"A": "condemnation", "B": "celebration", "C": "instruction", "D": "entertainment"}, "answer": "B", "explanation": "An Ode is a meditative poem which addresses itself to a person or thing in which the good qualities of such a person or object are highlighted and commended.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>21", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the passage below and answer the question    The killing of a whale at sea isn't pleasant to witness or even to contemplate. Hunted down through solar and other highly specialized equipment, the whale has no more chance of escape like a steer in a slaughterhouse. The manner of his death, however, is very different. A grenade-tipped harpoon explodes deep within his body, often causing prolonged suffering before the gentle-giant, whose intelligence may be second only to our own, is reduced to a carcass ready for processing into crayons, lipstick, shoe polish, fertilizer, margarine and pet food.   The inhumane manner of death , however, is the least part of the scandal known as the whaling industry. Much more important is the fact that the killing is quite unnecessary. Adequate substitutes exist for every single use to which the whale carcasses are currently put, and although some 32,000 whales are killed every year, the sum of commodities are provide is insignificant in the world's economy.    The passage is", "images": [], "options": {"A": "descriptive", "B": "narrative", "C": "argumentative", "D": "expository"}, "answer": "D", "explanation": "The passage is expository becasuse it sheds light on the brutal act of whale-killing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>22", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the passage below and answer the question    The killing of a whale at sea isn't pleasant to witness or even to contemplate. Hunted down through solar and other highly specialized equipment, the whale has no more chance of escape like a steer in a slaughterhouse. The manner of his death, however, is very different. A grenade-tipped harpoon explodes deep within his body, often causing prolonged suffering before the gentle-giant, whose intelligence may be second only to our own, is reduced to a carcass ready for processing into crayons, lipstick, shoe polish, fertilizer, margarine and pet food.   The inhumane manner of death , however, is the least part of the scandal known as the whaling industry. Much more important is the fact that the killing is quite unnecessary. Adequate substitutes exist for every single use to which the whale carcasses are currently put, and although some 32,000 whales are killed every year, the sum of commodities are provide is insignificant in the world's economy. The theme of the passage is (that)", "images": [], "options": {"A": "whales are a menace to mankind", "B": "the killing of whale is unnecessary", "C": "the importance of whale-hunting", "D": "whales are highly intelligent"}, "answer": "B", "explanation": "A theme is the central idea a work on art focuses on. The passage centres on the idea that whale-killing is not necessary.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>23", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the passage below and answer the question    The killing of a whale at sea isn't pleasant to witness or even to contemplate. Hunted down through solar and other highly specialized equipment, the whale has no more chance of escape like a steer in a slaughterhouse. The manner of his death, however, is very different. A grenade-tipped harpoon explodes deep within his body, often causing prolonged suffering before the gentle-giant, whose intelligence may be second only to our own, is reduced to a carcass ready for processing into crayons, lipstick, shoe polish, fertilizer, margarine and pet food.   The inhumane manner of death , however, is the least part of the scandal known as the whaling industry. Much more important is the fact that the killing is quite unnecessary. Adequate substitutes exist for every single use to which the whale carcasses are currently put, and although some 32,000 whales are killed every year, the sum of commodities are provide is insignificant in the world's economy. The underlined expression suggests that the writer", "images": [], "options": {"A": "has an aversion to the process", "B": "finds the activity fascinating", "C": "is aloof to the activity", "D": "does not dislike the process"}, "answer": "A", "explanation": "The underlined expression suggests that the writer hates the process, Aversion means great dislike or hatred.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>24", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the passage below and answer the question    The killing of a whale at sea isn't pleasant to witness or even to contemplate. Hunted down through solar and other highly specialized equipment, the whale has no more chance of escape like a steer in a slaughterhouse. The manner of his death, however, is very different. A grenade-tipped harpoon explodes deep within his body, often causing prolonged suffering before the gentle-giant, whose intelligence may be second only to our own, is reduced to a carcass ready for processing into crayons, lipstick, shoe polish, fertilizer, margarine and pet food.   The inhumane manner of death , however, is the least part of the scandal known as the whaling industry. Much more important is the fact that the killing is quite unnecessary. Adequate substitutes exist for every single use to which the whale carcasses are currently put, and although some 32,000 whales are killed every year, the sum of commodities are provide is insignificant in the world's economy. ''.....gentle giant'' conveys the picture of being", "images": [], "options": {"A": "ferocious", "B": "tame", "C": "timid", "D": "brave"}, "answer": "B", "explanation": "To be a gentle giant means to kind, mild or gentle despite being large in size. Tame is the most suitable option because tame animals are not dangerous.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>25", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the passage below and answer the question    The killing of a whale at sea isn't pleasant to witness or even to contemplate. Hunted down through solar and other highly specialized equipment, the whale has no more chance of escape like a steer in a slaughterhouse. The manner of his death, however, is very different. A grenade-tipped harpoon explodes deep within his body, often causing prolonged suffering before the gentle-giant, whose intelligence may be second only to our own, is reduced to a carcass ready for processing into crayons, lipstick, shoe polish, fertilizer, margarine and pet food.   The inhumane manner of death , however, is the least part of the scandal known as the whaling industry. Much more important is the fact that the killing is quite unnecessary. Adequate substitutes exist for every single use to which the whale carcasses are currently put, and although some 32,000 whales are killed every year, the sum of commodities are provide is insignificant in the world's economy. ''...like a steer in a slaughterhouse'' is an example of", "images": [], "options": {"A": "simile", "B": "metaphor", "C": "personification", "D": "assonance"}, "answer": "A", "explanation": "Simile is a figure of speech which draws compariosn between two things which are not always taken to be similar to each other. The use of LIKE exposes the deployment of the simile.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>26", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the question    Thou art the judge of man  Judging his plans and behaviour  Judging his speech and egotism  You are the patient Judge    Nations plan without having thee in view  They boast of their will  But soon you show them their follies  You are the patient Judge    Tomorrow and Tomorrow, go here and there  Time smiles and laughs  He frowns his face and consults with fate  You are the patient Judge.    The poetic device used in the first line is", "images": [], "options": {"A": "apostrophe", "B": "personification", "C": "euphemism", "D": "litotes"}, "answer": "A", "explanation": "Apostrophe is a reference to an entity, person or thing that is absent as if such an entity, person or thing were present. Here, Time is being referred to.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>27", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the question    Thou art the judge of man  Judging his plans and behaviour  Judging his speech and egotism  You are the patient Judge    Nations plan without having thee in view  They boast of their will  But soon you show them their follies  You are the patient Judge    Tomorrow and Tomorrow, go here and there  Time smiles and laughs  He frowns his face and consults with fate  You are the patient Judge. The last line of each stanza illustrates", "images": [], "options": {"A": "repetition", "B": "refrain", "C": "chorus", "D": "alliteration"}, "answer": "B", "explanation": "Refrain refers to a word, phrase or any expression that is repeated at regular intervals in a poem, often after a group of lines. The line, \"You are the patient judge\", is repeated at the end of each stanza: therefore, it is a refrain (chorus).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>28", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the question    Thou art the judge of man  Judging his plans and behaviour  Judging his speech and egotism  You are the patient Judge    Nations plan without having thee in view  They boast of their will  But soon you show them their follies  You are the patient Judge    Tomorrow and Tomorrow, go here and there  Time smiles and laughs  He frowns his face and consults with fate  You are the patient Judge. The dominant device used in stanza three is", "images": [], "options": {"A": "alliteration", "B": "assonance", "C": "onomatopoeia", "D": "personification"}, "answer": "D", "explanation": "Personification is a figurative device which gives the features of human beings to inanimate objects.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>29", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the question    Thou art the judge of man  Judging his plans and behaviour  Judging his speech and egotism  You are the patient Judge    Nations plan without having thee in view  They boast of their will  But soon you show them their follies  You are the patient Judge    Tomorrow and Tomorrow, go here and there  Time smiles and laughs  He frowns his face and consults with fate  You are the patient Judge. The poem is about", "images": [], "options": {"A": "judgement", "B": "fate", "C": "time", "D": "life"}, "answer": "C", "explanation": "The poem is all about time. Time is presented as a judge that judges the follies of man; time is all-powerful.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2001>30", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the question    Thou art the judge of man  Judging his plans and behaviour  Judging his speech and egotism  You are the patient Judge    Nations plan without having thee in view  They boast of their will  But soon you show them their follies  You are the patient Judge    Tomorrow and Tomorrow, go here and there  Time smiles and laughs  He frowns his face and consults with fate  You are the patient Judge. The extract teaches us to use time", "images": [], "options": {"A": "to the fullest", "B": "wisely", "C": "to plan", "D": "for pleasure"}, "answer": "B", "explanation": "The poem suggests that time is a judge that evaluates our actions and plans. It also suggests that time reveals the follies of those who do not consider it in their plans. Therefore, the poem teaches us to use time wisely.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>31", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    O that I served that lady,  And might not be delivered to the world  Till I had made mine own occasion mellow,  What my estate is!  (Act 1 Sc. 11)    The speaker is", "images": [], "options": {"A": "Orsino", "B": "Sir Andrew", "C": "Viola", "D": "Valentine"}, "answer": "B", "explanation": "The speaker is Sir Andrew. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>32", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    O that I served that lady,  And might not be delivered to the world  Till I had made mine own occasion mellow,  What my estate is!  (Act 1 Sc. 11) ''That lady'' refers to", "images": [], "options": {"A": "Olivia", "B": "Maria", "C": "Viola", "D": "the Duchess"}, "answer": "A", "explanation": "'That lady' in the extract refers to Olivia. In the play, Viola (as Cesario) serves and falls in love with Olivia.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>33", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    O that I served that lady,  And might not be delivered to the world  Till I had made mine own occasion mellow,  What my estate is!  (Act 1 Sc. 11) The speaker is addressing", "images": [], "options": {"A": "a sea captain, friend to Sebastian", "B": "a sea captain, friend to Viola", "C": "Sir Toby, uncle to Olivia", "D": "Malvolio, steward to Olivia"}, "answer": "B", "explanation": "In the given extract from Act 1 Scene 11, the speaker is addressing a sea captain who is a friend to Viola. The speaker is expressing a wish to serve the lady (Olivia) and not be 'delivered to the world' until he has made his own occasion mellow, meaning he wants to improve his own situation before being presented to the world. The sea captain is a friend to Viola, who is in disguise as Cesario in the play.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>34", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    O that I served that lady,  And might not be delivered to the world  Till I had made mine own occasion mellow,  What my estate is!  (Act 1 Sc. 11) The word ''delivered'' in line 2 means", "images": [], "options": {"A": "condemned", "B": "sent away", "C": "made known", "D": "forgotten"}, "answer": "B", "explanation": "It means sent away. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>35", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : I could marry this wenchfor this device  B : So could I too.  A : And ask no other dowry with her but such another jest.  B : Nor I neither.  C : Here comes my noble gull-catcher.  A : Wilt thou set thy foot o my neck?  B : Or o' mine either?  A : Shall I play my freedom at tray: and become thy bondslave?  B : I faith, or I either?  (Act 2 Sc V)    Speaker A is", "images": [], "options": {"A": "Anotonio", "B": "The Duke", "C": "Sir Toby", "D": "Fabian"}, "answer": "C", "explanation": "In the given extract from William Shakespeare's play 'Twelfth Night', Speaker A is Sir Toby. Sir Toby is a character in the play who is known for his wit and humor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>36", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : I could marry this wenchfor this device  B : So could I too.  A : And ask no other dowry with her but such another jest.  B : Nor I neither.  C : Here comes my noble gull-catcher.  A : Wilt thou set thy foot o my neck?  B : Or o' mine either?  A : Shall I play my freedom at tray: and become thy bondslave?  B : I faith, or I either?  (Act 2 Sc V) Speaker B is", "images": [], "options": {"A": "Sir Andrew", "B": "Feste", "C": "Curio", "D": "Sebastian"}, "answer": "A", "explanation": "In the given extract from William Shakespeare's play 'Twelfth Night', Speaker B is Sir Andrew. Sir Andrew is a character in the play who is often the butt of other characters' jokes.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2001>37", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : I could marry this wenchfor this device  B : So could I too.  A : And ask no other dowry with her but such another jest.  B : Nor I neither.  C : Here comes my noble gull-catcher.  A : Wilt thou set thy foot o my neck?  B : Or o' mine either?  A : Shall I play my freedom at tray: and become thy bondslave?  B : I faith, or I either?  (Act 2 Sc V) Speaker A and B are discussing", "images": [], "options": {"A": "Viola", "B": "Olivia", "C": "Maria", "D": "Malvolio"}, "answer": "C", "explanation": "The extract is from Shakespeare's play 'Twelfth Night'. In this scene, Sir Toby Belch (Speaker A) and Sir Andrew Aguecheek (Speaker B) are discussing Maria (Option 3). They are praising her for her wit and jesting, and joking about marrying her for it.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2001>38", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : I could marry this wenchfor this device  B : So could I too.  A : And ask no other dowry with her but such another jest.  B : Nor I neither.  C : Here comes my noble gull-catcher.  A : Wilt thou set thy foot o my neck?  B : Or o' mine either?  A : Shall I play my freedom at tray: and become thy bondslave?  B : I faith, or I either?  (Act 2 Sc V) The conversation reveals that Speaker B is", "images": [], "options": {"A": "very confident", "B": "very shy", "C": "easily persuaded", "D": "easily confused"}, "answer": "C", "explanation": "The conversation reveals that Speaker B is easily persuaded", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2001>39", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : I could marry this wenchfor this device  B : So could I too.  A : And ask no other dowry with her but such another jest.  B : Nor I neither.  C : Here comes my noble gull-catcher.  A : Wilt thou set thy foot o my neck?  B : Or o' mine either?  A : Shall I play my freedom at tray: and become thy bondslave?  B : I faith, or I either?  (Act 2 Sc V) Speaker A is", "images": [], "options": {"A": "Feste", "B": "Viola", "C": "Clown", "D": "Olivia"}, "answer": "B", "explanation": "Speaker A is Viola. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2001>40", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : I could marry this wenchfor this device  B : So could I too.  A : And ask no other dowry with her but such another jest.  B : Nor I neither.  C : Here comes my noble gull-catcher.  A : Wilt thou set thy foot o my neck?  B : Or o' mine either?  A : Shall I play my freedom at tray: and become thy bondslave?  B : I faith, or I either?  (Act 2 Sc V) Speaker B is", "images": [], "options": {"A": "Sir Andrew", "B": "Clown", "C": "Feste", "D": "The Duke"}, "answer": "C", "explanation": "Speaker B is Feste. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2001>41", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : Save thee, friend and thy music. Dost thou live by thy labor?  B : No, sir, I live by the church.  A : Art thou a churchman?  B : No such matter, sir, I do live by the church, for I do live at my hose, and my house doth stand by the church.  (Act 3 Sc 1.)    The phrase ''live by'' as used in the extract is an example of", "images": [], "options": {"A": "onomatopoeia", "B": "antithesis", "C": "pun", "D": "irony"}, "answer": "B", "explanation": "Antithesis is a device in which two unlike ideas are put against each other for effect and obvious contrast.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2001>42", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    A : Save thee, friend and thy music. Dost thou live by thy labor?  B : No, sir, I live by the church.  A : Art thou a churchman?  B : No such matter, sir, I do live by the church, for I do live at my hose, and my house doth stand by the church.  (Act 3 Sc 1.) Speakers A and B are", "images": [], "options": {"A": "at the sea-coat", "B": "in the theatre", "C": "in Orsino's palace", "D": "at Olivia's garden"}, "answer": "D", "explanation": "Speakers A and B are at Olivia's garden.This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2001>43", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question:    A : Fie, thou dishonest Satan! I call thee by the most modest  terms, for I am one of those gentle ones that will use the devil  himself with courtesy. Sayest thou that house is dark?  B : As hell, Sir Topas  (Act 4 sc. ll)    Speaker A is", "images": [], "options": {"A": "Feste", "B": "Clown", "C": "Sir Toby", "D": "Malvolio"}, "answer": "A", "explanation": "Speaker A is Feste. Feste is a character in Shakespeare's play 'Twelfth Night' who often disguises himself as Sir Topas, a priest. This is evident in the extract where speaker B addresses speaker A as Sir Topas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>44", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question:    A : Fie, thou dishonest Satan! I call thee by the most modest  terms, for I am one of those gentle ones that will use the devil  himself with courtesy. Sayest thou that house is dark?  B : As hell, Sir Topas  (Act 4 sc. ll) The person addressed is", "images": [], "options": {"A": "Febian", "B": "Sir Andrew", "C": "Sir Toby", "D": "Malvolio"}, "answer": "D", "explanation": "The person being addressed is Malvolio. Malvolio is another character in 'Twelfth Night' who is tricked into believing that he is possessed by the devil. This is evident in the extract where speaker A accuses the person being addressed of being dishonest and satanic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>45", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question:    A : Fie, thou dishonest Satan! I call thee by the most modest  terms, for I am one of those gentle ones that will use the devil  himself with courtesy. Sayest thou that house is dark?  B : As hell, Sir Topas  (Act 4 sc. ll) Speaker A, wants the audience to believe that he is", "images": [], "options": {"A": "dealing with a mad person", "B": "daling with a stranger", "C": "addressing a stranger", "D": "addressing a sane person"}, "answer": "A", "explanation": "Here, Feste the Fool approaches Malvolio and pretends to be \"Sir Topas.\" \"Sir Topas\" says that he's come to visit \"Malvolio the lunatic.\" Malvolio begs \"Sir Topas\" to fetch Olivia so the whole mess can be straightened out.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>46", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question:    A : Fie, thou dishonest Satan! I call thee by the most modest  terms, for I am one of those gentle ones that will use the devil  himself with courtesy. Sayest thou that house is dark?  B : As hell, Sir Topas  (Act 4 sc. ll) Sir Topas is expected to be a", "images": [], "options": {"A": "tacher", "B": "physician", "C": "parson", "D": "lunatic"}, "answer": "C", "explanation": "In the given extract, Speaker B addresses Speaker A as 'Sir Topas'. Sir Topas is a character from Shakespeare's play 'Twelfth Night' who is a curate or a parson. Therefore, in this context, Sir Topas is expected to be a 'parson'. A parson is a member of the clergy, especially a Protestant minister; pastor; rector. Hence, the correct answer is 'parson'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>47", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    I am sorry, madam, I have hurt your kinsman,  But had it been the brother of my blood,  I must have done no less with wit and safety.  You throw a strange regard upon me, and by that  I do perceieve it hath offended you;  Pardon me, sweet one, even for the vows  We made each other but so late ago.  (Act 5 Sc. 1)    The speaker is", "images": [], "options": {"A": "Sir Toby", "B": "Sebastian", "C": "Viola", "D": "Sir Andrew"}, "answer": "B", "explanation": "The speaker in the extract is Sebastian. In the play 'Twelfth Night' by William Shakespeare, Sebastian is the one who hurts Sir Toby, Olivia's kinsman, and then apologizes to Olivia (madam) for his actions. He explains that he would have done the same even if the person he hurt was his own brother, implying his actions were necessary for his safety.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>48", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    I am sorry, madam, I have hurt your kinsman,  But had it been the brother of my blood,  I must have done no less with wit and safety.  You throw a strange regard upon me, and by that  I do perceieve it hath offended you;  Pardon me, sweet one, even for the vows  We made each other but so late ago.  (Act 5 Sc. 1) .......''the brother of my blood'' implies he is", "images": [], "options": {"A": "your (own) brother", "B": "my (own) brother", "C": "our (own) brother", "D": "their (own) brother"}, "answer": "B", "explanation": "The phrase 'the brother of my blood' implies 'my own brother'. In this context, Sebastian is saying that even if the person he had hurt was his own brother, he would have done the same. This is a way of expressing that his actions were not personal but necessary for his safety.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>49", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    I am sorry, madam, I have hurt your kinsman,  But had it been the brother of my blood,  I must have done no less with wit and safety.  You throw a strange regard upon me, and by that  I do perceieve it hath offended you;  Pardon me, sweet one, even for the vows  We made each other but so late ago.  (Act 5 Sc. 1) ''the vows'' refers to", "images": [], "options": {"A": "divorce", "B": "love", "C": "marriage", "D": "courtship"}, "answer": "C", "explanation": "In the context of the extract, 'the vows' refers to promises or commitments made between two people, which is often associated with love or marriage. Therefore, the answer is 'marriage'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2001>50", "subject": "Literature", "year": "2001", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: TWELFTH NIGHT", "question": "Read the extract below and answer the question    I am sorry, madam, I have hurt your kinsman,  But had it been the brother of my blood,  I must have done no less with wit and safety.  You throw a strange regard upon me, and by that  I do perceieve it hath offended you;  Pardon me, sweet one, even for the vows  We made each other but so late ago.  (Act 5 Sc. 1) The speaker is replied by", "images": [], "options": {"A": "Antonio", "B": "Olivia", "C": "Sebastian", "D": "Orsino"}, "answer": "D", "explanation": "The speaker is replied by Orsino. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>1", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A couplet is", "images": [], "options": {"A": "a pastoral poem", "B": "two successive rhyming lines", "C": "a love poem", "D": "two successive unrhyming lines"}, "answer": "B", "explanation": "A couplet is a poem of two successive rhyming lines. e.g.   Had we but world enough and TIME (a)  This coyness lady were no CRIME (a)    A pastoral poem is a poem which describes the simple life of rural people, especially of shepherds, around whom are beauty, love, music and values which remain forever green in mind.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2002>2", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The first eight lines of a sonnet is a/an", "images": [], "options": {"A": "tercet", "B": "sestet", "C": "octave", "D": "quatrain"}, "answer": "C", "explanation": "Tercet  is a poem of three lines  Quatrain is a poem of four lines  Sestet is a poem of six lines  Couplet is a poem of two lines  Octave is a poem of eight lines    Hence, octave + sestet = sonnet.  Note that the pertrarchan sonnet is divided into two: an octave and a sestet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>3", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An ode is a", "images": [], "options": {"A": "poem about love", "B": "poem of mouring", "C": "praise poem", "D": "narrative poem"}, "answer": "C", "explanation": "An ode is a poem that is written in the form of an address to a thing. It often praises what it addresses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>4", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The expression of unpleasant experiences in a mild way is", "images": [], "options": {"A": "hyperbole", "B": "metaphor", "C": "euphemism", "D": "paradox"}, "answer": "C", "explanation": "Euphemism is a figure of speech which states a painful fact in a mild manner in order to cushion the effect of its seriousness. For example, when someone dies, we can say that the person has kicked the bucket.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2002>5", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A poem which tells a story in the form of a song is a/an", "images": [], "options": {"A": "epic", "B": "ballad", "C": "pastoral", "D": "eulogy"}, "answer": "B", "explanation": "A ballad is an anonymous narrative passed on from generation by word of mouth to be sung and danced to  before a crowd. Because it is a narrative, it tells a story and forms part of the oral traditions of the society it represents.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>6", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The paragraph in prose can be compared to _ in poetry", "images": [], "options": {"A": "couplet", "B": "line", "C": "stanza", "D": "verse"}, "answer": "C", "explanation": "Paragraph is to prose as stanza is to poetry.  A paragraph is a group of sentence that conntain one idea; similarly, a stanza is a group of lines that has a unified idea.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>7", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In  to eat of the tree , the device used is", "images": [], "options": {"A": "Irony", "B": "personification", "C": "allusion", "D": "synecdoche"}, "answer": "D", "explanation": "Synedoche is a figurative device in which, the part is used for the whole. It  substittutes a significant part of something for the thing itself. Here, the tree is used to represent a part (its fruit).", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2002>8", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Poetry is defined by", "images": [], "options": {"A": "words written in sequence", "B": "condensed use of language", "C": "evocation of feelings", "D": "legends and myths"}, "answer": "B", "explanation": "Poetry is different from other genres of literature in that it is written in condensed language, that is, poetry says a lot in a few lines.   Evocation of feeling is not synonymous with poetry because all genres have the ability to express feelings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2002>9", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Salute to the Elephant\" is an example of _ poetry", "images": [], "options": {"A": "traditional", "B": "dramatic", "C": "epic", "D": "narrative"}, "answer": "A", "explanation": "This is an example of a traditional poem. It talks about the elephant (Ajanaku) from the Yoruba worldview.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>10", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The juxtaposition of two seemingly contradictory words is", "images": [], "options": {"A": "contrast", "B": "anti-climax", "C": "oxymoron", "D": "anti-thesis"}, "answer": "C", "explanation": "The juxtaposition of two seemingly contradictory words is oxymoron.  It yokes terms together in a single expression to reflect a mixture of attitudes towrads an event. It is the placement of two contrasting words side by side, e,g. My experience with my ex-girlfriend was a bitter sweet one.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2002>11", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "''A little learning is dangerous  Drink deep or taste not the Pierian spring''    The extract illustrates a", "images": [], "options": {"A": "quatrain", "B": "hexameter", "C": "couplet", "D": "sestet"}, "answer": "B", "explanation": "A couplet should have two rhyming lines. These lines do not rhyme; therefore, it is wrong to brand them a couplet.     M.H Abrams defines the couplet as a pair of rhymed lines that are equal in length.   Hexameter refers to a combination of six feet. The extract above has eighteen syllables that can be broken into six groups consisting of three syllables each.    Therefore, the choice of hexameter appears to be the most logical.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>12", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Grace me no grace, nor uncle me no uncle;  I am no traitors uncle;  and that word ''grace'' in an ungracious mouth  is but profane.    The dominant literary device used in the extract is", "images": [], "options": {"A": "alliteration", "B": "assonance", "C": "onomatopoeia", "D": "repetition"}, "answer": "D", "explanation": "Repetition is a figure of speech in which a word, phrase or ideas is expressed more than once in a piece of poetry, drama passage or a passage for purpose of emphasis. Here, words such as \"grace\" and \"uncle\" are repeated for emphasis.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2002>13", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "You are the salt of my life illustrates a", "images": [], "options": {"A": "metaphor", "B": "simile", "C": "irony", "D": "personification"}, "answer": "A", "explanation": "Metaphor is a direct comparison between two entities of different nature. Here, the addressee is directly referred to as \"salt\".", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2002>14", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The sequence of beats in a poem is its", "images": [], "options": {"A": "rhythm", "B": "rhyme", "C": "irony", "D": "personification"}, "answer": "A", "explanation": "Rhythm is the measured flow of words and phrases in poetry . It can also be described as the movement of thought to facilitate mood and meaning in poetry. Rhythm is the sequence of beats in speech or poetry. In poetry, it is marked by poetic metre.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2002>15", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Charm strikes the sight, but merit wins the soul is an example of", "images": [], "options": {"A": "oxymoron", "B": "epigram", "C": "epithet", "D": "bathos"}, "answer": "B", "explanation": "The epigram is a short statement that contains a lot of wisdom; it is a short witty statement. Here, the speaker claims that your physical appeareance (charm) might appeal to people, but what actually attracts people is your merit (integrity and persdonality).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>16", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary device that creates a mental picture of a situation is", "images": [], "options": {"A": "imagery", "B": "symbolism", "C": "flashback", "D": "epilogue"}, "answer": "A", "explanation": "A literary device that creates a mental picture of a situation is imagery. It is the use of words to paint a picture of what is being discussed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>17", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short witty statement is an", "images": [], "options": {"A": "epistle", "B": "eulogy", "C": "epigram", "D": "anecdote"}, "answer": "C", "explanation": "An epigram is a brief, interesting, memorable, and sometimes surprising or satirical statement. It is often used in poetry, but also found in prose and drama. The term 'epigram' originates from the Greek word 'epigramma' meaning 'inscription'. Therefore, the correct answer is 'epigram'. An epistle is a formal letter, a eulogy is a speech or piece of writing that praises someone or something highly, typically someone who has just died, and an anecdote is a short amusing or interesting story about a real incident or person.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2002>18", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The whole town was present at the wedding ceremony is an example of", "images": [], "options": {"A": "oxymoron", "B": "hyperbole", "C": "onomatopoeia", "D": "repetition"}, "answer": "B", "explanation": "Hyperbole is an extravagant exaggeration of fact, often deployed for acute comic effect. Here, the speaker exaggerates by saying the whole town was present at the wedding ceremony.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2002>19", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In a literary work, a clown normally", "images": [], "options": {"A": "directs the action", "B": "creates comic relief", "C": "supports the protagonist", "D": "creats the atmosphere"}, "answer": "B", "explanation": "The main thing a clown does in a literary work is to provide humour. If the play is a tragedy, the clown will help to reduce the tension by creating comic relief.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>20", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Hear thou, great Ann ! Whom three realms obey,  Dost sometimes counsel take - and sometimes tea\"  depicts the use of", "images": [], "options": {"A": "paradox", "B": "imagery", "C": "pathos", "D": "bathos"}, "answer": "D", "explanation": "Bathos is also known as anti-climax. It is a descent from the sublime to the ridiculous. The expression, \"Dost sometimes counsel take - and sometimes tea\" shows a descent from something serious to something unserious: \"counsel\" and \"tea\".", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2002>21", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "The month of July crept in. The sky, like a hooded monk wore black, as in mourning, ready to shed its load. The sun was mystified while heaps of sand and dust spiralled high up in the sky, sending high and low alike scurrying into hiding. The town had never known such a downpour, it was forty-eight hours of weeping by both the heavens and the inhabitants of Olusi who lost most of their life's savings in this destructive blessing.    The subject of the passage is", "images": [], "options": {"A": "cloud", "B": "climate", "C": "rainfall", "D": "flood"}, "answer": "C", "explanation": "The subject of the passage is 'rainfall'. The passage describes a heavy downpour that lasted for forty-eight hours, causing destruction in the town of Olusi. The options 'cloud', 'climate', and 'flood' are related to the subject but they are not the main focus of the passage. The main focus is the heavy rainfall and its effects.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>22", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "The month of July crept in. The sky, like a hooded monk wore black, as in mourning, ready to shed its load. The sun was mystified while heaps of sand and dust spiralled high up in the sky, sending high and low alike scurrying into hiding. The town had never known such a downpour, it was forty-eight hours of weeping by both the heavens and the inhabitants of Olusi who lost most of their life's savings in this destructive blessing. The month of July crept in is an example of", "images": [], "options": {"A": "metaphor", "B": "synecdoche", "C": "imagery", "D": "apostrophe"}, "answer": "C", "explanation": "The phrase 'The month of July crept in' is an example of 'imagery'. Imagery is a literary device that uses descriptive language to create mental images and stimulate the senses. In this case, the phrase creates a mental image of the month of July slowly approaching, which sets the stage for the events that follow. The options 'metaphor', 'synecdoche', and 'apostrophe' are also literary devices, but they do not accurately describe the use of language in this phrase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>23", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "The month of July crept in. The sky, like a hooded monk wore black, as in mourning, ready to shed its load. The sun was mystified while heaps of sand and dust spiralled high up in the sky, sending high and low alike scurrying into hiding. The town had never known such a downpour, it was forty-eight hours of weeping by both the heavens and the inhabitants of Olusi who lost most of their life's savings in this destructive blessing. The expression the sky, like a hooded monk wore black, illustrates", "images": [], "options": {"A": "symbolism", "B": "paradox", "C": "personification", "D": "metaphor"}, "answer": "C", "explanation": "It is a figurative device which gives the features of human beings to inanimate objects", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>24", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "..........high and low alike refers to the", "images": [], "options": {"A": "rulers of the people", "B": "women and their children", "C": "chiefs and their subjects", "D": "rich and the poor"}, "answer": "D", "explanation": "The phrase 'high and low alike' refers to all categories of people irrespective of their social or economic status. In this context, it refers to the 'rich and the poor'. This is because the destructive blessing affected everyone in the town, regardless of their wealth or poverty.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2002>25", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "........destructive blessing shows the use of", "images": [], "options": {"A": "antithesis", "B": "oxymoron", "C": "apostrohe", "D": "parallelism"}, "answer": "B", "explanation": "Oxymoron refers to the placement of two contrasting words side by side. Here, \"destructive\" and \"blessings\" and two contrasting words that are juxtaposed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>26", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the question    Money here, Money there  Everywhere, anywhere, whatever you want, Money  But where is the Money to spend?    Children and family matters, you're useful  Health and education matters  Food and transport  Night and day  Church and Mosque  In the Lord's name you're needed everywhere  Life is tough without you  Nothing comes easy without you.    Money O! where are you?  You are as hard as a nut to crack  Without you our problems are like my mother's  Paying beads  Will you desert the commoners like that?    They search  They count  They wait  They cry  Yet their is life of beaded needs.    The theme of the poem is", "images": [], "options": {"A": "religion", "B": "enlightenment", "C": "struggle", "D": "hardship"}, "answer": "D", "explanation": "The theme of the poem is 'hardship'. The poem talks about the struggle of people in their daily lives without money. It mentions the various needs and wants that require money and how life is tough without it. This clearly depicts the hardship faced by people in their daily lives due to lack of money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>27", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the question    Money here, Money there  Everywhere, anywhere, whatever you want, Money  But where is the Money to spend?    Children and family matters, you're useful  Health and education matters  Food and transport  Night and day  Church and Mosque  In the Lord's name you're needed everywhere  Life is tough without you  Nothing comes easy without you.    Money O! where are you?  You are as hard as a nut to crack  Without you our problems are like my mother's  Paying beads  Will you desert the commoners like that?    They search  They count  They wait  They cry  Yet their is life of beaded needs. The dominant poetic devices used are", "images": [], "options": {"A": "onomatopoeia and refrain", "B": "metaphor and simile", "C": "repetition and personification", "D": "pun and hyperbole"}, "answer": "C", "explanation": "The dominant poetic devices used are repetition and personification. Money is repeated a number of times.  Personification is also dominant in that money is addressed and regarded as if it were human.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2002>28", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the question    Money here, Money there  Everywhere, anywhere, whatever you want, Money  But where is the Money to spend?    Children and family matters, you're useful  Health and education matters  Food and transport  Night and day  Church and Mosque  In the Lord's name you're needed everywhere  Life is tough without you  Nothing comes easy without you.    Money O! where are you?  You are as hard as a nut to crack  Without you our problems are like my mother's  Paying beads  Will you desert the commoners like that?    They search  They count  They wait  They cry  Yet their is life of beaded needs. The tone of the poem is one of", "images": [], "options": {"A": "sadness and lamentation", "B": "happiness and excitement", "C": "apathy and excitement", "D": "apathy and non-challance"}, "answer": "A", "explanation": "The tone of the poem is one of sadness and lamentation. This is seen in the way the speaker complains about how money is important but hard to get.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>29", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the question    Money here, Money there  Everywhere, anywhere, whatever you want, Money  But where is the Money to spend?    Children and family matters, you're useful  Health and education matters  Food and transport  Night and day  Church and Mosque  In the Lord's name you're needed everywhere  Life is tough without you  Nothing comes easy without you.    Money O! where are you?  You are as hard as a nut to crack  Without you our problems are like my mother's  Paying beads  Will you desert the commoners like that?    They search  They count  They wait  They cry  Yet their is life of beaded needs. The use of rhetorical questions _ the poet's message", "images": [], "options": {"A": "emphasizes", "B": "repeats", "C": "recasts", "D": "dramatizes"}, "answer": "A", "explanation": "The poet make use of rhetorical question to emphasise the facxt that money is important but hard to find.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>30", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the poem below and answer the question    Money here, Money there  Everywhere, anywhere, whatever you want, Money  But where is the Money to spend?    Children and family matters, you're useful  Health and education matters  Food and transport  Night and day  Church and Mosque  In the Lord's name you're needed everywhere  Life is tough without you  Nothing comes easy without you.    Money O! where are you?  You are as hard as a nut to crack  Without you our problems are like my mother's  Paying beads  Will you desert the commoners like that?    They search  They count  They wait  They cry  Yet their is life of beaded needs. Lines 13-15 illustrate the use of", "images": [], "options": {"A": "metaphor", "B": "alliteration", "C": "simile", "D": "pun"}, "answer": "C", "explanation": "Lines 13-15 illustrate the use of the simile. Here, money is indirectly compared to a hard nut througfh the use of \"as\".", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2002>31", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    Not in love neither? Then let us say you are sad  Because you are not merry; and 'twere as easy   for you to laugh and leap , and say you are merry  Because you are not sad.  (Act 1 sc 1).    The speaker is", "images": [], "options": {"A": "Portia", "B": "Solanio", "C": "Gratiano", "D": "Bassanjo"}, "answer": "D", "explanation": "The speaker is Bassanio. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>32", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    Not in love neither? Then let us say you are sad  Because you are not merry; and 'twere as easy   for you to laugh and leap , and say you are merry  Because you are not sad.  (Act 1 sc 1). The person addressed is", "images": [], "options": {"A": "Antonio", "B": "Nerissa", "C": "Lorenzo", "D": "Salarino"}, "answer": "B", "explanation": "The person addressed is Nerissa. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>33", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    Not in love neither? Then let us say you are sad  Because you are not merry; and 'twere as easy   for you to laugh and leap , and say you are merry  Because you are not sad.  (Act 1 sc 1). The dominant literary device used in the extract above is", "images": [], "options": {"A": "personification", "B": "contrast", "C": "metonymy", "D": "pun"}, "answer": "B", "explanation": "The dominant literary device used in the extract is contrast. The speaker is contrasting two opposite states of emotion - sadness and merriness. The speaker suggests that it's as easy to be merry because one is not sad, as it is to be sad because one is not merry. This is a clear use of contrast, a literary device where two opposing ideas are put together to highlight their differences.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2002>34", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    Not in love neither? Then let us say you are sad  Because you are not merry; and 'twere as easy   for you to laugh and leap , and say you are merry  Because you are not sad.  (Act 1 sc 1). The speaker is addressing the addressee's", "images": [], "options": {"A": "elopement", "B": "merchandise", "C": "engagement", "D": "melancholy"}, "answer": "D", "explanation": "Antonio (a Venetian merchant) is hanging out with his friends Salarino and Solanio on a street in Venice. Antonio is a sad bunny, though he claims he doesn't know why.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>35", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    Not in love neither? Then let us say you are sad  Because you are not merry; and 'twere as easy   for you to laugh and leap , and say you are merry  Because you are not sad.  (Act 1 sc 1). The underlined expression illustrates", "images": [], "options": {"A": "assonace", "B": "synecdoche", "C": "alliteration", "D": "irony"}, "answer": "C", "explanation": "Alliteration is a sysytematic repetition of certain consonat sounds in a poetic line or nereby lines in order to produce a specific sound effect.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2002>36", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer Question 36 - 40.  I am sorry thou wilt leave my father so  Our house is hell, and thou a merry devil   Didst rob it of some taste of tediousness  But fare thee well: there is a ducat for thee.    The speaker is", "images": [], "options": {"A": "Jessica", "B": "servingman", "C": "Nerissa", "D": "Portia"}, "answer": "A", "explanation": "The speaker in the extract is Jessica. This can be determined from the context of the extract. Jessica is the daughter of Shylock in the play 'The Merchant of Venice' by William Shakespeare. In this scene, she is speaking to Launcelot, who is leaving her father's service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>37", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer Question 36 - 40.  I am sorry thou wilt leave my father so  Our house is hell, and thou a merry devil   Didst rob it of some taste of tediousness  But fare thee well: there is a ducat for thee. Thou in the extract refers to", "images": [], "options": {"A": "Gobbo", "B": "Lancelot", "C": "Salerio", "D": "Leonardo"}, "answer": "B", "explanation": "In the extract, 'thou' refers to Lancelot. This is a line from Shakespeare's 'The Merchant of Venice'. In this scene, Jessica, Shylock's daughter, is speaking to Lancelot, who is leaving Shylock's service. She is expressing her regret that he is leaving, as his humor made their home less tedious.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>38", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer Question 36 - 40.  I am sorry thou wilt leave my father so  Our house is hell, and thou a merry devil   Didst rob it of some taste of tediousness  But fare thee well: there is a ducat for thee. During this speech, the speaker", "images": [], "options": {"A": "betrays his conscience", "B": "chooses the right partner", "C": "gives the addressee a letter", "D": "changes the course of action"}, "answer": "C", "explanation": "During this speech, the speaker gives the addressee a letter", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>39", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer Question 36 - 40.  I am sorry thou wilt leave my father so  Our house is hell, and thou a merry devil   Didst rob it of some taste of tediousness  But fare thee well: there is a ducat for thee. Merry devil illustrates", "images": [], "options": {"A": "oxymoron", "B": "simile", "C": "paradox", "D": "personifiication"}, "answer": "A", "explanation": "Oxymoron is the placing of two contradictory word side by side. Here, \"merry\" and \"devil\" are juxtaposed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>40", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer Question 36 - 40.  I am sorry thou wilt leave my father so  Our house is hell, and thou a merry devil   Didst rob it of some taste of tediousness  But fare thee well: there is a ducat for thee. The speaker is contemplating on", "images": [], "options": {"A": "marriage", "B": "love", "C": "elopement", "D": "disguise"}, "answer": "C", "explanation": "The speaker is contemplating on elopement. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>41", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    ....very vilely in the morning when he is sober, and most vilely  in the afternoon when he is drunk. When he is best he is a little  worse than a man, and when he is worst he is a little better than a beast  (Act 1 sc ll).    The speaker is", "images": [], "options": {"A": "Portia", "B": "Lancelot", "C": "Jessica", "D": "Antonio"}, "answer": "A", "explanation": "The extract is a quote from Portia in Act 1, Scene 2 of 'The Merchant of Venice' where she is talking about her suitors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>42", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    ....very vilely in the morning when he is sober, and most vilely  in the afternoon when he is drunk. When he is best he is a little  worse than a man, and when he is worst he is a little better than a beast  (Act 1 sc ll). The person addressed is", "images": [], "options": {"A": "Gobbo", "B": "Nerissa", "C": "Bassanio", "D": "Lorenzo"}, "answer": "B", "explanation": "In the given extract from Act 1, Scene 2 of 'The Merchant of Venice', Portia is talking to Nerissa about her suitors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>43", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    ....very vilely in the morning when he is sober, and most vilely  in the afternoon when he is drunk. When he is best he is a little  worse than a man, and when he is worst he is a little better than a beast  (Act 1 sc ll). The subject of discussion is the", "images": [], "options": {"A": "Prince of Morocco", "B": "young Baron of England", "C": "Prince of Arragon", "D": "Duke of saxony's nephew"}, "answer": "D", "explanation": "The extract is a description of the Duke of Saxony's nephew in the play 'The Merchant of Venice' by William Shakespeare. The character is described as behaving very badly when he is sober in the morning and even worse when he is drunk in the afternoon. At his best, he is a little worse than a man, and at his worst, he is a little better than a beast.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>44", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    ....very vilely in the morning when he is sober, and most vilely  in the afternoon when he is drunk. When he is best he is a little  worse than a man, and when he is worst he is a little better than a beast  (Act 1 sc ll). The speaker is contemplating on the", "images": [], "options": {"A": "choice of caskets", "B": "loss of his fortune", "C": "most eligible suitor", "D": "outcome of the trial"}, "answer": "C", "explanation": "The speaker is contemplating on the most eligible suitor", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>45", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    ....very vilely in the morning when he is sober, and most vilely  in the afternoon when he is drunk. When he is best he is a little  worse than a man, and when he is worst he is a little better than a beast  (Act 1 sc ll). The dominant literary device used in the extract is", "images": [], "options": {"A": "simile", "B": "paradox", "C": "repetition", "D": "oxymoron"}, "answer": "C", "explanation": "Repitition is a figure of speech in which a word, phrase or idea is expressed more than once in a piece of poetry, drama, passage or a passage for purpose of emphasis. Words like \"vilely\" and \"little\" are repeated.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2002>46", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    Lock up my doors, and when you hear the drum   And the vile squealing of the wry-necked fife.   Clamber not you up to the casements then  Nor thrust you up to the casements then  TO GAZE ON CHRISTIAN FOOLS WITH VARNISHED FACES.    (Act 11 sc V).    The speaker is", "images": [], "options": {"A": "Gratiano", "B": "Shylock", "C": "Lorenzo", "D": "Solanio"}, "answer": "B", "explanation": "The speaker is Shylock. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>47", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    Lock up my doors, and when you hear the drum   And the vile squealing of the wry-necked fife.   Clamber not you up to the casements then  Nor thrust you up to the casements then  TO GAZE ON CHRISTIAN FOOLS WITH VARNISHED FACES.    (Act 11 sc V). The dominant decive used in the extract is", "images": [], "options": {"A": "allusion", "B": "irony", "C": "symbolism", "D": "metonymy"}, "answer": "A", "explanation": "An allusion is a casual reference to a literary work", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>48", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    Lock up my doors, and when you hear the drum   And the vile squealing of the wry-necked fife.   Clamber not you up to the casements then  Nor thrust you up to the casements then  TO GAZE ON CHRISTIAN FOOLS WITH VARNISHED FACES.    (Act 11 sc V). The person addressed is", "images": [], "options": {"A": "Bassanio", "B": "Antonio", "C": "Lancelot", "D": "jessica"}, "answer": "C", "explanation": "Lancelot is the correct answer. This is the most accurate answer according to the text.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>49", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    Lock up my doors, and when you hear the drum   And the vile squealing of the wry-necked fife.   Clamber not you up to the casements then  Nor thrust you up to the casements then  TO GAZE ON CHRISTIAN FOOLS WITH VARNISHED FACES.    (Act 11 sc V). After this scene the person addressed", "images": [], "options": {"A": "portrayed love for his suitor", "B": "informs of the loss at sea", "C": "elopes with her lover", "D": "delivers letter to a suitor"}, "answer": "A", "explanation": "After this scene the person addressed portrayed love for his suitor", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2002>50", "subject": "Literature", "year": "2002", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    Lock up my doors, and when you hear the drum   And the vile squealing of the wry-necked fife.   Clamber not you up to the casements then  Nor thrust you up to the casements then  TO GAZE ON CHRISTIAN FOOLS WITH VARNISHED FACES.    (Act 11 sc V). The underlined expression illustrates", "images": [], "options": {"A": "alliteration", "B": "metaphor", "C": "synecdoche", "D": "personification"}, "answer": "B", "explanation": "Metaphor is a direct comparison between two entities of different nature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>1", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A narrative in the oral tradition that may include legends and fables is a", "images": [], "options": {"A": "balled", "B": "pastoral", "C": "folkale", "D": "romance"}, "answer": "C", "explanation": "Folktale is a narrative in the oral tradition that may include legends and fables.  The ballad is a type of poem that is meant to be sung.  Pastoral refers to poems about country or rural life.  Romance in poetry refers to poems about nature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>2", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short poem written on a tomb is a/an", "images": [], "options": {"A": "dirge", "B": "panegyric", "C": "epigram", "D": "epitaph"}, "answer": "D", "explanation": "An epitaph is an inscription on a tomb (grave).  The dirge is a poem of lamentation.  The epigram is a short witty statement.  Panegyric refers to a poem that gives high praise to its subject.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2003>3", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short speech at the begining of a literary work which serves as commentary is a/an", "images": [], "options": {"A": "monologue", "B": "prologue", "C": "dialogue", "D": "epilogue"}, "answer": "B", "explanation": "The prologue appears at the beginning of a literary work; it serves as an introduction.  A monologue is a long speech made by one person.  A sialogue is a conversation between characters.  An epilogue is the opposite of a prologue; it is the tail-piece of a literary work.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>4", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item", "images": [], "options": {"A": "tragedy", "B": "comdey", "C": "stanza", "D": "farce"}, "answer": "C", "explanation": "The odd item is stanza. tragedy, comdey and farce are all types of drama. Stanza is an element of poetry", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2003>5", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A long narrative  which depicts country life is a/an", "images": [], "options": {"A": "ballad", "B": "epic", "C": "ode", "D": "pastoral"}, "answer": "D", "explanation": "A long narrative which depicts country life is a pastoral. A pastoral is a work of literature portraying an idealized version of country life. The term 'pastoral' comes from 'pastor' meaning 'shepherd', thus associating these works with a life of shepherding, and by extension, the simplicity and purity of life in the country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>6", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Any literary work which holds up society to ridicule is a", "images": [], "options": {"A": "satire", "B": "fable", "C": "lampoon", "D": "limerick"}, "answer": "A", "explanation": "Satire is a literary work which holds up society to ridicule in order to bring about a desired change.  A fable is a story whereby animals are used as characters.   A lampoon is a piece of writing that criticises someone or something in order to make them look ridiculous.  A limerick is a humourous poem of five lines.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>7", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "One of the following is not an African poet", "images": [], "options": {"A": "Lenrie Peters", "B": "Thomas Gray", "C": "J. P. Clark", "D": "Sly Cheney - Coker."}, "answer": "B", "explanation": "Thomas Gray is not an African poet. He was an English poet, letter-writer, classical scholar, and professor at Pembroke College, Cambridge. He is widely known for his Elegy Written in a Country Churchyard, published in 1751. Lenrie Peters, J. P. Clark, and Sly Cheney - Coker are all African poets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2003>8", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item", "images": [], "options": {"A": "The Lion and the jewel", "B": "The Black Hermit", "C": "Murderer in Cathedral", "D": "Robinson Crusoe"}, "answer": "D", "explanation": "Robinson Crusoe by Daniel Defoe is the odd item becasue it is the only work of prose in the option.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2003>9", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A poem expressing on the death of a person is a/an", "images": [], "options": {"A": "epic", "B": "elegy", "C": "ode", "D": "ballad"}, "answer": "B", "explanation": "Elegy is a poem that mourns the death of a person.  An epic is a long narrative poem that tells the story of great warriors and their heroic deeds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>10", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "''Death lays his icy hands on king\" is an example of", "images": [], "options": {"A": "metaphor", "B": "paradox", "C": "hyperbole", "D": "personification"}, "answer": "D", "explanation": "It is a figurative device which gives the features of human beings to inanimate objects. Here, death is said to lay its hands on kings; that is, it is given the human attribute of laying of hands.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2003>11", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "pick the odd item", "images": [], "options": {"A": "structure", "B": "mood", "C": "style", "D": "language"}, "answer": "B", "explanation": "Mood is the odd item. The other options are among the elements of form in a literary work while the mood  falls under the content.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2003>12", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A recurrent image in a literary work that illustrates theme is", "images": [], "options": {"A": "symbol", "B": "dramatic irony", "C": "motif", "D": "pathetic fallacy"}, "answer": "C", "explanation": "A motif is a recurring image, idea, or symbol that develops or explains a theme in a work of literature. Motifs are used to establish a theme or a certain mood; they have a symbolic meaning. On the other hand, a symbol is a mark, sign, or word that indicates, signifies, or is understood as representing an idea, object, or relationship. Dramatic irony is a literary device by which the audience's or reader's understanding of events or individuals in a work surpasses that of its characters. Pathetic fallacy is a literary device that attributes human qualities and emotions to inanimate objects of nature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>13", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Diction is a writer's choice of", "images": [], "options": {"A": "styles", "B": "plot", "C": "theme", "D": "words"}, "answer": "D", "explanation": "Diction refers to the choice of words a writer uses in their work. It's about the vocabulary selections, the syntax (the order of words), and the complexity of the language. It's not about the style, plot, or theme of the work.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2003>14", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Enjambment\" is a poetic term referring to the use of", "images": [], "options": {"A": "run-on-lines", "B": "rhyme lines", "C": "rhythm", "D": "metre"}, "answer": "A", "explanation": "\"Enjambment\" also means run-on-lines. Enjambment is a technique used in poetry whereby the idea expressed in a line of poetry is compleeted in the next line.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>15", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Stanza refers to ......... in a poem", "images": [], "options": {"A": "devices", "B": "lines", "C": "sections", "D": "divisions"}, "answer": "D", "explanation": "Stanzas is the divisions of group of lines in a poem.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2003>16", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Life is an empty dream\" illustrate the use of", "images": [], "options": {"A": "synecdoche", "B": "peripeteia", "C": "litotes", "D": "allusion"}, "answer": "D", "explanation": "Allusion is a casual reference to a literary work. An Allusion could be biblical, historical and mythical.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>17", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The term used for the unravelling of complications of the plot at the end of a literary work is", "images": [], "options": {"A": "climax", "B": "denouement", "C": "conflict", "D": "tension"}, "answer": "B", "explanation": "Denouement is also known as resolution. It is the term used for the unravelling of complications of the plot at the end of a literary work. It is the final part of the plot, that is, the time when every issue has been settled.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>18", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item", "images": [], "options": {"A": "elegy", "B": "ballad", "C": "symbolism", "D": "haiku"}, "answer": "C", "explanation": "The odd item among the options is 'symbolism'. Elegy, ballad, and haiku are all types of poetic forms or genres. Symbolism, on the other hand, is a literary device used to imbue objects, persons, or events with additional meaning and is not a type of poem. Therefore, the correct answer is 'symbolism'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2003>19", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The feelings and attitude of a writer are conveyed by", "images": [], "options": {"A": "mood", "B": "style", "C": "theme", "D": "setting"}, "answer": "B", "explanation": "The feelings and attitude of a writer are conveyed by the writer's style. Style refers to thr way the author uses words and other elements to convey his feelings and attitude towards the subject matter.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2003>20", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An author's story about himself is a/an", "images": [], "options": {"A": "biography", "B": "essay", "C": "diary", "D": "autobiography"}, "answer": "D", "explanation": "Auto-biography is an author's story about himself. If the story is told by another person, it becomes a biography.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2003>21", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the extract below and answer the question    His mind flitted back memory lane. He remembered how time walked quietly in like a thief in the night and then put a sword in the heart of the land. He remembered all his life's sweat, drained away by the strife. He remembered his wife and two lovely kids, all slain pitilessly by the beasts in khaki. He remembered his only sister, a tender rose, defiled in turns by them and then slaughtered like a lamb upon the ritual table.    The mood the extract is one of", "images": [], "options": {"A": "gloom", "B": "serenity", "C": "anxiety", "D": "indifference"}, "answer": "A", "explanation": "The mood of the extract is one of gloom. The extract is filled with sorrowful memories and tragic events. The character remembers the time when his life was devastated, his family was killed, and his sister was violated and murdered. These are all tragic and sorrowful events, which create a mood of gloom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>22", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the extract below and answer the question    His mind flitted back memory lane. He remembered how time walked quietly in like a thief in the night and then put a sword in the heart of the land. He remembered all his life's sweat, drained away by the strife. He remembered his wife and two lovely kids, all slain pitilessly by the beasts in khaki. He remembered his only sister, a tender rose, defiled in turns by them and then slaughtered like a lamb upon the ritual table. The extract is about", "images": [], "options": {"A": "armed robbery", "B": "ritual killings", "C": "the tragedy of war", "D": "the tragedy of oppression"}, "answer": "C", "explanation": "The extract is about the tragedy of war. The war made the protagonist lose all that he had. His wife and children werre killed while his sister was raped and killed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>23", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the extract below and answer the question    His mind flitted back memory lane. He remembered how time walked quietly in like a thief in the night and then put a sword in the heart of the land. He remembered all his life's sweat, drained away by the strife. He remembered his wife and two lovely kids, all slain pitilessly by the beasts in khaki. He remembered his only sister, a tender rose, defiled in turns by them and then slaughtered like a lamb upon the ritual table. The dominant literary device used is", "images": [], "options": {"A": "metaphor", "B": "repetition", "C": "simile", "D": "personification"}, "answer": "A", "explanation": "The dominant literary device used is the personification. Here, \"time\" is said to walk in \"like a thief in the night and then put a sword in the heart of the land\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>24", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the extract below and answer the question    His mind flitted back memory lane. He remembered how time walked quietly in like a thief in the night and then put a sword in the heart of the land. He remembered all his life's sweat, drained away by the strife. He remembered his wife and two lovely kids, all slain pitilessly by the beasts in khaki. He remembered his only sister, a tender rose, defiled in turns by them and then slaughtered like a lamb upon the ritual table. \"... a tender rose\" is an example of a/an", "images": [], "options": {"A": "personification", "B": "imagery", "C": "symbolism", "D": "metaphor"}, "answer": "D", "explanation": "Metaphor is a direct  comparison between two entities of different nature. His sister is directly referred to as a tender rose.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>25", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the extract below and answer the question    His mind flitted back memory lane. He remembered how time walked quietly in like a thief in the night and then put a sword in the heart of the land. He remembered all his life's sweat, drained away by the strife. He remembered his wife and two lovely kids, all slain pitilessly by the beasts in khaki. He remembered his only sister, a tender rose, defiled in turns by them and then slaughtered like a lamb upon the ritual table. \"... put a sword in the heart of the land\" implies", "images": [], "options": {"A": "murder", "B": "danger", "C": "strife", "D": "destruction"}, "answer": "D", "explanation": "It implies destruction. That is, there was a war that caused the destruction of all he had and loved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>26", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem and answer the question    Move him into the sun  Gently its touch awoke him once,  At home, whispering of fields unsown  Always it woke him even in France  Until this morning and this snow  If anything might rouse him now  This kind old sun will know  Think how it wakes the seeds  Woke, once, the clays of a cold star  Are limbs, so dear achieved, are sides,  Full-nerved still warm too hard to stir?  Was it for this the clay grew tall?  O what made fatuous sunbeams toil  To break earth's sleep at all?    The poem is a/an", "images": [], "options": {"A": "elegy", "B": "epic", "C": "sonnet", "D": "lyric"}, "answer": "A", "explanation": "An elegy is a poem written to express the grief of the  death of a person. This poem mourns the death a man.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>27", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem and answer the question    Move him into the sun  Gently its touch awoke him once,  At home, whispering of fields unsown  Always it woke him even in France  Until this morning and this snow  If anything might rouse him now  This kind old sun will know  Think how it wakes the seeds  Woke, once, the clays of a cold star  Are limbs, so dear achieved, are sides,  Full-nerved still warm too hard to stir?  Was it for this the clay grew tall?  O what made fatuous sunbeams toil  To break earth's sleep at all? One of the dominant literary devices used in the poem is", "images": [], "options": {"A": "hyperbole", "B": "simile", "C": "assonance", "D": "metaphor"}, "answer": "A", "explanation": "Hyperbole is an extravagant exaggeration of fact, often deployed for acute comic effect.  Here, it is assumed that the sun has the power and knowledge to raise the dead.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>28", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem and answer the question    Move him into the sun  Gently its touch awoke him once,  At home, whispering of fields unsown  Always it woke him even in France  Until this morning and this snow  If anything might rouse him now  This kind old sun will know  Think how it wakes the seeds  Woke, once, the clays of a cold star  Are limbs, so dear achieved, are sides,  Full-nerved still warm too hard to stir?  Was it for this the clay grew tall?  O what made fatuous sunbeams toil  To break earth's sleep at all? The theme of the poem is the .... of life", "images": [], "options": {"A": "vanity", "B": "creation", "C": "distortion", "D": "futility"}, "answer": "D", "explanation": "The theme of the poem is the futility of life. The poem talks about the sun's futile attempts to wake the dead, symbolizing the futility of life. The sun, despite its warmth and life-giving properties, cannot bring back to life what is already dead. This reflects the poet's view on the futility and transient nature of life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>29", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem and answer the question    Move him into the sun  Gently its touch awoke him once,  At home, whispering of fields unsown  Always it woke him even in France  Until this morning and this snow  If anything might rouse him now  This kind old sun will know  Think how it wakes the seeds  Woke, once, the clays of a cold star  Are limbs, so dear achieved, are sides,  Full-nerved still warm too hard to stir?  Was it for this the clay grew tall?  O what made fatuous sunbeams toil  To break earth's sleep at all? The mood in the last two lines is one of", "images": [], "options": {"A": "surprise", "B": "lament", "C": "uncertainty", "D": "indifference"}, "answer": "B", "explanation": "The last two lines illustrate the use of the rhetorical question. This rhetorical question is in the form of a lamentation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>30", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem and answer the question    Move him into the sun  Gently its touch awoke him once,  At home, whispering of fields unsown  Always it woke him even in France  Until this morning and this snow  If anything might rouse him now  This kind old sun will know  Think how it wakes the seeds  Woke, once, the clays of a cold star  Are limbs, so dear achieved, are sides,  Full-nerved still warm too hard to stir?  Was it for this the clay grew tall?  O what made fatuous sunbeams toil  To break earth's sleep at all? The dominant images are associated with", "images": [], "options": {"A": "death", "B": "nature", "C": "life", "D": "age"}, "answer": "B", "explanation": "The dominant images are associated with nature. Here, we have words like \"sun\", \"clay\", \"star\", and \"seed\", etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>31", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    A : My people do already know my mind,  And will acknowledge you and Jessica  In place of Lord Bassanio and myself  So fare thee till we shall meet again    B : Fair thoughts and happy hours attend on you  (Act 111, sc IV).    Speaker A is", "images": [], "options": {"A": "Jessica", "B": "Gratiano", "C": "Portia", "D": "Nerissa"}, "answer": "C", "explanation": "In the play 'The Merchant of Venice', these lines are spoken by Portia. She is telling Lorenzo that her people already know her mind and will acknowledge him and Jessica in place of Lord Bassanio and herself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>32", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    A : My people do already know my mind,  And will acknowledge you and Jessica  In place of Lord Bassanio and myself  So fare thee till we shall meet again    B : Fair thoughts and happy hours attend on you  (Act 111, sc IV). Speaker B is", "images": [], "options": {"A": "Lorenzo", "B": "Solerio", "C": "Solarino", "D": "Lancelot"}, "answer": "A", "explanation": "In the play 'The Merchant of Venice', these lines are spoken by Lorenzo. He is responding to Portia's farewell with a wish for her to have 'fair thoughts and happy hours'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>33", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    A : My people do already know my mind,  And will acknowledge you and Jessica  In place of Lord Bassanio and myself  So fare thee till we shall meet again    B : Fair thoughts and happy hours attend on you  (Act 111, sc IV). From the extract speaker A intends", "images": [], "options": {"A": "eloping to the city", "B": "going to a monastery", "C": "challenging the jew", "D": "forgiving the merchant"}, "answer": "A", "explanation": "speaker A intends eloping to the city. This is the most accurate answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>34", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    A : My people do already know my mind,  And will acknowledge you and Jessica  In place of Lord Bassanio and myself  So fare thee till we shall meet again    B : Fair thoughts and happy hours attend on you  (Act 111, sc IV). The person addressed in in the company of", "images": [], "options": {"A": "Antonio", "B": "Solanio", "C": "Bassanio", "D": "Jessica"}, "answer": "C", "explanation": "The perosn addressed in in the company of Bassanio", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>35", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    A : My people do already know my mind,  And will acknowledge you and Jessica  In place of Lord Bassanio and myself  So fare thee till we shall meet again    B : Fair thoughts and happy hours attend on you  (Act 111, sc IV). \"My people\" refers to the speaker's", "images": [], "options": {"A": "friends", "B": "enemies", "C": "household", "D": "relatives"}, "answer": "C", "explanation": "In the context of the extract, \"My people\" refers to the speaker's household. The speaker is referring to those under his authority or care, which in this case would be his household, not his friends, enemies, or relatives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>36", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    As much as I deserve: why, that's the lady  I do in birth deserve her, and in fortunes  In graces, and in qualities of breeding  But more than these, in love I do deserves  (Act 11, sc VII).    The speaker is", "images": [], "options": {"A": "Arragon", "B": "Bassanio", "C": "Morocco", "D": "Gratiano"}, "answer": "C", "explanation": "The speaker is Morocco. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>37", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    As much as I deserve: why, that's the lady  I do in birth deserve her, and in fortunes  In graces, and in qualities of breeding  But more than these, in love I do deserves  (Act 11, sc VII). The subject of the extract is", "images": [], "options": {"A": "a declaration of love", "B": "the choice of caskets", "C": "the elopement of two lovers", "D": "a marriage proposal"}, "answer": "A", "explanation": "The extract is a declaration of love by the speaker. The speaker is expressing his feelings of love and his belief that he deserves the lady he is referring to, not only because of his birth, fortunes, graces, and qualities of breeding, but more importantly because of his love for her.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>38", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    As much as I deserve: why, that's the lady  I do in birth deserve her, and in fortunes  In graces, and in qualities of breeding  But more than these, in love I do deserves  (Act 11, sc VII). After the speech, the speaker", "images": [], "options": {"A": "marries his lover", "B": "betrays his emotions", "C": "fails in his venture", "D": "breaks the engagement"}, "answer": "C", "explanation": "After the speech, the speaker fails in his venture", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>39", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    As much as I deserve: why, that's the lady  I do in birth deserve her, and in fortunes  In graces, and in qualities of breeding  But more than these, in love I do deserves  (Act 11, sc VII). \"The lady\" in the extract refers to", "images": [], "options": {"A": "Balthazar", "B": "Nerissa", "C": "Jessica", "D": "Portia"}, "answer": "D", "explanation": "The extract is from Shakespeare's play 'The Merchant of Venice'. In this context, \"The lady\" refers to Portia. The speaker is Bassanio, who is expressing his love and desire for Portia. Therefore, the correct answer is Portia.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>40", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question    As much as I deserve: why, that's the lady  I do in birth deserve her, and in fortunes  In graces, and in qualities of breeding  But more than these, in love I do deserves  (Act 11, sc VII). The speech is an example of a/an", "images": [], "options": {"A": "monologue", "B": "aside", "C": "soliloquy", "D": "epilogue"}, "answer": "A", "explanation": "The speech is an example of a monologue. A monologue is a long speech by one actor in a play or movie, or as part of a theatrical or broadcast program. In this case, the character is expressing his thoughts aloud, but not to any other characters on the stage. This is different from a soliloquy, where the character is speaking his thoughts aloud when alone, or while the other actors are not paying attention. An aside is a short comment or speech that a character delivers directly to the audience or to himself, while other actors on the stage appear not to hear. An epilogue is a section or speech at the end of a book or play that serves as a comment on or a conclusion to what has happened.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>41", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question  .....I owe you much, and like a wilful youth  That which I owe is lost: but if you please   To shoot another arrow that self way  which you did shoot the first.  And thankfully rest debtor for the first  (Act 1 sc 1).    The speaker is", "images": [], "options": {"A": "Solanio", "B": "Lancelot", "C": "Bassanio", "D": "Lorenzo"}, "answer": "C", "explanation": "The extract is from Shakespeare's 'The Merchant of Venice', Act 1 Scene 1. The speaker of these lines is Bassanio. He is speaking to Antonio about his debts and asking for more money to woo Portia.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>42", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question  .....I owe you much, and like a wilful youth  That which I owe is lost: but if you please   To shoot another arrow that self way  which you did shoot the first.  And thankfully rest debtor for the first  (Act 1 sc 1). The person addressed is", "images": [], "options": {"A": "Antonio", "B": "shylock", "C": "Gratiano", "D": "Solanio"}, "answer": "A", "explanation": "In the given extract from Shakespeare's 'The Merchant of Venice', Act 1 Scene 1, Bassanio is speaking to Antonio. Therefore, the person addressed is Antonio.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>43", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question  .....I owe you much, and like a wilful youth  That which I owe is lost: but if you please   To shoot another arrow that self way  which you did shoot the first.  And thankfully rest debtor for the first  (Act 1 sc 1). The speaker intends to", "images": [], "options": {"A": "fulfil his part of the bond", "B": "raise money for his suit", "C": "seek redress in court", "D": "elope with his fiancee"}, "answer": "B", "explanation": "The speaker in the extract is asking for another chance to repay a debt that he has lost. He is not trying to fulfill his part of the bond, seek redress in court, or elope with his fiancee. He is asking for another opportunity to raise money for his suit, hence the correct answer is option 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>44", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question  .....I owe you much, and like a wilful youth  That which I owe is lost: but if you please   To shoot another arrow that self way  which you did shoot the first.  And thankfully rest debtor for the first  (Act 1 sc 1). The first line of the extract illustrates", "images": [], "options": {"A": "irony", "B": "sarcasm", "C": "parallelism", "D": "simile"}, "answer": "D", "explanation": "Simile is an indirect comparison between two entities with the use of \"as\" or \"like\". The expression, \"...like a fair youth\" poimts this out.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2003>45", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the question  .....I owe you much, and like a wilful youth  That which I owe is lost: but if you please   To shoot another arrow that self way  which you did shoot the first.  And thankfully rest debtor for the first  (Act 1 sc 1). The underlined expression is an example of", "images": [], "options": {"A": "symbolism", "B": "imagery", "C": "metaphor", "D": "allusion"}, "answer": "C", "explanation": "The underlined expression 'To shoot another arrow that self way which you did shoot the first' is a metaphor. A metaphor is a figure of speech that makes a comparison between two things that are basically dissimilar. In this case, the speaker is comparing his debt to shooting an arrow, implying that he wants to repay his debt in the same way that the first was given.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2003>46", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the Question    .....Thus ornament is but the guilded shore  To a most dangerous sea...........   The seeming truth which cunning times put on To entrap the wisest. Therefore thou gaudy gold  Hard food for Midas. I will none of thee.....  (Act III sc II).    The speaker is", "images": [], "options": {"A": "Arragon", "B": "Lorenzo", "C": "Bassanio", "D": "Morocco"}, "answer": "C", "explanation": "The speaker is Bassanio. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2003>47", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the Question    .....Thus ornament is but the guilded shore  To a most dangerous sea...........   The seeming truth which cunning times put on To entrap the wisest. Therefore thou gaudy gold  Hard food for Midas. I will none of thee.....  (Act III sc II). The first two lines convey an impression of", "images": [], "options": {"A": "radiance", "B": "deception", "C": "beauty", "D": "destruction"}, "answer": "B", "explanation": "The first two lines of the extract, 'Thus ornament is but the gilded shore to a most dangerous sea', convey an impression of deception. The speaker is comparing ornament (or superficial beauty) to a gilded shore, which is beautiful and attractive on the surface but hides a dangerous sea. This is a metaphor for deception, where something appears attractive but is potentially harmful.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2003>48", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the Question    .....Thus ornament is but the guilded shore  To a most dangerous sea...........   The seeming truth which cunning times put on To entrap the wisest. Therefore thou gaudy gold  Hard food for Midas. I will none of thee.....  (Act III sc II). The underlined expression is an example of", "images": [], "options": {"A": "Onamatopoeia", "B": "personification", "C": "hyperbole", "D": "metonymy"}, "answer": "B", "explanation": "It is a figurative device which gives the features of human beings to inanimate objects. Here, \"times\" is said to put on something. That is, times is given a human attribute.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>49", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the Question    .....Thus ornament is but the guilded shore  To a most dangerous sea...........   The seeming truth which cunning times put on To entrap the wisest. Therefore thou gaudy gold  Hard food for Midas. I will none of thee.....  (Act III sc II). \"Midas\" in the extract illustrates a/an", "images": [], "options": {"A": "anecdote", "B": "pun", "C": "allusion", "D": "allegory"}, "answer": "D", "explanation": "\"Midas\" in the extract illustrates an allegory. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2003>50", "subject": "Literature", "year": "2003", "type": "Objective", "topic": "WILLIAMS SHAKESPEARE: THE MERCHANT OF VENICE", "question": "Read the extract below and answer the Question    .....Thus ornament is but the guilded shore  To a most dangerous sea...........   The seeming truth which cunning times put on To entrap the wisest. Therefore thou gaudy gold  Hard food for Midas. I will none of thee.....  (Act III sc II). After the speech, the speaker proceeds to", "images": [], "options": {"A": "make the right choice", "B": "marry her lover", "C": "unlock the silver casket", "D": "expose the secret"}, "answer": "A", "explanation": "After the speech, the speaker proceeds to make the right choice. The speaker's rejection of the 'gaudy gold' and reference to the story of Midas suggests a decision to reject superficial wealth or appearances, which can be interpreted as making the right choice. The other options do not directly follow from the information given in the extract.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2004>1", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The persons created or presented in a literary work are", "images": [], "options": {"A": "heroes", "B": "clowns", "C": "actors", "D": "characters"}, "answer": "D", "explanation": "Characters: Every work of prose, drama and also poetry must have a character or characters. A character facilitates the development of the storyline. They act but the events recounted by the author and characters can represent human beings, in animate, objects, animals e.t.c.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2004>2", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item", "images": [], "options": {"A": "fiction", "B": "monologue", "C": "aside", "D": "soliloquy"}, "answer": "A", "explanation": "Fiction is a type of prose whereby the events and characters are created by the author. The other options are dramatic techniques.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>3", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A group of lines separated from other groups in a poem is known as", "images": [], "options": {"A": "verse", "B": "caesura", "C": "stanza", "D": "metre"}, "answer": "C", "explanation": "Stanza: This is a group of line or lines separated from other groups in a poem. It is a distinctive feature of poetry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>4", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Dialogue is the predominant feature of", "images": [], "options": {"A": "genre", "B": "drama", "C": "poetry", "D": "prose"}, "answer": "B", "explanation": "Dialogue refers to a conversation between characters. It is present in all genres of literature, but more prominent in drama.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2004>5", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item", "images": [], "options": {"A": "comedy", "B": "prose", "C": "drama", "D": "poetry"}, "answer": "A", "explanation": "Comedy: This is a light hearted play that ridicules or satirizes the follies of the character to instigate laughter while the events lead to a happy ending. It is a kind of drama. Comedy is the odd one out because it is a subtype of drama while the rest make up the genres of literature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2004>6", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary work in which animals are used as characters is a", "images": [], "options": {"A": "memoir", "B": "fable", "C": "biography", "D": "farce"}, "answer": "B", "explanation": "Fable: This is a narrative to teach moral lesson, often with animals or inanimate objects as characters. It possesses surface and deeper meaning i.e denotative and conotative.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2004>7", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"True wit is nature to advantage drest.  What oft was thought but ne'er so well expressed.\"    The extract is an example of", "images": [], "options": {"A": "rhythm", "B": "pun", "C": "rhyme", "D": "paradox"}, "answer": "C", "explanation": "Rhyme: This refers to the sameness of sounds between words in poetry. DREST (a) rhymes with EXPRESSED (a).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>8", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A character who creates humour in a play is a", "images": [], "options": {"A": "flat character", "B": "heroine", "C": "round character", "D": "clown"}, "answer": "D", "explanation": "Clown: This is a character in comedy that creates humour through his attributes, behaviour and role performed.  A flat character is a one-dimensional character: he has just one specific trait. The oppoisite of flat character is round.  The heroine/hero is the central character.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2004>9", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short witty statement in poetry constitutes a/an", "images": [], "options": {"A": "lyric", "B": "ode", "C": "epigram", "D": "elegy"}, "answer": "C", "explanation": "An epigram is a brief, interesting, memorable, and sometimes surprising or satirical statement in poetry. It is known for its brevity and wit. Therefore, the correct answer is 'epigram'. The other options do not fit the definition. A lyric is a type of emotional songlike poetry, distinguished from dramatic and narrative poetry. An ode is a type of lyrical stanza. It is an elaborately structured poem praising or glorifying an event or individual, describing nature intellectually as well as emotionally. An elegy is a sad poem, usually written to praise and express sorrow for someone who is dead.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>10", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary work is didactic if it", "images": [], "options": {"A": "entertains", "B": "comforts", "C": "criticizes", "D": "teaches"}, "answer": "D", "explanation": "A literary work is considered didactic if it aims to teach the reader something, whether it's a moral lesson, an academic lesson, a philosophical, political, or religious doctrine, or some other kind of instructional information. Therefore, the correct answer is 'teaches'. The other options do not fit the definition. A work that entertains is meant to amuse the reader, a work that comforts is meant to provide solace, and a work that criticizes is meant to critique or analyze something or someone.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>11", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item", "images": [], "options": {"A": "\"Elegy written in a country churchyard\"", "B": "\"Ulysses\"", "C": "\"No coffin, no Grave\"", "D": "\"Ode to the West Wind\""}, "answer": "C", "explanation": "\"No coffin, no Grave\": This is an African poem written by Jared Angira an African poet, while others are non-African poems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>12", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A poem that expresses grief over the death of a notable figure in society is a/an", "images": [], "options": {"A": "ode", "B": "ballad", "C": "limerick", "D": "elegy"}, "answer": "D", "explanation": "Elegy: This is a kind of poem that mourns the death of a person.  The ode is a poem that is written in the form of an address to a thing.  The limerick is a humourous poem of five lines.  The ballad is a poem that is passed from one generation orally.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2004>13", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd one", "images": [], "options": {"A": "Daniel Defoe", "B": "Thomas Gray", "C": "John", "D": "Alfred Tennyson"}, "answer": "A", "explanation": "Daniel Defoe: He is an English novelist and is best known for his novels Robinson Crusoe and Moll Flanders. It is believed that he wrote the first English novel.  While Thomas Gray, John Donne, Alfred Tennyson are all English Poets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>14", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A recurrent image in a literary work is the", "images": [], "options": {"A": "theme", "B": "motif", "C": "episode", "D": "mood"}, "answer": "B", "explanation": "Motif: A motif is a theme or idea that is frequently repeated throughout a piece of literature.  Theme refers to the central idea of a work of art.  Mood has to do with the writer's state of mind or the general atmosphere.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2004>15", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A dominant feature of poetry is its", "images": [], "options": {"A": "economy of language", "B": "depiction of scenes", "C": "use of dialogue", "D": "narration of tales"}, "answer": "A", "explanation": "Economy of language: Unlike other genres of literature, poetry is the usually the shortest. The poet uses a few words to express great and complex ideas.For example, Alfred Lord Tennyson is able to tell the story of Ullyses in a 70-line poem while James Joyce uses 700 pages to tell the same story in prose.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2004>16", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The position from which a story is presented is the", "images": [], "options": {"A": "narrative technique", "B": "point of view", "C": "setting", "D": "plot"}, "answer": "B", "explanation": "Point of view: This refers to the position or perspective from which the story is being narrated. It is also known as narrative technique..", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>17", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"For my yoke is easy and my burden is light\" illustrates the use of", "images": [], "options": {"A": "bathos", "B": "euphemism", "C": "paradox", "D": "irony"}, "answer": "D", "explanation": "Irony.  Here, the speaker says a thing but means the opposite. A burden or a yoke is not light but the speaker refers to them as something easy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>18", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The dominant literary device used in \"A drowsing numbness pains my sense\" is", "images": [], "options": {"A": "parallelism", "B": "symbolism", "C": "repetition", "D": "diction"}, "answer": "B", "explanation": "Symbolism: This is the use of symbols to represent ideas or qualities. In adequates, signifies, or is understood as representing an idea, object or relationship.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>19", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Setting has to do with", "images": [], "options": {"A": "time and place", "B": "incidents and events", "C": "tone and mood", "D": "rhythm and rhyme"}, "answer": "A", "explanation": "In literature, the term 'setting' refers to the time and place in which the events of a narrative occur. It can include the geographical location, the time period, the socio-economic conditions, and even the weather. Therefore, the correct answer is 'time and place'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2004>20", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"And yonder all before us lie  Deserts of vast eternity\" illustrates the use of", "images": [], "options": {"A": "allegory", "B": "personification", "C": "oxymoron", "D": "allusion"}, "answer": "D", "explanation": "Allusion has to do with making reference to something outside the immediate scope of what is being treated. Here, there is a biblical reference to ETERNITY.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>21", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the passage below and answer this question  The fact was that, no sooner had the sickles began to play than, the atmosphere suddenly felt as if cress would grow in it without other nourishment. It rubbed people's cheeks like damp flannel when they walked abroad. There was a gusty, high warm wind: isolated raindrops starred the window-panes at remote distances; the sunlight would flap out like a quickly opened fan, throw the pattern of the window upon the floor of the room in a milky, colourless shine, and withdraw as suddenly as it had passed.    The passage deals with", "images": [], "options": {"A": "atmosphere", "B": "temperature", "C": "scene", "D": "cloud"}, "answer": "A", "explanation": "The passage deals with the scenery. The writer attempts to give a detailed description of everything around.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>22", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the passage below and answer this question  The fact was that, no sooner had the sickles began to play than, the atmosphere suddenly felt as if cress would grow in it without other nourishment. It rubbed people's cheeks like damp flannel when they walked abroad. There was a gusty, high warm wind: isolated raindrops starred the window-panes at remote distances; the sunlight would flap out like a quickly opened fan, throw the pattern of the window upon the floor of the room in a milky, colourless shine, and withdraw as suddenly as it had passed.  The passage illustrates the use of ___________ prose.", "images": [], "options": {"A": "descriptive", "B": "narrative", "C": "expository", "D": "imaginative"}, "answer": "A", "explanation": "The writer paints illustrative pictures with the use of words in order to describe the environment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>23", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the passage below and answer this question  The fact was that, no sooner had the sickles began to play than, the atmosphere suddenly felt as if cress would grow in it without other nourishment. It rubbed people's cheeks like damp flannel when they walked abroad. There was a gusty, high warm wind: isolated raindrops starred the window-panes at remote distances; the sunlight would flap out like a quickly opened fan, throw the pattern of the window upon the floor of the room in a milky, colourless shine, and withdraw as suddenly as it had passed.  The dominant literary device used in the passage is", "images": [], "options": {"A": "metaphor", "B": "simile", "C": "oxymoron", "D": "hyperbole"}, "answer": "B", "explanation": "Simile: is a figure of speech in which a likeness is definitely or formally expressed. The objects or situations compared may be different kind and quality but similarity can be noticed in certain areas and the resemblance can be seen. Similies are used to create images to clearly identify merits and demerits of a literary work. In the passage, as and like are used to make various comparisons.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2004>24", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the passage below and answer this question  The fact was that, no sooner had the sickles began to play than, the atmosphere suddenly felt as if cress would grow in it without other nourishment. It rubbed people's cheeks like damp flannel when they walked abroad. There was a gusty, high warm wind: isolated raindrops starred the window-panes at remote distances; the sunlight would flap out like a quickly opened fan, throw the pattern of the window upon the floor of the room in a milky, colourless shine, and withdraw as suddenly as it had passed.  The last five lines makes use of __________ imagery", "images": [], "options": {"A": "tactile", "B": "auditory", "C": "gustatory", "D": "visual"}, "answer": "D", "explanation": "Visual: The last five lines of the unseen prose actually employ the use of visual imagery. Imagery is often created in any work of art by using figurative language through which we configure the picture of two or more things into writing, thereby bringing out the quality of the idea that is being presented.  The last five lines make an impression to the sense of sight; the writer uses words to create mental pictures.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2004>25", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The feeling induced is one of", "images": [], "options": {"A": "excitement", "B": "indifference", "C": "anger", "D": "despondency"}, "answer": "A", "explanation": "The images painted suggest excitement. This is the most accurate answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2004>26", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the poem below and answer this question  Diligent foot-worker  legs lithe, foot loose  to frantic drums  and frenetic flutes  Acrobat strokes swift in the air  wrought masterly like  a frenzied antelope   Gyrating to the April music  of the lust Savannah    The poem describes", "images": [], "options": {"A": "dancing", "B": "wrestling", "C": "hunting", "D": "drumming"}, "answer": "A", "explanation": "The poem describes a scene of intense, energetic movement, with references to 'frantic drums', 'frenetic flutes', 'Acrobat strokes swift in the air', and 'Gyrating to the April music'. These phrases suggest a scene of dancing, making option 1 the correct answer. The other options, wrestling, hunting, and drumming, do not fully capture the range of movement and energy described in the poem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>27", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the poem below and answer this question  Diligent foot-worker  legs lithe, foot loose  to frantic drums  and frenetic flutes  Acrobat strokes swift in the air  wrought masterly like  a frenzied antelope   Gyrating to the April music  of the lust Savannah  The atmosphere of the poem is one of", "images": [], "options": {"A": "anxiety", "B": "excitement", "C": "eagerness", "D": "despair"}, "answer": "B", "explanation": "The poem describes a scene of energetic and lively movement, with words such as 'frantic', 'frenetic', 'swift', 'frenzied', and 'gyrating'. These words create an atmosphere of excitement, not anxiety, eagerness, or despair.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>28", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the poem below and answer this question  Diligent foot-worker  legs lithe, foot loose  to frantic drums  and frenetic flutes  Acrobat strokes swift in the air  wrought masterly like  a frenzied antelope   Gyrating to the April music  of the lust Savannah  \"frenetic flutes\" illustrate the use of", "images": [], "options": {"A": "hyperbole", "B": "symbolism", "C": "metaphor", "D": "metonymy"}, "answer": "C", "explanation": "The term 'frenetic flutes' is a metaphor. A metaphor is a figure of speech that makes a comparison between two things that are basically dissimilar but have something in common. In this case, the flutes are not literally frenetic (wildly excited or uncontrolled), but they are described as such to convey the intensity and energy of the music they are producing. It's not a hyperbole (exaggeration), symbolism (where one thing represents another), or metonymy (where a thing is referred to by the name of something closely associated with it).", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2004>29", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the poem below and answer this question  Diligent foot-worker  legs lithe, foot loose  to frantic drums  and frenetic flutes  Acrobat strokes swift in the air  wrought masterly like  a frenzied antelope   Gyrating to the April music  of the lust Savannah  The dominant literary device in the poem is", "images": [], "options": {"A": "personification", "B": "simile", "C": "onomatopoeia", "D": "alliteration"}, "answer": "B", "explanation": "The dominant literary device in the poem is simile. A simile is a figure of speech that makes a comparison, showing similarities between two different things. In the poem, the phrase 'wrought masterly like a frenzied antelope' is a simile because it compares the acrobat's strokes to a frenzied antelope.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2004>30", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the poem below and answer this question  Diligent foot-worker  legs lithe, foot loose  to frantic drums  and frenetic flutes  Acrobat strokes swift in the air  wrought masterly like  a frenzied antelope   Gyrating to the April music  of the lust Savannah  The poem is an example of a/an", "images": [], "options": {"A": "lyric", "B": "ode", "C": "pastoral", "D": "ballad"}, "answer": "B", "explanation": "The poem is an ode for it is a meditation addressed to animate or inanimate objects. It speaks to a person or things to celebrate special event. It is themed to search for lasting beauty and happiness for permanent meaning in the world where everything fades and dies.    Pastoral poem has to do with rural life and shepherds. It is a poem that elevates the life of a shepherd or shepherdess versus the evils of the city. And certainly not a Ballad, for this a kind of poem that is written to narrate the story of unfulfilled love and belated expectations, historic battles, etc.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2004>31", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "WILLIAM SHAKESPEARE: The Merchant of Venice   Read the extract below and answer this question    A: I pray thee over-name them, and as thou namest them, I will describe them. And according to my description level at my affection.  B: First there is the Neapolitan prince.  A: Ay, that's a colt indeed, for he doth nothing but talk of his horse, and he makes it a great appropriation to his own good parts that he can shoe him himself. I am much afeared my lady his mother played false with a smith.    Speaker A is", "images": [], "options": {"A": "Nerissa", "B": "Portia", "C": "Jessica", "D": "Duke"}, "answer": "B", "explanation": "In the extract from 'The Merchant of Venice', the speaker A is Portia. This can be determined from the context of the conversation. Portia is discussing the suitors who have come to win her hand in marriage, and she is known for her wit and her critical observations of them. The Neapolitan prince is one of her suitors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>32", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "WILLIAM SHAKESPEARE: The Merchant of Venice   Read the extract below and answer this question    A: I pray thee over-name them, and as thou namest them, I will describe them. And according to my description level at my affection.  B: First there is the Neapolitan prince.  A: Ay, that's a colt indeed, for he doth nothing but talk of his horse, and he makes it a great appropriation to his own good parts that he can shoe him himself. I am much afeared my lady his mother played false with a smith.  Speaker B is", "images": [], "options": {"A": "Portia", "B": "Antonio", "C": "Nerissa", "D": "Bassanio"}, "answer": "C", "explanation": "Nerissa: she is portia's lady-in-waiting. She listens to Portia's complain about her life and the unfeurness of the casket contest and tells her to suck it up and be glad her father was wise enough to plan for his daughter's future. She marrys Graziano.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>33", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "WILLIAM SHAKESPEARE: The Merchant of Venice   Read the extract below and answer this question    A: I pray thee over-name them, and as thou namest them, I will describe them. And according to my description level at my affection.  B: First there is the Neapolitan prince.  A: Ay, that's a colt indeed, for he doth nothing but talk of his horse, and he makes it a great appropriation to his own good parts that he can shoe him himself. I am much afeared my lady his mother played false with a smith.  The attitude of Speaker A to the person mentioned by Speaker B is one of", "images": [], "options": {"A": "affection", "B": "contempt", "C": "indifference", "D": "resignation"}, "answer": "B", "explanation": "In the extract, Speaker A is describing the Neapolitan prince in a mocking and derogatory manner, suggesting that he is a 'colt' who does nothing but talk about his horse and that his mother may have been unfaithful with a smith. This shows that Speaker A holds the prince in contempt, not affection, indifference or resignation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>34", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    This kindness will I show.  Go with me to a notary; seal me there  Your single bond, and, in a merry sport,  If you repay me not on such a day,  ... let the forfeit  Be nominated for an equal pound . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act One Scene III)    The \"kindness\" the speaker has agreed to \"show\" is", "images": [], "options": {"A": "debt rescheduling", "B": "sponsorship of pilgrimage", "C": "payment of dowry", "D": "interest-free loan"}, "answer": "D", "explanation": "In the extract, the speaker is offering to go with the other person to a notary to seal a bond. If the other person does not repay the speaker on a certain day, the forfeit will be 'an equal pound'. This suggests that the 'kindness' the speaker is showing is an interest-free loan, not debt rescheduling, sponsorship of pilgrimage or payment of dowry.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2004>35", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    This kindness will I show.  Go with me to a notary; seal me there  Your single bond, and, in a merry sport,  If you repay me not on such a day,  ... let the forfeit  Be nominated for an equal pound . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act One Scene III)  The \"kindness\" is to be repaid within", "images": [], "options": {"A": "one month", "B": "three months", "C": "one year", "D": "a life-time"}, "answer": "B", "explanation": "Repayment is in three months.This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2004>36", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    This kindness will I show.  Go with me to a notary; seal me there  Your single bond, and, in a merry sport,  If you repay me not on such a day,  ... let the forfeit  Be nominated for an equal pound . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act One Scene III)  \"merry sport\" in line 3 means a", "images": [], "options": {"A": "feast", "B": "game", "C": "joke", "D": "carnival"}, "answer": "A", "explanation": "According to the extract, this means a feast. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>37", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    A: Let me choose,  &nbsp &nbsp  For as I am, I live upon the rack.    B: Upon the rack, Bassanio? then confess  &nbsp &nbsp  What treason there is mingled with your love.  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  Act Three Scene II    Speaker B is", "images": [], "options": {"A": "Lorenzo", "B": "Nerissa", "C": "Portia", "D": "Gratiano"}, "answer": "C", "explanation": "In the given extract from 'The Merchant of Venice' by William Shakespeare, the conversation is between Bassanio and Portia. Bassanio is in a state of anxiety about choosing the right casket to win Portia's hand in marriage. The 'rack' he refers to is a metaphor for his mental torture. Portia, who is in love with Bassanio, is unable to help him and is also in distress. Therefore, the correct answer is Portia.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>38", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    A: Let me choose,  &nbsp &nbsp  For as I am, I live upon the rack.    B: Upon the rack, Bassanio? then confess  &nbsp &nbsp  What treason there is mingled with your love.  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  Act Three Scene II  The \"rack\" symbolizes", "images": [], "options": {"A": "confession", "B": "torture", "C": "penitence", "D": "danger"}, "answer": "C", "explanation": "It symbolizes penitence. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>39", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    A: Let me choose,  &nbsp &nbsp  For as I am, I live upon the rack.    B: Upon the rack, Bassanio? then confess  &nbsp &nbsp  What treason there is mingled with your love.  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  Act Three Scene II  Speaker A had earlier been advised to", "images": [], "options": {"A": "pause a day or two", "B": "forgo the opportunity", "C": "pause a week or month", "D": "exploit the opportunity"}, "answer": "A", "explanation": "In the extract, Bassanio (Speaker A) is in a dilemma about choosing the right casket to win Portia's hand in marriage in Shakespeare's 'The Merchant of Venice'. He had been advised to 'pause a day or two' before making his choice. This is to reflect and make a wise decision. The 'rack' here symbolizes his state of mental torture due to the difficult decision he has to make.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>40", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    . . . if you prick us, do we not bleed?  If you tickle us, do we not laugh?  If you poison us, do we not die? - And if you wrong us, shall we not revenge?  If we are like you in the rest, we will resemble you in that.  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  Act Three Scene I    \"you\" refers to", "images": [], "options": {"A": "Merchants", "B": "Venetians", "C": "Christians", "D": "Jews"}, "answer": "C", "explanation": "Through the speech, Shylock declares that Jews are as human as Christians are and should be treated as such. He says that Jews bleed when they are hurt, laugh when they are tickled, and feel the elements as all other human beings do.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>41", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    . . . if you prick us, do we not bleed?  If you tickle us, do we not laugh?  If you poison us, do we not die? - And if you wrong us, shall we not revenge?  If we are like you in the rest, we will resemble you in that.  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  Act Three Scene I  \"you\" and \"we\" are related by their common", "images": [], "options": {"A": "religion", "B": "humanity", "C": "profession", "D": "nationality"}, "answer": "B", "explanation": "Through the speech, Shylock declares that Jews are as human as Christians are and should be treated as such. He says that Jews bleed when they are hurt, laugh when they are tickled, and feel the elements as all other human beings do.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>42", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    . . . if you prick us, do we not bleed?  If you tickle us, do we not laugh?  If you poison us, do we not die? - And if you wrong us, shall we not revenge?  If we are like you in the rest, we will resemble you in that.  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  &nbsp &nbsp  Act Three Scene I  The speech asserts the speaker's demand for", "images": [], "options": {"A": "mercy", "B": "reprieve", "C": "parole", "D": "justice"}, "answer": "D", "explanation": "The speaker talks about being wronged and seeking revenge, which implies a demand for justice. Therefore, the correct answer is 'justice'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>43", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    How to choose right, but then I am forsworn;  So will I never be; so you may miss me;  But if you do, you'll make me wish a sin,  That I had been forsworn.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp Act Three Scene II    The speaker is addressing", "images": [], "options": {"A": "Duke", "B": "Arragon", "C": "Bassanio", "D": "Morocco"}, "answer": "C", "explanation": "The extract is from Shakespeare's 'The Merchant of Venice', Act Three Scene II. In this scene, Portia is speaking to Bassanio. Therefore, the speaker is addressing Bassanio.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>44", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    How to choose right, but then I am forsworn;  So will I never be; so you may miss me;  But if you do, you'll make me wish a sin,  That I had been forsworn.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp Act Three Scene II  By the expression \" I am forsworn\", the reader becomes aware of the speaker's", "images": [], "options": {"A": "inheritance", "B": "fiancee", "C": "predicament", "D": "tradition"}, "answer": "C", "explanation": "The phrase 'I am forsworn' means that the speaker has sworn not to do something but is now going against that oath. In the context of the extract, Portia is expressing her predicament. She has sworn not to influence Bassanio's choice of the caskets, but she wishes she could. Therefore, the reader becomes aware of the speaker's predicament.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>45", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    How to choose right, but then I am forsworn;  So will I never be; so you may miss me;  But if you do, you'll make me wish a sin,  That I had been forsworn.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp Act Three Scene II  \". . . you may miss me\" implies", "images": [], "options": {"A": "separation", "B": "fear", "C": "death", "D": "failure"}, "answer": "D", "explanation": "The expression implies failure.  This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>46", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    This house, these servants, and this same myself  Are yours, my Lord! I give them with this ring,  Which when you part from, lose, or giveaway,  Let it presage the ruin of your love,  And be my vantage to exclaim on you.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp Act Three Scene II    The ring symbolizes", "images": [], "options": {"A": "love", "B": "marriage", "C": "engagement", "D": "surrender"}, "answer": "A", "explanation": "The ring symbolises love. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>47", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    This house, these servants, and this same myself  Are yours, my Lord! I give them with this ring,  Which when you part from, lose, or giveaway,  Let it presage the ruin of your love,  And be my vantage to exclaim on you.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp Act Three Scene II  The speaker is", "images": [], "options": {"A": "Nerissa", "B": "Portia", "C": "Antonio", "D": "Bassanio"}, "answer": "B", "explanation": "This is a scene from William Shakespeare's play 'The Merchant of Venice'. In this scene, Portia is speaking to Bassanio, offering him her house, servants, and herself along with a ring.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>48", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    This house, these servants, and this same myself  Are yours, my Lord! I give them with this ring,  Which when you part from, lose, or giveaway,  Let it presage the ruin of your love,  And be my vantage to exclaim on you.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp Act Three Scene II  \"... my Lord\" in line 2 refers to", "images": [], "options": {"A": "Due", "B": "Arragon", "C": "Morocco", "D": "Bassanio"}, "answer": "D", "explanation": "In the given extract, 'my Lord' refers to the person Portia is speaking to, which is Bassanio.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>49", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    This house, these servants, and this same myself  Are yours, my Lord! I give them with this ring,  Which when you part from, lose, or giveaway,  Let it presage the ruin of your love,  And be my vantage to exclaim on you.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp Act Three Scene II  \". . . And be my vantage to exclaim on you\" means the opportunity to . . . . him", "images": [], "options": {"A": "hate", "B": "love", "C": "embrace", "D": "reject"}, "answer": "B", "explanation": "It means love to him. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2004>50", "subject": "Literature", "year": "2004", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer this question    This house, these servants, and this same myself  Are yours, my Lord! I give them with this ring,  Which when you part from, lose, or giveaway,  Let it presage the ruin of your love,  And be my vantage to exclaim on you.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp Act Three Scene II  In \"Let it presage with the ruin of your love\", \"it\" implies", "images": [], "options": {"A": "commitment", "B": "friendship", "C": "betrayal", "D": "hatred"}, "answer": "A", "explanation": "In the phrase 'Let it presage the ruin of your love', 'it' refers to the ring mentioned in the previous lines. The ring is a symbol of their love and commitment, and if the lord parts from it, loses it, or gives it away, it would signify the ruin of their love.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>1", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A device that reveals a discrepancy between appearance and reality is", "images": [], "options": {"A": "oxymoron", "B": "irony", "C": "antithesis", "D": "bathos"}, "answer": "B", "explanation": "Irony  This is a figure of speech in which words are used in such a way that the intended meaning is different from the actual meaning of the words. In situational irony, there is a difference between what is expected and what occurs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>2", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A situation in which the audience knows more than the character does, is an instance of", "images": [], "options": {"A": "comic relief", "B": "interior monologue", "C": "dramatic irony", "D": "poetic licence"}, "answer": "C", "explanation": "Dramatic irony is a situation in literature in which the audience knows more than the characters do. This creates tension as the audience anticipates the characters' reactions when they discover the truth. Comic relief is a humorous scene, incident or speech that is included in a serious drama to provide a change from the mood of tragedy. Interior monologue is a narrative technique that shows the inner thoughts of a character. Poetic licence is the freedom that poets and other artists have to deviate from the normal rules and conventions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>3", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item from the options below", "images": [], "options": {"A": "Elegy", "B": "Epitaph", "C": "Dirge", "D": "Ode"}, "answer": "D", "explanation": "The ode is the odd one out because the others relate to death.   The epitaph is a short poem written on a tomb.  the dirge and elegy are poems that are written to mourn the dead.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2005>4", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A narrative poem in the manner of oral folk tradition is", "images": [], "options": {"A": "a pastoral", "B": "a lyric", "C": "a ballad", "D": "an elegy"}, "answer": "C", "explanation": "A ballad is a kind of poem that is arranged in quatrains with the rhyme scheme abab. It is a narrative poem that is passed from one generation to another through the use of word of mouth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>5", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In \"my finger click with a Snicker And, chuckling, they knuckle the key\" the dominant-figure of speech used is", "images": [], "options": {"A": "parallelism", "B": "litotes", "C": "hyperbole", "D": "onomatopoeia"}, "answer": "D", "explanation": "This refers to words that mimic or resemble the sound of the thing it describes. \"Clicks, snicker, chuckling and knuckling\" are typical examples.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>6", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item from the options below", "images": [], "options": {"A": "Plot", "B": "Theme", "C": "Metre", "D": "Subject"}, "answer": "C", "explanation": "The odd item from the options is 'Metre'. Plot, Theme, and Subject are all elements of a story or a literary work. They are related to the content and the message of the work. On the other hand, 'Metre' is related to the structure of a poem. It is a unit of rhythm in poetry, the pattern of the beats. It is not related to the content or the message of the work, but rather to its form.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2005>7", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Horrendous horrors haunted Helen's happiness\" illustrates", "images": [], "options": {"A": "alliteration", "B": "rhythm", "C": "repetition", "D": "assonance"}, "answer": "A", "explanation": "Alliteration is the occurrence of the same consonant letter or sound at the beginning of closely connected words.  Here, the sound /h/ alliterates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>8", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Which of the following poems is based on travel and adventure?", "images": [], "options": {"A": "\"Ode to the West Wind\"", "B": "\"Freetown\"", "C": "\"Ulysses\"", "D": "\"No Coffin, No Grave\""}, "answer": "C", "explanation": "The poem \"Ulysses\" by Alfred Lord Tennyson is based on travel and adventure. It is a dramatic monologue from the perspective of Ulysses (Odysseus), a character from Homer's epic, the Odyssey, who is known for his long journey home after the Trojan War. The other options do not primarily focus on the theme of travel and adventure.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>9", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item from the options below", "images": [], "options": {"A": "Comedy", "B": "Tragedy", "C": "Farce", "D": "Limerick"}, "answer": "D", "explanation": "Limerick is the odd one out. The others are sub-categories of the drama genre.  This is a humourous poem of five lines. It has a rhyming scheme of AABBA.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2005>10", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Which of the following poems is a lamentation?", "images": [], "options": {"A": "\"Elegy written in a Country Churchyard\"", "B": "\"No Coffin, No Grave\"", "C": "\"Ode to the West Wind\"", "D": "\"Ulysses\""}, "answer": "A", "explanation": "\"Elegy Written in a Country Churchyard\"  This is a poem written by Thomas Gray about the inevitability and hollowness of death.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>11", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "It runs through the reeds And away it proceeds, Through meadows and glade, In sun and in shade. The dominant device used in the above extract is", "images": [], "options": {"A": "imagery", "B": "symbolism", "C": "rhyme", "D": "pun"}, "answer": "C", "explanation": "Rhyme is a literary device in which the repetition of the same or similar sounds occurs in two or more words, usually at the end of lines in poems or songs.  REEDS and PROCEEDS rhyme and SHADE rhymes with GLADE.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>12", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item from the options below", "images": [], "options": {"A": "Simile", "B": "Metaphor", "C": "Synecdoche", "D": "Ballad"}, "answer": "D", "explanation": "The odd item from the options is 'Ballad'. Simile, Metaphor, and Synecdoche are all figures of speech used in literature to create comparisons or associations. A simile is a comparison using 'like' or 'as', a metaphor is a direct comparison, and synecdoche is a figure of speech where a part is made to represent the whole or vice versa. On the other hand, a Ballad is a type of poem or song that tells a story, so it doesn't fit with the other options which are all figures of speech.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2005>13", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The metrical pattern in, \"In mist or cloud, On mast or shroud is", "images": [], "options": {"A": "iambic", "B": "trochaic", "C": "anapaestic", "D": "dactylic"}, "answer": "A", "explanation": "Iambic Metre  Iambic metrical pattern is a line of poetry containing Iamb, which is a unit of meter with two syllables, where the first syllable is unstressed and the second syllable is stressed. In the extact below, the stressed syllables are capitalised:  In MIST or CLOUD, On MAST or SHROUD.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>14", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Which of the following is a praise poem?", "images": [], "options": {"A": "\"Freetown\"", "B": "\"Ulysses\"", "C": "\"Is my Team Ploughing?\"", "D": "\"Ode to the West Wind\""}, "answer": "D", "explanation": "Ode to the West Wind  An Ode is a type of lyrical poem structured to praise or glorify an event or individual, describing nature intellectual as well as emotion.  Thus, Percy Bysshe Shelley's \"Ode to the West Wind\" is a praise poem.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>15", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Poetry that avoids the use of regular metre is", "images": [], "options": {"A": "lyric", "B": "limerick", "C": "free verse", "D": "blank verse"}, "answer": "C", "explanation": "FREE VERSE: This is a poem that has no rhyme scheme or meter pattern  Blank verse is a literary device defined as un-rhyming verse written in iambic pentameter (regular meter).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>16", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The mood in \"Nothing so true as what you once let fall Most women have no characters at all\" is", "images": [], "options": {"A": "pessimistic", "B": "jubilant", "C": "anticipatory", "D": "optimistic"}, "answer": "A", "explanation": "The quote 'Nothing so true as what you once let fall Most women have no characters at all' suggests a negative or pessimistic view towards women. The speaker seems to believe that most women lack individuality or distinct characteristics. Therefore, the mood of this quote can be described as 'pessimistic'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>17", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Rhyming words", "images": [], "options": {"A": "have similar spellings", "B": "are parallel lines", "C": "sound alike", "D": "convey meaning"}, "answer": "C", "explanation": "Rhyming words are words that have the same ending sound. They do not necessarily have similar spellings, are not parallel lines, and do not necessarily convey meaning. Therefore, the correct answer is 'sound alike'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2005>18", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "He sits under the bough utters a loud cough, wipes his sweating brow and gives the dog a blow. The extract illustrates . . . . . . . rhyme", "images": [], "options": {"A": "masculine", "B": "eye", "C": "internal", "D": "end"}, "answer": "B", "explanation": "EYE RHYME  This is a type of rhyme where two words look alike but sound differently, e.g., BOUGH and COUGH have similar letters but they are pronounced differently. This difference in pronunciation is also seen in BROW and BLOW.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>19", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Death be not Proud\" illustrates", "images": [], "options": {"A": "euphemism", "B": "personification", "C": "metaphor", "D": "litotes"}, "answer": "B", "explanation": "Personification  This is the representation of an abstract quality in human form.  Here, death is given a human quality: pride (proud).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>20", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Lines that usually have a set pattern of metre and rhyme constitute", "images": [], "options": {"A": "stanza", "B": "verse", "C": "rhyme scheme", "D": "falling metre"}, "answer": "A", "explanation": "Lines that usually have a set pattern of metre and rhyme constitute a stanza. A stanza is a set of lines in a poem grouped together and set apart from other stanzas in the poem either by a double space or by different indentation. It often has a set pattern of meter and rhyme.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2005>21", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Tell me not (sweet) I am unkinde,  That from the Nunnerie  of thy chaste breast  and quiet minde,  To warre and Armes I flie.    True, a new Mistresse now I chase  The first Foe in the field;  And with a stronger faith imbrace,  A Sword, a Horse, a Shield.  Yet this Inconstancy is such,  As you too shall adore;  I could not love thee (Deare) so much,  Lov'd I not Honour more.    The dominant device used in", "images": [], "options": {"A": "contrast", "B": "paradox", "C": "oxymoron", "D": "parallelism"}, "answer": "A", "explanation": "Contrast.  The speaker contrasts the comfort he enjoys with his lover to brutal nature of war.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>22", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Tell me not (sweet) I am unkinde,  That from the Nunnerie  of thy chaste breast  and quiet minde,  To warre and Armes I flie.    True, a new Mistresse now I chase  The first Foe in the field;  And with a stronger faith imbrace,  A Sword, a Horse, a Shield.  Yet this Inconstancy is such,  As you too shall adore;  I could not love thee (Deare) so much,  Lov'd I not Honour more.  The reference to \". . . . the Nunnerie of thy chaste breast\" suggests that the woman is being", "images": [], "options": {"A": "praised", "B": "mocked", "C": "scorned", "D": "admired"}, "answer": "A", "explanation": "The reference to \"...the Nunnerie of thy chaste breast\" suggests that the woman is being praised. The speaker is comparing the woman's chaste breast to a nunnery, which is a place of purity and sanctity. This metaphor is used to express admiration and respect for the woman's virtue and purity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>23", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Tell me not (sweet) I am unkinde,  That from the Nunnerie  of thy chaste breast  and quiet minde,  To warre and Armes I flie.    True, a new Mistresse now I chase  The first Foe in the field;  And with a stronger faith imbrace,  A Sword, a Horse, a Shield.  Yet this Inconstancy is such,  As you too shall adore;  I could not love thee (Deare) so much,  Lov'd I not Honour more.  The rhyme pattern of the poem is", "images": [], "options": {"A": "abab", "B": "aabb", "C": "abcd", "D": "abba"}, "answer": "A", "explanation": "True, a new Mistresse now I chase (a)  The first Foe in the field; (b)  And with a stronger faith imbrace, (a)  A Sword, a Horse, a Shield. (a)", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>24", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Tell me not (sweet) I am unkinde,  That from the Nunnerie  of thy chaste breast  and quiet minde,  To warre and Armes I flie.    True, a new Mistresse now I chase  The first Foe in the field;  And with a stronger faith imbrace,  A Sword, a Horse, a Shield.  Yet this Inconstancy is such,  As you too shall adore;  I could not love thee (Deare) so much,  Lov'd I not Honour more.  \"Inconsistency\" in the poem implies that the", "images": [], "options": {"A": "man is unfaithful", "B": "woman is pure", "C": "woman is a nun", "D": "man loves war"}, "answer": "D", "explanation": "Man loves war because there is honour. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>25", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Tell me not (sweet) I am unkinde,  That from the Nunnerie  of thy chaste breast  and quiet minde,  To warre and Armes I flie.    True, a new Mistresse now I chase  The first Foe in the field;  And with a stronger faith imbrace,  A Sword, a Horse, a Shield.  Yet this Inconstancy is such,  As you too shall adore;  I could not love thee (Deare) so much,  Lov'd I not Honour more.  The theme of the poem is the pursuit of", "images": [], "options": {"A": "war", "B": "religion", "C": "honour", "D": "a horse"}, "answer": "C", "explanation": "The theme of the poem is the pursuit of 'honour'. This is evident in the last two lines of the poem where the speaker says, 'I could not love thee (Deare) so much, Lov'd I not Honour more.' This implies that the speaker values honour more than love, hence his decision to go to war. The speaker's pursuit of honour is also evident in the second stanza where he mentions chasing a 'new Mistress' which is a metaphor for honour.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>26", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage below and answer this question  Stella had to do her midweek shopping. There were four people before her in the queue. She watched the blond at the counter striking feverishly away at the numbers on the cold, light-flickering machine. There seemed to be a raging war between two mechanical contraptions, one, robot-like and the other stationary, but able to respond to the extent of punching, by sharp flickers of red light. It was an all-consuming battle, as a swift left hand positioned the price label of the ceaseless flow of items on the conveyor belt and the right delivered the punches. The intending owners were more unnoticed onlookers. Anyway, there is a belated recognition of them in \"thank you, call again balance sheet.\"  It's all so mechanical, she thought. I mean, any creature - baboon, extraterrestial being or anything - could as well receive the same treatment as long as the conditions are met - \"bring to the counter, labelled items from the shelves.\"  Where is the human touch? She wondered.    The dominant literary device used in the passage is", "images": [], "options": {"A": "litotes", "B": "personification", "C": "synecdoche", "D": "onomatopoeia"}, "answer": "B", "explanation": "Synecdoche.  This is a figurative device whereby a part of the body is used to represent the entire body.   Here, BLONDE (the hair) is used to represent the shop attendant.   Another examples is \"a swift left hand...\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>27", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage below and answer this question  Stella had to do her midweek shopping. There were four people before her in the queue. She watched the blond at the counter striking feverishly away at the numbers on the cold, light-flickering machine. There seemed to be a raging war between two mechanical contraptions, one, robot-like and the other stationary, but able to respond to the extent of punching, by sharp flickers of red light. It was an all-consuming battle, as a swift left hand positioned the price label of the ceaseless flow of items on the conveyor belt and the right delivered the punches. The intending owners were more unnoticed onlookers. Anyway, there is a belated recognition of them in \"thank you, call again balance sheet.\"  It's all so mechanical, she thought. I mean, any creature - baboon, extraterrestial being or anything - could as well receive the same treatment as long as the conditions are met - \"bring to the counter, labelled items from the shelves.\"  Where is the human touch? She wondered.  \"Where is the human touch?\" conveys an impression of", "images": [], "options": {"A": "disappointment", "B": "expectation", "C": "discontent", "D": "indifference"}, "answer": "A", "explanation": "The expression shows her disappointment. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>28", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage below and answer this question  Stella had to do her midweek shopping. There were four people before her in the queue. She watched the blond at the counter striking feverishly away at the numbers on the cold, light-flickering machine. There seemed to be a raging war between two mechanical contraptions, one, robot-like and the other stationary, but able to respond to the extent of punching, by sharp flickers of red light. It was an all-consuming battle, as a swift left hand positioned the price label of the ceaseless flow of items on the conveyor belt and the right delivered the punches. The intending owners were more unnoticed onlookers. Anyway, there is a belated recognition of them in \"thank you, call again balance sheet.\"  It's all so mechanical, she thought. I mean, any creature - baboon, extraterrestial being or anything - could as well receive the same treatment as long as the conditions are met - \"bring to the counter, labelled items from the shelves.\"  Where is the human touch? She wondered.  The narrative technique used in the passage is", "images": [], "options": {"A": "omniscient", "B": "third person", "C": "flashback", "D": "first person"}, "answer": "A", "explanation": "The third person omniscient point of view is used. This is seen in that the writer makes use of third person pronouns to tell the story. Most importantly, the writer knows the mind of the characters (omniscient).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>29", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage below and answer this question  Stella had to do her midweek shopping. There were four people before her in the queue. She watched the blond at the counter striking feverishly away at the numbers on the cold, light-flickering machine. There seemed to be a raging war between two mechanical contraptions, one, robot-like and the other stationary, but able to respond to the extent of punching, by sharp flickers of red light. It was an all-consuming battle, as a swift left hand positioned the price label of the ceaseless flow of items on the conveyor belt and the right delivered the punches. The intending owners were more unnoticed onlookers. Anyway, there is a belated recognition of them in \"thank you, call again balance sheet.\"  It's all so mechanical, she thought. I mean, any creature - baboon, extraterrestial being or anything - could as well receive the same treatment as long as the conditions are met - \"bring to the counter, labelled items from the shelves.\"  Where is the human touch? She wondered.  The dominant mood in the passage is one of", "images": [], "options": {"A": "excitement", "B": "fear", "C": "anxiety", "D": "joy"}, "answer": "C", "explanation": "The dominant mood in the passage is one of anxiety. Stella is anxious about the mechanical and impersonal nature of the shopping process. She feels that there is a lack of human touch and that any creature could receive the same treatment as long as the conditions are met. This creates a sense of unease and anxiety.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>30", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage below and answer this question  Stella had to do her midweek shopping. There were four people before her in the queue. She watched the blond at the counter striking feverishly away at the numbers on the cold, light-flickering machine. There seemed to be a raging war between two mechanical contraptions, one, robot-like and the other stationary, but able to respond to the extent of punching, by sharp flickers of red light. It was an all-consuming battle, as a swift left hand positioned the price label of the ceaseless flow of items on the conveyor belt and the right delivered the punches. The intending owners were more unnoticed onlookers. Anyway, there is a belated recognition of them in \"thank you, call again balance sheet.\"  It's all so mechanical, she thought. I mean, any creature - baboon, extraterrestial being or anything - could as well receive the same treatment as long as the conditions are met - \"bring to the counter, labelled items from the shelves.\"  Where is the human touch? She wondered.  \"...... a swift left hand ...... and the right hand delivered the punches\" illustrates", "images": [], "options": {"A": "symbolism", "B": "hyperbole", "C": "parallelism", "D": "alliteration"}, "answer": "C", "explanation": "Parallelism is the use of successive verbal constructions in poetry or prose which correspond in grammatical structure, sound, metre, meaning, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>31", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    If I can catch him once upon the hip,  I will feed fat the ancient grudge I bear him.  He hates our sacred nation, and he rails,  Even there where merchants most do congregate,  On me, my bargains, and my well-won thrift,  Which he calls interest;. . . . . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act I Scene Three, lines 39 - 44)    The speaker is", "images": [], "options": {"A": "Tubal", "B": "Antonio", "C": "Shylock", "D": "Bassanio"}, "answer": "C", "explanation": "Shylock is a Jewish merchant that lives in a predominantly christian environment. His life revolves around money as he is popularly known for charging to much interest on loans. He is a character that abhors greed jealousy and vengence in the play.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>32", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    If I can catch him once upon the hip,  I will feed fat the ancient grudge I bear him.  He hates our sacred nation, and he rails,  Even there where merchants most do congregate,  On me, my bargains, and my well-won thrift,  Which he calls interest;. . . . . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act I Scene Three, lines 39 - 44)  The extract is an example of", "images": [], "options": {"A": "epilogue", "B": "soliloquy", "C": "monologue", "D": "aside"}, "answer": "C", "explanation": "Monologue is a speech presented by a single character, most often to express their mental thoughts aloud, though sometimes also to address another character or the audience.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>33", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    If I can catch him once upon the hip,  I will feed fat the ancient grudge I bear him.  He hates our sacred nation, and he rails,  Even there where merchants most do congregate,  On me, my bargains, and my well-won thrift,  Which he calls interest;. . . . . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act I Scene Three, lines 39 - 44)  The underlined expression illustrates", "images": [], "options": {"A": "assonance", "B": "metaphor", "C": "wit", "D": "euphemism"}, "answer": "D", "explanation": "Euphemism: This is a literary device where unpleasant things are expressed in a milder way.  \"I will feed fat the ancient grudge\"  This is a mild way of saying you will not forgive.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>34", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    If I can catch him once upon the hip,  I will feed fat the ancient grudge I bear him.  He hates our sacred nation, and he rails,  Even there where merchants most do congregate,  On me, my bargains, and my well-won thrift,  Which he calls interest;. . . . . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act I Scene Three, lines 39 - 44)  \"my well-worn thrift\" is", "images": [], "options": {"A": "sarcasm", "B": "a parody", "C": "an understatement", "D": "an allegory"}, "answer": "A", "explanation": "Sarcasm: This is a sharp and often satirical or ironic utterance designed to cut or give pain. It is usually use to convey contempt.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>35", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    If I can catch him once upon the hip,  I will feed fat the ancient grudge I bear him.  He hates our sacred nation, and he rails,  Even there where merchants most do congregate,  On me, my bargains, and my well-won thrift,  Which he calls interest;. . . . . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act I Scene Three, lines 39 - 44)  From the extract the speaker is", "images": [], "options": {"A": "kind", "B": "tricky", "C": "vindictive", "D": "angry"}, "answer": "C", "explanation": "The speaker in the extract is expressing a deep-seated grudge and a desire for revenge, which suggests that he is vindictive. The phrase 'I will feed fat the ancient grudge I bear him' indicates a long-standing resentment that the speaker intends to satisfy. Therefore, the correct answer is 'vindictive'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>36", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    Alack, what heinous sin is it in me  To be ashamed to be my father's child!  But though I am a daughter to his blood  I am not to his manners. . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II Scene Three lines 15 - 18)    The extract is", "images": [], "options": {"A": "a soliloquy", "B": "an epilogue", "C": "an aside", "D": "a flashback"}, "answer": "A", "explanation": "Soliloquy   This is a speech in a play that the character speaks to himself or to the people watching rather than to the other characters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>37", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    Alack, what heinous sin is it in me  To be ashamed to be my father's child!  But though I am a daughter to his blood  I am not to his manners. . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II Scene Three lines 15 - 18)  The speaker is in love with", "images": [], "options": {"A": "Gratiano", "B": "Lorenzo", "C": "Antonio", "D": "Bassanio"}, "answer": "A", "explanation": "Gratiano is a friend of Bassanio. He is a great talker and cab be unmannerly is well. He accompanies him to Belmont. He is so vocal that he criticise shylock during the trial.  Gratiano falls in love with and eventually weeds portia's lady - in - waiting Nerissa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>38", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    Alack, what heinous sin is it in me  To be ashamed to be my father's child!  But though I am a daughter to his blood  I am not to his manners. . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II Scene Three lines 15 - 18)  The speaker has been addressing", "images": [], "options": {"A": "Solanio", "B": "Portia", "C": "Lancelot", "D": "Nerissa"}, "answer": "C", "explanation": "Lancelot  He is Bassanio's servant. A comical, clownish figure who is especially adopt at making Puns. Lancelot leaves shylock's service in order to work for Bassanio.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>39", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    Alack, what heinous sin is it in me  To be ashamed to be my father's child!  But though I am a daughter to his blood  I am not to his manners. . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II Scene Three lines 15 - 18)  The speaker is", "images": [], "options": {"A": "Tubal", "B": "Portia", "C": "Morocco", "D": "Jessica"}, "answer": "D", "explanation": "Jessica  She is shylock's daughter, she despises life in her Father's house and elopes with the young christian gentleman; lorenzo.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>40", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    Alack, what heinous sin is it in me  To be ashamed to be my father's child!  But though I am a daughter to his blood  I am not to his manners. . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II Scene Three lines 15 - 18)  \"I will feed fat the ancient grudge\" illustrates", "images": [], "options": {"A": "metonymy", "B": "contrast", "C": "apostrophe", "D": "metaphor"}, "answer": "D", "explanation": "Metaphor  A metaphor that refers to one thing by mentioning another. It may provide clarity or identify hidden similarities between two ideas.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>41", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the the extract below and answer this question    . . . . . . twere damnation  To think so base a thought; it were too gross  To rib her cerecloth in the obscure grave; ----  Or shall I think in silver she's immured;  *_Being ten times undervalued to tried gold?_  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II Scene Seven, lines 49 - 53)    The speaker is", "images": [], "options": {"A": "Arragon", "B": "Antonio", "C": "Morocco", "D": "Bassanio"}, "answer": "C", "explanation": "Morocco  The Prince of Morocco is one of the suitors that seeks portia's hand in marriage. He picks one of the three caskets that he feels reflect portia's beauty and stature, which is the gold casket and proves to be wrong.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>42", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the the extract below and answer this question    . . . . . . twere damnation  To think so base a thought; it were too gross  To rib her cerecloth in the obscure grave; ----  Or shall I think in silver she's immured;  *_Being ten times undervalued to tried gold?_  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II Scene Seven, lines 49 - 53)  The person referred to in the extract is", "images": [], "options": {"A": "Jessica", "B": "Antonio", "C": "Balthazar", "D": "Portia"}, "answer": "D", "explanation": "Portia  She is a wealthy heiress from Belmont. Her beauty matched her intelligence. She is bound by a clause in her father's will that forces her to marry whichever suitor chooses correctly among the three caskets.  Nonetheless, she is able to marry her true love; Bassanio. She also play a disguised role in the play when she disguise as a young law clerk, who saves Antonio from Shylok's knife.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>43", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the the extract below and answer this question    . . . . . . twere damnation  To think so base a thought; it were too gross  To rib her cerecloth in the obscure grave; ----  Or shall I think in silver she's immured;  *_Being ten times undervalued to tried gold?_  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II Scene Seven, lines 49 - 53)  \"Thought\" in the extract implies", "images": [], "options": {"A": "meditating on his love", "B": "associating the portrait with lead", "C": "challenging rival suitors", "D": "reflecting on his fate"}, "answer": "A", "explanation": "meditating on his love. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>44", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the the extract below and answer this question    . . . . . . twere damnation  To think so base a thought; it were too gross  To rib her cerecloth in the obscure grave; ----  Or shall I think in silver she's immured;  *_Being ten times undervalued to tried gold?_  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II Scene Seven, lines 49 - 53)  After this speech, the speaker", "images": [], "options": {"A": "unlocks the gold casket", "B": "engages his lover", "C": "unfolds his marriage plans", "D": "celebrates his victory"}, "answer": "A", "explanation": "In the context of the extract, after the speaker's contemplation about the value of the woman he loves, he decides to unlock the gold casket. This is because he believes that she is more valuable than silver or lead, and thus should be associated with gold. Therefore, the correct answer is option 1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>45", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the the extract below and answer this question    . . . . . . twere damnation  To think so base a thought; it were too gross  To rib her cerecloth in the obscure grave; ----  Or shall I think in silver she's immured;  *_Being ten times undervalued to tried gold?_  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II Scene Seven, lines 49 - 53)  \"Being ten times undervalued to try gold?\" reveals the speaker's", "images": [], "options": {"A": "strength of love", "B": "assessment of his lover's character", "C": "value of gold", "D": "estimate of his lover's worth"}, "answer": "C", "explanation": "It reveals the speaker's value of gold. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2005>46", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    When it is paid, according to the tenor.  It doth appear you are a worthy judge,  You knoe the law, your exposition  Hath been most sound. I charge you by the law; . . . . .   Proceed to judgement; . . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act IV Scene One, lines 231 - 236)    The speaker is", "images": [], "options": {"A": "Antonio", "B": "Shylock", "C": "Bassanio", "D": "Nerissa"}, "answer": "B", "explanation": "The speaker in the extract is addressing a judge, acknowledging their knowledge of the law and their sound exposition. This is a characteristic of Shylock's dialogue in the play, as he often appeals to the law to justify his actions. Therefore, the correct answer is option 2.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>47", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    When it is paid, according to the tenor.  It doth appear you are a worthy judge,  You knoe the law, your exposition  Hath been most sound. I charge you by the law; . . . . .   Proceed to judgement; . . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act IV Scene One, lines 231 - 236)  The person addressed is", "images": [], "options": {"A": "Jessica", "B": "Duke", "C": "Portia", "D": "Lorenzo"}, "answer": "C", "explanation": "The extract is from Shakespeare's 'The Merchant of Venice'. In this scene, Portia is disguised as a lawyer and is addressing the court. The speaker is praising the person addressed for their knowledge of the law and their sound exposition, which indicates that the person addressed is acting as a judge or lawyer. Among the given options, only Portia fits this description.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>48", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    When it is paid, according to the tenor.  It doth appear you are a worthy judge,  You knoe the law, your exposition  Hath been most sound. I charge you by the law; . . . . .   Proceed to judgement; . . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act IV Scene One, lines 231 - 236)  The extract conveys a feeling of", "images": [], "options": {"A": "dejection", "B": "anxiety", "C": "tolerance", "D": "confidence"}, "answer": "D", "explanation": "The speaker in the extract is expressing confidence in the person addressed, praising their knowledge of the law and their sound exposition. The speaker also charges the person addressed to proceed to judgement, indicating that they trust the person's judgement. Therefore, the extract conveys a feeling of confidence.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>49", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    When it is paid, according to the tenor.  It doth appear you are a worthy judge,  You knoe the law, your exposition  Hath been most sound. I charge you by the law; . . . . .   Proceed to judgement; . . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act IV Scene One, lines 231 - 236)  \"Your exposition\" refers to", "images": [], "options": {"A": "legal knowledge", "B": "plea for mercy", "C": "exercise of justice", "D": "enactment of the law"}, "answer": "C", "explanation": "exercise of justice is what is revealed. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2005>50", "subject": "Literature", "year": "2005", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer this question    When it is paid, according to the tenor.  It doth appear you are a worthy judge,  You knoe the law, your exposition  Hath been most sound. I charge you by the law; . . . . .   Proceed to judgement; . . . .  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act IV Scene One, lines 231 - 236)  At the end of the speech, the speaker", "images": [], "options": {"A": "proceeds to execute the bond", "B": "accepts the judgement of the court", "C": "submits to the Duke's authority", "D": "declares his unalterable stand"}, "answer": "B", "explanation": "Shylock accepts the judgement of the court. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>1", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\".......... the dragon fly  hangs like a blue bird thread  loosened from the sky...\" illustrates", "images": [], "options": {"A": "simile", "B": "litotes", "C": "contrast", "D": "metaphor"}, "answer": "A", "explanation": "Simile is a figure of speech which shows comparison between two ideas with the use of 'like' or 'as'. Here, the dragon-fly was compared to a blue thread. The use of the word, LIKE, proves this.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>2", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A pause within a line of a poem is a", "images": [], "options": {"A": "Zeugma", "B": "foot", "C": "caesura", "D": "stress"}, "answer": "C", "explanation": "A pause within a line of a poem is known as a caesura. It is a pause in a line of poetry that is formed by the rhythms of natural speech rather than by metrics. It usually occurs near the middle of a poetic line but can also occur at the beginning or the end of a line. Therefore, the correct answer is caesura.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>3", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Unryhmed iambic pentametric lines illustrates a", "images": [], "options": {"A": "rhyme scheme", "B": "heroic couplet", "C": "blank verse", "D": "free verse"}, "answer": "C", "explanation": "Blank verse is usually unrhymed but each line has ten syllables that can be broken into five unstressed syllables and five stressed syllables, following the pattern: unstressed syllable + stressed syllable.  . This pattern is known as the iambic pentameter.    A free verse has no rhyme scheme or meter pattern.  The heroic couplet refers to two lines of poetry with the same rhyme and rhythm.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>4", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The limerick", "images": [], "options": {"A": "is written to be sung", "B": "has serious subject matter", "C": "is always light humorous", "D": "uses lofty languages"}, "answer": "C", "explanation": "A limerick is a type of poetry that is often light and humorous. It consists of five lines with a particular rhythm and rhyme scheme. Therefore, the statement 'is always light humorous' is correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2006>5", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The elegy", "images": [], "options": {"A": "conforms to a fixed pattern of lines", "B": "is set on the country side", "C": "has a mournful tone", "D": "celebrates heroic deeds"}, "answer": "C", "explanation": "The elegy is a type of poem that mourns the death of a person. It takes death as its subject matter. Because it revolves around death, the tone is usually mournful.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>6", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" But at my back I always hear  Time's winged chariot hurrying near\" illustrates", "images": [], "options": {"A": "metaphor", "B": "apostrophe", "C": "oxymoron", "D": "metonymy"}, "answer": "A", "explanation": "Time is compared with a winged chariot. The statement means that time is short. Therefore, this extract is metaphorical", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>7", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A line of poetry is measured by the", "images": [], "options": {"A": "number of words", "B": "number of feet it contains", "C": "images", "D": "rhythm"}, "answer": "B", "explanation": "A line of poetry is measured by the number of feet it contains. In poetry, a 'foot' refers to the metrical unit composed of stressed and unstressed syllables. For example, in iambic pentameter, each line of poetry has five 'feet' of one unstressed syllable followed by one stressed syllable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>8", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The recurrence of rhythmic pattern of stress in a poem is a", "images": [], "options": {"A": "couplet", "B": "metre", "C": "consonance", "D": "scansion"}, "answer": "B", "explanation": "Meter is the pattern of stressed and unstressed syllables in a line of poetry.  Scansion has to do with the act of placing stress correctly or indicating where stress falls.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>9", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A humorous imitation of a serious literary work is", "images": [], "options": {"A": "an ode", "B": "a parody", "C": "an epitaph", "D": "a burlesque"}, "answer": "B", "explanation": "Burlesque and parody are often used interchangeably because they both mean the imitation of a literary work. However, the slight difference between them is that the burlesque is seen as a generic name for imitations of literary works while the parody is basically a form of the burlesque (Check  A Glossary of Literary Terms by M. H. Abrams).    The parody, according to M. H. Abrams, \"imitates the serious manner and characteristic features of a particular literary work.\" This imitation is usually humourous because it intends to ridicule what is being imitated. Therefore, the choice of parody is apt.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>10", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A struggle between opposing forces in a literary work is the", "images": [], "options": {"A": "plot", "B": "conflict", "C": "climax", "D": "denouncement"}, "answer": "B", "explanation": "CXonflict is regarded as the struggle between opposing forces in a work of art. Most times, this struggle is between the protagonbist and the antagonist.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>11", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A metrical pattern of stressed and unstressed syllables illustrates the", "images": [], "options": {"A": "iambus", "B": "anapaest", "C": "dactil", "D": "trochee"}, "answer": "D", "explanation": "The trochee is a combination of two syllables, the first of which is stressed while the second is unstressed ( Stressed + Unstressed).    The iambic foot is made up of an unstressed followed by stressed syllable.   The anapest is made up of three syllables. The first two are unstressed while the third syllable is stressed.   Dactyl is one stressed followed by two unstressed syllables.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>12", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A poem with fourteen lines of rhymed iambic pentrametre is", "images": [], "options": {"A": "an epic", "B": "a sonnet", "C": "a quatrain", "D": "an octave"}, "answer": "B", "explanation": "A sonnet is a poem of an expressive thought or idea made up of 14 lines, each being 10 syllables long. Its rhymes are arranged according to one of the certain definite schemes, being in strict or Italian form, divided usually between eight lines, called the octave, and six lines, called the sestet, or, in the commoner English or Shakespearean form, into three quatrains and a couplet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>13", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd items from the option listed below", "images": [], "options": {"A": "Euphemism", "B": "Oxymoron", "C": "Hyperbole", "D": "Rhythm"}, "answer": "D", "explanation": "The odd item among the options is 'Rhythm'. Euphemism, Oxymoron, and Hyperbole are all figures of speech, which are used to add effect or emphasis in a literary piece. On the other hand, Rhythm is a literary device that demonstrates the long and short patterns through stressed and unstressed syllables, particularly in verse form.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>14", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The specific Literary term used to distinguish a novel from a play is", "images": [], "options": {"A": "genre", "B": "verse", "C": "diction", "D": "style"}, "answer": "D", "explanation": "The style is what differentiates prode from drama. While prose is in the form of narration, drama (play) is in the form of action and dialogue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>15", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A pair of rhymed iambic pentametre lines is a", "images": [], "options": {"A": "tercet", "B": "heroic couplet", "C": "sestet", "D": "blank verse"}, "answer": "B", "explanation": "Heroic couplet refers to two lines of poetry that have the same rhyme and meteer pattern (iambic pentameter).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>16", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" Friendship is a sheltering tree\" illustrates", "images": [], "options": {"A": "simile", "B": "metaphor", "C": "personification", "D": "oxymoron"}, "answer": "B", "explanation": "Metaphor is used to show comparison between two ideas directly. Here, friendship is directly compared to a sheltering tree.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>17", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The dominant device used in drama is", "images": [], "options": {"A": "stage direction", "B": "dialogue", "C": "characterisation", "D": "soliloquy"}, "answer": "B", "explanation": "The dominant device used in drama is dialogue. Drama is a mode of fictional representation through dialogue and performance. It is one of the literary genres, which is usually performed in theatre, or on radio or television. The dialogue is the conversation between characters in a novel, drama, etc. It is the medium through which the characters of a drama communicate with each other.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>18", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" I don't forbid fruits of fashion and fads\" illustrates", "images": [], "options": {"A": "refrain", "B": "repetition", "C": "assonance", "D": "alliteration"}, "answer": "D", "explanation": "Alliteration is the repetition of consonant sound at the beginning of words in a line poetry.  \"I don't fancy forbidden fruits of fashion and fads\"  Here, the sound /f/ alliterates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>19", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item from the options listed below", "images": [], "options": {"A": "Romance", "B": "Novel", "C": "Short Story", "D": "Sonnet"}, "answer": "D", "explanation": "The sonnet is a poemof fourteen lines with a definite rhyme scheme and meter pattern while romance, novel and the short story are forms of fictitious prose", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2006>20", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" The strong gongs groaning as the  guns boom far\" illustrates", "images": [], "options": {"A": "metonymy", "B": "refrain", "C": "onomatopoeia", "D": "repetition"}, "answer": "C", "explanation": "This figure of speech suggests the meaning of words or expressions i.e  The sound echoes what is being portrayed  The strong gongs  groaning  as the guns boom  far", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>21", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the following passage and answer this question               Here in the station, it is in no way different save that the city is busy in its snow. But the old men cling to their seats as though they were symbolic and could not be given up. Now and then they sleep, their grey old hairs resting with painful awkwardness  on the backs of the benches .           Also, they are not at rest. For an hour, they may sleep in the gasping exhaustion of the ill nourished and aged . who have to walk in the night. Then, a policeman man comes by on his round and nudges them upright.             \" You cant sleep here\", he growls              A strange ritual then begins. An old man is difficult to wake. One man after a slight lurch, does not move at all he sleeps on steadily. Once in  a while, one of the sleepers will not wake; he will have had his wish to die in the great  droning  centre of the hive  rather than in some lonely room fulfilled.    The style of writing is", "images": [], "options": {"A": "argumentative", "B": "epistolary", "C": "narrative", "D": "expository"}, "answer": "D", "explanation": "The writeup sheds light on the plight of these old men.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>22", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the following passage and answer this question               Here in the station, it is in no way different save that the city is busy in its snow. But the old men cling to their seats as though they were symbolic and could not be given up. Now and then they sleep, their grey old hairs resting with painful awkwardness  on the backs of the benches .           Also, they are not at rest. For an hour, they may sleep in the gasping exhaustion of the ill nourished and aged . who have to walk in the night. Then, a policeman man comes by on his round and nudges them upright.             \" You cant sleep here\", he growls              A strange ritual then begins. An old man is difficult to wake. One man after a slight lurch, does not move at all he sleeps on steadily. Once in  a while, one of the sleepers will not wake; he will have had his wish to die in the great  droning  centre of the hive  rather than in some lonely room fulfilled.  \" ....... on the backs of the benches\" illustrates", "images": [], "options": {"A": "synecdoche", "B": "epithet", "C": "assonance", "D": "personification"}, "answer": "D", "explanation": "Here, benches are attributed with a human quality; that is, they are said to have a back.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>23", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the following passage and answer this question               Here in the station, it is in no way different save that the city is busy in its snow. But the old men cling to their seats as though they were symbolic and could not be given up. Now and then they sleep, their grey old hairs resting with painful awkwardness  on the backs of the benches .           Also, they are not at rest. For an hour, they may sleep in the gasping exhaustion of the ill nourished and aged . who have to walk in the night. Then, a policeman man comes by on his round and nudges them upright.             \" You cant sleep here\", he growls              A strange ritual then begins. An old man is difficult to wake. One man after a slight lurch, does not move at all he sleeps on steadily. Once in  a while, one of the sleepers will not wake; he will have had his wish to die in the great  droning  centre of the hive  rather than in some lonely room fulfilled.  The passage conveys  a mood of", "images": [], "options": {"A": "defiance", "B": "hope", "C": "fear", "D": "despair"}, "answer": "D", "explanation": "The dominant mood in the passage is that of hopelessness and despair. This mood of despair is reinforced in the last sentence where it is revealed that the men sometimes die in their sleep.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>24", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the following passage and answer this question               Here in the station, it is in no way different save that the city is busy in its snow. But the old men cling to their seats as though they were symbolic and could not be given up. Now and then they sleep, their grey old hairs resting with painful awkwardness  on the backs of the benches .           Also, they are not at rest. For an hour, they may sleep in the gasping exhaustion of the ill nourished and aged . who have to walk in the night. Then, a policeman man comes by on his round and nudges them upright.             \" You cant sleep here\", he growls              A strange ritual then begins. An old man is difficult to wake. One man after a slight lurch, does not move at all he sleeps on steadily. Once in  a while, one of the sleepers will not wake; he will have had his wish to die in the great  droning  centre of the hive  rather than in some lonely room fulfilled.  \" gasping exhaustion of the ill-nourished and aged\" infers", "images": [], "options": {"A": "helplessness", "B": "slowness", "C": "sadness", "D": "tiredness"}, "answer": "A", "explanation": "This suggests a state of helplessness. Old age is a time when many lose their strength and have to rely on others for survival.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>25", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the following passage and answer this question               Here in the station, it is in no way different save that the city is busy in its snow. But the old men cling to their seats as though they were symbolic and could not be given up. Now and then they sleep, their grey old hairs resting with painful awkwardness  on the backs of the benches .           Also, they are not at rest. For an hour, they may sleep in the gasping exhaustion of the ill nourished and aged . who have to walk in the night. Then, a policeman man comes by on his round and nudges them upright.             \" You cant sleep here\", he growls              A strange ritual then begins. An old man is difficult to wake. One man after a slight lurch, does not move at all he sleeps on steadily. Once in  a while, one of the sleepers will not wake; he will have had his wish to die in the great  droning  centre of the hive  rather than in some lonely room fulfilled.  \" droning\" and \"hive\" illustrates", "images": [], "options": {"A": "anecdote", "B": "epigram", "C": "allusion", "D": "epitaph"}, "answer": "C", "explanation": "Allusion has to do with making a reference to something outside the immediate scope of what is being treated.  The highligted expression is a reference to bees because the humming sound made by bees can be referred to as \"droning\" and bees also live in \"hives\"..", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>26", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this questions.    Sleep, O sleep,  With thy Rod of Incantation  Charm my Imagination  Then, only then, I cease to weap.    By thy power,  The Virgin, by Time O'ertaken  For years forlon, forsaken,  Enjoys the happy hour.    What's to sleep?  'Tis a Visionary Blessing;  A Dream that's past expressing;  Our utmost Wish possessing;  So may i always keep.    The poem is", "images": [], "options": {"A": "an epic", "B": "an ode", "C": "a lyric", "D": "a ballad"}, "answer": "B", "explanation": "Ode is a poem that is written in the form of a direct address to something. Here, SLEEP is directly addressed and praised.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>27", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this questions.    Sleep, O sleep,  With thy Rod of Incantation  Charm my Imagination  Then, only then, I cease to weap.    By thy power,  The Virgin, by Time O'ertaken  For years forlon, forsaken,  Enjoys the happy hour.    What's to sleep?  'Tis a Visionary Blessing;  A Dream that's past expressing;  Our utmost Wish possessing;  So may i always keep.  The dominant device used in the first line is", "images": [], "options": {"A": "oxymoron", "B": "apostrophe", "C": "rhyme", "D": "metaphor"}, "answer": "B", "explanation": "Apostrophe is used to address inanimate objects which may not be seen physically as if they understand or are personally present.  The persona addresses SLEEP as if it were alive and present.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>28", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this questions.    Sleep, O sleep,  With thy Rod of Incantation  Charm my Imagination  Then, only then, I cease to weap.    By thy power,  The Virgin, by Time O'ertaken  For years forlon, forsaken,  Enjoys the happy hour.    What's to sleep?  'Tis a Visionary Blessing;  A Dream that's past expressing;  Our utmost Wish possessing;  So may i always keep.  The poem makes use of the", "images": [], "options": {"A": "end-stopped line", "B": "run-on lines", "C": "rhyme", "D": "metaphor"}, "answer": "C", "explanation": "The poem possess rhymes. Stasnza one has a rhyme scheme of abba.  Sleep, O sleep, (a)  With thy Rod of Incantation (b)  Charm my Imagination (b)  Then, only then, I cease to weep. (a)", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>29", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this questions.    Sleep, O sleep,  With thy Rod of Incantation  Charm my Imagination  Then, only then, I cease to weap.    By thy power,  The Virgin, by Time O'ertaken  For years forlon, forsaken,  Enjoys the happy hour.    What's to sleep?  'Tis a Visionary Blessing;  A Dream that's past expressing;  Our utmost Wish possessing;  So may i always keep.  \" Sleep\" in the poem is an example of", "images": [], "options": {"A": "alliteration", "B": "apostrophe", "C": "onomatopoeia", "D": "pun"}, "answer": "B", "explanation": "Here, sleep is addressed as if it were present and could hear. Apostrophe is a figure of speech used to refer to an inanimate object as if human or someone  absent as if present.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>30", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this questions.    Sleep, O sleep,  With thy Rod of Incantation  Charm my Imagination  Then, only then, I cease to weap.    By thy power,  The Virgin, by Time O'ertaken  For years forlon, forsaken,  Enjoys the happy hour.    What's to sleep?  'Tis a Visionary Blessing;  A Dream that's past expressing;  Our utmost Wish possessing;  So may i always keep.  The power of \"sleep\" is described as", "images": [], "options": {"A": "majestic", "B": "magical", "C": "poetic", "D": "worshipful"}, "answer": "B", "explanation": "MAGICAL!    \"with thy red of incantation   charm my imagination  Then, only then, I cease to weep\"    In the extract above, sleep is presented as something that could charm and make a person stop weeping.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>31", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question    If thou hast any sound, or use of voice,  speak to me:  If there be any good thing to be done,   That may to thee do ease and grace to me,  speak to me:  If thou art privy to the country's fate,  O, speak  Or if thou has uphoarded in thy life,  Extorted treasure in the womb of earth,  For which, they say you spirit oft walk in death,  Speak of it:  (Act one, scene 1, lines 128-139)    The speaker is", "images": [], "options": {"A": "Hamlet", "B": "Marcellus", "C": "Horaito", "D": "Claudius"}, "answer": "A", "explanation": "This happened on a platform before the castle when a ghost appeared about 12 midnight in the form of the dead king: Hamlet's father.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>32", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question    If thou hast any sound, or use of voice,  speak to me:  If there be any good thing to be done,   That may to thee do ease and grace to me,  speak to me:  If thou art privy to the country's fate,  O, speak  Or if thou has uphoarded in thy life,  Extorted treasure in the womb of earth,  For which, they say you spirit oft walk in death,  Speak of it:  (Act one, scene 1, lines 128-139)  The character addressed is", "images": [], "options": {"A": "the queen", "B": "the ghost", "C": "Bernado", "D": "Renaldo"}, "answer": "B", "explanation": "In the given extract from Shakespeare's Hamlet, the character being addressed is the ghost of King Hamlet. Marcellus, the speaker, is urging the ghost to speak, hoping to learn if there is something he can do to ease the ghost's suffering or to benefit Denmark.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>33", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question    If thou hast any sound, or use of voice,  speak to me:  If there be any good thing to be done,   That may to thee do ease and grace to me,  speak to me:  If thou art privy to the country's fate,  O, speak  Or if thou has uphoarded in thy life,  Extorted treasure in the womb of earth,  For which, they say you spirit oft walk in death,  Speak of it:  (Act one, scene 1, lines 128-139)  The speech was made after", "images": [], "options": {"A": "the killing of Pollonius", "B": "Hamlet's arrival at the palace", "C": "the arrival of the players", "D": "the appearance of the ghost"}, "answer": "D", "explanation": "Immediately the ghost appeared the second time, Horatio referred to it as an illusion (line 127) and asked it to speak!", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>34", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question    If thou hast any sound, or use of voice,  speak to me:  If there be any good thing to be done,   That may to thee do ease and grace to me,  speak to me:  If thou art privy to the country's fate,  O, speak  Or if thou has uphoarded in thy life,  Extorted treasure in the womb of earth,  For which, they say you spirit oft walk in death,  Speak of it:  (Act one, scene 1, lines 128-139)  The speaker's mood is", "images": [], "options": {"A": "anger", "B": "regret", "C": "anxiety", "D": "disappointment"}, "answer": "C", "explanation": "Anxiety seeps into every word Horatio uses and this is noted in such urgency and desperation with which he speaks.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>35", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question    If thou hast any sound, or use of voice,  speak to me:  If there be any good thing to be done,   That may to thee do ease and grace to me,  speak to me:  If thou art privy to the country's fate,  O, speak  Or if thou has uphoarded in thy life,  Extorted treasure in the womb of earth,  For which, they say you spirit oft walk in death,  Speak of it:  (Act one, scene 1, lines 128-139)  During this speech", "images": [], "options": {"A": "the palace soldiers arrived", "B": "Hamlet attacked the speaker", "C": "the queen fainted", "D": "a cock crowed"}, "answer": "D", "explanation": "In the given extract from Shakespeare's Hamlet, the speaker is imploring a ghost to speak to him. The ghost is believed to be the spirit of Hamlet's father. The speaker is asking the ghost to reveal any secrets it might know about the fate of the country or any hidden treasures. The extract ends without any interruption, but the next scene in the play is the break of dawn, which is traditionally signaled by a cock's crow. Therefore, the correct answer is 'a cock crowed'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>36", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the following extract and answer this question    Y:  Do you know me , my Lord?  Z:  Excellent well; you are  fishmonger   Y:  Not I, my Lord  Z  Then i would you were so honest a man  Y  Honest, my Lord!  Z  Ay, sir to be honest, as this world ages, is to be one man picked out of ten thousand  (Act Two, Scene II, lines 173-179)    Speakers  Y and z are", "images": [], "options": {"A": "Polonius and Hamlet", "B": "Caludius and Laertes", "C": "Laertes and Horatio", "D": "Marcellus and Reynaldo"}, "answer": "A", "explanation": "In the given extract from Shakespeare's Hamlet, the speakers Y and Z are Polonius and Hamlet respectively. This can be inferred from the dialogue where Z (Hamlet) calls Y (Polonius) a 'fishmonger', which is a derogatory term used by Hamlet to insult Polonius. The dialogue also includes a discussion about honesty, a theme that is often associated with the interactions between these two characters in the play.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>37", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the following extract and answer this question    Y:  Do you know me , my Lord?  Z:  Excellent well; you are  fishmonger   Y:  Not I, my Lord  Z  Then i would you were so honest a man  Y  Honest, my Lord!  Z  Ay, sir to be honest, as this world ages, is to be one man picked out of ten thousand  (Act Two, Scene II, lines 173-179)  Speaker Z's responses suggests that he is", "images": [], "options": {"A": "planning revenge", "B": "pretending to be mad", "C": "telling a lie", "D": "preparing to commit suicide"}, "answer": "B", "explanation": "The extract is from Shakespeare's play 'Hamlet'. In this scene, Hamlet (Speaker Z) is pretending to be mad. He is speaking in riddles and nonsense to confuse Polonius (Speaker Y). The term 'fishmonger' is a derogatory term used by Hamlet to insult Polonius. Hamlet's feigned madness is a significant part of the play's plot.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>38", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the following extract and answer this question    Y:  Do you know me , my Lord?  Z:  Excellent well; you are  fishmonger   Y:  Not I, my Lord  Z  Then i would you were so honest a man  Y  Honest, my Lord!  Z  Ay, sir to be honest, as this world ages, is to be one man picked out of ten thousand  (Act Two, Scene II, lines 173-179)  The two characters who just left the scene are", "images": [], "options": {"A": "Rosencrantz and Guildenstern", "B": "Hamlet and the ghost", "C": "The king and the queen", "D": "Polonius and ophelia"}, "answer": "C", "explanation": "Tghe king and the queen were in the scene with Polonius but they left immediately Hamlet came in so as to give Polonius the opportunity to find out if Hamlet was insane or not.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>39", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the following extract and answer this question    Y:  Do you know me , my Lord?  Z:  Excellent well; you are  fishmonger   Y:  Not I, my Lord  Z  Then i would you were so honest a man  Y  Honest, my Lord!  Z  Ay, sir to be honest, as this world ages, is to be one man picked out of ten thousand  (Act Two, Scene II, lines 173-179)  Speak er Z thinks Y is", "images": [], "options": {"A": "very honest", "B": "as dishonest as most people", "C": "more dishonest than anyone", "D": "more dishonest than ten thousand people"}, "answer": "B", "explanation": "' ... to be honest, as this word goes, is to be one man picked out of then thousand' shows that lots of people are dishonest just like Polonius.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>40", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the following extract and answer this question    Y:  Do you know me , my Lord?  Z:  Excellent well; you are  fishmonger   Y:  Not I, my Lord  Z  Then i would you were so honest a man  Y  Honest, my Lord!  Z  Ay, sir to be honest, as this world ages, is to be one man picked out of ten thousand  (Act Two, Scene II, lines 173-179)  The underlined statement illustrates", "images": [], "options": {"A": "metaphor", "B": "simile", "C": "hyperbole", "D": "irony"}, "answer": "A", "explanation": "Metaphor is used to relate one thing to mean exactly another thing.   Polonius is directly referred to as a fishmonger", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>41", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the following extract and answer this questions.    And you can, by no drift of circumstance,  Get from him why he puts on this confusion,  Grating so harshly all his days of quiet,  with turbulent and dangerous lunacy?  (Act Three, scene 1, line 1-4)    The speaker is", "images": [], "options": {"A": "Gertrude", "B": "Ophelia", "C": "Claudius", "D": "Polonius"}, "answer": "C", "explanation": "In a room in the castle, King Claudius, Queen Gertrude, Polinius, Ophelia, Rosencrantz and Guildenstern assemble to discuss Hamlet's madness. Claudius is the one speaking.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>42", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the following extract and answer this questions.    And you can, by no drift of circumstance,  Get from him why he puts on this confusion,  Grating so harshly all his days of quiet,  with turbulent and dangerous lunacy?  (Act Three, scene 1, line 1-4)  The person being discussed is", "images": [], "options": {"A": "Voltimand", "B": "Hamlet", "C": "Ophelia", "D": "Rosencrantz"}, "answer": "B", "explanation": "In line 4, ' with turbulence and dangerous lunacy' illustrates madness. The only one who is inferred to be mad by people is Hamlet.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>43", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the following extract and answer this questions.    And you can, by no drift of circumstance,  Get from him why he puts on this confusion,  Grating so harshly all his days of quiet,  with turbulent and dangerous lunacy?  (Act Three, scene 1, line 1-4)  The character being addressed are", "images": [], "options": {"A": "Marcelllus and Horatio", "B": "Bernado and Francisco", "C": "Rosencrantz and Guildernsten", "D": "Marcellus and Francisco"}, "answer": "C", "explanation": "Though, they are not the only ones present, the question is directed to them as they have been sent earlier to visit Hamlet", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>44", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the following extract and answer this questions.    And you can, by no drift of circumstance,  Get from him why he puts on this confusion,  Grating so harshly all his days of quiet,  with turbulent and dangerous lunacy?  (Act Three, scene 1, line 1-4)  The response given to this specch indicates that the attempt was", "images": [], "options": {"A": "unsuccessful", "B": "successful", "C": "progressing", "D": "dangerous"}, "answer": "A", "explanation": "In the response that follows in line 6, Rosencrantz that ' but from what cause he (Hamlet) will by no means speak.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>45", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the following extract and answer this questions.    And you can, by no drift of circumstance,  Get from him why he puts on this confusion,  Grating so harshly all his days of quiet,  with turbulent and dangerous lunacy?  (Act Three, scene 1, line 1-4)  The character being addressed is", "images": [], "options": {"A": "Hamlet", "B": "laertes", "C": "Ophelia", "D": "Horatio"}, "answer": "C", "explanation": "Ophelia is also present during the discussion alongside five others.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>46", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question    Why, now you speak  Like a good child and true gentleman.  That I am guiltless of your father's death,  And most sensibly in grief for it,  It shall as level to your judgement pierce   As day does to your eyes   (Act four scene V, lines 128-133)    The speaker is", "images": [], "options": {"A": "the king", "B": "the queen", "C": "the ghost", "D": "Polonius"}, "answer": "A", "explanation": "In this extract, the speaker is trying to convince someone that they are innocent of their father's death. This is a reference to the plot point where Claudius, the king, tries to convince Hamlet that he is not responsible for the death of Hamlet's father.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>47", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question    Why, now you speak  Like a good child and true gentleman.  That I am guiltless of your father's death,  And most sensibly in grief for it,  It shall as level to your judgement pierce   As day does to your eyes   (Act four scene V, lines 128-133)  The underlined statement illustrates", "images": [], "options": {"A": "Irony", "B": "Metaphor", "C": "Paradox", "D": "Simile"}, "answer": "D", "explanation": "The underlined statement 'As day does to your eyes' is a simile. A simile is a figure of speech that makes a comparison, showing similarities between two different things. In this case, the speaker is comparing the clarity of his innocence to the clarity of daylight to the eyes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2006>48", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question    Why, now you speak  Like a good child and true gentleman.  That I am guiltless of your father's death,  And most sensibly in grief for it,  It shall as level to your judgement pierce   As day does to your eyes   (Act four scene V, lines 128-133)  The character who has just been murdered is", "images": [], "options": {"A": "Hamlet", "B": "Gertrude", "C": "Polonius", "D": "Claudius"}, "answer": "C", "explanation": "In the context of the play 'Hamlet' by William Shakespeare, the character who has just been murdered and whose death is being referred to in the extract is Polonius. Polonius is the father of Ophelia and Laertes, and the chief counsellor to the king, Claudius.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>49", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "AFRICAN DRAMA", "question": "Read the extract and answer this question    Why, now you speak  Like a good child and true gentleman.  That I am guiltless of your father's death,  And most sensibly in grief for it,  It shall as level to your judgement pierce   As day does to your eyes   (Act four scene V, lines 128-133)  The speech can best be interpreted to mean", "images": [], "options": {"A": "that the murder was an act of revenge", "B": "a denial of responsibility", "C": "that it is not easy to know who the murderer is", "D": "that the murderer is present on the scene"}, "answer": "B", "explanation": "A denial for responsibility of the murder  The words 'guiltless' and ' in grief' in lines 130 and 131 respectively shows innocence.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2006>50", "subject": "Literature", "year": "2006", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question    Why, now you speak  Like a good child and true gentleman.  That I am guiltless of your father's death,  And most sensibly in grief for it,  It shall as level to your judgement pierce   As day does to your eyes   (Act four scene V, lines 128-133)  The setting is", "images": [], "options": {"A": "the graveyard", "B": "a platform in front of the castle", "C": "a room in Polinius' house", "D": "a room in the castle"}, "answer": "D", "explanation": "This is where King Claudius lives. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>1", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" she waited for him for a thousand years\" illustrates", "images": [], "options": {"A": "euphemism", "B": "hyperbole", "C": "assonance", "D": "ellipsis"}, "answer": "B", "explanation": "The hyperbole refers to an excessive exaggeration. Here, it is exaggerated the that the woman waited for a man for a thousand years. What this means is that she waited for him for a very long time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>2", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A bitter remark intended to wound the feelings is", "images": [], "options": {"A": "satire", "B": "an allusion", "C": "a sarcasm", "D": "an ambiguity"}, "answer": "C", "explanation": "The sarcasm is a form of irony. It is usually caustic witha view to hurting the feelings of tghe person being talked about.  An allusion is a reference to something outside what is being treated.  Ambiguity refers to a statement with more than one meaning.  A satire is a work that criticises the ills of teh society in a bid to instigate a change.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>3", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary device which expresses meaning in their direct opposite is", "images": [], "options": {"A": "metaphor", "B": "paradox", "C": "parody", "D": "irony"}, "answer": "D", "explanation": "The irony is a literary device that is used to show a discrepancy between was is said and what is meant or between what is exoected and what actually occurs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>4", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"They also serve who only stand and wait\" illustrates", "images": [], "options": {"A": "an epigram", "B": "a synecdoche", "C": "a simile", "D": "an antithesis"}, "answer": "A", "explanation": "Epigram is used to express an idea in a concise and memorable way", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>5", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item out of the options listed below", "images": [], "options": {"A": "verse", "B": "stanza", "C": "rhythm", "D": "dialogue"}, "answer": "D", "explanation": "The term 'dialogue' is the odd one out because it refers to a conversation between two or more people as a feature of a book, play, or film. On the other hand, 'verse', 'stanza', and 'rhythm' are all terms related to poetry. A verse is a single line of a poem, a stanza is a group of lines forming the basic recurring metrical unit in a poem, and rhythm is a strong, regular, repeated pattern of movement or sound in poetry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2007>6", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In drama, \"denouement\" is the same as", "images": [], "options": {"A": "resolution", "B": "climax", "C": "anti-climax", "D": "conflict"}, "answer": "A", "explanation": "This is the final stage of the plot; it is the point where every dispute is settled. RESOLUTION = DENOUEMENT", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2007>7", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Which of the following is NOT true of a ballad?", "images": [], "options": {"A": "They were originally sung", "B": "They are mostly part of oral tradition", "C": "They tell a popular story", "D": "They are written in iambic metres"}, "answer": "C", "explanation": "Ballads were usually sung to accompany dances and were passed down orally from generation to generation. They are usually written in iambic tetrameter and trimeter.  The story told in a ballad need not be popular.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>8", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract and answer this question    My heart leaps up when I behold  A rainbow in the sky;  So was it when my life began  So is it now that I am a man  So be it when I shall grow  The child is father of the man.    The mood of the poem is that of", "images": [], "options": {"A": "sorrow", "B": "elation", "C": "anxiety", "D": "sarcasm"}, "answer": "B", "explanation": "The poet was filled with happiness. This happiness is evident through the excitement he feels when he sees a rainbow.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>9", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract and answer this question    My heart leaps up when I behold  A rainbow in the sky;  So was it when my life began  So is it now that I am a man  So be it when I shall grow  The child is father of the man.  The rhyme scheme of the poem is", "images": [], "options": {"A": "ab cc dc", "B": "ac bc ca", "C": "ab ca cc", "D": "ab ac bc"}, "answer": "A", "explanation": "The rhyme scheme of the poem is 'ab cc dc'. A rhyme scheme is the pattern of rhymes at the end of each line of a poem or song. It is usually referred to by using letters to indicate which lines rhyme. In this case, 'behold' and 'man' rhyme (a), 'sky' and 'man' rhyme (b), 'began' and 'grow' rhyme (c), and 'man' and 'man' rhyme (d).", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>10", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract and answer this question    My heart leaps up when I behold  A rainbow in the sky;  So was it when my life began  So is it now that I am a man  So be it when I shall grow  The child is father of the man.  The subject of the extract is", "images": [], "options": {"A": "childlessness", "B": "the adverse effect of the rainbow on man", "C": "the unchanging circle of nature", "D": "the adverse effect of old age"}, "answer": "C", "explanation": "The rainbow is present since the beginning of time and will be in the future. Therefore, nature is presented as unchanging.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>11", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN PROSE", "question": "Read the extract and answer this question    My heart leaps up when I behold  A rainbow in the sky;  So was it when my life began  So is it now that I am a man  So be it when I shall grow  The child is father of the man.  The literary device used in line 1 is", "images": [], "options": {"A": "simile", "B": "alliteration", "C": "litotes", "D": "personification"}, "answer": "D", "explanation": "The literary device used in line 1, 'My heart leaps up when I behold', is personification. Personification is a figure of speech in which a thing, an idea or an animal is given human attributes. In this case, the poet's heart is given the human attribute of 'leaping up', which is an expression of joy or excitement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>12", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract and answer this question    My heart leaps up when I behold  A rainbow in the sky;  So was it when my life began  So is it now that I am a man  So be it when I shall grow  The child is father of the man.  The literary device used in line 6 is an example of", "images": [], "options": {"A": "synecdoche", "B": "irony", "C": "paradox", "D": "hyperbole"}, "answer": "C", "explanation": "The line seems unreasonable but it has a deeper meaning. The statement means that the traits we have as children will still manifest when we are adults; little wonder both children and adults are elated at the sight of a rainbow.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>13", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" Forty hands descended on the devilish head\" illustrates", "images": [], "options": {"A": "epigram", "B": "synecdoche", "C": "metonymy", "D": "allegory"}, "answer": "B", "explanation": "The phrase \"Forty hands descended on the devilish head\" illustrates 'synecdoche'. Synecdoche is a figure of speech in which a part is made to represent the whole or vice versa. In this case, 'forty hands' is used to represent a group of people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>14", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item out of the options listed below", "images": [], "options": {"A": "sonnet", "B": "epic", "C": "allusion", "D": "ode"}, "answer": "C", "explanation": "The odd item out of the options listed is 'allusion'. Sonnet, epic, and ode are all types of poetic forms, while allusion is a literary device that references a person, place, thing, or event in the real world. It's not a form of poetry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2007>15", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A deliberate violation of the rules of versification constitutes", "images": [], "options": {"A": "imperfect rhyme", "B": "poetic license", "C": "verbal irony", "D": "comic relief"}, "answer": "B", "explanation": "A deliberate violation of the rules of versification constitutes a poetic license. Poetic license is a literary term that is actually quite easy to understand. The term 'poetic license' refers to the freedom that poets and other artists have to deviate from the norm - to 'break the rules' - in order to create a particular effect. They might do this by using unconventional grammar, punctuation, or pronunciation. They might also do it by presenting events or details in a non-chronological or non-factual order.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2007>16", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A praise poem is", "images": [], "options": {"A": "a dirge", "B": "an epic", "C": "a ballad", "D": "an ode"}, "answer": "D", "explanation": "A praise poem is an ode. An ode is a type of lyrical stanza. It is an elaborately structured poem praising or glorifying an event or individual, describing nature intellectually as well as emotionally.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2007>17", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Lines of regular recurrence in a poem constitutes", "images": [], "options": {"A": "an alliteration", "B": "a refrain", "C": "an assonance", "D": "a theme"}, "answer": "B", "explanation": "Lines of regular recurrence in a poem constitute a refrain. A refrain in poetry is a repeated part of a poem, typically a line or lines, that appears at regular intervals throughout the piece. It is used to emphasize a point or theme in the poem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>18", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An individual who acts, appears or referred to as playing a part in a literary work is a", "images": [], "options": {"A": "villain", "B": "character", "C": "clown", "D": "narrator"}, "answer": "B", "explanation": "Character is a person who acts a role in a literary work A chraracter can be regarded as a participant in a work of art.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2007>19", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A regular group of lines in poetry constitutes", "images": [], "options": {"A": "stanza", "B": "rhythm", "C": "verse", "D": "metre"}, "answer": "A", "explanation": "A regular group of lines in a poem is referred to as a 'stanza'. This is similar to a paragraph in prose. The other options do not fit the definition. 'Rhythm' refers to the pattern of stressed and unstressed syllables in a line of poetry. 'Verse' can refer to a single line of poetry, or a specified stanza within a poem. 'Metre' refers to the rhythmic structure of lines in poetry, specifically the number and types of stresses, or beats, in each line.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2007>20", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" A black beautiful brilliant bride\" is an example of", "images": [], "options": {"A": "alliteration", "B": "assonance", "C": "onomatopoeia", "D": "pun"}, "answer": "A", "explanation": "The sound /b/ alliterates i.e it appears at the beginning of the words  ... black beautiful brilliant bride", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2007>21", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question    Bent-double like old beggars under sacks,   Knock-Kneed, coughing like hags, we curse through  sludge   Till on the haunting flares we turned our backs  And towards our distant rest began to trudge,  Men marched asleep, many had lost their boots,  But limped on, blood-shed. All went lame, all blind;   Drunk with fatigue ; even deaf to the hoots  Of gas-shells dropping softly behind    The extract contains a mood of", "images": [], "options": {"A": "dejection", "B": "desperation", "C": "resentment", "D": "resignation"}, "answer": "A", "explanation": "Words like 'old beggars under sacks, curse through, drunk with fatigue, etc' show this", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>22", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question    Bent-double like old beggars under sacks,   Knock-Kneed, coughing like hags, we curse through  sludge   Till on the haunting flares we turned our backs  And towards our distant rest began to trudge,  Men marched asleep, many had lost their boots,  But limped on, blood-shed. All went lame, all blind;   Drunk with fatigue ; even deaf to the hoots  Of gas-shells dropping softly behind  The dominant figure of speech in the first stanza is", "images": [], "options": {"A": "hyperbole", "B": "simile", "C": "euphemism", "D": "pun"}, "answer": "B", "explanation": "\"Bent-double like old beggars under sacks,   Knock-Kneed, coughing like hags\"  The use of LIKE in this extract proves that the simile dominates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>23", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question    Bent-double like old beggars under sacks,   Knock-Kneed, coughing like hags, we curse through  sludge   Till on the haunting flares we turned our backs  And towards our distant rest began to trudge,  Men marched asleep, many had lost their boots,  But limped on, blood-shed. All went lame, all blind;   Drunk with fatigue ; even deaf to the hoots  Of gas-shells dropping softly behind  The expression  drunk with fatigue illustrates", "images": [], "options": {"A": "metaphor", "B": "synecdoche", "C": "litotes", "D": "irony"}, "answer": "A", "explanation": "Being drunk is compared to tiredness. The statement is highly metaphorical: that is, it has a deeper meaning.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>24", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question    Bent-double like old beggars under sacks,   Knock-Kneed, coughing like hags, we curse through  sludge   Till on the haunting flares we turned our backs  And towards our distant rest began to trudge,  Men marched asleep, many had lost their boots,  But limped on, blood-shed. All went lame, all blind;   Drunk with fatigue ; even deaf to the hoots  Of gas-shells dropping softly behind  The rhyme scheme of the first stanza is", "images": [], "options": {"A": "aabb", "B": "abab", "C": "abcd", "D": "abba"}, "answer": "B", "explanation": "sacks - a  sludge - b  backs - a   trudge - b  This rhyme scheme is called ALTERNATE RHYMES.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>25", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question    Bent-double like old beggars under sacks,   Knock-Kneed, coughing like hags, we curse through  sludge   Till on the haunting flares we turned our backs  And towards our distant rest began to trudge,  Men marched asleep, many had lost their boots,  But limped on, blood-shed. All went lame, all blind;   Drunk with fatigue ; even deaf to the hoots  Of gas-shells dropping softly behind  Sludge in the extract means", "images": [], "options": {"A": "water", "B": "fire", "C": "snow", "D": "mud"}, "answer": "D", "explanation": "It means thick, soft, wet mud or a similar viscous mixture of liquid and solid components, especially the product of an industrial or refining process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2007>26", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this.    ........ What were the use of my creation if I was entirely contained here? My great miseries in world have been Heathcliff's miseries, and I watched and felt each from the beginning. My great thought in living is himself.  If all else perished, and he remained , I should still continue to be. And if all else remained and he was  annihiliated   , The universe will be turned to a mighty stranger ------ I should not seem a part of it. My love for Linton is like the foilage in the woods; time will change it. I'm well aware, as winter changes the trees.  My love for Heathcliff resembles the eternal rocks beneath  ---- as source of little visible little delight, but necessary. Nelly, i am Heathcliff!. He's always , always in my mind ---- not as a pleasure to myself, but as my own being.    The speakers's love for Heathcliff is", "images": [], "options": {"A": "platonic", "B": "indestructive", "C": "ephemeral", "D": "universal"}, "answer": "B", "explanation": "The speaker described her love for Heathcliff as one that will stand the test of time; it can never fade.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>27", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this.    ........ What were the use of my creation if I was entirely contained here? My great miseries in world have been Heathcliff's miseries, and I watched and felt each from the beginning. My great thought in living is himself.  If all else perished, and he remained , I should still continue to be. And if all else remained and he was  annihiliated   , The universe will be turned to a mighty stranger ------ I should not seem a part of it. My love for Linton is like the foilage in the woods; time will change it. I'm well aware, as winter changes the trees.  My love for Heathcliff resembles the eternal rocks beneath  ---- as source of little visible little delight, but necessary. Nelly, i am Heathcliff!. He's always , always in my mind ---- not as a pleasure to myself, but as my own being.   My love for Heathcliff resembles the eternal rocks from beneath  illustrates", "images": [], "options": {"A": "metaphor", "B": "allusion", "C": "euphemism", "D": "simile"}, "answer": "B", "explanation": "A reference is made to eternal rocks. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>28", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this.    ........ What were the use of my creation if I was entirely contained here? My great miseries in world have been Heathcliff's miseries, and I watched and felt each from the beginning. My great thought in living is himself.  If all else perished, and he remained , I should still continue to be. And if all else remained and he was  annihiliated   , The universe will be turned to a mighty stranger ------ I should not seem a part of it. My love for Linton is like the foilage in the woods; time will change it. I'm well aware, as winter changes the trees.  My love for Heathcliff resembles the eternal rocks beneath  ---- as source of little visible little delight, but necessary. Nelly, i am Heathcliff!. He's always , always in my mind ---- not as a pleasure to myself, but as my own being.  Annihilated in the extract implies", "images": [], "options": {"A": "rebirth", "B": "death", "C": "marriage", "D": "problems"}, "answer": "B", "explanation": "When a human is annihilated -  i.e reduced to nothing, destroyed or eradicated - such person is dead.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>29", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this.    ........ What were the use of my creation if I was entirely contained here? My great miseries in world have been Heathcliff's miseries, and I watched and felt each from the beginning. My great thought in living is himself.  If all else perished, and he remained , I should still continue to be. And if all else remained and he was  annihiliated   , The universe will be turned to a mighty stranger ------ I should not seem a part of it. My love for Linton is like the foilage in the woods; time will change it. I'm well aware, as winter changes the trees.  My love for Heathcliff resembles the eternal rocks beneath  ---- as source of little visible little delight, but necessary. Nelly, i am Heathcliff!. He's always , always in my mind ---- not as a pleasure to myself, but as my own being.   If all else perished and he remained  illustrates", "images": [], "options": {"A": "paradox", "B": "irony", "C": "bathos", "D": "antithesis"}, "answer": "D", "explanation": "Antithesis is a figure of speech in which a striking opposition is made in the same sentence. It occurs when we have two contrasting statements,  \"Perished and remained\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>30", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this.    ........ What were the use of my creation if I was entirely contained here? My great miseries in world have been Heathcliff's miseries, and I watched and felt each from the beginning. My great thought in living is himself.  If all else perished, and he remained , I should still continue to be. And if all else remained and he was  annihiliated   , The universe will be turned to a mighty stranger ------ I should not seem a part of it. My love for Linton is like the foilage in the woods; time will change it. I'm well aware, as winter changes the trees.  My love for Heathcliff resembles the eternal rocks beneath  ---- as source of little visible little delight, but necessary. Nelly, i am Heathcliff!. He's always , always in my mind ---- not as a pleasure to myself, but as my own being.  The diction of the extract conveys the speaker's", "images": [], "options": {"A": "contempt", "B": "despair", "C": "assurance", "D": "determination"}, "answer": "D", "explanation": "The diction of the extract conveys the speaker's 'determination'. The speaker is determined to continue to exist if 'he' remains, even if everything else perishes. The speaker also expresses a strong and unwavering love for Heathcliff, likening it to the eternal rocks beneath, which further conveys a sense of determination.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>31", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    A:   What, has  this thing  appeared again tonight?  B:   I have seen nothing   ( Act 1, scene one, lines 21-22)    Speaker A is", "images": [], "options": {"A": "Bernado", "B": "Horatio", "C": "Francisco", "D": "Marcellus"}, "answer": "D", "explanation": "In Act 1, Scene 1 of Hamlet, Marcellus is the character who asks if the ghost has appeared again. Therefore, the correct answer is Marcellus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>32", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    A:   What, has  this thing  appeared again tonight?  B:   I have seen nothing   ( Act 1, scene one, lines 21-22)  Speaker B is", "images": [], "options": {"A": "Hamlet", "B": "Francisco", "C": "Marcellus", "D": "Bernado"}, "answer": "D", "explanation": "In the same scene, Bernado is the character who responds that he has seen nothing. Therefore, the correct answer is Bernado.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>33", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    A:   What, has  this thing  appeared again tonight?  B:   I have seen nothing   ( Act 1, scene one, lines 21-22)   this thing  refer to a", "images": [], "options": {"A": "ghost", "B": "horse", "C": "guard", "D": "soldier"}, "answer": "A", "explanation": "In the context of the play 'Hamlet' by William Shakespeare, 'this thing' referred to in the extract is the ghost of Hamlet's father. The ghost is a significant character in the play, appearing several times and setting the plot in motion by revealing the truth about his death to Hamlet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>34", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    A:   What, has  this thing  appeared again tonight?  B:   I have seen nothing   ( Act 1, scene one, lines 21-22)  The speakers were", "images": [], "options": {"A": "in a room in the castle", "B": "in the courtyard", "C": "on a platform in front of the castle", "D": "on the battle field"}, "answer": "C", "explanation": "In the play 'Hamlet', the conversation in the extract takes place on a platform in front of the castle. This is where the ghost of Hamlet's father appears and is seen by the guards and later by Hamlet himself. The platform is a significant location in the play as it is where the ghost first appears and reveals the truth about his death.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>35", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    A:   What, has  this thing  appeared again tonight?  B:   I have seen nothing   ( Act 1, scene one, lines 21-22)  Speakers  A and B   are", "images": [], "options": {"A": "officers", "B": "soldiers", "C": "servants", "D": "courtiers"}, "answer": "B", "explanation": "In the play 'Hamlet' by William Shakespeare, the speakers in the given extract are soldiers. The extract is from Act 1, Scene 1 where the soldiers Bernardo and Francisco are on guard duty at the castle of Elsinore. Bernardo asks Francisco if the ghost has appeared again, to which Francisco replies that he has seen nothing. Therefore, the correct answer is 'soldiers'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2007>36", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    As thou art to thyself  Such was the very armour he had on  When he the Ambitious Norway Combated;  So frown'd he once, when, in angry parle.  He smote the sledded Pollack's  on the ice....  (Act 1, scene one, lines 59-63)    The speaker is", "images": [], "options": {"A": "Horatio", "B": "Marcellus", "C": "Bernado", "D": "Francisco"}, "answer": "A", "explanation": "In the play 'Hamlet' by William Shakespeare, the speaker in the given extract is Horatio. The extract is from Act 1, Scene 1 where Horatio is describing the ghost of King Hamlet, who appeared in the same armor he wore when he fought against the ambitious Norway. Therefore, the correct answer is 'Horatio'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>37", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    As thou art to thyself  Such was the very armour he had on  When he the Ambitious Norway Combated;  So frown'd he once, when, in angry parle.  He smote the sledded Pollack's  on the ice....  (Act 1, scene one, lines 59-63)  The speaker is addressing", "images": [], "options": {"A": "Marcellus", "B": "Francisco", "C": "the ghost", "D": "Horatio"}, "answer": "A", "explanation": "Marcellus is a guard who also sees the ghost appear during their watch.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>38", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    As thou art to thyself  Such was the very armour he had on  When he the Ambitious Norway Combated;  So frown'd he once, when, in angry parle.  He smote the sledded Pollack's  on the ice....  (Act 1, scene one, lines 59-63)  The passage conveys an atmosphere of", "images": [], "options": {"A": "peace", "B": "celebration", "C": "war", "D": "anxiety"}, "answer": "D", "explanation": "The is the general feeling of anxiety because the soldiers are afraid of the ghost.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>39", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    As thou art to thyself  Such was the very armour he had on  When he the Ambitious Norway Combated;  So frown'd he once, when, in angry parle.  He smote the sledded Pollack's  on the ice....  (Act 1, scene one, lines 59-63)  The subject of discussion is", "images": [], "options": {"A": "Hamlet", "B": "the ghost", "C": "Claudius", "D": "laertes"}, "answer": "B", "explanation": "In the given extract from Hamlet, the subject of discussion is 'the ghost'. The lines are spoken by Horatio as he describes the ghost of Hamlet's father, the former King of Denmark, to Hamlet. He describes the ghost as wearing the armor he wore when he fought against 'Ambitious Norway', which refers to the King of Norway. The ghost is said to have a frowning expression, similar to the one he had when he struck down the 'sledded Polacks' on the ice, referring to a past battle. Therefore, the subject of discussion is the ghost, not Hamlet, Claudius, or Laertes.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>40", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    X:   What is the matter  Y:   Save yourself; my Lord               the ocean, overpearing of his list,                Eats not the flats with more  impetuous  haste               Than young laertes  (Act 4, scene five, lines 97-101)    Speaker x is", "images": [], "options": {"A": "a messenger", "B": "the king", "C": "the queen", "D": "laertes"}, "answer": "B", "explanation": "Speaker X is the king. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>41", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    X:   What is the matter  Y:   Save yourself; my Lord               the ocean, overpearing of his list,                Eats not the flats with more  impetuous  haste               Than young laertes  (Act 4, scene five, lines 97-101)  Speaker Y is", "images": [], "options": {"A": "the queen", "B": "Polonius", "C": "an attendant", "D": "ophelia"}, "answer": "C", "explanation": "Speaker Y is an attendant.  This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>42", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    X:   What is the matter  Y:   Save yourself; my Lord               the ocean, overpearing of his list,                Eats not the flats with more  impetuous  haste               Than young laertes  (Act 4, scene five, lines 97-101)  The character who came on the scene shortly afterwards are", "images": [], "options": {"A": "Laertes and the Danes", "B": "the Queen and Hamlet", "C": "Ophelia and the Danes", "D": "Hamlet and Laertes"}, "answer": "A", "explanation": "King Claudius: The doors are broke - line 3   noise within   Enter LAERTES, armed; Danes following", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>43", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    X:   What is the matter  Y:   Save yourself; my Lord               the ocean, overpearing of his list,                Eats not the flats with more  impetuous  haste               Than young laertes  (Act 4, scene five, lines 97-101)  The other character present in the scene is", "images": [], "options": {"A": "the Queen", "B": "Hamlet", "C": "Horatio", "D": "Marcellus"}, "answer": "A", "explanation": "Queen Gertrude: How cheerfully..  line 109   O, this is counter  Queen Gertrude: Calmly, good laertes - line 118", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>44", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    X:   What is the matter  Y:   Save yourself; my Lord               the ocean, overpearing of his list,                Eats not the flats with more  impetuous  haste               Than young laertes  (Act 4, scene five, lines 97-101)  The king had just requested that all the", "images": [], "options": {"A": "doors be broken", "B": "doors be guarded", "C": "windows be locked", "D": "windows be opened"}, "answer": "B", "explanation": "In the given extract from Hamlet, Act 4, Scene 5, the King (Claudius) is not present and therefore does not make any requests. However, in the broader context of the scene, the King does order for Ophelia to be closely watched due to her unstable state of mind, which can be interpreted as having the 'doors be guarded'. Therefore, the most fitting answer is that the King had just requested that all the doors be guarded.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>45", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    Angels and ministers of grace defend us  Be thou a spirit of health, goblin damn'd  Bring with thee airs from heaven, or blast from hell  By thy intents wicked or charitable,  Thou comest in such a questionable shape..  (Act 1, scene four, lines 39-43)    The speaker is", "images": [], "options": {"A": "Hamlet", "B": "Marcellus", "C": "Horatio", "D": "Laertes"}, "answer": "A", "explanation": "In this extract from Hamlet, the speaker is Hamlet himself. He is speaking to the ghost of his father, questioning its origins and intentions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>46", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    Angels and ministers of grace defend us  Be thou a spirit of health, goblin damn'd  Bring with thee airs from heaven, or blast from hell  By thy intents wicked or charitable,  Thou comest in such a questionable shape..  (Act 1, scene four, lines 39-43)  The character being addressed is", "images": [], "options": {"A": "the king", "B": "the ghost", "C": "Angels", "D": "God"}, "answer": "B", "explanation": "In this extract from Hamlet, the character being addressed is the ghost of Hamlet's father. Hamlet is questioning whether the ghost comes from heaven or hell, and whether its intentions are wicked or charitable.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>47", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    Angels and ministers of grace defend us  Be thou a spirit of health, goblin damn'd  Bring with thee airs from heaven, or blast from hell  By thy intents wicked or charitable,  Thou comest in such a questionable shape..  (Act 1, scene four, lines 39-43)  The character who just spoke before the speaker is", "images": [], "options": {"A": "Horatio", "B": "Laertes", "C": "Hamlet", "D": "Marcellus"}, "answer": "A", "explanation": "In Act 1, Scene 4 of Hamlet, Horatio is the one who warns Hamlet about the ghost before Hamlet starts speaking to it. Therefore, the character who just spoke before the speaker in the given extract is Horatio.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>48", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    Angels and ministers of grace defend us  Be thou a spirit of health, goblin damn'd  Bring with thee airs from heaven, or blast from hell  By thy intents wicked or charitable,  Thou comest in such a questionable shape..  (Act 1, scene four, lines 39-43)  The setting of the extract is", "images": [], "options": {"A": "a room in the castle", "B": "the platform", "C": "the queen's closet", "D": "a graveyard"}, "answer": "B", "explanation": "The platform is the place were the ghost usually appears, so Hamlet has been summoned by Horatio to see for himself.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>49", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    Angels and ministers of grace defend us  Be thou a spirit of health, goblin damn'd  Bring with thee airs from heaven, or blast from hell  By thy intents wicked or charitable,  Thou comest in such a questionable shape..  (Act 1, scene four, lines 39-43)  The passage creates an atmosphere of", "images": [], "options": {"A": "surprise and determination", "B": "insecurity and resignation", "C": "security and assurance", "D": "courage and assurance"}, "answer": "A", "explanation": "Hamlet is supposed to see a ghost but also decided to speak to it.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2007>50", "subject": "Literature", "year": "2007", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    Angels and ministers of grace defend us  Be thou a spirit of health, goblin damn'd  Bring with thee airs from heaven, or blast from hell  By thy intents wicked or charitable,  Thou comest in such a questionable shape..  (Act 1, scene four, lines 39-43)  Line1 suggests the speakers belief in", "images": [], "options": {"A": "ghosts", "B": "spirits", "C": "purgatory", "D": "magic"}, "answer": "C", "explanation": "'Angels and Ministers of grace' are spirits not usually visible to the physical eyes", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>1", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary work in which actions and character represent ideas is", "images": [], "options": {"A": "an allusion", "B": "an epigram", "C": "an allegory", "D": "an innuendo"}, "answer": "C", "explanation": "Allegory is a literary work in which abstract, symbol or animal are used to create ideas or represent humans. In an allegory, each character represents an idea, philosophy or a segment of the society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>2", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" Peter's pretty partner paid the bill\" is an example of", "images": [], "options": {"A": "alliteration", "B": "rhyme", "C": "satire", "D": "digression"}, "answer": "A", "explanation": "The alliteration is the repetition of a particular consonant sound at word-initial position.  Here, /p/ alliterates.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2008>3", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A stanza of four lines in poetry is", "images": [], "options": {"A": "a quatrain", "B": "a sestet", "C": "an octave", "D": "an elegy"}, "answer": "A", "explanation": "An OCTAVE refers to four lines of a poem.   A sestet is a stanza of six lines while an octave consists of eight lines. An elegy is a form of poetry that mourns the death of a person.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2008>4", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" O happy torment\" is an example of", "images": [], "options": {"A": "oxymoron", "B": "synecdoche", "C": "innuendo", "D": "simile"}, "answer": "A", "explanation": "\"O happy torment\" is an example of an oxymoron. An oxymoron is a figure of speech in which two opposite ideas are joined to create an effect. The common oxymoron phrase is a combination of an adjective proceeded by a noun with contrasting meanings, such as 'happy torment'. 'Synecdoche' is a figure of speech in which a part is made to represent the whole or vice versa, 'innuendo' is an allusive or oblique remark or hint, typically a suggestive or disparaging one, and 'simile' is a figure of speech involving the comparison of one thing with another thing of a different kind, so these options are incorrect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>5", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A recurring dominant idea in a work of art is called", "images": [], "options": {"A": "setting", "B": "conflict", "C": "plot", "D": "motif"}, "answer": "D", "explanation": "Plot is the sequential arrangement of events in a literary work while a setting is the time and place of a work of art.  Conflict refers to the struggle between two opposing forces.  Setting refers to the place and time of the action.  Motif is a theme that occurs frequently in a work of literature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>6", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A question which does not require answer is", "images": [], "options": {"A": "discourse", "B": "rhetorical", "C": "ironic", "D": "flashback"}, "answer": "B", "explanation": "A question which does not require an answer is called a rhetorical question. A rhetorical question is a figure of speech in the form of a question that is asked to make a point rather than to elicit an answer. Though a rhetorical question does not require a direct answer, in many cases it may be intended to start a discussion or at least draw an acknowledgement that the listener understands the intended message.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>7", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary work written in form of a letter is", "images": [], "options": {"A": "creative", "B": "romantic", "C": "tautological", "D": "epistolary"}, "answer": "D", "explanation": "The word, EPISTOLARY, refers to letters; therefore, a work of literature that is written in the form of a letter can be said to have an epistolary format.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>8", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" The lawyer addressed the bench\"   illustrates", "images": [], "options": {"A": "metonymy", "B": "alliteration", "C": "simile", "D": "oxymoron"}, "answer": "A", "explanation": "This is a literary device which uses a thing closely related to represent an object or person. Bench ( a place where judges sit) is used to represent judges or the jury.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>9", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The concluding part of a play where the conflict is resolved is", "images": [], "options": {"A": "anagnorisis", "B": "enjambment", "C": "denouement", "D": "climax"}, "answer": "C", "explanation": "The conflict is usually resolved in the last part of the plot which is thje denouement (resolution).", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>10", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A character whose flaws combined with external forces lead to his suffering is a", "images": [], "options": {"A": "heroine", "B": "tragic-hero", "C": "hero", "D": "protagonist"}, "answer": "B", "explanation": "A tragic hero is a character whose flaws combined with external forces lead to his suffering. This character is typically a protagonist who is noble and has a significant flaw that leads to his downfall and death, often due to his own actions. A heroine is a female hero. A hero is a person who is admired for their courage, outstanding achievements, or noble qualities. A protagonist is the leading character or one of the major characters in a drama, movie, novel, or other fictional text.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>11", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd item out of the under listed", "images": [], "options": {"A": "ode", "B": "elegy", "C": "sonnet", "D": "simile"}, "answer": "D", "explanation": "The question asks to pick the odd item out of the list. The items listed are 'ode', 'elegy', 'sonnet', and 'simile'. The first three items - 'ode', 'elegy', and 'sonnet' - are all types of poems. However, 'simile' is a figure of speech used in literature to compare two things. Therefore, 'simile' is the odd item out.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2008>12", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Pregnant clouds\" is an example of", "images": [], "options": {"A": "cliche", "B": "litotes", "C": "metaphor", "D": "setting"}, "answer": "C", "explanation": "A metaphor either expresses a direct comparison or a statement with a deeper meaning. The phrase, PREGNANT CLOUD, is metaphorical. It can be rewritten as: \"The sky is pregnant.\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>13", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A writer's choice of words in his", "images": [], "options": {"A": "diction", "B": "mood", "C": "tone", "D": "setting"}, "answer": "A", "explanation": "The choice of word employed by a writer refers to diction.  Mood is the general atmosphere that pervades the piece of writing.  Tone refers to a writer's attitude towards the subject matter.  Setting is the place and time of the actiom in a literary eork.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2008>14", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The art of creating fictional personages constitutes", "images": [], "options": {"A": "point of view", "B": "characterization", "C": "narrative technique", "D": "symbolism"}, "answer": "B", "explanation": "Characterization means presentation,description and representation and characters in a literary work. It also refers to the way the characters are presented in relation to the roles they play.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>15", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A deliberate use of exaggeration for the purpose of humour/emphasis is", "images": [], "options": {"A": "metaphor", "B": "irony", "C": "simile", "D": "hyperbole"}, "answer": "D", "explanation": "I ate a  bucket full of eba. This shows I ate a lot.  She waited a thousand years. She waited a long time  (emphasis)  The hyperbole, therefore, refers to an excessive exaggeration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>16", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Drama is meant to", "images": [], "options": {"A": "teach manners only", "B": "criticize", "C": "educate and entertain", "D": "be read and acted only"}, "answer": "C", "explanation": "Drama teaches morals (didactic), enlightens, and is also fun to read. Horace in his Ars Poetica affirmed that the aim of literature (poetry/drama) is to teach and delight (utile et dulce)", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>17", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A piece of witing which teaches morals is", "images": [], "options": {"A": "serious", "B": "didactic", "C": "playful", "D": "analytical"}, "answer": "B", "explanation": "A piece of writing which teaches morals is referred to as 'didactic'. The term 'didactic' is used to describe literature or other types of art that are instructional or informative. The term comes from the Greek word 'didaktikos', meaning 'apt at teaching'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2008>18", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A poem of fourteen lines is", "images": [], "options": {"A": "an elegy", "B": "a dirge", "C": "a sonnet", "D": "an ode"}, "answer": "C", "explanation": "A sonnet usually consists of fourteen lines, divided into an octave and a sestet in the case of an Italian sonnet. The Shakespearean sonnet is divided into four: three quatrains and a couplet. A sonnet is a poem of fourteen lines with a regular rhyme scheme and metre pattern.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>19", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Shakespeare's poetry consisted mainly of", "images": [], "options": {"A": "quatrains", "B": "heroic verse", "C": "blank verse", "D": "couplet"}, "answer": "A", "explanation": "Most poems of shakespare contains quatrains. Shakespearean sonnets contains three quatrains and a heroic couplet.  Shakespeare introduces his argument in the first quatrain, builds up the argument in the second and third quatrains, and concludes the argument in the couplet.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>20", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A piece of writing or speech at the beginning of a work of art is the", "images": [], "options": {"A": "prologue", "B": "dialogue", "C": "monologue", "D": "epilogue"}, "answer": "A", "explanation": "A piece of writing or speech at the beginning of a work of art is the prologue. A prologue is an opening to a story that establishes the context and gives background details, often some earlier story that ties into the main one, and other miscellaneous information. The Ancient Greek prólogos included the modern meaning of prologue, but was of wider significance, more like the meaning of preface.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2008>21", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN POETRY AND PROSE   Read the poem and answer this question    At the onset of the rain  The drought stricken land  suck up the wetness  And the gates of the field  Are flung widely open.  It is the signal for planting  It is time for joyous planting!  It is time for joyous toiling!  At various time of day  The hard and erect hoe  Would thrust and dig deep  Into the receiving wet soil  Seeds in different quantities  Seeds of varying potency  Are broadcasted in layers  Into the womb of the earth  With time and much labour  The seed now transformed  blossoms and grows into new life!    The subject matter of the extract is", "images": [], "options": {"A": "harvesting", "B": "rain", "C": "time", "D": "farming"}, "answer": "D", "explanation": "The subject matter revolves around farming. The rain has helped to make the soil wet and soft, and suitable for planting.See the extract below:    \"...land suck up wetness  It is signal for planting   ...hoe would thrust and dig deep  seeds ... broadcasted in layers  ...grows into new life\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>22", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN POETRY AND PROSE   Read the poem and answer this question    At the onset of the rain  The drought stricken land  suck up the wetness  And the gates of the field  Are flung widely open.  It is the signal for planting  It is time for joyous planting!  It is time for joyous toiling!  At various time of day  The hard and erect hoe  Would thrust and dig deep  Into the receiving wet soil  Seeds in different quantities  Seeds of varying potency  Are broadcasted in layers  Into the womb of the earth  With time and much labour  The seed now transformed  blossoms and grows into new life!  The dominant device used in the extract is", "images": [], "options": {"A": "metaphor", "B": "paradox", "C": "symbolism", "D": "simile"}, "answer": "A", "explanation": "The metaphor dominates. E.g, \"drought stricken land\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>23", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "UNSEEN POETRY AND PROSE   Read the poem and answer this question    At the onset of the rain  The drought stricken land  suck up the wetness  And the gates of the field  Are flung widely open.  It is the signal for planting  It is time for joyous planting!  It is time for joyous toiling!  At various time of day  The hard and erect hoe  Would thrust and dig deep  Into the receiving wet soil  Seeds in different quantities  Seeds of varying potency  Are broadcasted in layers  Into the womb of the earth  With time and much labour  The seed now transformed  blossoms and grows into new life!  \" The hard and erect hoe\" connotes", "images": [], "options": {"A": "uprooting of weeds", "B": "the sowing of seed", "C": "digging of the soil", "D": "farming implement"}, "answer": "D", "explanation": "In farming, the hoe is used to make ridges in preparation for planting seeds. It is a tool used for farming.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>24", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "UNSEEN POETRY AND PROSE   Read the poem and answer this question    At the onset of the rain  The drought stricken land  suck up the wetness  And the gates of the field  Are flung widely open.  It is the signal for planting  It is time for joyous planting!  It is time for joyous toiling!  At various time of day  The hard and erect hoe  Would thrust and dig deep  Into the receiving wet soil  Seeds in different quantities  Seeds of varying potency  Are broadcasted in layers  Into the womb of the earth  With time and much labour  The seed now transformed  blossoms and grows into new life!  \"Joyous toiling\" is an example of", "images": [], "options": {"A": "onomatopoeia", "B": "oxymoron", "C": "irony", "D": "metaphor"}, "answer": "B", "explanation": "\"Joyous toiling\" is an example of an oxymoron. An oxymoron is a figure of speech in which two opposite ideas are joined to create an effect. The common oxymoron phrase is a combination of an adjective proceeded by a noun with contrasting meanings, e.g. \"sweet sorrow\" or \"cold fire\". In this case, 'joyous' and 'toiling' are contrasting because 'toiling' usually refers to hard and strenuous work, which is not typically associated with joy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>25", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "UNSEEN POETRY AND PROSE   Read the poem and answer this question    At the onset of the rain  The drought stricken land  suck up the wetness  And the gates of the field  Are flung widely open.  It is the signal for planting  It is time for joyous planting!  It is time for joyous toiling!  At various time of day  The hard and erect hoe  Would thrust and dig deep  Into the receiving wet soil  Seeds in different quantities  Seeds of varying potency  Are broadcasted in layers  Into the womb of the earth  With time and much labour  The seed now transformed  blossoms and grows into new life!  The last line of the extract suggests the", "images": [], "options": {"A": "growth of a seed", "B": "birth of a child", "C": "harvesting of fruits", "D": "nourishing of flowers"}, "answer": "A", "explanation": "The last line of the extract 'blossoms and grows into new life!' suggests the growth of a seed. The poem describes the process of planting seeds in the ground, waiting for them to grow, and finally seeing them blossom into new life. This is a metaphor for the growth of a seed from being planted in the ground to growing into a plant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>26", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN POETRY AND PROSE   Read the poem and answer this question.     Ralph wormed his way  through the thicket towards the forest, keeping as far as possible beneath the smoke. Presently, he saw an open space and the green leaves of the edge of the thicket. A smallish savage was standing between him and the rest of the forest, a savage striped red and white, and carrying a spear. He was coughing, and smearing the paint about his eyes with the back of his hand as he tries to see through the increasing smoke..              Ralph launched himself like a car ; stabbed, snarling, with the spear, and the savage doubled up. There was a shout from beyond the thicket and then Ralph was running with the swiftness of fear through the undergrowth. He came to a pig-run, followed it for perhaps a hundred yards and then swerved off. Behind him the ululation swept across the island once more and a single voice shouted three times. He guessed that was the signal to advance and sped away again till his chest was like fire.            Then he flung himself down under a bush and waited for a moment till his breathing steadied. He passed his tongue tentatively over his teeth and lips and heard far off the ululation of the pursuers    The passage is", "images": [], "options": {"A": "narrative", "B": "expository", "C": "descriptive", "D": "argumentation"}, "answer": "A", "explanation": "The passage is narrative. A narrative passage is a story or account of events or experiences. It can be either factual, as in a news report or fictional, as in a novel. In this passage, the author is telling a story about Ralph's experience in the forest, his encounter with a savage, and his subsequent escape. The passage includes elements of a narrative such as characters (Ralph and the savage), setting (the forest), and a sequence of events (Ralph's encounter with the savage, his escape, and his hiding).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>27", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "UNSEEN POETRY AND PROSE   Read the poem and answer this question.     Ralph wormed his way  through the thicket towards the forest, keeping as far as possible beneath the smoke. Presently, he saw an open space and the green leaves of the edge of the thicket. A smallish savage was standing between him and the rest of the forest, a savage striped red and white, and carrying a spear. He was coughing, and smearing the paint about his eyes with the back of his hand as he tries to see through the increasing smoke..              Ralph launched himself like a car ; stabbed, snarling, with the spear, and the savage doubled up. There was a shout from beyond the thicket and then Ralph was running with the swiftness of fear through the undergrowth. He came to a pig-run, followed it for perhaps a hundred yards and then swerved off. Behind him the ululation swept across the island once more and a single voice shouted three times. He guessed that was the signal to advance and sped away again till his chest was like fire.            Then he flung himself down under a bush and waited for a moment till his breathing steadied. He passed his tongue tentatively over his teeth and lips and heard far off the ululation of the pursuers  \" Ralph wormed his way\" is an example of", "images": [], "options": {"A": "irony", "B": "apostrophe", "C": "metaphor", "D": "allusion"}, "answer": "C", "explanation": "The phrase 'Ralph wormed his way' is an example of a metaphor. A metaphor is a figure of speech that makes a comparison between two things that are basically dissimilar. In this case, Ralph is being compared to a worm, suggesting that he is moving slowly and cautiously.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>28", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN POETRY AND PROSE   Read the poem and answer this question.     Ralph wormed his way  through the thicket towards the forest, keeping as far as possible beneath the smoke. Presently, he saw an open space and the green leaves of the edge of the thicket. A smallish savage was standing between him and the rest of the forest, a savage striped red and white, and carrying a spear. He was coughing, and smearing the paint about his eyes with the back of his hand as he tries to see through the increasing smoke..              Ralph launched himself like a car ; stabbed, snarling, with the spear, and the savage doubled up. There was a shout from beyond the thicket and then Ralph was running with the swiftness of fear through the undergrowth. He came to a pig-run, followed it for perhaps a hundred yards and then swerved off. Behind him the ululation swept across the island once more and a single voice shouted three times. He guessed that was the signal to advance and sped away again till his chest was like fire.            Then he flung himself down under a bush and waited for a moment till his breathing steadied. He passed his tongue tentatively over his teeth and lips and heard far off the ululation of the pursuers  The mood of the passage is", "images": [], "options": {"A": "anger", "B": "sarcasm", "C": "indifference", "D": "fright"}, "answer": "D", "explanation": "Fear is shown in lots of words like ' running with the swiftness of fear', ' his chest was like fire' till his breathing steadied' and ' of the pursuers'.  The atmosphere is shrouded in fear because Ralph is running for dear life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>29", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN POETRY AND PROSE   Read the poem and answer this question.     Ralph wormed his way  through the thicket towards the forest, keeping as far as possible beneath the smoke. Presently, he saw an open space and the green leaves of the edge of the thicket. A smallish savage was standing between him and the rest of the forest, a savage striped red and white, and carrying a spear. He was coughing, and smearing the paint about his eyes with the back of his hand as he tries to see through the increasing smoke..              Ralph launched himself like a car ; stabbed, snarling, with the spear, and the savage doubled up. There was a shout from beyond the thicket and then Ralph was running with the swiftness of fear through the undergrowth. He came to a pig-run, followed it for perhaps a hundred yards and then swerved off. Behind him the ululation swept across the island once more and a single voice shouted three times. He guessed that was the signal to advance and sped away again till his chest was like fire.            Then he flung himself down under a bush and waited for a moment till his breathing steadied. He passed his tongue tentatively over his teeth and lips and heard far off the ululation of the pursuers  The literary device use in \" Ralph launched himself like a cat\" is", "images": [], "options": {"A": "assonance", "B": "simile", "C": "contrast", "D": "personification"}, "answer": "B", "explanation": "The literary device used in \"Ralph launched himself like a cat\" is a simile. A simile is a figure of speech that makes a comparison, showing similarities between two different things. In this case, Ralph's action is being compared to the way a cat might launch itself, using the word 'like' to make the comparison.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>30", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN POETRY AND PROSE   Read the poem and answer this question.     Ralph wormed his way  through the thicket towards the forest, keeping as far as possible beneath the smoke. Presently, he saw an open space and the green leaves of the edge of the thicket. A smallish savage was standing between him and the rest of the forest, a savage striped red and white, and carrying a spear. He was coughing, and smearing the paint about his eyes with the back of his hand as he tries to see through the increasing smoke..              Ralph launched himself like a car ; stabbed, snarling, with the spear, and the savage doubled up. There was a shout from beyond the thicket and then Ralph was running with the swiftness of fear through the undergrowth. He came to a pig-run, followed it for perhaps a hundred yards and then swerved off. Behind him the ululation swept across the island once more and a single voice shouted three times. He guessed that was the signal to advance and sped away again till his chest was like fire.            Then he flung himself down under a bush and waited for a moment till his breathing steadied. He passed his tongue tentatively over his teeth and lips and heard far off the ululation of the pursuers  The writer's diction portrays", "images": [], "options": {"A": "repetition", "B": "irony", "C": "tension", "D": "humour"}, "answer": "C", "explanation": "The choice of words of the writer portrays tension; that is, Ralph is trying hard to escape those who want to kill him.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2008>31", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet   Read the extract and answer this question.    It is here......., thou art slain;  No medicine in the world can do thee good;  In thee there is not half an hour of life;  The treacherous instrument in thy hand,  Unbated and evenom'd; the foul practice  Hath turn'd itself on me; lo, here I lie        (Act 1, scene two, lines 298-303)    The speaker is", "images": [], "options": {"A": "Fortinbras", "B": "Guildenstern", "C": "Laertes", "D": "Hamlet"}, "answer": "C", "explanation": "Here, Laertes and Hamlet just fought a duel which results in their death. Laertes is the speaker. He has been fatally injured by Hamlet.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>32", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet   Read the extract and answer this question.    It is here......., thou art slain;  No medicine in the world can do thee good;  In thee there is not half an hour of life;  The treacherous instrument in thy hand,  Unbated and evenom'd; the foul practice  Hath turn'd itself on me; lo, here I lie        (Act 1, scene two, lines 298-303)   The queen has just", "images": [], "options": {"A": "left the scene", "B": "died", "C": "run away", "D": "arrived"}, "answer": "B", "explanation": "Queen Gertrude:  No,no, the drink, ... o my dear  - line 293  Hamlet , .. - line 294  The drink, the drink! I am poisoned - line 295     Dies     The queen mistakenly drank from a poisoned ciup of wine that was reserved for Hamlet.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>33", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet   Read the extract and answer this question.    It is here......., thou art slain;  No medicine in the world can do thee good;  In thee there is not half an hour of life;  The treacherous instrument in thy hand,  Unbated and evenom'd; the foul practice  Hath turn'd itself on me; lo, here I lie        (Act 1, scene two, lines 298-303)   The character being addressed is", "images": [], "options": {"A": "Hamlet", "B": "the queen", "C": "the king", "D": "Fortinbras"}, "answer": "A", "explanation": "It is here, Hamlet, thou art slain; - line 278  Hamlet is being addressed by Laertes. Laertes confesses to Hamlet his part in a ploy hatched by the king to get Hamlet killed.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>34", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet   Read the extract and answer this question.    It is here......., thou art slain;  No medicine in the world can do thee good;  In thee there is not half an hour of life;  The treacherous instrument in thy hand,  Unbated and evenom'd; the foul practice  Hath turn'd itself on me; lo, here I lie        (Act 1, scene two, lines 298-303)   The addressee later", "images": [], "options": {"A": "kills himself", "B": "sleeps off", "C": "runs away", "D": "stabs the king"}, "answer": "D", "explanation": "HAMLET  The point! ... envenom'd too!  Then, venom, to thy work   Stabs KING CLAUDIUS     When Hamlet realises that he will soon die, he kills the king.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>35", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet   Read the extract and answer this question.    It is here......., thou art slain;  No medicine in the world can do thee good;  In thee there is not half an hour of life;  The treacherous instrument in thy hand,  Unbated and evenom'd; the foul practice  Hath turn'd itself on me; lo, here I lie        (Act 1, scene two, lines 298-303)   The setting is", "images": [], "options": {"A": "a hall in the castle", "B": "the battlefield", "C": "a platform in front of the castle", "D": "the queen's room"}, "answer": "A", "explanation": "The extract is from the play 'Hamlet' by William Shakespeare. The lines are spoken by Hamlet himself, after he has been wounded by a poisoned sword in a duel with Laertes. The setting of this scene is a hall in the castle. The duel takes place in the presence of the King, Queen, and courtiers. Therefore, the correct answer is 'a hall in the castle'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>36", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet   Read the extract and answer this question.     Thrift, thrift........! the funeral baked meats  Did coldly furnish forth the marriages tables,  Would I had seen that day, ...........!  My father!_____ Me thinks I see my father  (Act 1, scene two, lines 180-184)    The speaker is", "images": [], "options": {"A": "Polinuis", "B": "the king", "C": "Hamlet", "D": "the queen"}, "answer": "C", "explanation": "The extract is from the play 'Hamlet' by William Shakespeare. The lines are spoken by Hamlet, who is expressing his grief over his father's death and his mother's hasty remarriage. The phrase 'Thrift, thrift' is Hamlet's sarcastic comment on the economy of using the leftovers from his father's funeral feast for his mother's wedding. Therefore, the correct answer is 'Hamlet'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>37", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet   Read the extract and answer this question.     Thrift, thrift........! the funeral baked meats  Did coldly furnish forth the marriages tables,  Would I had seen that day, ...........!  My father!_____ Me thinks I see my father  (Act 1, scene two, lines 180-184)  The character being addressed is", "images": [], "options": {"A": "Horatio", "B": "Marcellus", "C": "Polinius", "D": "Laertes"}, "answer": "A", "explanation": "Horatio is a soldier of the castle, who saw the ghost of Hamlet's dead father. He is the person Hamlet is talking to.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>38", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet   Read the extract and answer this question.     Thrift, thrift........! the funeral baked meats  Did coldly furnish forth the marriages tables,  Would I had seen that day, ...........!  My father!_____ Me thinks I see my father  (Act 1, scene two, lines 180-184)  The speaker is suffering from", "images": [], "options": {"A": "malaria", "B": "headache", "C": "tumor", "D": "hallucination"}, "answer": "D", "explanation": "In the given extract, the speaker, Hamlet, is not suffering from a physical ailment such as malaria, headache, or tumor. Instead, he is experiencing a hallucination. He believes he sees his father, who is actually dead. This is a psychological phenomenon, not a physical one, hence the correct answer is hallucination.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>39", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet   Read the extract and answer this question.     Thrift, thrift........! the funeral baked meats  Did coldly furnish forth the marriages tables,  Would I had seen that day, ...........!  My father!_____ Me thinks I see my father  (Act 1, scene two, lines 180-184)  The other character in the scene is", "images": [], "options": {"A": "the king", "B": "Marcellus", "C": "Polinius", "D": "the queen"}, "answer": "B", "explanation": "Between line 157 - 158 , Horatio, Marcellus and Bernado enter the scene. Marcellus is another soldier who acts as guard.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>40", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet   Read the extract and answer this question.     Thrift, thrift........! the funeral baked meats  Did coldly furnish forth the marriages tables,  Would I had seen that day, ...........!  My father!_____ Me thinks I see my father  (Act 1, scene two, lines 180-184)  The character that just left the scene are", "images": [], "options": {"A": "Hamlet and Horatio", "B": "Rosencrants and the queen", "C": "the king and the queen", "D": "the queen and Guildenstern"}, "answer": "C", "explanation": "Before the arrival of the soldiers, Hamlet is having a conversation with Queen Gertrude and King Claudius. The king and queen lagter leave the scene.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>41", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet   Read the extract and answer this question.    I shall the effect of this good lesson keep  As watchman to my heart, But, good my brother,  Do not, as soon as ungracious pastors do,  Show me the steep and stormy way to heaven;  While, like a puff'd and reckless libertine,  Himself the  primrose path of dalliance  treads,  And wrecks not his own rede.  (Act1, scene three, lines 45-51)    The speaker is", "images": [], "options": {"A": "Getrude", "B": "Ophelia", "C": "Relnaldo", "D": "Guildenstern"}, "answer": "B", "explanation": "Ophelia, Hamlet's bethrothed, and her brother are having a conversation shortly before the departure of her brother..", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>42", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet   Read the extract and answer this question.    I shall the effect of this good lesson keep  As watchman to my heart, But, good my brother,  Do not, as soon as ungracious pastors do,  Show me the steep and stormy way to heaven;  While, like a puff'd and reckless libertine,  Himself the  primrose path of dalliance  treads,  And wrecks not his own rede.  (Act1, scene three, lines 45-51)  The character being addressed is", "images": [], "options": {"A": "Laertes", "B": "Polinius", "C": "Horatio", "D": "the king"}, "answer": "A", "explanation": "The character being addressed in the extract is Laertes. This is evident from the context where the speaker refers to \"my brother\". In the play Hamlet, Ophelia and Laertes are siblings.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>43", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet   Read the extract and answer this question.    I shall the effect of this good lesson keep  As watchman to my heart, But, good my brother,  Do not, as soon as ungracious pastors do,  Show me the steep and stormy way to heaven;  While, like a puff'd and reckless libertine,  Himself the  primrose path of dalliance  treads,  And wrecks not his own rede.  (Act1, scene three, lines 45-51)  \" Thee primrose path of dalliance\" means", "images": [], "options": {"A": "a religious life", "B": "a reckless life", "C": "the way to heaven", "D": "the way to hell"}, "answer": "B", "explanation": "One of the meaning of dalliance is ' a wasting of time in idleness or trifles' which is synonymous to recklessness.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>44", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet   Read the extract and answer this question.    I shall the effect of this good lesson keep  As watchman to my heart, But, good my brother,  Do not, as soon as ungracious pastors do,  Show me the steep and stormy way to heaven;  While, like a puff'd and reckless libertine,  Himself the  primrose path of dalliance  treads,  And wrecks not his own rede.  (Act1, scene three, lines 45-51)  The other character who comes in the scene after this is", "images": [], "options": {"A": "the queen", "B": "Horatio", "C": "Polonius", "D": "the king"}, "answer": "C", "explanation": "In Act 1, Scene 3 of Hamlet, Polonius is the character who enters the scene after Laertes and Ophelia's conversation, which includes the lines quoted in the question. Therefore, the correct answer is 'Polonius'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>45", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet   Read the extract and answer this question.    I shall the effect of this good lesson keep  As watchman to my heart, But, good my brother,  Do not, as soon as ungracious pastors do,  Show me the steep and stormy way to heaven;  While, like a puff'd and reckless libertine,  Himself the  primrose path of dalliance  treads,  And wrecks not his own rede.  (Act1, scene three, lines 45-51)  The setting is", "images": [], "options": {"A": "A room in Polonius house", "B": "A room in the castle", "C": "the queens room", "D": "the kings room"}, "answer": "A", "explanation": "Ophelia and Laertes are both Polonius' children. This conversation takes place in their house.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>46", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet   Read the extract and answer this question.    I prithee, when thou seest the act afoot,  Even with the very comment of thy soul  Observe mine uncle; if his occulted guilt  Do not itself unkennel in one speech,   It is a damned ghost that we have seen...  ( Act 3, scene two, lines 73-77 )    The speaker is", "images": [], "options": {"A": "Hamlet", "B": "Claudius", "C": "the king", "D": "the queen"}, "answer": "A", "explanation": "The speaker in this extract is Hamlet. In Act 3, Scene 2, Hamlet is speaking to Horatio about his plan to observe Claudius's reaction to the play they are about to watch. The play is designed to mimic the murder of Hamlet's father, and Hamlet believes Claudius's reaction will reveal his guilt. Therefore, the correct answer is 'Hamlet'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>47", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet   Read the extract and answer this question.    I prithee, when thou seest the act afoot,  Even with the very comment of thy soul  Observe mine uncle; if his occulted guilt  Do not itself unkennel in one speech,   It is a damned ghost that we have seen...  ( Act 3, scene two, lines 73-77 )  The character being addressed is", "images": [], "options": {"A": "Gertrude", "B": "Ophelia", "C": "Horatio", "D": "Claudius"}, "answer": "C", "explanation": "In the given extract from Hamlet, Act 3, Scene 2, Hamlet is speaking to Horatio. He is asking Horatio to observe Claudius (Hamlet's uncle) during the play they are about to watch. Hamlet believes that the play, which mirrors the way in which he believes Claudius murdered his father, will provoke a guilty reaction from Claudius, thus proving his guilt.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>48", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet   Read the extract and answer this question.    I prithee, when thou seest the act afoot,  Even with the very comment of thy soul  Observe mine uncle; if his occulted guilt  Do not itself unkennel in one speech,   It is a damned ghost that we have seen...  ( Act 3, scene two, lines 73-77 )  The \" Uncle\" being referred to is", "images": [], "options": {"A": "Laertes", "B": "Claudius", "C": "Guildenstern", "D": "Horatio"}, "answer": "B", "explanation": "In the given extract from Hamlet, Act 3, Scene 2, the 'Uncle' being referred to is Claudius. Claudius is Hamlet's uncle, who has married Hamlet's mother, Gertrude, after the death of Hamlet's father. Hamlet suspects Claudius of murdering his father to ascend to the throne.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>49", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet   Read the extract and answer this question.    I prithee, when thou seest the act afoot,  Even with the very comment of thy soul  Observe mine uncle; if his occulted guilt  Do not itself unkennel in one speech,   It is a damned ghost that we have seen...  ( Act 3, scene two, lines 73-77 )  The \"Occulted guilt\" here means", "images": [], "options": {"A": "Wizardry", "B": "love", "C": "witchcraft", "D": "conscience"}, "answer": "D", "explanation": "The conscience is referred to a thing that capable of judging a person.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2008>50", "subject": "Literature", "year": "2008", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet   Read the extract and answer this question.    I prithee, when thou seest the act afoot,  Even with the very comment of thy soul  Observe mine uncle; if his occulted guilt  Do not itself unkennel in one speech,   It is a damned ghost that we have seen...  ( Act 3, scene two, lines 73-77 )  The scene after this consist of", "images": [], "options": {"A": "closet scene", "B": "dumb show", "C": "graceyard scene", "D": "ghost scene"}, "answer": "B", "explanation": "The scene after the given extract is the 'dumb show'. In this scene, Hamlet presents a play within the play, which is a silent pantomime that mimics the murder of Hamlet's father. This is done in an attempt to provoke a guilty reaction from his uncle, Claudius.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>1", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN PROSE", "question": "A poem consisting of fourteen lines is", "images": [], "options": {"A": "a narrative", "B": "a sonnet", "C": "an ode", "D": "an elegy"}, "answer": "B", "explanation": "A sonnet is a lyrical poem of fourteen lines with a fixed pattern of rhyme scheme and metrical pattern which is usually the iambic pentameter.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2009>2", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The attitude of a writer towards the subject matter is the", "images": [], "options": {"A": "tone", "B": "plot", "C": "crisis", "D": "climax"}, "answer": "A", "explanation": "The attitude of a writer towards the subject matter is referred to as the tone. The tone of a piece of literature is the speaker's or narrator's attitude towards the subject, rather than what the reader feels, as in mood. Plot, crisis, and climax are all elements of a story, but they do not reflect the writer's attitude towards the subject matter.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2009>3", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The pattern of end rhyme in a poem is called", "images": [], "options": {"A": "internal rhyme", "B": "rhyme scheme", "C": "rhythm", "D": "scansion"}, "answer": "B", "explanation": "The pattern formed with the use of rhymes at the end of lines of poetry is called rhyme scheme. That is, the rhyme is derived from the last word on each line/.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2009>4", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The most exciting and tense part of a story is the", "images": [], "options": {"A": "epilogue", "B": "climax", "C": "prologue", "D": "exposition"}, "answer": "B", "explanation": "The climax is the part of the story whereby the action or tension is at its most intense stage. It is the highest point of the action.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>5", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Lines of unrhymed poetry are known as", "images": [], "options": {"A": "blank verse", "B": "assonance", "C": "consonance", "D": "free verse"}, "answer": "D", "explanation": "The free verse does not possess any form of rhyme. While the blank verse has no rhyme, it is written in iambic pentameter.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2009>6", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A dramatic performance with only bodily movement and without word is", "images": [], "options": {"A": "A mime", "B": "metonymy", "C": "a soliloquy", "D": "an opera"}, "answer": "A", "explanation": "This is an organised performance which involves gestures, dances or performances without speaking. In a mime, dialogue is substituted for movements and gesturs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>7", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" Mathematics is my Achilles'heel' is an example of", "images": [], "options": {"A": "litotes", "B": "metonymy", "C": "allusion", "D": "analogy"}, "answer": "C", "explanation": "This means reference to an event that is outside the immediate scope of what is being treated. Here, a reference is made to the mythical Greek warrior, Achilles. A reference to Greek mythology is known as classical allusion.   Achilles was a powerful man whose weak point was his heel. The enemies knew this and gave him a wound on his heel, which later killed him.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>8", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short poem lamenting the death of someone is", "images": [], "options": {"A": "lyric", "B": "sonnet", "C": "ballad", "D": "threnody"}, "answer": "D", "explanation": "Threnody is a song or poem of lamentation or mourning for a dead  person. It can also be regarded as an elegy or a dirge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>9", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In a story, the adversary of the protagonist is the", "images": [], "options": {"A": "hero", "B": "heroine", "C": "antagonist", "D": "foil"}, "answer": "C", "explanation": "The antagonist is the character that contents against the protagonist (hero or heroine).  The foil is usually a character that is used to contrast another character in a bid to bring out the qualities of sucvh character.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>10", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" Tell me not, I am unkind\" illustrates", "images": [], "options": {"A": "inversion", "B": "paradox", "C": "humour", "D": "mood"}, "answer": "B", "explanation": "This statement seems absurd and self-contradictory but reveals much sense and meaning.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>11", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The art of giving human attributes to non-human object is", "images": [], "options": {"A": "personification", "B": "allegory", "C": "anecdote", "D": "allusion"}, "answer": "A", "explanation": "The art of giving human attributes to non-human objects is known as personification. Personification is a figure of speech in which a thing, an idea or an animal is given human attributes. The non-human objects are portrayed in such a way that we feel they have the ability to act like human beings. For example, 'The flowers danced in the gentle breeze'. Here, the flowers are given the human attribute of dancing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2009>12", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A long narrative poem which deals with heroic deeds is", "images": [], "options": {"A": "lyric", "B": "epic", "C": "ode", "D": "euphony"}, "answer": "B", "explanation": "A long narrative poem which deals with heroic deeds is known as an epic. An epic is a lengthy narrative poem, ordinarily involving a time beyond living memory in which occurred the extraordinary doings of the extraordinary men and women who, in dealings with the gods or other superhuman forces, gave shape to the mortal universe for their descendants, the poet and his audience, to understand themselves as a people or nation. For example, 'The Iliad' and 'The Odyssey' by Homer are examples of epic poems.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2009>13", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A poem of four line is called", "images": [], "options": {"A": "quatrain", "B": "sestet", "C": "sonnet", "D": "couplet"}, "answer": "A", "explanation": "Sestet is a poem or stanza of six lines  Sonnet is a poem of fourteen lines with a definite rhyme scheme and meter pattern.  The couplet refers to two rhyming lines of a poem.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2009>14", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary piece used to mock or ridicule a society or practice is called", "images": [], "options": {"A": "an allegory", "B": "a fable", "C": "a farce", "D": "a satire"}, "answer": "D", "explanation": "A satire is a work of art that is written to mock the problems of the society in a bid to instigate a positive change.  A fable is a literary work whereby animals are use as characters.  A farce is an exaggerated form of comedy.  An allegory is a work whereby abstract ideas are personified.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2009>15", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The story a persons life written by another is", "images": [], "options": {"A": "history", "B": "autobiography", "C": "biography", "D": "anthology"}, "answer": "C", "explanation": "When a person writes his story himself, it is called  an autobiography; but when such story is written by another, it is called a biography.   An anthology refers to a collection of poems or literary works.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2009>16", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "When characters talk to each, it is referred to as", "images": [], "options": {"A": "soliloquy", "B": "monologue", "C": "dialogue", "D": "recitation"}, "answer": "C", "explanation": "Dialogue is the conversation between two or more people in a literary work.  Soliloquy refers to when a character is speaking to himself.  Monologue is a speech made by one person.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>17", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A folktale is a", "images": [], "options": {"A": "novel", "B": "work of fiction", "C": "biography", "D": "novelette"}, "answer": "B", "explanation": "A folktale is a fictitious work that originates from a particular place and is usually passed orally from one generation to another. This story usually contains the traditions, beliefs and superstitions of the people.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2009>18", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A poem written in an elaborate style to address or celebrate an object or event is called", "images": [], "options": {"A": "a ballad", "B": "an epic", "C": "a dirge", "D": "an ode"}, "answer": "D", "explanation": "Ode is a poem that celebrates a special event or thing. It is wriotten in the form of an address to what it celebrates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>19", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract and answer this question.    I have to thank God I'm a woman,  For in these ordered days a woman only  Is free to be hungry, very lonely    The dominant device in the above line is", "images": [], "options": {"A": "burlesque", "B": "paradox", "C": "conflict", "D": "irony"}, "answer": "D", "explanation": "The dominant device is the irony.  The speaker ironically thanks God for her unpleasant situation - \"hungry\" and \"lonely\".", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>20", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract and answer this question.    I have to thank God I'm a woman,  For in these ordered days a woman only  Is free to be hungry, very lonely  The tone of the poem is one of", "images": [], "options": {"A": "sorry", "B": "sarcasm", "C": "happiness", "D": "anger"}, "answer": "B", "explanation": "Sarcasm is a scornful or ironic remark. The writer is certainly not thankful to be deprived freedom and left to suffer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>21", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this question.    \" Diversion through Larteh!\" This is the sign in the middle of the road. They have diverted the 24-kilometre Mamfe- Aburi- Adente Road because of the major road works. The Mamfe - larteh - Adente diversion makes the journey twice as long. The longer route is the shorter.       The little jeep flashes past the deserted police checkpoint. The howling wind, like a stretching comb, stretches Kwyeiwa's hair flapping furrows behind her as she stands clinging to a metal surpport in the back of the open jeep, pertrified. The jeep negotiates the hair pin bend below the overhang near Tamara's place at break neck speed; Now it is on the stretch to Kadiabe junction.  The little vehicle laps up the distance . Presently the driver arrives at the last cross roads, Kodiabe lies at the crow flies, Somanya to the left. The jeep turns right towards Accra.    Kwyeiwa is", "images": [], "options": {"A": "relaxed", "B": "ecstatic", "C": "frightened", "D": "elated"}, "answer": "C", "explanation": "'... as she stands digging to a metal support ... petrified  The above extract proves that she is frightened.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>22", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this question.    \" Diversion through Larteh!\" This is the sign in the middle of the road. They have diverted the 24-kilometre Mamfe- Aburi- Adente Road because of the major road works. The Mamfe - larteh - Adente diversion makes the journey twice as long. The longer route is the shorter.       The little jeep flashes past the deserted police checkpoint. The howling wind, like a stretching comb, stretches Kwyeiwa's hair flapping furrows behind her as she stands clinging to a metal surpport in the back of the open jeep, pertrified. The jeep negotiates the hair pin bend below the overhang near Tamara's place at break neck speed; Now it is on the stretch to Kadiabe junction.  The little vehicle laps up the distance . Presently the driver arrives at the last cross roads, Kodiabe lies at the crow flies, Somanya to the left. The jeep turns right towards Accra.  The narrative technique is", "images": [], "options": {"A": "third person", "B": "a soliloquy", "C": "first person", "D": "an aside"}, "answer": "A", "explanation": "Third person narrative technique occurs when the writer does not connect himself with the other casts in the novel, he rather describes that the character does. The use of the third-person pronoun, SHE, to describe Kwyeiwa proves the choice of third person.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>23", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this question.    \" Diversion through Larteh!\" This is the sign in the middle of the road. They have diverted the 24-kilometre Mamfe- Aburi- Adente Road because of the major road works. The Mamfe - larteh - Adente diversion makes the journey twice as long. The longer route is the shorter.       The little jeep flashes past the deserted police checkpoint. The howling wind, like a stretching comb, stretches Kwyeiwa's hair flapping furrows behind her as she stands clinging to a metal surpport in the back of the open jeep, pertrified. The jeep negotiates the hair pin bend below the overhang near Tamara's place at break neck speed; Now it is on the stretch to Kadiabe junction.  The little vehicle laps up the distance . Presently the driver arrives at the last cross roads, Kodiabe lies at the crow flies, Somanya to the left. The jeep turns right towards Accra.  The passage is", "images": [], "options": {"A": "expository", "B": "argumentative", "C": "narrative", "D": "analytic"}, "answer": "C", "explanation": "The passage is narrative because it tells the reader what happens along the roads to the passengers' destination.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>24", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this question.    \" Diversion through Larteh!\" This is the sign in the middle of the road. They have diverted the 24-kilometre Mamfe- Aburi- Adente Road because of the major road works. The Mamfe - larteh - Adente diversion makes the journey twice as long. The longer route is the shorter.       The little jeep flashes past the deserted police checkpoint. The howling wind, like a stretching comb, stretches Kwyeiwa's hair flapping furrows behind her as she stands clinging to a metal surpport in the back of the open jeep, pertrified. The jeep negotiates the hair pin bend below the overhang near Tamara's place at break neck speed; Now it is on the stretch to Kadiabe junction.  The little vehicle laps up the distance . Presently the driver arrives at the last cross roads, Kodiabe lies at the crow flies, Somanya to the left. The jeep turns right towards Accra.  The atmosphere in the passage is one of", "images": [], "options": {"A": "love", "B": "fear", "C": "anger", "D": "joy"}, "answer": "B", "explanation": "The movement of the car is too fast , so the passengers are scared. Some of the words which illustrates this are 'flashes past', 'petrified' and 'breakneck speed'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>25", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this question.    \" Diversion through Larteh!\" This is the sign in the middle of the road. They have diverted the 24-kilometre Mamfe- Aburi- Adente Road because of the major road works. The Mamfe - larteh - Adente diversion makes the journey twice as long. The longer route is the shorter.       The little jeep flashes past the deserted police checkpoint. The howling wind, like a stretching comb, stretches Kwyeiwa's hair flapping furrows behind her as she stands clinging to a metal surpport in the back of the open jeep, pertrified. The jeep negotiates the hair pin bend below the overhang near Tamara's place at break neck speed; Now it is on the stretch to Kadiabe junction.  The little vehicle laps up the distance . Presently the driver arrives at the last cross roads, Kodiabe lies at the crow flies, Somanya to the left. The jeep turns right towards Accra.  \"The littele vehicle laps the distance\" conveys the impression of", "images": [], "options": {"A": "leisure", "B": "pleasure", "C": "strength", "D": "speed"}, "answer": "D", "explanation": "'Laps up the distance' indictate that the bus quickly covers the distance; that is, the bus is really moving fast.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>26", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question.    In front of the gate, the guard stands with his riffle,  Above, untidy clouds are carrying away the moon,  The bedbugs are swarming around like army tanks or manoeuvers  While the mosquitoes form squadrons, attacking like fighter plane    My heart travels a thousand miles towards my native land;   My dream intertwines with sadness like a stein of  a thousand threads.    Innocent, I have endured a whole year in prison  Using my tears for ink, i turn my thoughts into verses.    The poem is about", "images": [], "options": {"A": "war", "B": "dirt", "C": "travelling", "D": "prison life"}, "answer": "D", "explanation": "'Innocent, I have endured a whole year in prison'  The extract shows that the poem is about prison life. The appaling living conditions - mosquitoes and bedbugs - also prove that the poem revolves around prison life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>27", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question.    In front of the gate, the guard stands with his riffle,  Above, untidy clouds are carrying away the moon,  The bedbugs are swarming around like army tanks or manoeuvers  While the mosquitoes form squadrons, attacking like fighter plane    My heart travels a thousand miles towards my native land;   My dream intertwines with sadness like a stein of  a thousand threads.    Innocent, I have endured a whole year in prison  Using my tears for ink, i turn my thoughts into verses.  The imagery in the first four lines is predominantly", "images": [], "options": {"A": "agricultural", "B": "military", "C": "political", "D": "social"}, "answer": "B", "explanation": "The imagery is largely military. In line one, a guard is with a rifle (gun).  In the subsequent lines, the mosquitoes and bedbugs are described using military terminologies such as army trucks, manoeuvres, squadrons and fighter planes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>28", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question.    In front of the gate, the guard stands with his riffle,  Above, untidy clouds are carrying away the moon,  The bedbugs are swarming around like army tanks or manoeuvers  While the mosquitoes form squadrons, attacking like fighter plane    My heart travels a thousand miles towards my native land;   My dream intertwines with sadness like a stein of  a thousand threads.    Innocent, I have endured a whole year in prison  Using my tears for ink, i turn my thoughts into verses.  \"....... a thousand miles\" is an example of", "images": [], "options": {"A": "hyperbole", "B": "irony", "C": "antithesis", "D": "epigram"}, "answer": "A", "explanation": "\"....... a thousand miles\" is an example of hyperbole. Hyperbole is a figure of speech that involves exaggeration of ideas for the sake of emphasis. In this context, the poet uses 'a thousand miles' to exaggerate the emotional distance he feels from his native land, emphasizing his longing and homesickness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>29", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question.    In front of the gate, the guard stands with his riffle,  Above, untidy clouds are carrying away the moon,  The bedbugs are swarming around like army tanks or manoeuvers  While the mosquitoes form squadrons, attacking like fighter plane    My heart travels a thousand miles towards my native land;   My dream intertwines with sadness like a stein of  a thousand threads.    Innocent, I have endured a whole year in prison  Using my tears for ink, i turn my thoughts into verses.  The poem is written in", "images": [], "options": {"A": "blank verse", "B": "pentameter", "C": "free verse", "D": "trochee"}, "answer": "C", "explanation": "The poem with no rhyme or metre pattern; therefore, it is a free verse.  A blank verse, on the other hand, has no rhyme scheme but is written in iambic pentametre.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>30", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question.    In front of the gate, the guard stands with his riffle,  Above, untidy clouds are carrying away the moon,  The bedbugs are swarming around like army tanks or manoeuvers  While the mosquitoes form squadrons, attacking like fighter plane    My heart travels a thousand miles towards my native land;   My dream intertwines with sadness like a stein of  a thousand threads.    Innocent, I have endured a whole year in prison  Using my tears for ink, i turn my thoughts into verses.  The impression created of the personia is one of", "images": [], "options": {"A": "anger", "B": "competitiveness", "C": "reconciliation", "D": "resignation"}, "answer": "D", "explanation": "The persona in the poem expresses feelings of longing for his homeland, sadness, and acceptance of his situation. This creates an impression of resignation. Resignation in this context refers to the acceptance of something undesirable but inevitable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>31", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    Think it no more;  From nature, Crescent, does not grow alone  In  thews and bulk,  as this temple waxes,   The inward service of the mind and soul  Grows wide withal. Perhaps he loves you now,  And now no soil of  cantle doth besmirch  The virtue of his will  (Act one, scene three, line 10-16)    The speaker is", "images": [], "options": {"A": "Polinius", "B": "Reynaldo", "C": "Rosencrantz", "D": "Laertes"}, "answer": "D", "explanation": "In the given extract from Shakespeare's Hamlet, the speaker is Laertes. This is a part of Laertes' advice to his sister Ophelia, warning her about Hamlet's intentions. Laertes is a character in the play who is Ophelia's brother and Polonius's son.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>32", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    Think it no more;  From nature, Crescent, does not grow alone  In  thews and bulk,  as this temple waxes,   The inward service of the mind and soul  Grows wide withal. Perhaps he loves you now,  And now no soil of  cantle doth besmirch  The virtue of his will  (Act one, scene three, line 10-16)  The character being addressed is", "images": [], "options": {"A": "Ophelia", "B": "Hamlet", "C": "Marcellus", "D": "Bernado"}, "answer": "A", "explanation": "In the given extract from Shakespeare's Hamlet, the character being addressed is Ophelia. This is a part of Laertes' advice to his sister Ophelia, warning her about Hamlet's intentions. Ophelia is a character in the play who is the daughter of Polonius and the sister of Laertes.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>33", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    Think it no more;  From nature, Crescent, does not grow alone  In  thews and bulk,  as this temple waxes,   The inward service of the mind and soul  Grows wide withal. Perhaps he loves you now,  And now no soil of  cantle doth besmirch  The virtue of his will  (Act one, scene three, line 10-16)  The subject of discussion is", "images": [], "options": {"A": "Horatio", "B": "Hamlet", "C": "Marcellus", "D": "Bernado"}, "answer": "B", "explanation": "Ophelia is in love with Hamlet but Laertes warns her against it because Hamlet has been acting insane.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>34", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    Think it no more;  From nature, Crescent, does not grow alone  In  thews and bulk,  as this temple waxes,   The inward service of the mind and soul  Grows wide withal. Perhaps he loves you now,  And now no soil of  cantle doth besmirch  The virtue of his will  (Act one, scene three, line 10-16)  The speaker is", "images": [], "options": {"A": "Happy", "B": "confused", "C": "excited", "D": "anxious"}, "answer": "D", "explanation": "Laertes is greatly worried about his sister's love for Hamlet.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>35", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    Think it no more;  From nature, Crescent, does not grow alone  In  thews and bulk,  as this temple waxes,   The inward service of the mind and soul  Grows wide withal. Perhaps he loves you now,  And now no soil of  cantle doth besmirch  The virtue of his will  (Act one, scene three, line 10-16)   Thews and bulk  means", "images": [], "options": {"A": "power", "B": "body and soul", "C": "strength and size", "D": "brain"}, "answer": "C", "explanation": "In the context of the extract from Shakespeare's Hamlet, 'thews and bulk' refers to physical strength and size. The phrase is used to describe the physical growth of a person, in contrast to the growth of the mind and soul. Therefore, the correct answer is 'strength and size'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>36", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    X :  Tis gone, and will not answer  Y :   How now.......! you tremble and look pale:               Is not this more than fantasy?               What think you on it?  Z :   Before my God, i might not this believe               Without the sensible and true avouch                Of mine own eyes     (Act1, scene 1, lines 52-58)    Speaker Y is", "images": [], "options": {"A": "Horatio", "B": "Marcellus", "C": "Hamlet", "D": "Laertes"}, "answer": "B", "explanation": "Marcellus and other soldiers on guard are discussing ghost that has just disappeared. This ghost is Hamlet's slain father.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>37", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    X :  Tis gone, and will not answer  Y :   How now.......! you tremble and look pale:               Is not this more than fantasy?               What think you on it?  Z :   Before my God, i might not this believe               Without the sensible and true avouch                Of mine own eyes     (Act1, scene 1, lines 52-58)  Speaker Z is", "images": [], "options": {"A": "Bernado", "B": "Fransisco", "C": "Polinius", "D": "Rosencrantz"}, "answer": "A", "explanation": "In the play 'Hamlet' by William Shakespeare, the extract is taken from Act 1, Scene 1 where the characters Bernardo, Marcellus, and Horatio are present. In this scene, they are discussing the ghost of King Hamlet that they have just seen. Speaker Z is Bernardo, who is one of the guards who first witness the ghost. Therefore, the correct answer is Bernardo.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>38", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    X :  Tis gone, and will not answer  Y :   How now.......! you tremble and look pale:               Is not this more than fantasy?               What think you on it?  Z :   Before my God, i might not this believe               Without the sensible and true avouch                Of mine own eyes     (Act1, scene 1, lines 52-58)   Tis gone and will not answer  refers to", "images": [], "options": {"A": "gravedigger", "B": "ghost", "C": "servant", "D": "soldier"}, "answer": "B", "explanation": "A ghost in form of the dead king appears and disappears before the soldiers. The ghost does not speak to any of them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>39", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    X :  Tis gone, and will not answer  Y :   How now.......! you tremble and look pale:               Is not this more than fantasy?               What think you on it?  Z :   Before my God, i might not this believe               Without the sensible and true avouch                Of mine own eyes     (Act1, scene 1, lines 52-58)  The atmosphere is", "images": [], "options": {"A": "Frightening", "B": "peaceful", "C": "relaxed", "D": "bleak"}, "answer": "A", "explanation": "The atmosphere in the given extract from Shakespeare's Hamlet is frightening. This is evident from the dialogue where character Y notices that character X is trembling and looking pale, suggesting fear or anxiety. Character Z also expresses disbelief at what they are witnessing, further adding to the sense of fear and uncertainty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>40", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    X :  Tis gone, and will not answer  Y :   How now.......! you tremble and look pale:               Is not this more than fantasy?               What think you on it?  Z :   Before my God, i might not this believe               Without the sensible and true avouch                Of mine own eyes     (Act1, scene 1, lines 52-58)  The setting is", "images": [], "options": {"A": "another part of the platform", "B": "a platform in front of the castle", "C": "the queen's palace", "D": "a room in the castle"}, "answer": "B", "explanation": "The place setting is a platform in front of the castle.  This is where the soldiers stay to guard the castle", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2009>41", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    And for your part,.......,Ii do wish  That your true beauties be the happy cause  Of.....  wildness : s shall I hope your virtues  Will bring him to his wonted way again  To both your honours.  (Act 3, scene one, lines 37-42)    The speaker is", "images": [], "options": {"A": "the king", "B": "Laertes", "C": "the queen", "D": "Polinius"}, "answer": "C", "explanation": "Queen Gertrude addresses Ophelia concerning Hamlet's madness", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>42", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    And for your part,.......,Ii do wish  That your true beauties be the happy cause  Of.....  wildness : s shall I hope your virtues  Will bring him to his wonted way again  To both your honours.  (Act 3, scene one, lines 37-42)  After this speech, the speaker", "images": [], "options": {"A": "exits", "B": "dies", "C": "wakes up", "D": "sleeps off"}, "answer": "A", "explanation": "In the given extract from Shakespeare's Hamlet, after Polonius delivers this speech to Ophelia, he exits the scene. This is a part of Act 3, Scene 1. Therefore, the correct answer is 'exits'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>43", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    And for your part,.......,Ii do wish  That your true beauties be the happy cause  Of.....  wildness : s shall I hope your virtues  Will bring him to his wonted way again  To both your honours.  (Act 3, scene one, lines 37-42)  The character being addressed is", "images": [], "options": {"A": "Laertes", "B": "Hamlet", "C": "Polinius", "D": "Ophelia"}, "answer": "D", "explanation": "Ophelia loves Hamlet, so the Queen wishes to think Hamlet's love for Ophelia may be his cause of his madness.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>44", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    And for your part,.......,Ii do wish  That your true beauties be the happy cause  Of.....  wildness : s shall I hope your virtues  Will bring him to his wonted way again  To both your honours.  (Act 3, scene one, lines 37-42)  Another character present on the scene is", "images": [], "options": {"A": "Resencrantz", "B": "Guildenstern", "C": "Polonius", "D": "Hamlet"}, "answer": "C", "explanation": "The other character present in the scene is Polonius. This is inferred from the line 'To both your honours.' which implies that there is another person present in the scene who is being addressed along with Ophelia. Polonius is Ophelia's father and is often present in scenes involving her.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>45", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet  Read the extract and answer this question.    And for your part,.......,Ii do wish  That your true beauties be the happy cause  Of.....  wildness : s shall I hope your virtues  Will bring him to his wonted way again  To both your honours.  (Act 3, scene one, lines 37-42)  The wilderness referred to can also be called", "images": [], "options": {"A": "love", "B": "madness", "C": "happiness", "D": "death"}, "answer": "A", "explanation": "Hamlet is believed to be madly in love. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>46", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    H :  Where is this  sight   I :    What is it ye would see? If ought of Noe wonder, cedase your search.  (Act 5, scene two, lines 348-350)    Speaker H is", "images": [], "options": {"A": "Fortinbras", "B": "Horatio", "C": "Osric", "D": "Ambassador"}, "answer": "A", "explanation": "Prince Fortinbras, who has just arrived with the English ambassadors, sees lots of people dead and is completely baffled.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>47", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    H :  Where is this  sight   I :    What is it ye would see? If ought of Noe wonder, cedase your search.  (Act 5, scene two, lines 348-350)  Speaker I is", "images": [], "options": {"A": "Horatio", "B": "Claudius", "C": "Hamlet", "D": "Osric"}, "answer": "A", "explanation": "In the given extract from William Shakespeare's 'Hamlet', the speaker 'I' is Horatio. In Act 5, Scene 2, Horatio is present with Hamlet in the court of Denmark. Hamlet is referred to as 'H' and Horatio as 'I'. Therefore, the correct answer is Horatio.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>48", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    H :  Where is this  sight   I :    What is it ye would see? If ought of Noe wonder, cedase your search.  (Act 5, scene two, lines 348-350)   Sight", "images": [], "options": {"A": "players and drummers", "B": "soldiers from England", "C": "incest committed", "D": "dead bodies"}, "answer": "D", "explanation": "In the context of the given extract from William Shakespeare's 'Hamlet', the term ' Sight ' refers to the dead bodies. In Act 5, Scene 2, Hamlet and Horatio are in the court of Denmark where they witness the aftermath of a duel, which results in multiple deaths. Therefore, the correct answer is 'dead bodies'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>49", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    H :  Where is this  sight   I :    What is it ye would see? If ought of Noe wonder, cedase your search.  (Act 5, scene two, lines 348-350)  Shortly before the speech ............. died", "images": [], "options": {"A": "the king", "B": "the queen", "C": "Hamlet", "D": "Polonius"}, "answer": "C", "explanation": "In the given extract from William Shakespeare's Hamlet, Act 5, Scene 2, lines 348-350, the character 'H' is asking about a sight, to which 'I' responds asking what they would like to see. The question asks who died shortly before this speech, and the answer is Hamlet. In the play, Hamlet dies in Act 5, Scene 2, shortly after a duel with Laertes, during which he is wounded with a poisoned sword.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2009>50", "subject": "Literature", "year": "2009", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet  Read the extract and answer this question.    H :  Where is this  sight   I :    What is it ye would see? If ought of Noe wonder, cedase your search.  (Act 5, scene two, lines 348-350)  Other characters who died earlier were", "images": [], "options": {"A": "the queen and the ambassador", "B": "Hamlet and Osric", "C": "Ophelia and Horatio", "D": "Laertes and the king"}, "answer": "D", "explanation": "The question asks about the characters who died earlier in the play. The correct answer is Laertes and the king. In the play, King Claudius dies after being stabbed by Hamlet and forced to drink the poison that he had originally intended for Hamlet. Laertes also dies in Act 5, Scene 2, after being wounded with his own poisoned sword during the duel with Hamlet.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>1", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short introductory speech delivered as part of a play is called", "images": [], "options": {"A": "a preamble", "B": "a prologue", "C": "an introduction", "D": "an epilogue"}, "answer": "B", "explanation": "In the context of a play, a short introductory speech is referred to as a prologue. A prologue is a separate introductory section that comes before the main body of a play, novel, or other literary work. It often provides background information, sets the scene, or introduces the characters or themes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>2", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS", "question": "The limerick", "images": [], "options": {"A": "is written to be sung", "B": "has a serious subject matter", "C": "is always light and humorous", "D": "uses lofty languages"}, "answer": "C", "explanation": "A limerick is a type of poem that is often light and humorous. It consists of five lines with a particular rhythm and rhyme scheme. The content of a limerick is typically humorous or nonsense in nature, making it a light-hearted form of poetry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2010>3", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Unrhymed iambic pentametre lines illustrates", "images": [], "options": {"A": "rhyme scheme", "B": "heroic couplet", "C": "blank verse", "D": "Free verse"}, "answer": "C", "explanation": "Blank verse has no rhyme but five unstressed and five stressed syllables. This pattern constitutes the iambic pentametr.  A free verse, on the other hand, has no rhyme scheme and metre pattern.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>4", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS", "question": "The major distinctive feature of drama is", "images": [], "options": {"A": "dialogue", "B": "setting", "C": "epilogue", "D": "plot"}, "answer": "A", "explanation": "Dialogue is the conversation between characters in a play. In drama, the entire story is presented in the form of conversations between the characters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>5", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS", "question": "The recurrence of rhythmic pattern of stress in a poem is", "images": [], "options": {"A": "couplet", "B": "metre", "C": "consonance", "D": "strophe"}, "answer": "B", "explanation": "The recurrence of a rhythmic pattern of stress in a poem is referred to as 'metre'. Metre is the basic rhythmic structure of a verse or lines in verse. It involves the arrangement of words in regularly measured, patterned, or rhythmic lines or verses. The other options do not fit the definition. A couplet is a pair of successive lines of metre in poetry. Consonance refers to repetitive sounds produced by consonants within a sentence or phrase. Strophe is the first section of an ancient Greek choral ode or of one division of it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>6", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A poem written in praise of someone or something is", "images": [], "options": {"A": "a ballad", "B": "an epic", "C": "a sonnet", "D": "an ode"}, "answer": "D", "explanation": "Ode is a poem that celebrates a special event or thing. It is written in the form of an direct address to the thing or person it praises.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2010>7", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this questions.    \" No longer mourn for me when I am dead  Then you shall hear the surly sullen bell  Give warning to the wall now that I am fled  from the vile world, where vilest worms do dwell\"    The mood of the poet is one of", "images": [], "options": {"A": "anger", "B": "humour", "C": "melancholy", "D": "gaiety"}, "answer": "D", "explanation": "The writer is happy or willing to leave the world because he considers the world to be a wicked place.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>8", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this questions.    \" No longer mourn for me when I am dead  Then you shall hear the surly sullen bell  Give warning to the wall now that I am fled  from the vile world, where vilest worms do dwell\"  The poet uses", "images": [], "options": {"A": "eye-rhyme", "B": "run-on-lines", "C": "end -stopped-lines", "D": "internal rhyme"}, "answer": "B", "explanation": "The idea in line three is completed in line four.    \"Give warning to the wall now that I am fled   from the vile world, where vilest worms do dwell\"    This is also known as enjambment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>9", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this questions.    \" No longer mourn for me when I am dead  Then you shall hear the surly sullen bell  Give warning to the wall now that I am fled  from the vile world, where vilest worms do dwell\"  The rhyming patterns of the line is", "images": [], "options": {"A": "abab", "B": "abba", "C": "aabb", "D": "aaab"}, "answer": "A", "explanation": "The rhyming pattern of the poem is ABAB. This is determined by looking at the end word of each line and finding words that rhyme. In this case, 'dead' rhymes with 'fled' (A) and 'bell' rhymes with 'dwell' (B). Therefore, the pattern is ABAB.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>10", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" But at my back i always hear  Time's winged chariot hurrying near\" illustrates", "images": [], "options": {"A": "metaphor", "B": "apostrophe", "C": "oxymoron", "D": "metonymy"}, "answer": "A", "explanation": "Time is compared with a winged chariot. The extract means that time is short. It is culled from Andrew Marvell's \"To his Coy Mistress\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>11", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The central idea of a story or a poem is the", "images": [], "options": {"A": "title", "B": "climax", "C": "theme", "D": "conflict"}, "answer": "C", "explanation": "This is the message a writer, poet or playwright is trying to pass across to the readers or audience. It is the central idea.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>12", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An emphasis placed on a syllable in pronunciation is", "images": [], "options": {"A": "metre", "B": "rhythm", "C": "accent", "D": "rhyme"}, "answer": "C", "explanation": "Accent or stress refers to the extra emphasis that is placed on a syllable during pronunciation. Such syllable tends to be louder and longer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>13", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The timing and location of a literary work is", "images": [], "options": {"A": "theme", "B": "plot", "C": "setting", "D": "atmosphere"}, "answer": "C", "explanation": "The timing and location of a literary work is referred to as the 'setting'. The setting of a story, poem, or play is the environment in which the action takes place. It includes the geographical location, the time period, the socio-economic conditions, and more.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2010>14", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The elegy", "images": [], "options": {"A": "conforms to a fixed pattern of lines", "B": "is set in the country side", "C": "has a mournful tone", "D": "celebrates herioc deeds"}, "answer": "C", "explanation": "Elegy is a lyrical poem which mournfully reflects on death. The elegy takes death as its subject matter.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>15", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The major genres of literature are", "images": [], "options": {"A": "Fiction, non-fiction, drama", "B": "prose, farce, comedy", "C": "prose, drama, poetry", "D": "poetry, prose, fiction"}, "answer": "C", "explanation": "The major genres of literature are prose, drama, and poetry. Prose is a form of language that has no formal metrical structure. It applies a natural flow of speech, and ordinary grammatical structure rather than rhythmic structure, such as in the case of traditional poetry. Drama is a mode of fictional representation through dialogue and performance. It is one of the literary genres, which is usually performed in a theater, or on radio or television. Poetry is a type of literature that uses aesthetic and rhythmic qualities of language to evoke meanings in addition to, or in place of, the prosaic ostensible meaning.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2010>16", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "AFRICAN POETRY", "question": "Pick the odd item out of the option listed", "images": [], "options": {"A": "The Joys of Motherhood", "B": "Sons and Daughters", "C": "A Man For All Season", "D": "The Last Duty"}, "answer": "C", "explanation": "All are written by Africans except A Man For All Seasons written by a non- Africans (Robert Bolt).", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2010>17", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN POETRY", "question": "' My bounty is as bountless as the sea  My love as deep\"  the above lines illustrates", "images": [], "options": {"A": "epigram", "B": "hyperbole", "C": "apostrophe", "D": "parody"}, "answer": "B", "explanation": "The speaker exaggerates that is love is as deep as the sea. The hyperbole refers to an excessive exaggeration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>18", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN POETRY", "question": "\" The strong gongs groaning as the guns borns far\" illustrates", "images": [], "options": {"A": "metonymy", "B": "refrain", "C": "onomatopoeia", "D": "repetition"}, "answer": "C", "explanation": "The use of sound to suggest meaning is what the onomatopoeia is concerned with. Here, the gong is said to be making \"groaning\" noises.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>19", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pick the odd items out of the options listed below", "images": [], "options": {"A": "Euphemism", "B": "Oxymoron", "C": "Hyperbole", "D": "Rhythm"}, "answer": "D", "explanation": "The odd item out is 'Rhythm'. Euphemism, Oxymoron, and Hyperbole are all figures of speech, which are used to add effect and create emphasis in a piece of literature. Rhythm, on the other hand, is a literary device that demonstrates the long and short patterns through stressed and unstressed syllables, particularly in verse form.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2010>20", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\" Poetry gets bored of being alone  It wants to go out door to chew on the winds\"    The dominant figure of speech in the above lines is", "images": [], "options": {"A": "Paradox", "B": "Pun", "C": "Parallelism", "D": "Personification"}, "answer": "D", "explanation": "The personification is a device that gives human qualities to inanimate objects.  Human attributes (bored, go, chew) are transferred to poetry, an inanimate object.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>21", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this questions.    What a morning!  The sound of guns was everywhere  The city was trapped  I heaved a mournful sigh  Rebels.!    Boom Boom Boom!  The heart pounds at sound of the blast  Lord! When will all this end?  This is the Fourth day.    You say you are free  Oh no, You are not  You are trapped  A prisoner in your own home    The song is every where  What next?  Food - water - hiding place  far from the sound of the gun    The theme of the poem is", "images": [], "options": {"A": "peace", "B": "war", "C": "love", "D": "death"}, "answer": "B", "explanation": "The theme of the poem is 'war'. This is evident from the references to guns, blasts, rebels, and the city being trapped. The speaker also mentions being a prisoner in their own home, which suggests a state of conflict or war. The theme of a poem is its central or main idea, the topic it revolves around.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>22", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this questions.    What a morning!  The sound of guns was everywhere  The city was trapped  I heaved a mournful sigh  Rebels.!    Boom Boom Boom!  The heart pounds at sound of the blast  Lord! When will all this end?  This is the Fourth day.    You say you are free  Oh no, You are not  You are trapped  A prisoner in your own home    The song is every where  What next?  Food - water - hiding place  far from the sound of the gun  \" Boom Boom Boom!\" is an example of", "images": [], "options": {"A": "symbols", "B": "onomatopoeia", "C": "metonymy", "D": "allusion"}, "answer": "B", "explanation": "An onomatopoeia refers to the use of sound to suggest meaning. Here, \"boom\" is used to represent the sound of guns.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>23", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this questions.    What a morning!  The sound of guns was everywhere  The city was trapped  I heaved a mournful sigh  Rebels.!    Boom Boom Boom!  The heart pounds at sound of the blast  Lord! When will all this end?  This is the Fourth day.    You say you are free  Oh no, You are not  You are trapped  A prisoner in your own home    The song is every where  What next?  Food - water - hiding place  far from the sound of the gun  The atmosphere of the poem implies", "images": [], "options": {"A": "danger and confusion", "B": "peace and reconciliation", "C": "happiness", "D": "hope"}, "answer": "A", "explanation": "Since the poem is set during a war, it comes as no surprise that the atmosphere is replete with fear, danger and confusion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>24", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this questions.    What a morning!  The sound of guns was everywhere  The city was trapped  I heaved a mournful sigh  Rebels.!    Boom Boom Boom!  The heart pounds at sound of the blast  Lord! When will all this end?  This is the Fourth day.    You say you are free  Oh no, You are not  You are trapped  A prisoner in your own home    The song is every where  What next?  Food - water - hiding place  far from the sound of the gun  The second stanza refers to", "images": [], "options": {"A": "the uncertainty of life", "B": "the pleasures of life", "C": "the meaning of life", "D": "the joys of life"}, "answer": "A", "explanation": "\"Lord! When will all this end?\"  The rhetorical question in this stanza shows the uncertainty of life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>25", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this questions.    What a morning!  The sound of guns was everywhere  The city was trapped  I heaved a mournful sigh  Rebels.!    Boom Boom Boom!  The heart pounds at sound of the blast  Lord! When will all this end?  This is the Fourth day.    You say you are free  Oh no, You are not  You are trapped  A prisoner in your own home    The song is every where  What next?  Food - water - hiding place  far from the sound of the gun  The song is everywhere\" refers to", "images": [], "options": {"A": "freedom", "B": "anxiety", "C": "pleasure", "D": "satisfaction"}, "answer": "B", "explanation": "The poem describes a situation of unrest and fear, with the sound of guns, the city being trapped, and the speaker feeling like a prisoner in their own home. The phrase 'The song is everywhere' is likely referring to the pervasive and inescapable nature of this unrest. Therefore, the best option that matches this interpretation is 'anxiety'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>26", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question.    Here in the station it is no way different save that the city is busy in his snow. But the old men cling to their seats as though they were symbolic and could not be given up. Now ad then they sleep, their grey old heads resting with painful awkwardness  on the backs of the benches .             Also they are not at rest. For an hour they may sleep in the  gasping exhaustion of the ill-nourished and aged , who have to walk in the night. Then a police man comes by on his rounds and nudges them upright.       \"You can't sleep here\", he growls.       A strange ritual then begins. A n old man is difficult to wake. One man after a slight lurch, does not move at all, he sleeps on steadily. Once in a while, one of the sleepers will not wake, he will have had his wish to die in the great  droning  centre of the  hive  rather than in some lonely room fulfilled.    The style of writing is", "images": [], "options": {"A": "argumentative", "B": "epistolary", "C": "narrative", "D": "expository"}, "answer": "D", "explanation": "The writer is explaining how poor old men live through each day. Therefore, the extract is expository.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>27", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question.    Here in the station it is no way different save that the city is busy in his snow. But the old men cling to their seats as though they were symbolic and could not be given up. Now ad then they sleep, their grey old heads resting with painful awkwardness  on the backs of the benches .             Also they are not at rest. For an hour they may sleep in the  gasping exhaustion of the ill-nourished and aged , who have to walk in the night. Then a police man comes by on his rounds and nudges them upright.       \"You can't sleep here\", he growls.       A strange ritual then begins. A n old man is difficult to wake. One man after a slight lurch, does not move at all, he sleeps on steadily. Once in a while, one of the sleepers will not wake, he will have had his wish to die in the great  droning  centre of the  hive  rather than in some lonely room fulfilled.  \" ....... on the backs of the benches\" illustrates", "images": [], "options": {"A": "synedoche", "B": "epithet", "C": "assonance", "D": "personification"}, "answer": "D", "explanation": "Personification refers to the transfer of human qualities to inanimate objects.  Humans, not inanimate objects like benches, have backs", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>28", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question.    Here in the station it is no way different save that the city is busy in his snow. But the old men cling to their seats as though they were symbolic and could not be given up. Now ad then they sleep, their grey old heads resting with painful awkwardness  on the backs of the benches .             Also they are not at rest. For an hour they may sleep in the  gasping exhaustion of the ill-nourished and aged , who have to walk in the night. Then a police man comes by on his rounds and nudges them upright.       \"You can't sleep here\", he growls.       A strange ritual then begins. A n old man is difficult to wake. One man after a slight lurch, does not move at all, he sleeps on steadily. Once in a while, one of the sleepers will not wake, he will have had his wish to die in the great  droning  centre of the  hive  rather than in some lonely room fulfilled.  The passage conveys a mood of", "images": [], "options": {"A": "defiance", "B": "hope", "C": "fear", "D": "despair"}, "answer": "D", "explanation": "The old men live their lives in a state of hopelessness of despair. This is evinced in the last sentence where it is reported that spome of them die in their sleep.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>29", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question.    Here in the station it is no way different save that the city is busy in his snow. But the old men cling to their seats as though they were symbolic and could not be given up. Now ad then they sleep, their grey old heads resting with painful awkwardness  on the backs of the benches .             Also they are not at rest. For an hour they may sleep in the  gasping exhaustion of the ill-nourished and aged , who have to walk in the night. Then a police man comes by on his rounds and nudges them upright.       \"You can't sleep here\", he growls.       A strange ritual then begins. A n old man is difficult to wake. One man after a slight lurch, does not move at all, he sleeps on steadily. Once in a while, one of the sleepers will not wake, he will have had his wish to die in the great  droning  centre of the  hive  rather than in some lonely room fulfilled.  \".......... gasping exhaustion of the ill-nourished and aged......\" infers", "images": [], "options": {"A": "helplessness", "B": "slowness", "C": "sadness", "D": "tiredness"}, "answer": "A", "explanation": "The old men have no hope and have resigned to fate in their state of penury.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>30", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the poem and answer this question.    Here in the station it is no way different save that the city is busy in his snow. But the old men cling to their seats as though they were symbolic and could not be given up. Now ad then they sleep, their grey old heads resting with painful awkwardness  on the backs of the benches .             Also they are not at rest. For an hour they may sleep in the  gasping exhaustion of the ill-nourished and aged , who have to walk in the night. Then a police man comes by on his rounds and nudges them upright.       \"You can't sleep here\", he growls.       A strange ritual then begins. A n old man is difficult to wake. One man after a slight lurch, does not move at all, he sleeps on steadily. Once in a while, one of the sleepers will not wake, he will have had his wish to die in the great  droning  centre of the  hive  rather than in some lonely room fulfilled.  \"droning\" and \"hive\" illustrates", "images": [], "options": {"A": "anecdote", "B": "epigram", "C": "allusion", "D": "epitaph"}, "answer": "C", "explanation": "This is a reference to bees. The sounds bees make while flying could be regarded as droning. A hive refers to where bees live.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2010>31", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    Your leave and favour to return to France;   From whence tho willingly i came to Denmark  To show my duty in your coronation,  Yet now, I must confess, that duty done.  My thought that wishes bend a gain towards France  And bow them to your gracious leave and pardon.  ( Act one, Scene two, lines 51-57)    The speaker is", "images": [], "options": {"A": "Laertes", "B": "Polinius", "C": "Hamlet", "D": "Claudius"}, "answer": "A", "explanation": "Laertes wishes to return to his abode, so he discusses this with the king in a bid to seek the king's permission.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>32", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    Your leave and favour to return to France;   From whence tho willingly i came to Denmark  To show my duty in your coronation,  Yet now, I must confess, that duty done.  My thought that wishes bend a gain towards France  And bow them to your gracious leave and pardon.  ( Act one, Scene two, lines 51-57)  The speaker is addressing", "images": [], "options": {"A": "Hamlet", "B": "Claudius", "C": "Horatio", "D": "Marcellus"}, "answer": "B", "explanation": "In the given extract, the speaker is addressing Claudius. This is because Laertes is asking for Claudius's permission to return to France.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>33", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    Your leave and favour to return to France;   From whence tho willingly i came to Denmark  To show my duty in your coronation,  Yet now, I must confess, that duty done.  My thought that wishes bend a gain towards France  And bow them to your gracious leave and pardon.  ( Act one, Scene two, lines 51-57)  \"Duty\" in the extract refers to", "images": [], "options": {"A": "job", "B": "faith", "C": "loyalty", "D": "task"}, "answer": "C", "explanation": "Duty, here, means loyalty. Laertes came from France solely to pledge his allegiance at Cllaudius during Claudius' coronation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>34", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    Your leave and favour to return to France;   From whence tho willingly i came to Denmark  To show my duty in your coronation,  Yet now, I must confess, that duty done.  My thought that wishes bend a gain towards France  And bow them to your gracious leave and pardon.  ( Act one, Scene two, lines 51-57)  The speaker intends to return to", "images": [], "options": {"A": "the seaside", "B": "the war front", "C": "Denmark", "D": "France"}, "answer": "D", "explanation": "Laertes came from France to Denmark and because his duty has been done, he intends to go back to France.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>35", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    Your leave and favour to return to France;   From whence tho willingly i came to Denmark  To show my duty in your coronation,  Yet now, I must confess, that duty done.  My thought that wishes bend a gain towards France  And bow them to your gracious leave and pardon.  ( Act one, Scene two, lines 51-57)  The other character present at the scene is", "images": [], "options": {"A": "Rosencrantz", "B": "Ophelia", "C": "Guildenstern", "D": "Polonius"}, "answer": "D", "explanation": "Polinius, Laertes' father is also present to ask the king for permission to leave on behalf of his son", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>36", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    Do not forget: this visitation  is but to what the almost blunted purpose  But, look, amazement as thy mother sits:  O,, step between her and her fighting soul;  (Act 3, scene four, lines 107 - 110)    The speaker is", "images": [], "options": {"A": "Claudius", "B": "Ghost", "C": "Gertrude", "D": "Horatio"}, "answer": "B", "explanation": "In the given extract from Hamlet, Act 3, scene four, lines 107 - 110, the speaker is the Ghost of Hamlet's father. The Ghost is urging Hamlet not to forget his purpose, which is to avenge his father's murder. Therefore, the correct answer is Ghost.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>37", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    Do not forget: this visitation  is but to what the almost blunted purpose  But, look, amazement as thy mother sits:  O,, step between her and her fighting soul;  (Act 3, scene four, lines 107 - 110)  The character being addressed is", "images": [], "options": {"A": "Polinius", "B": "Laertes", "C": "Ophelia", "D": "Hamlet"}, "answer": "D", "explanation": "In the given extract from Hamlet, Act 3, Scene 4, the character being addressed is Hamlet. The speaker is the Ghost of Hamlet's father, who is reminding Hamlet of his duty to avenge his father's murder. The reference to 'thy mother' indicates that the speaker is addressing Hamlet, as the mother referred to is Queen Gertrude, Hamlet's mother.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>38", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    Do not forget: this visitation  is but to what the almost blunted purpose  But, look, amazement as thy mother sits:  O,, step between her and her fighting soul;  (Act 3, scene four, lines 107 - 110)  The speech is made in the", "images": [], "options": {"A": "Queen's closet", "B": "Queen's room", "C": "hall", "D": "Palace"}, "answer": "B", "explanation": "The scene takes place in the queen's room. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>39", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    Do not forget: this visitation  is but to what the almost blunted purpose  But, look, amazement as thy mother sits:  O,, step between her and her fighting soul;  (Act 3, scene four, lines 107 - 110)  \" blunted purpose\" implies", "images": [], "options": {"A": "inactivity", "B": "blindness", "C": "happiness", "D": "tiredness"}, "answer": "A", "explanation": "In the context of the extract from Shakespeare's Hamlet, \"blunted purpose\" implies a lack of action or inactivity. The term 'blunted' is often used to describe something that has been dulled or is no longer sharp, in this case, it refers to Hamlet's purpose or resolve which has become less focused or intense, hence the term 'inactivity'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>40", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    Do not forget: this visitation  is but to what the almost blunted purpose  But, look, amazement as thy mother sits:  O,, step between her and her fighting soul;  (Act 3, scene four, lines 107 - 110)  \"fighting soul\" implies", "images": [], "options": {"A": "clear conscience", "B": "hope", "C": "fear", "D": "guilty conscience"}, "answer": "D", "explanation": "The ghost believes that when one does wrong the conscience serves as a judge, causing an internal battle within.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>41", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    If thou has any sound, or use of voice,  Speak to me;  If there be any good thing to be done,  Which, Happily, foreknowing may avoid,   O, speak!  Or if thou hast uphoarded in thy life  Extorted treasure in the womb of the earth,  For which, they say, you spirit oft work in death  Speak to it:  (Act 1, Scene one, lines 129 - 139)    The speaker is", "images": [], "options": {"A": "Hamlet", "B": "Marcellus", "C": "Horatio", "D": "Claudius"}, "answer": "C", "explanation": "While on guard, Horatio sees a ghost and speaks to it. This ghost turns out to be the previous king who was slain,.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>42", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    If thou has any sound, or use of voice,  Speak to me;  If there be any good thing to be done,  Which, Happily, foreknowing may avoid,   O, speak!  Or if thou hast uphoarded in thy life  Extorted treasure in the womb of the earth,  For which, they say, you spirit oft work in death  Speak to it:  (Act 1, Scene one, lines 129 - 139)  The character being addressed is", "images": [], "options": {"A": "the Queen", "B": "the Ghost", "C": "Bernado", "D": "Reynaldo"}, "answer": "B", "explanation": "In the given extract from Shakespeare's Hamlet, the character being addressed is the Ghost. In Act 1, Scene 1, Horatio is trying to communicate with the ghost of Hamlet's father. He is asking the ghost to speak if it has any information that could help them or if it has any hidden treasures. Therefore, the correct answer is the Ghost.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>43", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    If thou has any sound, or use of voice,  Speak to me;  If there be any good thing to be done,  Which, Happily, foreknowing may avoid,   O, speak!  Or if thou hast uphoarded in thy life  Extorted treasure in the womb of the earth,  For which, they say, you spirit oft work in death  Speak to it:  (Act 1, Scene one, lines 129 - 139)  The speech is made after", "images": [], "options": {"A": "the killing of Polinius", "B": "Hamlet's arrival of the place", "C": "the arrival of the players", "D": "the appearance of the ghost"}, "answer": "D", "explanation": "The extract is from Act 1, Scene 1 of Shakespeare's Hamlet. In this scene, the ghost of Hamlet's father appears to Hamlet and his friends. The lines are spoken by Hamlet, who is urging the ghost to speak to him. Therefore, the speech is made after the appearance of the ghost.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>44", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    If thou has any sound, or use of voice,  Speak to me;  If there be any good thing to be done,  Which, Happily, foreknowing may avoid,   O, speak!  Or if thou hast uphoarded in thy life  Extorted treasure in the womb of the earth,  For which, they say, you spirit oft work in death  Speak to it:  (Act 1, Scene one, lines 129 - 139)  The speaker's mood is one of", "images": [], "options": {"A": "anger", "B": "regret", "C": "anxiety", "D": "disappointment"}, "answer": "C", "explanation": "In the given extract, Hamlet is speaking to the ghost of his father. He is urging the ghost to speak to him, to tell him if there is anything he can do to help or any danger he can avoid. This shows that Hamlet is anxious. He is worried about what the ghost might tell him and eager to do whatever he can to help. Therefore, the speaker's mood is one of anxiety.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>45", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Hamlet    Read the extract and answer this question.    If thou has any sound, or use of voice,  Speak to me;  If there be any good thing to be done,  Which, Happily, foreknowing may avoid,   O, speak!  Or if thou hast uphoarded in thy life  Extorted treasure in the womb of the earth,  For which, they say, you spirit oft work in death  Speak to it:  (Act 1, Scene one, lines 129 - 139)  During the speech,", "images": [], "options": {"A": "the palace soldiers arrived", "B": "Hamlet attacked the speaker", "C": "the queen fainted", "D": "the cock crowed"}, "answer": "D", "explanation": "Speak to me   - line 130   'cock crows'   If there be any good thing to be done - line 131", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>46", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet    Read the extract and answer questions 46-50    And can you, by no drift of circumstance,  get from him why he put on this confusion,  Grating so harshly all his days of quiet  With turbukent and dangerous lunacy?  (Act 3, scene one, lines 1-4)    The speaker is", "images": [], "options": {"A": "Gertrude", "B": "Ophelia", "C": "Claudius", "D": "Polinius"}, "answer": "C", "explanation": "The speaker in the given extract is asking someone to find out why Hamlet is acting in a confused and dangerous manner. This is a conversation between King Claudius and Queen Gertrude, where Claudius is the speaker. Therefore, the correct answer is Claudius.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>47", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet    Read the extract and answer questions 46-50    And can you, by no drift of circumstance,  get from him why he put on this confusion,  Grating so harshly all his days of quiet  With turbukent and dangerous lunacy?  (Act 3, scene one, lines 1-4)  The character being discussed is", "images": [], "options": {"A": "Voltimand", "B": "Hamlet", "C": "Ophelia", "D": "Rosencrantz"}, "answer": "B", "explanation": "The words, 'confusion' and 'lunacy', here refer to Hamlet's madness. Note that Hamlet is pretending to be insane.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>48", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet    Read the extract and answer questions 46-50    And can you, by no drift of circumstance,  get from him why he put on this confusion,  Grating so harshly all his days of quiet  With turbukent and dangerous lunacy?  (Act 3, scene one, lines 1-4)  The characters being addressed are", "images": [], "options": {"A": "Mercullus and Horatio", "B": "Bernado and Francisco", "C": "Rosencrantz and Giuldenstein", "D": "Mercullus and Francisco"}, "answer": "C", "explanation": "In Act 3, Scene 1, King Claudius and Queen Gertrude ask Rosencrantz and Guildenstern to find out what is causing Hamlet's strange behavior.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>49", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet    Read the extract and answer questions 46-50    And can you, by no drift of circumstance,  get from him why he put on this confusion,  Grating so harshly all his days of quiet  With turbukent and dangerous lunacy?  (Act 3, scene one, lines 1-4)  The response given to the speech indicates that the attempt was", "images": [], "options": {"A": "unsuccessful", "B": "successful", "C": "progressing", "D": "dangerous"}, "answer": "A", "explanation": "The tone of the extract suggests that the attempt to understand why the character is behaving in a confused and turbulent manner was not successful.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2010>50", "subject": "Literature", "year": "2010", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPARE: Hamlet    Read the extract and answer questions 46-50    And can you, by no drift of circumstance,  get from him why he put on this confusion,  Grating so harshly all his days of quiet  With turbukent and dangerous lunacy?  (Act 3, scene one, lines 1-4)  The enquiry is about", "images": [], "options": {"A": "Hamlet", "B": "Laertes", "C": "Ophelia", "D": "Horatio"}, "answer": "A", "explanation": "The extract is from the play 'Hamlet' by William Shakespeare, and the character who is behaving in a confused and turbulent manner is Hamlet.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>1", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The protagonist is the", "images": [], "options": {"A": "author", "B": "villian", "C": "hero", "D": "speaker"}, "answer": "C", "explanation": "The protagonist is the major character in a literary work. Another name for such character is hero/heroine.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2011>2", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "As chapter is to prose, so _____________ is to poetry", "images": [], "options": {"A": "couplet", "B": "stanza", "C": "line", "D": "chorus"}, "answer": "B", "explanation": "Stanza is a group of line which form a division of a poem. Prose, on the other hand, is divided into chapters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>3", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Verbal irony occurs when a speaker on stage", "images": [], "options": {"A": "says the opposite of what the speaker means", "B": "is misunderstood", "C": "tried to deceive the audience", "D": "is alone"}, "answer": "A", "explanation": "Verbal irony is a figure of speech in which what is said is the opposite of what is meant. It is often used for dramatic or comedic effect. Therefore, the correct answer is 'says the opposite of what the speaker means'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>4", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A humorous scene in a play intended to ease tension is", "images": [], "options": {"A": "climax", "B": "tragi-comedy", "C": "comedy", "D": "comic relief"}, "answer": "D", "explanation": "Comic relief refers to a humourous scene in a tragedy that is done for the sole aim of reducing the tension.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>5", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN PROSE", "question": "A dead metaphor is one that is", "images": [], "options": {"A": "overused and ineffective", "B": "extended in meaning", "C": "implied", "D": "mixed"}, "answer": "A", "explanation": "When a metaphor has been overused to the extent that it has lost its meaning, such metaphor is regarded as a dead metaphor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>6", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "My \"love is as deep as the sea\" is an example of", "images": [], "options": {"A": "hyperbole", "B": "litotes", "C": "euphemism", "D": "paradox"}, "answer": "A", "explanation": "Hyperbole: This is a form of exaggeration done in order to emphasise a thing. Here, the speaker describes the love he has for someone to be as deep as the sea.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2011>7", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Through the trees, I'll hear a single ringing sound, a cowbell JINGLE. The text in capital illustrate ...... rhyme", "images": [], "options": {"A": "end", "B": "decasyllabic", "C": "internal", "D": "diameter"}, "answer": "C", "explanation": "The text in capital letters illustrates an internal rhyme. An internal rhyme is a rhyme that occurs within a single line of verse, or between internal phrases across multiple lines. In this case, 'single' and 'jingle' rhyme within the same line.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>8", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary work is a satire when it", "images": [], "options": {"A": "finds fault", "B": "humorously criticises to improve a situation", "C": "provokes laughter", "D": "teaches a lesson for social improvement"}, "answer": "B", "explanation": "A literary work is a satire when it humorously criticises to improve a situation. Satire is a genre of literature that uses humor, irony, exaggeration, or ridicule to expose and criticize people's stupidity or vices, particularly in the context of contemporary politics and other topical issues.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>9", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Foreshadowing is a device used to", "images": [], "options": {"A": "prepare the render for the direction a plot will take", "B": "introduce the plot", "C": "shed light on events through background information", "D": "recall the past"}, "answer": "A", "explanation": "Forshadowing is used to describe events that are yet to take place in a story. This device is used to predict future events.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>10", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A mountain of fufu was placed before the hungry visitors. The device used above is", "images": [], "options": {"A": "hyperbole", "B": "euphemism", "C": "alliteration", "D": "assonance"}, "answer": "A", "explanation": "The phrase 'A mountain of fufu was placed before the hungry visitors' is an example of hyperbole. Hyperbole is a figure of speech that involves exaggeration of ideas for the sake of emphasis. In this case, the quantity of fufu is exaggerated as a 'mountain' to emphasize the large amount of food.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2011>11", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The pattern of beats to denote movement in poetry is", "images": [], "options": {"A": "refrain", "B": "metre", "C": "rhyme", "D": "scansion"}, "answer": "B", "explanation": "The pattern of beats in poetry is referred to as 'metre'. This is the basic rhythmic structure of a verse or lines in verse. It involves stressed and unstressed syllables. The other options do not correctly define the pattern of beats in poetry. 'Refrain' is a repeated line or number of lines in a poem or song, typically at the end of each verse. 'Rhyme' is a correspondence of sound between words or the endings of words, especially when these are used at the ends of lines of poetry. 'Scansion' is the action of scanning a line of verse to determine its rhythm.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>12", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Here lies our sovereign lord the king    Whose word no man relies on    Who never said a foolish thing    And never did a wise one     The extract is an example of a/an", "images": [], "options": {"A": "dirge", "B": "epigram", "C": "oxymoron", "D": "parody"}, "answer": "B", "explanation": "The extract is an example of an 'epigram'. An epigram is a pithy saying or remark expressing an idea in a clever and amusing way. It often includes a twist of some sort at the end, which is evident in the extract. The other options do not correctly define the extract. A 'dirge' is a lament for the dead, especially one forming part of a funeral rite. An 'oxymoron' is a figure of speech in which apparently contradictory terms appear in conjunction. A 'parody' is an imitation of the style of a particular writer, artist, or genre with deliberate exaggeration for comic effect.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>13", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Here lies our sovereign lord the king    Whose word no man relies on    Who never said a foolish thing    And never did a wise one   The tone of the extract is one of", "images": [], "options": {"A": "anger", "B": "pity", "C": "sarcasm", "D": "indifference"}, "answer": "C", "explanation": "Sarcasm is a scornful or ironic remark that is made to hurt the feelings of another. The writer is obviously scornful towards the king because the king did not have any memorable achievement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>14", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Here lies our sovereign lord the king    Whose word no man relies on    Who never said a foolish thing    And never did a wise one   A poem whose shape resembles the object described is a/an", "images": [], "options": {"A": "emblematic", "B": "romantic poem", "C": "elegy", "D": "sonnet"}, "answer": "A", "explanation": "Gotten from the word 'emblem' which serves as a symbol of a particular concept. This is also called concrete poetry.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>15", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The omniscient narrator is", "images": [], "options": {"A": "all knowing", "B": "limited", "C": "realistic", "D": "always humorous"}, "answer": "A", "explanation": "The omniscient narrator is all-knowing. He tells us the actions of the characters as well as their thoughts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2011>16", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Which of the following does not define a character?", "images": [], "options": {"A": "The way the character appears", "B": "What the character says", "C": "What others says about the character", "D": "What the character does"}, "answer": "A", "explanation": "Options B, C, D are the most common ways of character identification.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>17", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A bard is a", "images": [], "options": {"A": "novelist", "B": "playwright", "C": "poet", "D": "narrator"}, "answer": "C", "explanation": "A bard is a poet. The term 'bard' originally comes from the Celtic language and was used to refer to a professional story teller, verse-maker, music composer, oral historian and genealogist, employed by a patron (such as a monarch or noble) to commemorate the patron's ancestors and to praise the patron's own activities. In modern times, the term is often used to refer to any poet, especially a lyric poet.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2011>18", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary work that vividly portrays life can be described as", "images": [], "options": {"A": "realistic", "B": "romantic", "C": "idealistic", "D": "sarcastic"}, "answer": "A", "explanation": "Realism is a feature of literature that deals with the representation of life. It is often used interchangeably with MIMESIS (the imitation of life).  Romance, as regards to prose, relates to unrealistic events. In poetry, it is seen in tyerms of its deification of nature.  Idealism has to do with the belie that everything is perfect.  Sarcasm is a form of irony that is used with the intention of hurting the feelings of the person being addressed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>19", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Which of the following is not a type of play?", "images": [], "options": {"A": "Tragedy", "B": "Tragic flaw", "C": "Comedy", "D": "Tragic-comedy"}, "answer": "B", "explanation": "Tragic flaw is not a type of play; rather, it is a concept used in a tragedy to to describe the weakness or mistake made by the tragic hero.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>20", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The attitude of an author towards the subject matter is", "images": [], "options": {"A": "theme", "B": "tone", "C": "style", "D": "setting"}, "answer": "B", "explanation": "The tone refers to the attitude of hte writer towards the subject matter.  Theme is the central idea.  The style refers to all the techniques that are deployed by a writer to pass across his message.  The setting is the time and place of the action.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>21", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Each profession, intellectual or manual, deserves consideration, whether it requires painful effort or manual dexterity, wide knowledge or the patience of an ant. Ours, like that of the doctor, does not allow for any mistake. You don't joke with life, and life is both body and mind. To warp a soul is as much as a sacrilege as murder. Teachers - at kindergarten level, as at university level - form a noble army accomplishing daily feats, never praised never decorated. An army forever on the move, forever vigilant: an army without drums, without gleaming uniforms.    This army, thwarting traps and snares, everywhere plants the flag of knowledge and morality.    The writer's mood is that of", "images": [], "options": {"A": "excitement", "B": "optimism", "C": "indifference", "D": "frustration"}, "answer": "D", "explanation": "The dominant mood is that of frustration. The speaker is embittered by the fact that teachers are not given the recognition they deserve. The extract below proves this:  '... never praised never decorated'  '... an army without drums, without gleaming uniforms'", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>22", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Each profession, intellectual or manual, deserves consideration, whether it requires painful effort or manual dexterity, wide knowledge or the patience of an ant. Ours, like that of the doctor, does not allow for any mistake. You don't joke with life, and life is both body and mind. To warp a soul is as much as a sacrilege as murder. Teachers - at kindergarten level, as at university level - form a noble army accomplishing daily feats, never praised never decorated. An army forever on the move, forever vigilant: an army without drums, without gleaming uniforms.    This army, thwarting traps and snares, everywhere plants the flag of knowledge and morality.   The writer of the passage is a", "images": [], "options": {"A": "doctor", "B": "soldier", "C": "teacher", "D": "student"}, "answer": "C", "explanation": "The writer is obviously a teacher, and this explains why he is frustrated at the way teachers are not rated highly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>23", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Each profession, intellectual or manual, deserves consideration, whether it requires painful effort or manual dexterity, wide knowledge or the patience of an ant. Ours, like that of the doctor, does not allow for any mistake. You don't joke with life, and life is both body and mind. To warp a soul is as much as a sacrilege as murder. Teachers - at kindergarten level, as at university level - form a noble army accomplishing daily feats, never praised never decorated. An army forever on the move, forever vigilant: an army without drums, without gleaming uniforms.    This army, thwarting traps and snares, everywhere plants the flag of knowledge and morality.   The dominant image in the passage is that of", "images": [], "options": {"A": "soldiery", "B": "machine", "C": "religion", "D": "education"}, "answer": "A", "explanation": "The dominant mental picture in the passage is that of soldiering. Teachers are compared to soldiers; howbeit, soldiers that are not recognised or valued.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>24", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Each profession, intellectual or manual, deserves consideration, whether it requires painful effort or manual dexterity, wide knowledge or the patience of an ant. Ours, like that of the doctor, does not allow for any mistake. You don't joke with life, and life is both body and mind. To warp a soul is as much as a sacrilege as murder. Teachers - at kindergarten level, as at university level - form a noble army accomplishing daily feats, never praised never decorated. An army forever on the move, forever vigilant: an army without drums, without gleaming uniforms.    This army, thwarting traps and snares, everywhere plants the flag of knowledge and morality.   The underlined illustrates", "images": [], "options": {"A": "antithesis", "B": "allusion", "C": "parallelism", "D": "parody"}, "answer": "A", "explanation": "The underlined expression is antithetical in that the statements in it contrast. Firstly, the teachers are presented as marching soldier, and later, they are portrayed as soldiers without any form of glory: \"without uniforms\", \"without drums\".", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>25", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Each profession, intellectual or manual, deserves consideration, whether it requires painful effort or manual dexterity, wide knowledge or the patience of an ant. Ours, like that of the doctor, does not allow for any mistake. You don't joke with life, and life is both body and mind. To warp a soul is as much as a sacrilege as murder. Teachers - at kindergarten level, as at university level - form a noble army accomplishing daily feats, never praised never decorated. An army forever on the move, forever vigilant: an army without drums, without gleaming uniforms.    This army, thwarting traps and snares, everywhere plants the flag of knowledge and morality.   \"The flag of knowledge and morality\" illustrates", "images": [], "options": {"A": "euphemism", "B": "litotes", "C": "metaphor", "D": "metonymy"}, "answer": "C", "explanation": "The phrase 'The flag of knowledge and morality' is a metaphor. A metaphor is a figure of speech that makes a comparison between two things that are basically dissimilar. In this case, the 'flag of knowledge and morality' is compared to the teachings and values imparted by teachers, which is not literally a flag.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>26", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Here stood our ancestral home    The crumbling wall marks the spot    Here a sheep was led to the slaughter    To appease the gods and atone    For faults which our destiny    Has blossomed into crimes    There my cursed father once stood    And shouted to us, his children    To come back from our play    To our evening meal and sleep.    The mood of the poem is", "images": [], "options": {"A": "hopeful", "B": "joyful", "C": "nostalgic", "D": "exciting"}, "answer": "C", "explanation": "The mood of the poem is nostalgic. The mood in literature is the atmosphere or pervasive feeling of a work. Nostalgia is a sentimental longing or wistful affection for a period in the past. The poem reflects on the past, the ancestral home, and past events, which creates a nostalgic mood.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>27", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Here stood our ancestral home    The crumbling wall marks the spot    Here a sheep was led to the slaughter    To appease the gods and atone    For faults which our destiny    Has blossomed into crimes    There my cursed father once stood    And shouted to us, his children    To come back from our play    To our evening meal and sleep.   The sheep was led to the slaughter", "images": [], "options": {"A": "to prepare their evening meal", "B": "because it was a troublesome sheep", "C": "because their father was a teacher", "D": "as a sacrifice to their gods"}, "answer": "D", "explanation": "The extract means that the sheep was offered as a sacrifice to the gods.  'To appease the gods and atone'", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>28", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Here stood our ancestral home    The crumbling wall marks the spot    Here a sheep was led to the slaughter    To appease the gods and atone    For faults which our destiny    Has blossomed into crimes    There my cursed father once stood    And shouted to us, his children    To come back from our play    To our evening meal and sleep.   \"To appease to gods............\" implies", "images": [], "options": {"A": "seeking the favour of the gods", "B": "offering meals to the gods", "C": "accusing the gods for their misfortune", "D": "reciting incantations to the gods"}, "answer": "A", "explanation": "The phrase 'To appease the gods' implies that the action taken (in this case, the slaughtering of a sheep) is done to seek the favour of the gods. This is a common practice in many religions where sacrifices or offerings are made to gods in order to gain their favour or appease them. The other options do not accurately reflect the meaning of the phrase in the context of the poem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>29", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Here stood our ancestral home    The crumbling wall marks the spot    Here a sheep was led to the slaughter    To appease the gods and atone    For faults which our destiny    Has blossomed into crimes    There my cursed father once stood    And shouted to us, his children    To come back from our play    To our evening meal and sleep.   The crumbling wall marks the spot   The underlined means that", "images": [], "options": {"A": "they were living in a house with a high wall", "B": "their building is no longer where it used to be", "C": "the children had caused the wall to crumble", "D": "their father made them pull down the wall"}, "answer": "B", "explanation": "The phrase 'The crumbling wall marks the spot' is a metaphorical way of saying that the location of their ancestral home is now marked by a crumbling wall, indicating that the building is no longer where it used to be. This suggests that the building has either been destroyed or has deteriorated over time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>30", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Here stood our ancestral home    The crumbling wall marks the spot    Here a sheep was led to the slaughter    To appease the gods and atone    For faults which our destiny    Has blossomed into crimes    There my cursed father once stood    And shouted to us, his children    To come back from our play    To our evening meal and sleep.   The image used in line six is taken from", "images": [], "options": {"A": "war", "B": "the moon", "C": "flowers", "D": "prison"}, "answer": "C", "explanation": "The image used in line six 'For faults which our destiny has blossomed into crimes' is a metaphor taken from flowers. The word 'blossomed' is typically used to describe the process of a flower opening or a person developing in a promising or healthy way. In this context, it is used to describe how their destiny has developed into crimes, suggesting a negative transformation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>31", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Be not afraid: the isle is full of noises    Sounds and sweet airs, that give delight and hurt not.    Sometimes a thousand twangling instruments    Will hum about mine ears, and sometime voices    That, if then had waked after long sleep,    Will make me sleep again. And then, in dreaming ,   The clouds methought would open, and show riches    Ready to drop upon me; that, when I waked,    I cried to dream again    (Act III, Scene Two, Lines 132-140)    The speaker is", "images": [], "options": {"A": "Ferdinand", "B": "Gonzalo", "C": "Alonso", "D": "Caliban"}, "answer": "D", "explanation": "Caliban reassures Stephano and Trinculo not to panic as a result of the music they hear because the sound of music is a regular occurence on the island.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>32", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Be not afraid: the isle is full of noises    Sounds and sweet airs, that give delight and hurt not.    Sometimes a thousand twangling instruments    Will hum about mine ears, and sometime voices    That, if then had waked after long sleep,    Will make me sleep again. And then, in dreaming ,   The clouds methought would open, and show riches    Ready to drop upon me; that, when I waked,    I cried to dream again    (Act III, Scene Two, Lines 132-140)   The character addressed is", "images": [], "options": {"A": "Harotio", "B": "Caliban", "C": "Stephano", "D": "Ferdinand"}, "answer": "C", "explanation": "The character addressed in these lines is Stephano. Caliban is trying to convince Stephano (and Trinculo) that the island is a wonderful place, not a place to be feared. He is doing this in an attempt to persuade Stephano to kill Prospero, the magician who has enslaved him.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>33", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Be not afraid: the isle is full of noises    Sounds and sweet airs, that give delight and hurt not.    Sometimes a thousand twangling instruments    Will hum about mine ears, and sometime voices    That, if then had waked after long sleep,    Will make me sleep again. And then, in dreaming ,   The clouds methought would open, and show riches    Ready to drop upon me; that, when I waked,    I cried to dream again    (Act III, Scene Two, Lines 132-140)   The speaker is a", "images": [], "options": {"A": "carnivore", "B": "savage", "C": "sailor", "D": "devourer"}, "answer": "B", "explanation": "The speaker in the given extract is Caliban, a character from Shakespeare's play 'The Tempest'. Caliban is often described as a savage or a wild man, due to his uncivilized behavior and his status as a servant on the island. He is not a carnivore, sailor, or devourer, which makes option 2 the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>34", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Be not afraid: the isle is full of noises    Sounds and sweet airs, that give delight and hurt not.    Sometimes a thousand twangling instruments    Will hum about mine ears, and sometime voices    That, if then had waked after long sleep,    Will make me sleep again. And then, in dreaming ,   The clouds methought would open, and show riches    Ready to drop upon me; that, when I waked,    I cried to dream again    (Act III, Scene Two, Lines 132-140)   What are 'noises' in the extract?", "images": [], "options": {"A": "shouting", "B": "clapping", "C": "thunder", "D": "music"}, "answer": "D", "explanation": "The noises are in the form of music. Ariel who is invisible to the characters on the scene plays a tune into their ears.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>35", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Be not afraid: the isle is full of noises    Sounds and sweet airs, that give delight and hurt not.    Sometimes a thousand twangling instruments    Will hum about mine ears, and sometime voices    That, if then had waked after long sleep,    Will make me sleep again. And then, in dreaming ,   The clouds methought would open, and show riches    Ready to drop upon me; that, when I waked,    I cried to dream again    (Act III, Scene Two, Lines 132-140)   Another character present is", "images": [], "options": {"A": "Trinculo", "B": "Ferdinand", "C": "Miranda", "D": "Prospero"}, "answer": "A", "explanation": "After the shipwreck, Sabestian and Trinculo meets Caliban on the Island and they all plot to take over the island by killing Prospero..", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>36", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Faith, sir, you need not fear. When we were boys,    Who would believe that there were mountaineers    Dew-lapped like bulls, whose throats had hanging at 'em    Wallets of flesh? or that there were such men    Whose heads stood in their breasts? which now we find    Each putter-out of five for one will bring us    Good warrant of.    (act III, scene Three, lines 44-49)    The speaker is", "images": [], "options": {"A": "Gonzalo", "B": "Stephano", "C": "ferdinand", "D": "Caliban"}, "answer": "A", "explanation": "The excerpt is a dialogue by Gonzalo in Shakespeare's 'The Tempest'. Therefore, the correct option is Gonzalo.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>37", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Faith, sir, you need not fear. When we were boys,    Who would believe that there were mountaineers    Dew-lapped like bulls, whose throats had hanging at 'em    Wallets of flesh? or that there were such men    Whose heads stood in their breasts? which now we find    Each putter-out of five for one will bring us    Good warrant of.    (act III, scene Three, lines 44-49)   The character addressed is", "images": [], "options": {"A": "Sebastian", "B": "Ferdinand", "C": "Gonzalo", "D": "Alonso"}, "answer": "D", "explanation": "Sabestian suggests they eat the meal but Alonso refuses showing fear.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>38", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Faith, sir, you need not fear. When we were boys,    Who would believe that there were mountaineers    Dew-lapped like bulls, whose throats had hanging at 'em    Wallets of flesh? or that there were such men    Whose heads stood in their breasts? which now we find    Each putter-out of five for one will bring us    Good warrant of.    (act III, scene Three, lines 44-49)   In the extract a .............. is laid before them", "images": [], "options": {"A": "problem", "B": "banquet", "C": "bed", "D": "gift"}, "answer": "B", "explanation": "In the extract, a banquet is laid before them. This is also from the context of the play 'The Tempest'. In Act III, Scene Three, a magical banquet is laid before Alonso, Sebastian, Antonio, and Gonzalo by Ariel (under Prospero's orders). The banquet is a part of Prospero's plan to torment his enemies.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>39", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Faith, sir, you need not fear. When we were boys,    Who would believe that there were mountaineers    Dew-lapped like bulls, whose throats had hanging at 'em    Wallets of flesh? or that there were such men    Whose heads stood in their breasts? which now we find    Each putter-out of five for one will bring us    Good warrant of.    (act III, scene Three, lines 44-49)   \"Dew-lapped like bulls\" refers to the", "images": [], "options": {"A": "mountaineers", "B": "people of the land", "C": "savages", "D": "islanders"}, "answer": "C", "explanation": "This description fits how civilised men see people who still live in uncivilized places like Prospero's Island", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>40", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Faith, sir, you need not fear. When we were boys,    Who would believe that there were mountaineers    Dew-lapped like bulls, whose throats had hanging at 'em    Wallets of flesh? or that there were such men    Whose heads stood in their breasts? which now we find    Each putter-out of five for one will bring us    Good warrant of.    (act III, scene Three, lines 44-49)   What happens to the spirits?", "images": [], "options": {"A": "They are killed", "B": "They stay on", "C": "They served Prospero", "D": "They disappeared"}, "answer": "C", "explanation": "When Prospero gets to the Island, he uses the magic to make the spirits subject to him", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>41", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Tell me, heavenly bow,    If Venus or her son, as thou dost know,    Do now attend the queen? Since they did plot    The means that dusky Dis my daughter got,    Her and her blind boy's scandalled company    I have forsworn      (Act IV, Scene One, line 86 - 91)    The speaker is", "images": [], "options": {"A": "Ferdinand", "B": "Miranda", "C": "Ceres", "D": "iris"}, "answer": "C", "explanation": "The speaker of these lines is Ceres. She is speaking about Venus and her son Cupid, who she believes have conspired to make her daughter, Proserpina, fall in love with Pluto (also known as Dis), the god of the underworld.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>42", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Tell me, heavenly bow,    If Venus or her son, as thou dost know,    Do now attend the queen? Since they did plot    The means that dusky Dis my daughter got,    Her and her blind boy's scandalled company    I have forsworn      (Act IV, Scene One, line 86 - 91)  The character addressed is", "images": [], "options": {"A": "Caliban", "B": "Iris", "C": "Ceres", "D": "Venus"}, "answer": "B", "explanation": "They have all been called by Prospero concerning the union of his daughter and Ferdinand. Iris and Ceres are good spirits of the Island", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>43", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Tell me, heavenly bow,    If Venus or her son, as thou dost know,    Do now attend the queen? Since they did plot    The means that dusky Dis my daughter got,    Her and her blind boy's scandalled company    I have forsworn      (Act IV, Scene One, line 86 - 91)  The purpose of the gathering is to", "images": [], "options": {"A": "settle a dispute between Prospero and his brother", "B": "punish Miranda for running away with Stephano", "C": "Set Ariel free from his burden", "D": "Celebrate the betrothal of Ferdinand and Miranda"}, "answer": "D", "explanation": "Prospero, having  confirmed that Ferdinand truly loves his daughter, approves their marriage. Hence, the gathering is done to celebrate their bethrotal.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>44", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Tell me, heavenly bow,    If Venus or her son, as thou dost know,    Do now attend the queen? Since they did plot    The means that dusky Dis my daughter got,    Her and her blind boy's scandalled company    I have forsworn      (Act IV, Scene One, line 86 - 91)  \"heavenly bow\" refers to", "images": [], "options": {"A": "sailor", "B": "king", "C": "spirit", "D": "man"}, "answer": "C", "explanation": "In the given lines, 'heavenly bow' is a reference to Juno, the Roman goddess of marriage and childbirth, who is often associated with the rainbow. Juno is a spirit, not a sailor, king, or man. Therefore, the correct answer is option 3.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>45", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "... The Duke of Milan    And his more braver daughter could control thee.    If now't were fit to do't. At the first sight    They have changed eyes. Delicate Ariel,    I'll set thee free for this!     (Act I, Scene Two, lines 441 - 445)    The character who secretly watches and listen is   The speaker is", "images": [], "options": {"A": "Ceres", "B": "Iris", "C": "Ariel", "D": "Juno"}, "answer": "B", "explanation": "Ceres calls Iris heavenly bow. Iris is a spirit. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2011>46", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "... The Duke of Milan    And his more braver daughter could control thee.    If now't were fit to do't. At the first sight    They have changed eyes. Delicate Ariel,    I'll set thee free for this!     (Act I, Scene Two, lines 441 - 445)  The speaker is", "images": [], "options": {"A": "Miranda", "B": "Ferdinand", "C": "Prospero", "D": "Caliban"}, "answer": "C", "explanation": "The speaker in this context is Prospero. Prospero is the rightful Duke of Milan in Shakespeare's play 'The Tempest'. He is speaking to Ariel about the Duke of Milan and his daughter, and promising to set Ariel free.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>47", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "... The Duke of Milan    And his more braver daughter could control thee.    If now't were fit to do't. At the first sight    They have changed eyes. Delicate Ariel,    I'll set thee free for this!     (Act I, Scene Two, lines 441 - 445)  \"Thee\" in line two refers to", "images": [], "options": {"A": "Prospero", "B": "Sabastian", "C": "Ferdinand", "D": "Antonio"}, "answer": "C", "explanation": "In the given excerpt from Act I, Scene Two, lines 441 - 445, \"Thee\" in line two refers to Ariel, the spirit servant of Prospero. However, Ariel is not an option in the given choices. The closest character to Ariel in the context of the play is Ferdinand, who is the one being controlled by Prospero and his daughter, Miranda. Therefore, the answer is Ferdinand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>48", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "... The Duke of Milan    And his more braver daughter could control thee.    If now't were fit to do't. At the first sight    They have changed eyes. Delicate Ariel,    I'll set thee free for this!     (Act I, Scene Two, lines 441 - 445)  What does \"they have changed eyes\" mean?", "images": [], "options": {"A": "They have exchanged looks at each other", "B": "They have met before", "C": "They have fallen in love", "D": "They have lost sight"}, "answer": "C", "explanation": "Ferdinand and Miranda falls in love immediately they set eyes on each other.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>49", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "... The Duke of Milan    And his more braver daughter could control thee.    If now't were fit to do't. At the first sight    They have changed eyes. Delicate Ariel,    I'll set thee free for this!     (Act I, Scene Two, lines 441 - 445)  \"They\" in the extract refers to", "images": [], "options": {"A": "Prospero and Ariel", "B": "Prospero and Miranda", "C": "Ferdinand and Miranda", "D": "Ariel and Ferdinand"}, "answer": "C", "explanation": "Prospero's daughter, Miranda and Alonso's son, Ferdinand are the ones being referred to, for they are in love.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2011>50", "subject": "Literature", "year": "2011", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "... The Duke of Milan    And his more braver daughter could control thee.    If now't were fit to do't. At the first sight    They have changed eyes. Delicate Ariel,    I'll set thee free for this!     (Act I, Scene Two, lines 441 - 445)  The character addressed", "images": [], "options": {"A": "Prospero", "B": "Miranda", "C": "Sebastian", "D": "Ariel"}, "answer": "D", "explanation": "In the given extract, the character being addressed is Ariel. This is evident from the line 'Delicate Ariel, I'll set thee free for this!'. Therefore, the correct answer is 'Ariel'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>1", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A story which explains a natural phenomenon is", "images": [], "options": {"A": "legend", "B": "parable", "C": "myth", "D": "fiction"}, "answer": "C", "explanation": "A myth explains a natural phenomenon. It is a story that has no historical backing but is believed to be true by a particular set of people and is oftrn passed from one generation to another.  A legend is a story that has been exaggerated. Unlike the myth, legends have historical proofs or backing.  A parable is a short story that teaches a religious or moral lesson.  Fiction is a type of prose whereby the actions and the characters are the result of the creative imagination of the author.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>2", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A narrative in which characters and events are invented is", "images": [], "options": {"A": "fiction", "B": "epistolary", "C": "autobiography", "D": "biography"}, "answer": "A", "explanation": "Fiction is a type of prose whereby the actions and the characters are the result of the creative imagination of the author.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>3", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Lines and stanzas are to poetry as action and dialogue are to", "images": [], "options": {"A": "music", "B": "prose", "C": "fiction", "D": "drama"}, "answer": "D", "explanation": "Drama differs from other genres in that it exists mainly in action and dialogue. Prose is usually in the form of narration while poetry is in verse form.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>4", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The performers in a play constitute the", "images": [], "options": {"A": "chorus", "B": "characters", "C": "audience", "D": "cast"}, "answer": "B", "explanation": "Characters are the human, non-human or supernatural beings that perform all the events that took place in a play.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2012>5", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Truth may blend but will never break:    It will ever rise above falsehood as oil above water    The alliteration in the first line", "images": [], "options": {"A": "draws attention to the key ideas", "B": "draws attention to the rhythm of the line", "C": "makes the idea sound more true", "D": "makes the line sound more pleasant"}, "answer": "D", "explanation": "When 'b' alliterates it emphasizes the pleasing tone and feeling intended by the poet.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>6", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Truth may blend but will never break:    It will ever rise above falsehood as oil above water   The simile in the second line", "images": [], "options": {"A": "expresses the idea more vividly", "B": "tells one that oil is heavier than water", "C": "makes a comparison between oil and water", "D": "express the idea in a complex manner"}, "answer": "C", "explanation": "Simile shows comparison with the use of 'like' or 'has'. Here, water and oil are compared", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>7", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The types of literary work are", "images": [], "options": {"A": "eras", "B": "episodes", "C": "genres", "D": "cantos"}, "answer": "C", "explanation": "The types of literary work are referred to as genres. Genres are categories of literary composition. Different genres have different styles, forms, and subjects. For example, drama, poetry, and novel are all genres of literature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2012>8", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The choice of words to create special effects is called", "images": [], "options": {"A": "fallacy", "B": "atmosphere", "C": "diction", "D": "mood"}, "answer": "C", "explanation": "Diction refers to a writer's choice of words.  Every writer, poet or playwright has a peculiar group of selected words which may be simple or complex, to pass across messages", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>9", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN PROSE", "question": "The long narrative chronicling a family's heroic deeds is a/an", "images": [], "options": {"A": "opera", "B": "epistle", "C": "fable", "D": "saga"}, "answer": "D", "explanation": "Saga is a long story of heroic deeds.  Opera is a form of drama whereby dialogue is presented in the form of music.  Epistle is a piece of writing that is written in the form of a letter.  A fable is a story that uses animals as characters.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2012>10", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Those that I fight I do not hate ,  Those that I guard, I do not love;\"    The above lines illustrates", "images": [], "options": {"A": "paradox", "B": "euphemism", "C": "personification", "D": "metonymy"}, "answer": "A", "explanation": "The lines illustrate a paradox. A paradox is a statement or proposition that, despite sound (or apparently sound) reasoning from acceptable premises, leads to a conclusion that seems senseless, logically unacceptable, or self-contradictory. In this case, the speaker is fighting those he does not hate and guarding those he does not love, which is a paradoxical situation. Euphemism is a mild or indirect word or expression substituted for one considered to be too harsh or blunt when referring to something unpleasant or embarrassing. Personification is a figure of speech where human qualities are given to animals, objects or ideas. Metonymy is a figure of speech that replaces the name of a thing with the name of something else with which it is closely associated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>11", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Those that I fight I do not hate ,  Those that I guard, I do not love;\"   ------------ in drama operates against a character who is unaware of a situation which is known to the audience.", "images": [], "options": {"A": "Verbal irony", "B": "Dramatic irony", "C": "Satire", "D": "Parody"}, "answer": "B", "explanation": "Dramatic irony is a form of irony that occurs when the audience are aware of an event that is unknown to the character.  Verbal irony occurs when a speaker says a thing but means the opposite  A parody is an imitation of a literary work with the intention to ridicule it.  A satire is a piece of writing that criticises the ills in the society in porder to bring about positive change.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>12", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The use of dialoque creates a/an ----------- effect", "images": [], "options": {"A": "humorous", "B": "poetic", "C": "ironic", "D": "dramatic"}, "answer": "D", "explanation": "Dialogue is a conversation between two or more people in a work of literature. Dialogue can be used to reveal character, advance the plot, and create a certain mood or tone. In this case, the use of dialogue creates a dramatic effect. It helps in developing the plot and unfolding the characters and their emotions, thus creating drama.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>13", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "One of the following is not a form poetry", "images": [], "options": {"A": "Sonnet", "B": "Ode", "C": "Suspense", "D": "Lyric"}, "answer": "C", "explanation": "Suspense is not a form of poetry. Rather it is a device that is used to keep the reader's interest in what is being read.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>14", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "But since, alas! frail beauty must decay.    curled or uncurled, since looks will turn to gray;   since painted or unpainted; all shall fade.    A literary device used in the first line is", "images": [], "options": {"A": "paradox", "B": "litotes", "C": "hyperbole", "D": "metaphor"}, "answer": "D", "explanation": "Beauty is described as frail. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>15", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "But since, alas! frail beauty must decay.    curled or uncurled, since looks will turn to gray;   since painted or unpainted; all shall fade.    The device used in the second and third lines", "images": [], "options": {"A": "antithesis", "B": "pun", "C": "onomatopoeia", "D": "euphemism"}, "answer": "A", "explanation": "The lines are antithetical because two contrasting statements are deployed.  ' curled or uncurled'  '... painted or unpainted'", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>16", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "But since, alas! frail beauty must decay.    curled or uncurled, since looks will turn to gray;   since painted or unpainted; all shall fade.    The use of the word 'since' illustrates", "images": [], "options": {"A": "alliteration", "B": "repetition", "C": "assonance", "D": "consonance"}, "answer": "B", "explanation": "The use of the word 'since' illustrates 'repetition'. Repetition is a literary device that repeats the same words or phrases a few times to make an idea clearer and more memorable. In this case, the word 'since' is repeated in the second and third lines, making it an example of repetition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>17", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Identify the odd item", "images": [], "options": {"A": "Poetry", "B": "Prose", "C": "Melodrama", "D": "Drama"}, "answer": "C", "explanation": "Melodrama is not a genre of literature unlike prose, play and poetry. The melodrama is one of the subgenres of drama.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2012>18", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The clash of interest that originates from opposing forces in literature is", "images": [], "options": {"A": "climax", "B": "denouement", "C": "conflict", "D": "aside"}, "answer": "C", "explanation": "The clash of interest that originates from opposing forces in literature is referred to as 'Conflict'. Conflict is a literary element that involves a struggle between two opposing forces usually a protagonist and an antagonist. It is what drives the plot and is the main focus of any story. Climax is the most intense point in a story, denouement is the resolution of the story, and aside is a dramatic device in which a character speaks to the audience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>19", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A major character whose flaws combine with external forces that lead to his downfall is a", "images": [], "options": {"A": "flat character", "B": "round character", "C": "romantic hero", "D": "tragic hero"}, "answer": "D", "explanation": "A tragic hero is one whose weakness of flaw leads to hios downfall. Such weakness is known as TRAGIC FLAW or HAMARTIA.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>20", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Which of the following is not a drama?", "images": [], "options": {"A": "Burlesque", "B": "Resolution", "C": "Pantomime", "D": "Opera"}, "answer": "B", "explanation": "Resolution refers to the last part of the plot structure. It is the point whereby every conflict has been settled.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>21", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I wonder how long, you awful parasite    Shall share with me this little bed,    And make, from sweet dreams be lost    By sucking blood from my poor head.      I should but say man has much    Blood, which you and your families do feed on;   for supper, dinner and lunch    And besides, you do in my bed breed.       Clever thou art, tiny creature;    You attend me when I am asleep    When thou art sure, I can't you capture,    Just at the time I snore deep.       \"Tis so strange that before twilight,    The bed clear of you would seem;    For not one of you is in my sight    As if your presence was in a dream.\"    The poem is about a", "images": [], "options": {"A": "nightmare", "B": "dream", "C": "raid of bugs", "D": "raid of mosquitoes"}, "answer": "C", "explanation": "He is referring to bed-bugs. They live in bed and suck people's blood.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>22", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I wonder how long, you awful parasite    Shall share with me this little bed,    And make, from sweet dreams be lost    By sucking blood from my poor head.      I should but say man has much    Blood, which you and your families do feed on;   for supper, dinner and lunch    And besides, you do in my bed breed.       Clever thou art, tiny creature;    You attend me when I am asleep    When thou art sure, I can't you capture,    Just at the time I snore deep.       \"Tis so strange that before twilight,    The bed clear of you would seem;    For not one of you is in my sight    As if your presence was in a dream.\"   The poem is generally made up of", "images": [], "options": {"A": "rhyming couplets", "B": "heroic couplets", "C": "end-stopped lines", "D": "run-on lines"}, "answer": "C", "explanation": "End-stopped lines in poetry refer to lines that end in a definitive pause. This pause is usually in the form of punctuation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>23", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I wonder how long, you awful parasite    Shall share with me this little bed,    And make, from sweet dreams be lost    By sucking blood from my poor head.      I should but say man has much    Blood, which you and your families do feed on;   for supper, dinner and lunch    And besides, you do in my bed breed.       Clever thou art, tiny creature;    You attend me when I am asleep    When thou art sure, I can't you capture,    Just at the time I snore deep.       \"Tis so strange that before twilight,    The bed clear of you would seem;    For not one of you is in my sight    As if your presence was in a dream.\"   The poem is a/an", "images": [], "options": {"A": "monologue", "B": "dialogue", "C": "epilogue", "D": "prologue"}, "answer": "A", "explanation": "The poem is a monologue. A monologue is a long speech by one person. The poem is a single speaker expressing his thoughts and feelings about the 'parasite' sharing his bed. There is no dialogue or conversation with another character, and it is not an epilogue or prologue, which are sections at the beginning or end of a book.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>24", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I wonder how long, you awful parasite    Shall share with me this little bed,    And make, from sweet dreams be lost    By sucking blood from my poor head.      I should but say man has much    Blood, which you and your families do feed on;   for supper, dinner and lunch    And besides, you do in my bed breed.       Clever thou art, tiny creature;    You attend me when I am asleep    When thou art sure, I can't you capture,    Just at the time I snore deep.       \"Tis so strange that before twilight,    The bed clear of you would seem;    For not one of you is in my sight    As if your presence was in a dream.\"   The poet's mood is one of", "images": [], "options": {"A": "sarcasm", "B": "indifference", "C": "joy", "D": "despair"}, "answer": "D", "explanation": "The poet's mood is one of despair. The poet expresses frustration and despair over the presence of the 'parasite' in his bed, which disrupts his sleep and feeds on his blood. The tone is not sarcastic or joyful, and the poet is not indifferent to the situation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>25", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I wonder how long, you awful parasite    Shall share with me this little bed,    And make, from sweet dreams be lost    By sucking blood from my poor head.      I should but say man has much    Blood, which you and your families do feed on;   for supper, dinner and lunch    And besides, you do in my bed breed.       Clever thou art, tiny creature;    You attend me when I am asleep    When thou art sure, I can't you capture,    Just at the time I snore deep.       \"Tis so strange that before twilight,    The bed clear of you would seem;    For not one of you is in my sight    As if your presence was in a dream.\"   The dominant attitude of the poet is one of", "images": [], "options": {"A": "amazement", "B": "pity", "C": "regret", "D": "nonchalance"}, "answer": "A", "explanation": "The dominant attitude of the poet in the given poem is one of 'amazement'. This is evident from the poet's detailed observation and description of the parasite's behavior and lifestyle. The poet expresses surprise at the parasite's ability to share his bed, feed on his blood, breed in his bed, and cleverly avoid capture by attacking when the poet is asleep. The poet also marvels at the parasite's ability to disappear by daylight, making its presence seem like a dream.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>26", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "The bright sun continues to smile. Andrew's face beamed with pleasure with every passing moment. Very few of his contemporaries have so succeeded in reaching the top of the ladder. Andrew in particular had been an orphan of storm. His father's death during his third year in the secondary school coupled with the physical misfortune which he suffered a when a stockfish machine severed his left middle finger, constituted a serious setback but Andrew did not despair.       The courage to fail is very cheap; every fool can afford to fail. But it raises one above the herd of cowards and never-do-wells to be up and struggling. The reward of forbearance in the end is resounding success.       And so it was for Andrew ever since he finished his university education; it had been success galore. He had got a good job in one of the country's insurance companies. His pay was good, his prospects seemed bright. The habitual Thomases in his family found it very hard to believe. At forty he had a good car and had already built a house of his own.    The world was at his feet.    \"Orphan of storm\" implies that Andrew", "images": [], "options": {"A": "had a good life", "B": "was orphaned of birth", "C": "had a difficult early life", "D": "was not afraid of storm"}, "answer": "C", "explanation": "The phrase 'orphan of storm' in the context of the passage implies that Andrew had a difficult early life. This is supported by the subsequent sentences which detail the hardships Andrew faced, including the death of his father during his third year in secondary school and a physical misfortune that resulted in the loss of his left middle finger. Despite these challenges, Andrew persevered and achieved success, indicating that his early life was characterized by adversity and struggle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>27", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "The bright sun continues to smile. Andrew's face beamed with pleasure with every passing moment. Very few of his contemporaries have so succeeded in reaching the top of the ladder. Andrew in particular had been an orphan of storm. His father's death during his third year in the secondary school coupled with the physical misfortune which he suffered a when a stockfish machine severed his left middle finger, constituted a serious setback but Andrew did not despair.       The courage to fail is very cheap; every fool can afford to fail. But it raises one above the herd of cowards and never-do-wells to be up and struggling. The reward of forbearance in the end is resounding success.       And so it was for Andrew ever since he finished his university education; it had been success galore. He had got a good job in one of the country's insurance companies. His pay was good, his prospects seemed bright. The habitual Thomases in his family found it very hard to believe. At forty he had a good car and had already built a house of his own.    The world was at his feet.  The passage is an example of a/an", "images": [], "options": {"A": "autobiography", "B": "expository passage", "C": "descriptive passage", "D": "biography"}, "answer": "D", "explanation": "The passage is a biography because it tells the story of Andrew's life, his struggles, and his achievements. A biography is a detailed description or account of someone's life. It entails more than basic facts like education, work, relationships, and death; it portrays a person's experience of these life events.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>28", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "The bright sun continues to smile. Andrew's face beamed with pleasure with every passing moment. Very few of his contemporaries have so succeeded in reaching the top of the ladder. Andrew in particular had been an orphan of storm. His father's death during his third year in the secondary school coupled with the physical misfortune which he suffered a when a stockfish machine severed his left middle finger, constituted a serious setback but Andrew did not despair.       The courage to fail is very cheap; every fool can afford to fail. But it raises one above the herd of cowards and never-do-wells to be up and struggling. The reward of forbearance in the end is resounding success.       And so it was for Andrew ever since he finished his university education; it had been success galore. He had got a good job in one of the country's insurance companies. His pay was good, his prospects seemed bright. The habitual Thomases in his family found it very hard to believe. At forty he had a good car and had already built a house of his own.    The world was at his feet.  The mood of the extract is one of", "images": [], "options": {"A": "love", "B": "admiration", "C": "hatred", "D": "resignation"}, "answer": "B", "explanation": "The mood is one of admiration because the narrator is impressed about how Andrew was able to overcome a kot of hurdles to become successful.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>29", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "The bright sun continues to smile. Andrew's face beamed with pleasure with every passing moment. Very few of his contemporaries have so succeeded in reaching the top of the ladder. Andrew in particular had been an orphan of storm. His father's death during his third year in the secondary school coupled with the physical misfortune which he suffered a when a stockfish machine severed his left middle finger, constituted a serious setback but Andrew did not despair.       The courage to fail is very cheap; every fool can afford to fail. But it raises one above the herd of cowards and never-do-wells to be up and struggling. The reward of forbearance in the end is resounding success.       And so it was for Andrew ever since he finished his university education; it had been success galore. He had got a good job in one of the country's insurance companies. His pay was good, his prospects seemed bright. The habitual Thomases in his family found it very hard to believe. At forty he had a good car and had already built a house of his own.    The world was at his feet.  \"The world was at his feet\" implies that Andrew", "images": [], "options": {"A": "was loving", "B": "was standing on the the world", "C": "was arrogant", "D": "achieved result easily"}, "answer": "D", "explanation": "To have the world at one's feet implies that one is successful enough and can easily achieve things.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>30", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "The bright sun continues to smile. Andrew's face beamed with pleasure with every passing moment. Very few of his contemporaries have so succeeded in reaching the top of the ladder. Andrew in particular had been an orphan of storm. His father's death during his third year in the secondary school coupled with the physical misfortune which he suffered a when a stockfish machine severed his left middle finger, constituted a serious setback but Andrew did not despair.       The courage to fail is very cheap; every fool can afford to fail. But it raises one above the herd of cowards and never-do-wells to be up and struggling. The reward of forbearance in the end is resounding success.       And so it was for Andrew ever since he finished his university education; it had been success galore. He had got a good job in one of the country's insurance companies. His pay was good, his prospects seemed bright. The habitual Thomases in his family found it very hard to believe. At forty he had a good car and had already built a house of his own.    The world was at his feet.  \"habitual Thomases\" is an example of a/an", "images": [], "options": {"A": "allegory", "B": "aphorism", "C": "allusion", "D": "apostrophe"}, "answer": "C", "explanation": "'Habitual Thomases' is an allusion. An allusion is a figure of speech that refers to a well-known story, event, person, or object in order to make a comparison in the readers' minds. In this case, 'Habitual Thomases' is an allusion to the biblical character Thomas, who is known for his doubt. Therefore, 'Habitual Thomases' refers to people who habitually doubt or are skeptical.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>31", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "P: Mark his condition, and the event: then tell me.   If this might be a brother.    Q: I should sin    To think but nobly of my grandmother    Good wombs have borne bad sons.    (Acts I, Scene Two, lines 116-120)    The speaker P is", "images": [], "options": {"A": "Alonso", "B": "Antonio", "C": "Ferdinand", "D": "Prospero"}, "answer": "D", "explanation": "In the given lines from 'The Tempest', speaker P is Prospero. He is speaking to Miranda about his brother Antonio's treachery. Prospero is a major character in the play, who was the Duke of Milan before his brother Antonio, supported by Alonso, King of Naples, usurped him.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>32", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "P: Mark his condition, and the event: then tell me.   If this might be a brother.    Q: I should sin    To think but nobly of my grandmother    Good wombs have borne bad sons.    (Acts I, Scene Two, lines 116-120)   The speaker Q is", "images": [], "options": {"A": "Miranda", "B": "prospero", "C": "Sebastian", "D": "Caliban"}, "answer": "A", "explanation": "In the given lines from 'The Tempest', speaker Q is Miranda. She is responding to Prospero's comment about his brother Antonio. Miranda is Prospero's daughter, and she is known for her compassion and innocence in the play.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>33", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "P: Mark his condition, and the event: then tell me.   If this might be a brother.    Q: I should sin    To think but nobly of my grandmother    Good wombs have borne bad sons.    (Acts I, Scene Two, lines 116-120)   The dialogue recalls", "images": [], "options": {"A": "their exile to the island", "B": "the killing of the king", "C": "their love affair", "D": "the grandmother's death"}, "answer": "A", "explanation": "Prospero relates how his brother overthrew him, mounted the throne and sent him packing alongside his three-year old daughter.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>34", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "P: Mark his condition, and the event: then tell me.   If this might be a brother.    Q: I should sin    To think but nobly of my grandmother    Good wombs have borne bad sons.    (Acts I, Scene Two, lines 116-120)   Speaker P wants his partner to", "images": [], "options": {"A": "pity his condition", "B": "fight his brother", "C": "justify his action", "D": "love him"}, "answer": "C", "explanation": "Miranda just watched his father raise a storm against the smooth sail of Antonio, Alonso and others. Prospero explains this as revenge for their conspiracy against him years back", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>35", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "P: Mark his condition, and the event: then tell me.   If this might be a brother.    Q: I should sin    To think but nobly of my grandmother    Good wombs have borne bad sons.    (Acts I, Scene Two, lines 116-120)   The speakers are", "images": [], "options": {"A": "grandfather and son", "B": "lovers", "C": "father and daughter", "D": "friends"}, "answer": "C", "explanation": "Prospero is Miranda's father. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>36", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "At mine unworthiness, that dare not offer    What I desire to give; and much less take    What I shall die to want. But this is trifling;    And all the more it seeked to hide itself,    The bigger bulk it shows. Hence, bashful cunning!    And prompt me, plain and holy innocence!    (Act III, Scene One, lines 78-83)    The speaker is", "images": [], "options": {"A": "Ferdinand", "B": "Stephano", "C": "Miranda", "D": "Prospero"}, "answer": "C", "explanation": "The speaker in the given lines from Act III, Scene One of 'The Tempest' by William Shakespeare is Miranda. In these lines, Miranda is expressing her feelings of unworthiness and desire towards Ferdinand. She is also expressing her innocence and naivety, which are key characteristics of her character throughout the play.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>37", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "At mine unworthiness, that dare not offer    What I desire to give; and much less take    What I shall die to want. But this is trifling;    And all the more it seeked to hide itself,    The bigger bulk it shows. Hence, bashful cunning!    And prompt me, plain and holy innocence!    (Act III, Scene One, lines 78-83)   The character addressed is", "images": [], "options": {"A": "Prospero", "B": "Ferdinand", "C": "Alonso", "D": "Juno"}, "answer": "B", "explanation": "The character addressed in this excerpt is Ferdinand. In this scene, Ferdinand is expressing his feelings of unworthiness and desire towards Miranda, Prospero's daughter. He is struggling with his feelings of love and his sense of duty and honor.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>38", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "At mine unworthiness, that dare not offer    What I desire to give; and much less take    What I shall die to want. But this is trifling;    And all the more it seeked to hide itself,    The bigger bulk it shows. Hence, bashful cunning!    And prompt me, plain and holy innocence!    (Act III, Scene One, lines 78-83)   After this speech, the character addressed", "images": [], "options": {"A": "sings", "B": "dances", "C": "kneels", "D": "weeps"}, "answer": "C", "explanation": "After this speech, the character addressed, Ferdinand, kneels. He kneels to propose to Miranda, expressing his deep love and commitment to her.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>39", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "At mine unworthiness, that dare not offer    What I desire to give; and much less take    What I shall die to want. But this is trifling;    And all the more it seeked to hide itself,    The bigger bulk it shows. Hence, bashful cunning!    And prompt me, plain and holy innocence!    (Act III, Scene One, lines 78-83)   The speaker is expressing", "images": [], "options": {"A": "love", "B": "hatred", "C": "sorrow", "D": "regret"}, "answer": "A", "explanation": "Ferdinand just professes  his love, so Miranda also reciprocates.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>40", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "At mine unworthiness, that dare not offer    What I desire to give; and much less take    What I shall die to want. But this is trifling;    And all the more it seeked to hide itself,    The bigger bulk it shows. Hence, bashful cunning!    And prompt me, plain and holy innocence!    (Act III, Scene One, lines 78-83)   The character who secretly watches and listen is", "images": [], "options": {"A": "Triculo", "B": "Stephano", "C": "Caliban", "D": "Prospero"}, "answer": "D", "explanation": "The character who secretly watches and listens in Act III, Scene One, lines 78-83 is Prospero. In the play 'The Tempest' by William Shakespeare, Prospero is known to be a character who often observes others secretly.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>41", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "M: No, as I am a man    N: There's nothing ill can dwell in such a temple.    If the ill spirit have so fair a house,    Good things will strive to dwell with't    (Act I, Scene Two, lines 459-462)    The speakers are", "images": [], "options": {"A": "arguing", "B": "in prison", "C": "dancing", "D": "in love"}, "answer": "D", "explanation": "Miranda and Ferdinand just met and their love can be regarded as love at first sight.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>42", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "M: No, as I am a man    N: There's nothing ill can dwell in such a temple.    If the ill spirit have so fair a house,    Good things will strive to dwell with't    (Act I, Scene Two, lines 459-462)   Speaker N", "images": [], "options": {"A": "is attracted to the temple", "B": "admires speaker M", "C": "dislikes the spirit in the house", "D": "dwells in the temple"}, "answer": "B", "explanation": "From the context, it's clear that Speaker N is admiring Speaker M, saying that there's nothing bad that can dwell in such a good person (temple). Therefore, the correct answer is that Speaker N admires Speaker M.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>43", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "M: No, as I am a man    N: There's nothing ill can dwell in such a temple.    If the ill spirit have so fair a house,    Good things will strive to dwell with't    (Act I, Scene Two, lines 459-462)   Speaker M means to", "images": [], "options": {"A": "defend himself", "B": "kill himself", "C": "escape from prison", "D": "dine with N"}, "answer": "A", "explanation": "Speaker M seems to be defending himself, based on the context of the lines. However, without additional context or knowledge of the play, this interpretation might not be accurate.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>44", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "M: No, as I am a man    N: There's nothing ill can dwell in such a temple.    If the ill spirit have so fair a house,    Good things will strive to dwell with't    (Act I, Scene Two, lines 459-462)   The other character present is", "images": [], "options": {"A": "Alonso", "B": "Caliban", "C": "Prospero", "D": "Antonio"}, "answer": "C", "explanation": "Speaker M's words are responses to Prospero's accusation", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>45", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "M: No, as I am a man    N: There's nothing ill can dwell in such a temple.    If the ill spirit have so fair a house,    Good things will strive to dwell with't    (Act I, Scene Two, lines 459-462)   Speaker M is", "images": [], "options": {"A": "prince", "B": "trailor", "C": "king", "D": "sailor"}, "answer": "A", "explanation": "Ferdinand is the son of Alonso, the king of Naples", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2012>46", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: Come on then; down, and swear.    Y: I shall laugh myself to death at this puppy-headed monster.    A most scurvy monster! I could find in my heart to beat him -    X: come, kiss    (Act II, Scene Two, line 139 - 143)    Speaker X is", "images": [], "options": {"A": "Stepheno", "B": "Ferdinand", "C": "Miranda", "D": "Caliban"}, "answer": "A", "explanation": "The excerpt is from 'The Tempest' by William Shakespeare. In this scene, Stephano (X) is speaking to Trinculo (Y) and Caliban. Therefore, speaker X is Stephano, which is the first option provided.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>47", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: Come on then; down, and swear.    Y: I shall laugh myself to death at this puppy-headed monster.    A most scurvy monster! I could find in my heart to beat him -    X: come, kiss    (Act II, Scene Two, line 139 - 143)   Speaker Y is", "images": [], "options": {"A": "Prospero", "B": "Gonzalo", "C": "Trinculo", "D": "Caliban"}, "answer": "C", "explanation": "In the play 'The Tempest', the character Trinculo refers to Caliban as a 'puppy-headed monster' and a 'scurvy monster'. Therefore, speaker Y is Trinculo.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>48", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: Come on then; down, and swear.    Y: I shall laugh myself to death at this puppy-headed monster.    A most scurvy monster! I could find in my heart to beat him -    X: come, kiss    (Act II, Scene Two, line 139 - 143)   Another character present is", "images": [], "options": {"A": "Francisco", "B": "Sebastian", "C": "Adrian", "D": "Caliban"}, "answer": "D", "explanation": "Caliban met these two characters on the Island after the wreck and joins them in their mission to kill Prospero and take over the island.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>49", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: Come on then; down, and swear.    Y: I shall laugh myself to death at this puppy-headed monster.    A most scurvy monster! I could find in my heart to beat him -    X: come, kiss    (Act II, Scene Two, line 139 - 143)   Speaker Y is a", "images": [], "options": {"A": "monster", "B": "musician", "C": "set caption", "D": "Jester"}, "answer": "D", "explanation": "Speaker Y is making fun of the 'monster', which is a typical behavior of a jester in Shakespeare's plays.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2012>50", "subject": "Literature", "year": "2012", "type": "Objective", "topic": "NON-AFRICAN POETRY", "question": "X: Come on then; down, and swear.    Y: I shall laugh myself to death at this puppy-headed monster.    A most scurvy monster! I could find in my heart to beat him -    X: come, kiss    (Act II, Scene Two, line 139 - 143)   The setting is", "images": [], "options": {"A": "in front of Prosperos cell", "B": "on a ship", "C": "on the seashore", "D": "another part of the island"}, "answer": "D", "explanation": "Considering the overall context of 'The Tempest', many scenes take place on an island, which Prospero, the protagonist, has made his home.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>1", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "-------- is fundamental to a play or novel.", "images": [], "options": {"A": "Mime", "B": "Conflict", "C": "Flashback", "D": "Epilogue"}, "answer": "B", "explanation": "Every play or novel must have a conflict.  The conflict refers to the struggle between two opposing forces. Most times, this struggle manifests itself in a confrontation between the protagonist and the antagonist.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>2", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A long and serious narative about heroic characters is a/an", "images": [], "options": {"A": "Burlesque", "B": "Ballad", "C": "Epic", "D": "Elegy"}, "answer": "C", "explanation": "An epic is a long and serious narrative about heroic characters. It is a genre of poetry, and the heroes of epics are often of divine descent or have divine favor. The actions of these heroes often determine the fate of a nation or people. Examples of epics include Homer's 'Iliad' and 'Odyssey', Virgil's 'Aeneid', and Dante's 'Divine Comedy'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>3", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The device used in 'light as wind on water laid' is", "images": [], "options": {"A": "Rhyme", "B": "Simile", "C": "Onomatopoeia", "D": "Pun"}, "answer": "B", "explanation": "Simile: an indirect comparison that requires the use of \"as\" or \"like\".  Here, something is compared to be as light as wind in water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>4", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "'The fire gnawed ceaselessly at the bark of the tree' illustrates", "images": [], "options": {"A": "Personification", "B": "Epithet", "C": "Allusion", "D": "Paradox"}, "answer": "A", "explanation": "The phrase 'The fire gnawed ceaselessly at the bark of the tree' illustrates personification. Personification is a figure of speech in which a thing, an idea or an animal is given human attributes. Here, the fire is given the human attribute of gnawing, which is something that humans or animals do.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>5", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A hyperbole is also referred to as", "images": [], "options": {"A": "Irony", "B": "Paradox", "C": "Exaggeration", "D": "Understatement"}, "answer": "C", "explanation": "Hyperbole is a figure of speech used to used to exaggerate for purpose of humour or emphasis.  It is known as an excessive exaggeration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>6", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "This book should fill the memory, rule the heart and guide the feet.  The above expression illustrates the use of", "images": [], "options": {"A": "Repetition", "B": "Refrain", "C": "Synecdoche", "D": "Metaphor"}, "answer": "C", "explanation": "Synecdoche: the use of a part of the body to represent the entire body.  The book is meant to guide humans, represented by parts of the body: memory, heart and feet", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>7", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The author's attitude towards the subject being treated is", "images": [], "options": {"A": "mood", "B": "Tone", "C": "feeling", "D": "Atmosphere"}, "answer": "B", "explanation": "The author's attitude towards the subject being treated is referred to as the 'Tone'. Tone in literature is the attitude or approach that the author takes toward the work's central theme or subject. It is conveyed through the choice of words or the viewpoint of a writer on a particular subject.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>8", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "One of the following makes use of gesture only", "images": [], "options": {"A": "Comedy", "B": "Lampoon", "C": "Mime", "D": "Satire"}, "answer": "C", "explanation": "Mime is a type of performance that makes use of gestures only, without words. It is a form of acting where the story is told through body motions, without use of speech.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>9", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An omniscient narrator in a novel", "images": [], "options": {"A": "Detaches himself from the story", "B": "Knows nothing about the characters and events", "C": "Knows everything about the characters and events", "D": "Is a character in the story"}, "answer": "C", "explanation": "An omniscient is all knowing and usually tells all events and happenings in a story. This narrator not only describes the actions of the character but also reveals what is in their minds.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>10", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In poetry ------------ is made up of stressed and unstressed syllables?", "images": [], "options": {"A": "An iambus", "B": "An anapaest", "C": "Trochee", "D": "Dactyl"}, "answer": "C", "explanation": "Trochee is a form of metre where a stressed syllable is followed by an unstressed one . The iambus starts with an unstressed syllable followed by a stressed one.   The anapest is made up of three syllables, the first and second syllables are unstressed while the third is stressed.  The dactyl contains three syllables that are follow the pattern\" STRESSED + UNSTRESSED + UNSTRESSED", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>11", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Blank verse has no", "images": [], "options": {"A": "Meter", "B": "Rhyme", "C": "Rhythm", "D": "Imagery"}, "answer": "B", "explanation": "Blank verse is a type of poetry that has a specific meter, usually iambic pentameter, but does not contain rhyme. Therefore, the correct answer is 'Rhyme'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>12", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A very brief story is an", "images": [], "options": {"A": "Allusion", "B": "Autobiography", "C": "Allegory", "D": "Anecdote"}, "answer": "D", "explanation": "A very brief story is an Anecdote. An anecdote is a short, often amusing story about a real incident or person. It is not an allusion, which is a reference to another work of literature, person, or event. It is not an autobiography, which is a self-written life story. And it is not an allegory, which is a story, poem, or picture that can be interpreted to reveal a hidden meaning, typically a moral or political one.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2013>13", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An epilogue", "images": [], "options": {"A": "introduces a play", "B": "Develop characters", "C": "Sums up a play", "D": "Introduces characters"}, "answer": "C", "explanation": "Epilogue is the concluding section of a play or prose. It is the opposite of prologue 9the introduction).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>14", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The king has joined his ancestor's is an example of", "images": [], "options": {"A": "Euphemism", "B": "Eulogy", "C": "Malapropism", "D": "Trilogy"}, "answer": "A", "explanation": "Euphemism: a device that expresses unpleasant events in a pleasant or mild manner.   To join one's ancestors means that one is dead.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>15", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In the line \"season of mist and mellow fruitfulness\" the main appeal is to the sense of", "images": [], "options": {"A": "Touch", "B": "sight", "C": "hearing", "D": "Smell"}, "answer": "B", "explanation": "This refers to autumn.  The extract appeals to the sense of sight. \"Mellow\" has to do with colours while \"mist\" relates to the inability to see clearly.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>16", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A question used for effect which does not require an answer is", "images": [], "options": {"A": "Oratorical", "B": "Antithetical", "C": "Anti-climatic", "D": "Rhetorical"}, "answer": "D", "explanation": "A question used for effect which does not require an answer is called a rhetorical question. A rhetorical question is a figure of speech in the form of a question that is asked to make a point rather than to elicit an answer. The speaker does not expect an answer because the answer is implied in the question itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>17", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"The pen is mightier than the sword\" is an example of", "images": [], "options": {"A": "Symbol", "B": "Metaphor", "C": "Metonymy", "D": "Oxymoron"}, "answer": "C", "explanation": "Metonymy uses something related to represent an object.  Here, the pen is used to represent education or writings while the sword represents violence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>18", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In a play, unfolding events reach their peak in the", "images": [], "options": {"A": "Climax", "B": "Denouncement", "C": "Catharsis", "D": "Conflict"}, "answer": "A", "explanation": "The climax is the highest point of the conflict in a work of art. It is at this point that the protagonist clashes with the antagonist.  Denouement also means resolution. It is the point when every conflict is settled.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>19", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"But at my back, I always hear time's winged chariot hurrying near\" illustrates", "images": [], "options": {"A": "Metaphor", "B": "Apostrophe", "C": "Oxymoron", "D": "Metonymy"}, "answer": "A", "explanation": "The phrase \"But at my back, I always hear time's winged chariot hurrying near\" is an example of a metaphor. A metaphor is a figure of speech that makes a comparison between two things that are basically dissimilar. In this case, time is being compared to a winged chariot, suggesting that time is fast and unstoppable.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>20", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short witty saying is a/an", "images": [], "options": {"A": "Epitaph", "B": "Sonnet", "C": "Limerick", "D": "Epigram"}, "answer": "D", "explanation": "Epigram is used to express an idea in a concise, humorous and memorable way. To express simply, it is a short and wise statement.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2013>21", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "As they trooped off down the field with their sullen dogs, the farmer started the tractor up and the cutter blade blurred into life. Left alne, Grooby sank into a shocked stupor. His mind whirled around like a fly that dared not alight. A blank vacancy held him. He seemed unable to move, even to wipe away the sweat that collected in his eyebrows and leaked down into his eyes. He sensed that the sun had settled over the earth, so that the air was actually burning gas. He watched the tractor dwindle in the bottom of the field, as if it were melting into a glittering muddle in the haze.     \"... The cutter blade blurred into life\"    The above expression appeals to the sense of", "images": [], "options": {"A": "Hearing", "B": "Touch", "C": "Sight", "D": "Taste"}, "answer": "A", "explanation": "The sound a cutter blade makes can be heard; therefore, it appeals to the sense of hearing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>22", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "As they trooped off down the field with their sullen dogs, the farmer started the tractor up and the cutter blade blurred into life. Left alne, Grooby sank into a shocked stupor. His mind whirled around like a fly that dared not alight. A blank vacancy held him. He seemed unable to move, even to wipe away the sweat that collected in his eyebrows and leaked down into his eyes. He sensed that the sun had settled over the earth, so that the air was actually burning gas. He watched the tractor dwindle in the bottom of the field, as if it were melting into a glittering muddle in the haze.     \"... The cutter blade blurred into life\"   \"The air was actually burning gas\" is a", "images": [], "options": {"A": "Personification", "B": "Euphemism", "C": "Metaphor", "D": "Paradox"}, "answer": "A", "explanation": "Here, the air is said to be burning something. This action is something only humans can perform; therefore, the extract is a personification.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>23", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "As they trooped off down the field with their sullen dogs, the farmer started the tractor up and the cutter blade blurred into life. Left alne, Grooby sank into a shocked stupor. His mind whirled around like a fly that dared not alight. A blank vacancy held him. He seemed unable to move, even to wipe away the sweat that collected in his eyebrows and leaked down into his eyes. He sensed that the sun had settled over the earth, so that the air was actually burning gas. He watched the tractor dwindle in the bottom of the field, as if it were melting into a glittering muddle in the haze.     \"... The cutter blade blurred into life\"   The diction conveys a feeling of", "images": [], "options": {"A": "Hope", "B": "Helplessness", "C": "Anger", "D": "Indifference"}, "answer": "B", "explanation": "'... sank into a shocked stupor'  '... blank vacancy...'  '...  seemed unable to move...'  The choice of the words above help to convey a feeling of helplessness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>24", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "As they trooped off down the field with their sullen dogs, the farmer started the tractor up and the cutter blade blurred into life. Left alne, Grooby sank into a shocked stupor. His mind whirled around like a fly that dared not alight. A blank vacancy held him. He seemed unable to move, even to wipe away the sweat that collected in his eyebrows and leaked down into his eyes. He sensed that the sun had settled over the earth, so that the air was actually burning gas. He watched the tractor dwindle in the bottom of the field, as if it were melting into a glittering muddle in the haze.     \"... The cutter blade blurred into life\"   The expression \"like a fly that dare not alight\" is a/an", "images": [], "options": {"A": "simile", "B": "Hyperbole", "C": "Irony", "D": "Alliteration"}, "answer": "A", "explanation": "The expression 'like a fly that dare not alight' is a simile. A simile is a figure of speech that makes a comparison between two different things using the words 'like' or 'as'. In this case, the author is comparing Grooby's mind to a fly that does not dare to land, suggesting that his thoughts are in a state of constant motion or turmoil.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>25", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "As they trooped off down the field with their sullen dogs, the farmer started the tractor up and the cutter blade blurred into life. Left alne, Grooby sank into a shocked stupor. His mind whirled around like a fly that dared not alight. A blank vacancy held him. He seemed unable to move, even to wipe away the sweat that collected in his eyebrows and leaked down into his eyes. He sensed that the sun had settled over the earth, so that the air was actually burning gas. He watched the tractor dwindle in the bottom of the field, as if it were melting into a glittering muddle in the haze.     \"... The cutter blade blurred into life\"   The setting of the extract is", "images": [], "options": {"A": "Dawn", "B": "Midday", "C": "Evening", "D": "Night"}, "answer": "B", "explanation": "' .... the sun had settled over the earth...'  The presence of the sun proves that it is set in mid day.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>26", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I'm going soldering:    Mad the rhythm runs,    With drumming and with trumpeting    And glory of the guns.       I've come home again:    I know that blood is red    I know how sodden falls the rain   Where flesh lies dead.    The theme of the poem is best described as the", "images": [], "options": {"A": "Love of war", "B": "Glory of war", "C": "Excitement of nwar", "D": "Reality of war"}, "answer": "D", "explanation": "The persona is at first excited to go to war; however, he later realises that there is nothing pleasant about it: \"blood is red.\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>27", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I'm going soldering:    Mad the rhythm runs,    With drumming and with trumpeting    And glory of the guns.       I've come home again:    I know that blood is red    I know how sodden falls the rain   Where flesh lies dead.   \"Mad the rhythm runs\" is an example of", "images": [], "options": {"A": "Pathos", "B": "Oxymoron", "C": "Bathos", "D": "Inversion"}, "answer": "D", "explanation": "Inversion occurs when we change the normal word order of a structure.  The rhythm runs mad, becomes \"mad the rhythm runs.\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>28", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I'm going soldering:    Mad the rhythm runs,    With drumming and with trumpeting    And glory of the guns.       I've come home again:    I know that blood is red    I know how sodden falls the rain   Where flesh lies dead.   The document sound device in the second stanza is", "images": [], "options": {"A": "Alliteration", "B": "Assonance", "C": "Onomatopoeia", "D": "Repetition"}, "answer": "D", "explanation": "Repetion   'I know' was repeated in line 6-7. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>29", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I'm going soldering:    Mad the rhythm runs,    With drumming and with trumpeting    And glory of the guns.       I've come home again:    I know that blood is red    I know how sodden falls the rain   Where flesh lies dead.   The rhyme scheme in the first stanza is", "images": [], "options": {"A": "aabb", "B": "abab", "C": "abaa", "D": "aabc"}, "answer": "B", "explanation": "The rhyme scheme of the first stanza is abab because the first and third lines do not rhyme, and the second and fourth lines do rhyme.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>30", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I'm going soldering:    Mad the rhythm runs,    With drumming and with trumpeting    And glory of the guns.       I've come home again:    I know that blood is red    I know how sodden falls the rain   Where flesh lies dead.   The two contrasting moods in the poem are", "images": [], "options": {"A": "Sadness and hope", "B": "Bravery and cowardice", "C": "Excitement and disappointment", "D": "Calmness and anxiety"}, "answer": "C", "explanation": "The persona is excited about the prospects of going to war in the first stanza. However, in the second stanza (after the war). he realises that war is not as romantic as people describe; war is brutal. Hence, he is disappointed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>31", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Thou liest most ignorant monster! I am in case to jostle a constable. Why, thou debossed  fish, thou, was there ever man a coward that hath drunk so much sack as a I today. Wilt thou tell monstrous lie, being but half a fish and half a monster?     The speaker is", "images": [], "options": {"A": "Stephano", "B": "Caliban", "C": "Triculo", "D": "Adrian"}, "answer": "C", "explanation": "Trinculo and Sabastian meets Caliban on the the Island and make a series of drunken exchanges and banter.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>32", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Thou liest most ignorant monster! I am in case to jostle a constable. Why, thou debossed  fish, thou, was there ever man a coward that hath drunk so much sack as a I today. Wilt thou tell monstrous lie, being but half a fish and half a monster?   The character addressed is", "images": [], "options": {"A": "Triculo", "B": "Stephano", "C": "Sebastian", "D": "Caliban"}, "answer": "D", "explanation": "The character being addressed in the quote is Caliban. Caliban is a native of the island, the son of a witch and is often referred to as a 'monster' by the other characters.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>33", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Thou liest most ignorant monster! I am in case to jostle a constable. Why, thou debossed  fish, thou, was there ever man a coward that hath drunk so much sack as a I today. Wilt thou tell monstrous lie, being but half a fish and half a monster?   The \"lie\" is that the speaker is a/an", "images": [], "options": {"A": "Drunkard", "B": "Coward", "C": "Ass", "D": "Idiot"}, "answer": "B", "explanation": "From the context of the passage, it can be inferred that the speaker is being accused of being a coward. This is because the speaker mentions 'was there ever man a coward that hath drunk so much sack as I today'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>34", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Thou liest most ignorant monster! I am in case to jostle a constable. Why, thou debossed  fish, thou, was there ever man a coward that hath drunk so much sack as a I today. Wilt thou tell monstrous lie, being but half a fish and half a monster?   The addressee asks that the speaker be", "images": [], "options": {"A": "Punished severely", "B": "Hanged on a tree", "C": "Beated to death", "D": "Bitten to death"}, "answer": "D", "explanation": "CALIBAN   Lo, lo, again! Bite him to death, I prithee. ---Line 30", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>35", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Thou liest most ignorant monster! I am in case to jostle a constable. Why, thou debossed  fish, thou, was there ever man a coward that hath drunk so much sack as a I today. Wilt thou tell monstrous lie, being but half a fish and half a monster?   Later in the scene the addressee proposes a plot to", "images": [], "options": {"A": "Make Triculo king of the island", "B": "Kill prospero", "C": "Steal Miranda", "D": "Rob Prospero of his clothes"}, "answer": "B", "explanation": "Caliban who is Prospero's servant claims Prospero is wicked and uses dark magic, so enjoins Trinculo and Stephano to aid him in his plan to kill Prospero by knocking a nail into his head.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>36", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "You are three men of sin, whom Destiny -    That hath to instrument this lower world    And what is in it - the never-surfeited sea    Hath caused to belch up you; and on this island,    Where man doth not inhabit - you amongst men    Being most unfit to live.      (Act III, Scene Three, Lines 53 - 58)    The speaker is", "images": [], "options": {"A": "Prospero", "B": "Miranda", "C": "Ariel", "D": "Gonzalo"}, "answer": "C", "explanation": "The quote is from Act III, Scene Three of Shakespeare's 'The Tempest'. The speaker is Ariel, a spirit who serves Prospero. Ariel is addressing Alonso, Sebastian, and Antonio, calling them 'three men of sin'. Ariel is invisible to them and is creating a harrowing experience to make them realize their guilt for their past actions. Therefore, the correct answer is 'Ariel'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>37", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "You are three men of sin, whom Destiny -    That hath to instrument this lower world    And what is in it - the never-surfeited sea    Hath caused to belch up you; and on this island,    Where man doth not inhabit - you amongst men    Being most unfit to live.      (Act III, Scene Three, Lines 53 - 58)   The \"three men of sin\" are", "images": [], "options": {"A": "Alonso, Gonzalo and Antonio", "B": "Alonso, Antonio and Sebastian", "C": "Antonio, Sebastian and Gonzalo", "D": "Sebastian, Gonzalo and Antonio"}, "answer": "B", "explanation": "Alonso, Antonio and Sabestian are the three men of sin.   Antonio is Prospero's brother who betrayed him with the help of Alonso. Sabastian is Alonso's younger brother who is also evil at heart.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>38", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "You are three men of sin, whom Destiny -    That hath to instrument this lower world    And what is in it - the never-surfeited sea    Hath caused to belch up you; and on this island,    Where man doth not inhabit - you amongst men    Being most unfit to live.      (Act III, Scene Three, Lines 53 - 58)   In the first line, 'Destiny' is", "images": [], "options": {"A": "Metaphor", "B": "Personification", "C": "Allusion", "D": "Euphemism"}, "answer": "B", "explanation": "In the first line, 'Destiny' is personified. Personification is a figure of speech in which a thing, an idea or an animal is given human attributes. The non-human entities are portrayed in such a way that we feel they have the ability to act like human beings. Here, 'Destiny' is given the human ability to 'instrument this lower world', which means it is controlling or manipulating the world. This is a common technique in literature to help readers connect more deeply with non-human or abstract concepts.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>39", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "AFRICAN DRAMA", "question": "You are three men of sin, whom Destiny -    That hath to instrument this lower world    And what is in it - the never-surfeited sea    Hath caused to belch up you; and on this island,    Where man doth not inhabit - you amongst men    Being most unfit to live.      (Act III, Scene Three, Lines 53 - 58)   The speaker immediately", "images": [], "options": {"A": "report them to Prospero", "B": "Make them repent", "C": "drive them away", "D": "Make them go mad temporarily"}, "answer": "D", "explanation": "In the play, the speaker is Ariel, a spirit serving Prospero, who is disguised as a harpy during this scene. After this speech, Ariel makes the three men (Alonso, Sebastian, and Antonio) go mad temporarily.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>40", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "You are three men of sin, whom Destiny -    That hath to instrument this lower world    And what is in it - the never-surfeited sea    Hath caused to belch up you; and on this island,    Where man doth not inhabit - you amongst men    Being most unfit to live.      (Act III, Scene Three, Lines 53 - 58)   A character in the scene whom Prospero admires is", "images": [], "options": {"A": "Ferdinand", "B": "Gonzalo", "C": "Adrian", "D": "Franciso"}, "answer": "B", "explanation": "Prospero admires Gonzalo.  When Prospero was sent into exile, Gonzalo helped him by providing him books and food at their departure.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>41", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Look thou be true. Do not give dalliance    Too much the rain. The strongest oaths are straw    To the fire, I' the blood. Be more abstemious    Or else, good night your vow!    (Act IV, Scene One, Lines 51 - 54)    The speaker is", "images": [], "options": {"A": "Alonso", "B": "Prospero", "C": "Gonzalo", "D": "Ferdinand"}, "answer": "B", "explanation": "In the play 'The Tempest' by William Shakespeare, these lines are spoken by Prospero to Ferdinand, warning him to be true to his daughter Miranda and not to break his vows of love.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>42", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Look thou be true. Do not give dalliance    Too much the rain. The strongest oaths are straw    To the fire, I' the blood. Be more abstemious    Or else, good night your vow!    (Act IV, Scene One, Lines 51 - 54)  The character addressed is", "images": [], "options": {"A": "Miranda", "B": "Antonio", "C": "Ferdinand", "D": "Sebastian"}, "answer": "C", "explanation": "Prospero is speaking these lines to Ferdinand, warning him to be true to his daughter Miranda and not to break his vows of love.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>43", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Look thou be true. Do not give dalliance    Too much the rain. The strongest oaths are straw    To the fire, I' the blood. Be more abstemious    Or else, good night your vow!    (Act IV, Scene One, Lines 51 - 54)  The literary device in line 52 and 53 is", "images": [], "options": {"A": "Personification", "B": "Simile", "C": "Metaphor", "D": "Synecdoche"}, "answer": "C", "explanation": "In line 52, the device used is the metaphor. Oaths are compared to straws and fire to blood.  strongest oaths are compared to straws and in line 53, fire is compared to blood", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>44", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Look thou be true. Do not give dalliance    Too much the rain. The strongest oaths are straw    To the fire, I' the blood. Be more abstemious    Or else, good night your vow!    (Act IV, Scene One, Lines 51 - 54)  Another character present in the scene is", "images": [], "options": {"A": "Caliban", "B": "Triculo", "C": "Stephano", "D": "Miranda"}, "answer": "D", "explanation": "Miranda is present as her father admonishes Ferdinand.  At the beginning of the scene '  Enter Prospero, Ferdinand and Miranda  '", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>45", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Look thou be true. Do not give dalliance    Too much the rain. The strongest oaths are straw    To the fire, I' the blood. Be more abstemious    Or else, good night your vow!    (Act IV, Scene One, Lines 51 - 54)  The \"oath\" referred to in the scene is that", "images": [], "options": {"A": "Miranda shall not give in to Ferdinand", "B": "Ferdinand shall not have intimate contact with Miranda", "C": "Miranda shall vow to be faithful to Ferdinand", "D": "Ferdinand shall not tell his father about Miranda"}, "answer": "B", "explanation": "Prospero agrees to Ferdinand and Miranda's marriage but warns not to be intimate before their marriage. The consequence of disobeying this vow is that their union would be childless.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>46", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "AFRICAN DRAMA", "question": "Oh! a Cherubin   Thou wast that did preserve me. Thou didst smile, infused with a fortitude from heaven,  when I have decked the sea with drops full salt . Under my burthen groaned, which raised in me.    An undergoing stomach, to bear up Against what should ensue.     The speaker is", "images": [], "options": {"A": "Alonso", "B": "Gonzalo", "C": "Prospero", "D": "Sebastian"}, "answer": "C", "explanation": "In 'The Tempest' by William Shakespeare, the lines are spoken by Prospero. He is referring to Ariel, the spirit who serves him, as a cherub or angel who has helped him survive. Prospero is expressing his gratitude to Ariel for giving him the strength to endure his trials. Therefore, the speaker is Prospero.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>47", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Oh! a Cherubin   Thou wast that did preserve me. Thou didst smile, infused with a fortitude from heaven,  when I have decked the sea with drops full salt . Under my burthen groaned, which raised in me.    An undergoing stomach, to bear up Against what should ensue.    The character addressed is", "images": [], "options": {"A": "Ferdinard", "B": "Ariel", "C": "Caliban", "D": "Miranda"}, "answer": "D", "explanation": "In the given passage from 'The Tempest', Prospero is speaking to his daughter Miranda. He refers to her as a 'Cherubin' and talks about how she preserved him and gave him the strength to bear up against what should ensue.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>48", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Oh! a Cherubin   Thou wast that did preserve me. Thou didst smile, infused with a fortitude from heaven,  when I have decked the sea with drops full salt . Under my burthen groaned, which raised in me.    An undergoing stomach, to bear up Against what should ensue.    The speaker sees the addressee as a/an", "images": [], "options": {"A": "Lover", "B": "Saviour", "C": "Burden", "D": "Antagonist"}, "answer": "B", "explanation": "From the passage, it can be inferred that the speaker sees the addressee as a saviour. The speaker says 'Thou wast that did preserve me. Thou didst smile, infused with a fortitude from heaven', which indicates that the speaker sees the addressee as someone who saved him/her.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2013>49", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Oh! a Cherubin   Thou wast that did preserve me. Thou didst smile, infused with a fortitude from heaven,  when I have decked the sea with drops full salt . Under my burthen groaned, which raised in me.    An undergoing stomach, to bear up Against what should ensue.    \"When I have decked the sea with drops full salt\" suggests", "images": [], "options": {"A": "dreaming", "B": "swimming", "C": "weeping", "D": "sleeping"}, "answer": "C", "explanation": "The phrase \"When I have decked the sea with drops full salt\" is a metaphorical way of saying that the speaker was crying. The 'drops full salt' refers to tears, which are salty. Therefore, the correct answer is 'weeping'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2013>50", "subject": "Literature", "year": "2013", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Oh! a Cherubin   Thou wast that did preserve me. Thou didst smile, infused with a fortitude from heaven,  when I have decked the sea with drops full salt . Under my burthen groaned, which raised in me.    An undergoing stomach, to bear up Against what should ensue.    Soon after this dialoque appears", "images": [], "options": {"A": "Ariel", "B": "Ferdinard", "C": "Gonzalo", "D": "Caliban"}, "answer": "A", "explanation": "Ariel returns to give Prospero update concerning the tempest they both created to trap the ship bearing King Alonso and his entourage.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>1", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In drama, comic relief often occurs in", "images": [], "options": {"A": "comedies", "B": "tragedies", "C": "historical plays", "D": "romantic plays"}, "answer": "B", "explanation": "Comic relief is a short humorous act  meant to ease tension in tragedies. It is a funny scene that is adapted into a tragedy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2014>2", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A struggle between opposing forces in a story or play is", "images": [], "options": {"A": "denouement", "B": "conflict", "C": "comedy", "D": "tragedy"}, "answer": "B", "explanation": "Conflict refers to the struggle between two opposing forces, usually the protagonist and the antagonist.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>3", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An expression from which one derives a mental picture is", "images": [], "options": {"A": "paradox", "B": "exaggeration", "C": "imagery", "D": "photography"}, "answer": "C", "explanation": "Imagery in literature is used to generate a mental picture or sensation in the reader's mind. It's a way for the author to use words and phrases to create 'mental images' for the reader. Imagery helps the reader to visualize more realistically the author's writings. The usage of metaphors, allusions, descriptive words and similes amongst other literary forms in order to \"tickle\" and awaken the readers' sensory perceptions is referred to as imagery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>4", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The repetition of the same vowel sounds in a line is", "images": [], "options": {"A": "alliteration", "B": "assonance", "C": "onomatopoeia", "D": "parallelism"}, "answer": "B", "explanation": "Assonance is the repetition of vowel sounds in the middle of words in a line of poetry  They g o t sh o t n o t l o ng ago  Alliteration refers to the repetition of consonant sounds at the beginning of words, e.g, Father Francis fire five French footballers on Friday. Here, /f/ alliterates.  Parallelism occurs when two statements have the same meaning.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>5", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A character in the story who narrates what happened to him or her is", "images": [], "options": {"A": "a second person narrator", "B": "a first person narrator", "C": "an omniscient narrator", "D": "a third person narrator"}, "answer": "B", "explanation": "A first person narrator uses 'I' and 'We' in his narration and such character is a participant in the action.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>6", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An understatement is otherwise called", "images": [], "options": {"A": "Litotes", "B": "Conceit", "C": "Pun", "D": "Contrast"}, "answer": "A", "explanation": "Litotes, also known as Meiosis, is regarded as the opposite of hyperbole; it is an understatement. Litotes are identified through the use of double negatives, e.g., I am NOT UNgrateful.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>7", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The loneliest person lives in the most crowded places illustrates", "images": [], "options": {"A": "paradox", "B": "ancedote", "C": "allegory", "D": "parody"}, "answer": "A", "explanation": "One would wonder how a person can be lonely in the company of so many people but this statement has a deeper meaning. Being alone is different from being lonely. Loneliness comes from within.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>8", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A person's life story written by another is", "images": [], "options": {"A": "a commentary", "B": "a biography", "C": "an autobiography", "D": "an epistolary"}, "answer": "B", "explanation": "The biography is a story of a person that is written by another.  Autobiography, on the other hand, is a person's life story written by the person..", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>9", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The term used to depict the freedom of a poet with language is", "images": [], "options": {"A": "poetic diction", "B": "bathos", "C": "graphology", "D": "poetic licence"}, "answer": "D", "explanation": "The term 'poetic licence' refers to the liberty that authors and poets have to deviate from conventional forms, rules, and facts to create a more compelling or effective piece of literature. It allows them to use their creativity to its fullest extent, bending or breaking the rules of grammar, syntax, or facts to suit their needs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>10", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A poem in which a lone speaker seems to be addressing someone else is a", "images": [], "options": {"A": "pathetic fallacy", "B": "verbal irony", "C": "dramatic irony", "D": "dramatic monologue"}, "answer": "D", "explanation": "Sometimes the character expresses his inner feelings to the audience without other characters identifying this feelings.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>11", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A story which explains a natural phenomenon is", "images": [], "options": {"A": "legend", "B": "parable", "C": "myth", "D": "fiction"}, "answer": "C", "explanation": "Myths are stories that were once believed to be true by a particular set of people. These stories often form part of their superstitions and folktale. Sometimes, these stories often talk about natural phenomena such as The Creation. Myths have no historical evidence.  Legends differ from myths in that legends have historical backing, that is, they actually happened.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>12", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short poem that expresses an idea in a clever way is", "images": [], "options": {"A": "an epigram", "B": "a limerick", "C": "an ode", "D": "a lyric"}, "answer": "A", "explanation": "An epigram is a short witty poem that explains an event in a concise and memorable way.  A limerick is a humorous poem of five lines with a rhyme scheme of aabba.  An ode is a praise poem that is written in the form of an address to something.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2014>13", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary work that vividly portrays life can be described as", "images": [], "options": {"A": "realistic", "B": "romantic", "C": "idealistic", "D": "sarcastic"}, "answer": "A", "explanation": "Realism is a feature of literary works that reflect life. It is often used as a synonym for MIMETICISM (the imitation of life in literature).  Romancve in prose has to do with unrealistic events. In poetry, it refers to poems about nature.  Idealism refers to the belief that life is perfect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>14", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A character whose actions or qualities served to heighten those of the hero through contrast is", "images": [], "options": {"A": "an adversary", "B": "protagonist", "C": "an antagonist", "D": "a foil"}, "answer": "D", "explanation": "A foil is a character brings out the qualities of another character by acting in contrast.  The antagonist is a character that contends against the protagonist.  The protagonist is the hero.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>15", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "One of the following is used to develop character", "images": [], "options": {"A": "Climax", "B": "Atmosphere", "C": "Setting", "D": "Dialogue"}, "answer": "D", "explanation": "The speeches made by each character will determine his role in the play. A character can be identified by what he says and what others say about him; therefore, dialogue is crucial to character development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>16", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A curtain raiser is an introductory performance that is", "images": [], "options": {"A": "not part of the main play", "B": "the first part of the main play", "C": "not separate from the play", "D": "the first part of the final scene"}, "answer": "A", "explanation": "A curtain raiser is an introductory performance that is not part of the main play. It is often used to set the mood or introduce the themes of the main performance. It is separate from the main play and does not directly contribute to the plot or character development of the main play.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>17", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A stanza of four lines is a", "images": [], "options": {"A": "couplet", "B": "quintet", "C": "septet", "D": "quatrain"}, "answer": "D", "explanation": "Quatrain: a stanza of four lines.  Couplet    - two rhyming lines of a poem  quintlet     - five lines of a poem or a stanza of five lines  septet      - seven lines of poem. It is also known as heptastich.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2014>18", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "------------ in drama operates against a character who is unaware of a situation which the audience know about.", "images": [], "options": {"A": "Verbal irony", "B": "Dramatic irony", "C": "Satire", "D": "Parody"}, "answer": "B", "explanation": "Dramatic irony is a literary device where the audience knows something that the characters do not. In this situation, the audience is aware of a situation that a character is unaware of, which is the definition of dramatic irony. Verbal irony is when what is said is the opposite of what is meant. Satire is the use of humor, irony, exaggeration, or ridicule to expose and criticize people's stupidity or vices. Parody is an imitation of the style of a particular writer, artist, or genre with deliberate exaggeration for comic effect.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>19", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Said the Lion: \"On music I dote    But something is wrong with my throat    When I practice a scale    The listeners quail    And flee at the first note\"    What type of poem is this?", "images": [], "options": {"A": "Epic", "B": "Limerick", "C": "Ode", "D": "Sonnet"}, "answer": "B", "explanation": "This is a humorous poems of five lines with the rhyme scheme aabba.    An ode is a praise poem that is written in the form of an address to a person or thing.  The sonnet is a poem of fourteen lines with a regular rhyme scheme and meter pattern.  The epic is a long narrative poem about heroic deeds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>20", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Said the Lion: \"On music I dote    But something is wrong with my throat    When I practice a scale    The listeners quail    And flee at the first note\"  The rhyme scheme of the poem is", "images": [], "options": {"A": "aabba", "B": "ababa", "C": "ababb", "D": "abbaa"}, "answer": "A", "explanation": "The rhyme scheme of the given poem is AABBA. This is typical of a Limerick. The first, second, and fifth lines (A) rhyme with each other and have three feet of three syllables each. The third and fourth lines (B) rhyme with each other and have two feet of three syllables each.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>21", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "The goldsmith at work is a priest at the altar. As though he were performing the Eucharist, he is engaged in deliberate motions of reverence. The small vials of various liquids such as mercury are little vessels of communion wine. The minuscule rings of intricately crafted gold are like miniature wafers .     He dips one tiny ring into a liquid, lift it up to the sky and presses it onto a space in the growing length of necklace. It fits -- it is like dipping bread into wine and slipping it between the parted lips of a communicant.    Our lent vigils are not as solemn as the goldsmith's silent solemnity that directs his work. We look on as the wizardry of the master craftsman displays itself. We are held in thrall.    The subject matter of the passage is", "images": [], "options": {"A": "a goldsmith at work", "B": "celebrating the Eucharist", "C": "a priest at the altar", "D": "communion wine and wafers"}, "answer": "A", "explanation": "The passage describes a goldsmith at work. The narrator does this by comparing the job of the goldsmith to that of the priest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>22", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "The goldsmith at work is a priest at the altar. As though he were performing the Eucharist, he is engaged in deliberate motions of reverence. The small vials of various liquids such as mercury are little vessels of communion wine. The minuscule rings of intricately crafted gold are like miniature wafers .     He dips one tiny ring into a liquid, lift it up to the sky and presses it onto a space in the growing length of necklace. It fits -- it is like dipping bread into wine and slipping it between the parted lips of a communicant.    Our lent vigils are not as solemn as the goldsmith's silent solemnity that directs his work. We look on as the wizardry of the master craftsman displays itself. We are held in thrall.  The dominion devices used are", "images": [], "options": {"A": "personification and irony", "B": "parallelism and repetition", "C": "metaphor and simile", "D": "metonymy and synecdoche"}, "answer": "C", "explanation": "'... goldsmith at work is a priest ...' - metaphpor  ' ... mercy are little vessels of communication wine' - metaphpor  ' ... crafted gold are like minature wafters..' - simile  '... it is like dripping bread..' - simile  '... not as solemn as the goldsmith's ...' -simile    The extracts above prove that the metaphor and simile are the dominant devices in the passage. The comparison between a goldsmith and a priest constitutes a metaphor.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>23", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "The goldsmith at work is a priest at the altar. As though he were performing the Eucharist, he is engaged in deliberate motions of reverence. The small vials of various liquids such as mercury are little vessels of communion wine. The minuscule rings of intricately crafted gold are like miniature wafers .     He dips one tiny ring into a liquid, lift it up to the sky and presses it onto a space in the growing length of necklace. It fits -- it is like dipping bread into wine and slipping it between the parted lips of a communicant.    Our lent vigils are not as solemn as the goldsmith's silent solemnity that directs his work. We look on as the wizardry of the master craftsman displays itself. We are held in thrall.  The use of the above devices creates an atmosphere of", "images": [], "options": {"A": "fear", "B": "doom", "C": "hope", "D": "awe"}, "answer": "D", "explanation": "Comparing a goldsmith to a priest makes the readers to see the goldsmith in new light and also admire him.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>24", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "The goldsmith at work is a priest at the altar. As though he were performing the Eucharist, he is engaged in deliberate motions of reverence. The small vials of various liquids such as mercury are little vessels of communion wine. The minuscule rings of intricately crafted gold are like miniature wafers .     He dips one tiny ring into a liquid, lift it up to the sky and presses it onto a space in the growing length of necklace. It fits -- it is like dipping bread into wine and slipping it between the parted lips of a communicant.    Our lent vigils are not as solemn as the goldsmith's silent solemnity that directs his work. We look on as the wizardry of the master craftsman displays itself. We are held in thrall.  The writer's attitude is one of", "images": [], "options": {"A": "bewilderment", "B": "reverence", "C": "indifference", "D": "arrogance"}, "answer": "B", "explanation": "The writer's attitude towards the goldsmith and his work is one of reverence. This is evident from the religious and sacred imagery used to describe the goldsmith's work. The goldsmith is compared to a priest, his work to the Eucharist, and his tools to vessels of communion wine. The writer also describes the goldsmith's work as 'wizardry' and states that they are 'held in thrall' by it. Therefore, the correct answer is 'reverence'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>25", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "The goldsmith at work is a priest at the altar. As though he were performing the Eucharist, he is engaged in deliberate motions of reverence. The small vials of various liquids such as mercury are little vessels of communion wine. The minuscule rings of intricately crafted gold are like miniature wafers .     He dips one tiny ring into a liquid, lift it up to the sky and presses it onto a space in the growing length of necklace. It fits -- it is like dipping bread into wine and slipping it between the parted lips of a communicant.    Our lent vigils are not as solemn as the goldsmith's silent solemnity that directs his work. We look on as the wizardry of the master craftsman displays itself. We are held in thrall.  The narrative technique captures the ------- of the scene", "images": [], "options": {"A": "seriousness", "B": "vividness", "C": "ordinariness", "D": "loneliness"}, "answer": "B", "explanation": "The narrative technique captures the 'vividness' of the scene. The author uses detailed and descriptive language to paint a clear and lively picture of the goldsmith at work. The comparison of the goldsmith's work to a religious ceremony adds depth and richness to the scene, making it more vivid and engaging for the reader.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>26", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "At dawn must I rise to till the rock   That our land has turned into    The land where on we'd gleefully harvested paddy    Planted and nurtured and tended on plots revenges    Our woes are bloody woes of accursed revenges    Of the land spirits aggrieved by paltry human respect    For the life of fellow man by his fellow    Kindred blood has counted for less than no value    Brother's wife has been wife to other brother's brother     Communal loot has emptied our country silos      The earth has stopped breathing and sighed     Soldered tears has the moon shed    The earth was scorched at noon-day night    And our land has turned to hoeing rock.    The theme of the poem is", "images": [], "options": {"A": "famine and disease", "B": "draught and heat", "C": "abomination and retribution", "D": "sickness and death"}, "answer": "C", "explanation": "'... on plots revenges'  '... land spirits aggrieved ...'  The theme of the poem is abomination and retribution. In the poem, the people are suffering as a consequence for their evil deeds.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>27", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "At dawn must I rise to till the rock   That our land has turned into    The land where on we'd gleefully harvested paddy    Planted and nurtured and tended on plots revenges    Our woes are bloody woes of accursed revenges    Of the land spirits aggrieved by paltry human respect    For the life of fellow man by his fellow    Kindred blood has counted for less than no value    Brother's wife has been wife to other brother's brother     Communal loot has emptied our country silos      The earth has stopped breathing and sighed     Soldered tears has the moon shed    The earth was scorched at noon-day night    And our land has turned to hoeing rock.  The mood of the poet is one of", "images": [], "options": {"A": "recklessness", "B": "hopelessness", "C": "happiness", "D": "loneliness"}, "answer": "B", "explanation": "He is sad, unhappy and has resigned to suffering because he knows that all they currently face is as a result of their sins.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>28", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "At dawn must I rise to till the rock   That our land has turned into    The land where on we'd gleefully harvested paddy    Planted and nurtured and tended on plots revenges    Our woes are bloody woes of accursed revenges    Of the land spirits aggrieved by paltry human respect    For the life of fellow man by his fellow    Kindred blood has counted for less than no value    Brother's wife has been wife to other brother's brother     Communal loot has emptied our country silos      The earth has stopped breathing and sighed     Soldered tears has the moon shed    The earth was scorched at noon-day night    And our land has turned to hoeing rock.  \"The earth has stopped breathing and sighed\" illustrates", "images": [], "options": {"A": "bathos", "B": "climax", "C": "personification", "D": "paradox"}, "answer": "C", "explanation": "The phrase 'The earth has stopped breathing and sighed' is an example of personification. Personification is a figure of speech in which an inanimate object or abstraction is given human qualities or abilities. In this case, the earth is personified as a living, breathing entity that is capable of sighing, which is a human action.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>29", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "At dawn must I rise to till the rock   That our land has turned into    The land where on we'd gleefully harvested paddy    Planted and nurtured and tended on plots revenges    Our woes are bloody woes of accursed revenges    Of the land spirits aggrieved by paltry human respect    For the life of fellow man by his fellow    Kindred blood has counted for less than no value    Brother's wife has been wife to other brother's brother     Communal loot has emptied our country silos      The earth has stopped breathing and sighed     Soldered tears has the moon shed    The earth was scorched at noon-day night    And our land has turned to hoeing rock.  The run-on lines convey the speaker's", "images": [], "options": {"A": "indignation", "B": "lamentation", "C": "disappointment", "D": "defiance"}, "answer": "B", "explanation": "The run-on lines are lines 3 The poem has a lamentative tone, and this is brought to the fore through the use of run-on-lines (enjambment).", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>30", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "At dawn must I rise to till the rock   That our land has turned into    The land where on we'd gleefully harvested paddy    Planted and nurtured and tended on plots revenges    Our woes are bloody woes of accursed revenges    Of the land spirits aggrieved by paltry human respect    For the life of fellow man by his fellow    Kindred blood has counted for less than no value    Brother's wife has been wife to other brother's brother     Communal loot has emptied our country silos      The earth has stopped breathing and sighed     Soldered tears has the moon shed    The earth was scorched at noon-day night    And our land has turned to hoeing rock.  There is a predominance of words associated with", "images": [], "options": {"A": "celebration", "B": "nature", "C": "governance", "D": "nurture"}, "answer": "B", "explanation": "The dominant images here are taken from nature, that is, rock, land, earth, moon, and night are all used for emphasis in the poem.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>31", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "At dawn must I rise to till the rock   That our land has turned into    The land where on we'd gleefully harvested paddy    Planted and nurtured and tended on plots revenges    Our woes are bloody woes of accursed revenges    Of the land spirits aggrieved by paltry human respect    For the life of fellow man by his fellow    Kindred blood has counted for less than no value    Brother's wife has been wife to other brother's brother     Communal loot has emptied our country silos      The earth has stopped breathing and sighed     Soldered tears has the moon shed    The earth was scorched at noon-day night    And our land has turned to hoeing rock.  What is Caliban promising to do?", "images": [], "options": {"A": "Carry more wood", "B": "Behave appropriately for forgiveness", "C": "Denounce Stephano and Trinculo", "D": "Confess his part in the conspiracy"}, "answer": "B", "explanation": "Caliban, Trinculo and Stephano has been reprimanded and sent to prison by prospero, so Caliban has decided to obey and regrets conspiring with the others.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>32", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Caliban : Ay, that I will; and I'll be wise hereafter,    And seek for grace. What thrice-double as    Was I, to take  this drunkard for a god,    And worship this dull fool!     Prospero: Go to; away!    Alonso: Hence, and bestow your luggage where you found it.    Sebastian: Or stole it, rather.     (Act V, Scene One, lines 293-299)    Prospero has asked Caliban to", "images": [], "options": {"A": "go and bring Miranda", "B": "go to Prospero's cell", "C": "fetch more wood", "D": "learn his language lessons"}, "answer": "B", "explanation": "This is Caliban's punishment for his sin. This is the most accurate answer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>33", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Caliban : Ay, that I will; and I'll be wise hereafter,    And seek for grace. What thrice-double as    Was I, to take  this drunkard for a god,    And worship this dull fool!     Prospero: Go to; away!    Alonso: Hence, and bestow your luggage where you found it.    Sebastian: Or stole it, rather.     (Act V, Scene One, lines 293-299)  The contents of \"your luggage\" are", "images": [], "options": {"A": "Alonso's sachel and swords.", "B": "food and water from the ship", "C": "paddles, fur and harpoon", "D": "the clothing put up by Ariel"}, "answer": "C", "explanation": "These items are stolen from Alonso and his companions", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>34", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Caliban : Ay, that I will; and I'll be wise hereafter,    And seek for grace. What thrice-double as    Was I, to take  this drunkard for a god,    And worship this dull fool!     Prospero: Go to; away!    Alonso: Hence, and bestow your luggage where you found it.    Sebastian: Or stole it, rather.     (Act V, Scene One, lines 293-299)  This drunkard is", "images": [], "options": {"A": "Trinculo", "B": "Stephano", "C": "Gonzalo", "D": "Alonso"}, "answer": "B", "explanation": "In the given excerpt from Act V, Scene One of 'The Tempest', 'this drunkard' refers to Stephano. Caliban, the speaker, had been fooled into thinking Stephano was a god because he had given him wine, which Caliban had never tasted before. Caliban was intoxicated and was easily manipulated by Stephano, hence referring to him as 'this drunkard'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>35", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Caliban : Ay, that I will; and I'll be wise hereafter,    And seek for grace. What thrice-double as    Was I, to take  this drunkard for a god,    And worship this dull fool!     Prospero: Go to; away!    Alonso: Hence, and bestow your luggage where you found it.    Sebastian: Or stole it, rather.     (Act V, Scene One, lines 293-299)  Sebastians says \"Or stole it, rather\" because the luggage", "images": [], "options": {"A": "does not belong to Caliban", "B": "belongs to Caliban", "C": "is not from the boat", "D": "is not from the ship"}, "answer": "A", "explanation": "In the given excerpt from Shakespeare's 'The Tempest', Sebastian's line 'Or stole it, rather' is a sarcastic remark implying that the luggage does not belong to Caliban. Caliban, a native of the island, is considered a savage and a thief by the shipwrecked nobles. Therefore, Sebastian is suggesting that Caliban must have stolen the luggage, not owned it.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>36", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Prospero:  Of my instruction hast thou nothin bated     In what thou hadst to say. So, with good life    And observation range, my meaner ministers    Their several kinds have done. My high charms works,    And these,  mine enemies  are all knit up    In their distractions, they now are in my power;    And in these fits, I leave them, ...    (Act III, Scene Three, lines 85-91)     Prospero is speaking to", "images": [], "options": {"A": "Caliban", "B": "Miranda", "C": "Ferdinard", "D": "Ariel"}, "answer": "D", "explanation": "In the given excerpt, Prospero is speaking to Ariel. This can be inferred from the context of the lines. Prospero is praising the listener for their obedience and successful execution of his orders. Among the given options, Ariel, the spirit who serves Prospero, is the one who carries out Prospero's instructions throughout the play. Therefore, it is most likely that Prospero is speaking to Ariel in this instance.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>37", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Prospero:  Of my instruction hast thou nothin bated     In what thou hadst to say. So, with good life    And observation range, my meaner ministers    Their several kinds have done. My high charms works,    And these,  mine enemies  are all knit up    In their distractions, they now are in my power;    And in these fits, I leave them, ...    (Act III, Scene Three, lines 85-91)   The first line means that the addressee", "images": [], "options": {"A": "obeyed Prospero's instruction exactly", "B": "did not carry out prospero's instructions", "C": "modified the instructions os Prospero", "D": "failed to understand the instructions of prospero"}, "answer": "A", "explanation": "The phrase 'nothing bated' means 'nothing reduced or lessened', indicating that the person addressed has followed Prospero's instructions exactly as given.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>38", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Prospero:  Of my instruction hast thou nothin bated     In what thou hadst to say. So, with good life    And observation range, my meaner ministers    Their several kinds have done. My high charms works,    And these,  mine enemies  are all knit up    In their distractions, they now are in my power;    And in these fits, I leave them, ...    (Act III, Scene Three, lines 85-91)   Prospero's enemies include the voyagers but not", "images": [], "options": {"A": "Alonso", "B": "Antonio", "C": "Francisco", "D": "Stephano"}, "answer": "C", "explanation": "Francisco doesn't know about the conspiracy which displaces Prospero, he is only a Lord in Alonso's suite.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>39", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Prospero:  Of my instruction hast thou nothin bated     In what thou hadst to say. So, with good life    And observation range, my meaner ministers    Their several kinds have done. My high charms works,    And these,  mine enemies  are all knit up    In their distractions, they now are in my power;    And in these fits, I leave them, ...    (Act III, Scene Three, lines 85-91)   What has just taken place is that", "images": [], "options": {"A": "the enemies have been tantalized with a banquet", "B": "Caliban brought home some wood", "C": "Ferdinand is splitting wood", "D": "Miranda has offered to help Ferdinand"}, "answer": "A", "explanation": "Ariel makes a table filled with mouth watering dishes appear before Prospero's enemies and also makes them seem delusional", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>40", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Prospero:  Of my instruction hast thou nothin bated     In what thou hadst to say. So, with good life    And observation range, my meaner ministers    Their several kinds have done. My high charms works,    And these,  mine enemies  are all knit up    In their distractions, they now are in my power;    And in these fits, I leave them, ...    (Act III, Scene Three, lines 85-91)   Prospero decides to", "images": [], "options": {"A": "sit back and watch", "B": "kick Caliban in the mouth", "C": "go to Ferdinard", "D": "discharge Ariel"}, "answer": "C", "explanation": "... while I visit                             - line 91  Young Ferdinand, ...                   - line 92  PROSPERO  And in these fits I leave them, while I visit young Ferdinand", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2014>41", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: So they are.    My spirits, as in a dream, are all bound up    My father's loss, the weakness which I feel,    The wrack of all my friends, nor  this man's  threats    To whom I am subdued, are but light to me    Might I but through my prison once a day    Behold this maid. All corners else o 'th' earth    Let liberty make use of, ...    (Act I, Scene Two, lines 487-496)      The speaker is", "images": [], "options": {"A": "Alonso", "B": "Ferdinand", "C": "Gonzalo", "D": "Boatswain"}, "answer": "B", "explanation": "The speaker is Ferdinand. This is evident from the context of the play where Ferdinand, the son of Alonso, is mourning his father's loss and is also in love with Miranda (the maid he wants to behold).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>42", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: So they are.    My spirits, as in a dream, are all bound up    My father's loss, the weakness which I feel,    The wrack of all my friends, nor  this man's  threats    To whom I am subdued, are but light to me    Might I but through my prison once a day    Behold this maid. All corners else o 'th' earth    Let liberty make use of, ...    (Act I, Scene Two, lines 487-496)     \"this man\" is", "images": [], "options": {"A": "Alonso", "B": "Trinculo", "C": "Stephano", "D": "Prospero"}, "answer": "D", "explanation": "\"this man\" is Prospero, who has enslaved Ferdinand and is using him to ensure his plans come to fruition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>43", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: So they are.    My spirits, as in a dream, are all bound up    My father's loss, the weakness which I feel,    The wrack of all my friends, nor  this man's  threats    To whom I am subdued, are but light to me    Might I but through my prison once a day    Behold this maid. All corners else o 'th' earth    Let liberty make use of, ...    (Act I, Scene Two, lines 487-496)     \"the maid\" is", "images": [], "options": {"A": "Caribel", "B": "Miranda", "C": "Sycorax", "D": "Dido"}, "answer": "B", "explanation": "The only woman present at the scene and young enough to be called a maiden is Miranda.  Miranda is Prospero's daughter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>44", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: So they are.    My spirits, as in a dream, are all bound up    My father's loss, the weakness which I feel,    The wrack of all my friends, nor  this man's  threats    To whom I am subdued, are but light to me    Might I but through my prison once a day    Behold this maid. All corners else o 'th' earth    Let liberty make use of, ...    (Act I, Scene Two, lines 487-496)     Those present in this scene are", "images": [], "options": {"A": "Stephano and Trinculo", "B": "Prospero and Miranda", "C": "Prospero and Gonzalo", "D": "Miranda and Alonso"}, "answer": "B", "explanation": "The excerpt is from Act I, Scene Two of 'The Tempest' by William Shakespeare. In this scene, the characters present are Prospero and Miranda. Prospero is Miranda's father and the former Duke of Milan. Therefore, the correct answer is Prospero and Miranda.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>45", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: So they are.    My spirits, as in a dream, are all bound up    My father's loss, the weakness which I feel,    The wrack of all my friends, nor  this man's  threats    To whom I am subdued, are but light to me    Might I but through my prison once a day    Behold this maid. All corners else o 'th' earth    Let liberty make use of, ...    (Act I, Scene Two, lines 487-496)     \"so they are\" refers to the", "images": [], "options": {"A": "speaker's friends", "B": "speaker's nerves", "C": "monster's threats", "D": "listener's spirits"}, "answer": "B", "explanation": "Before this speech, Prospero says Ferdinand's nerves are weak, so the latter confirms it", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>46", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "If I speak true! If hollowly, invert    What best is boded me to mischief! I,    Beyond all limit of what else i' the world,    Do love, prize, honour you.    (Act III, Scene One, lines 70 - 73)    The speaker is", "images": [], "options": {"A": "prospero", "B": "Ferdinard", "C": "Miranda", "D": "Gonzalo"}, "answer": "B", "explanation": "In the given passage, the speaker is expressing his deep love, respect, and value for the person he is addressing. He is saying that he loves this person beyond all limits of the world. This passage is from Act III, Scene One of 'The Tempest' by William Shakespeare. In this scene, Ferdinand is expressing his love for Miranda. Therefore, the correct answer is 'Ferdinand'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>47", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "If I speak true! If hollowly, invert    What best is boded me to mischief! I,    Beyond all limit of what else i' the world,    Do love, prize, honour you.    (Act III, Scene One, lines 70 - 73)    Who is with the speaker?", "images": [], "options": {"A": "Miranda", "B": "Gonzalo", "C": "Prospero", "D": "Ferdinand"}, "answer": "A", "explanation": "The speaker of these lines is Ferdinand, and he is speaking to Miranda. Therefore, the correct answer is Miranda.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>48", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "If I speak true! If hollowly, invert    What best is boded me to mischief! I,    Beyond all limit of what else i' the world,    Do love, prize, honour you.    (Act III, Scene One, lines 70 - 73)    The speaker wants to", "images": [], "options": {"A": "prove his love", "B": "deny his love", "C": "prove his innocence", "D": "affirm his loyalty"}, "answer": "A", "explanation": "In these lines, Ferdinand is expressing his deep love for Miranda, so he wants to prove his love. Therefore, the correct answer is 'prove his love'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>49", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "If I speak true! If hollowly, invert    What best is boded me to mischief! I,    Beyond all limit of what else i' the world,    Do love, prize, honour you.    (Act III, Scene One, lines 70 - 73)    The speaker is lured to that place by", "images": [], "options": {"A": "Ariel", "B": "Caliban", "C": "Miranda", "D": "Gonzalo"}, "answer": "A", "explanation": "The speaker in these lines is Ferdinand, who was led to that place by Ariel, a spirit under the command of Prospero. Ariel, disguised as a water nymph, led Ferdinand to Miranda, with whom he fell in love.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2014>50", "subject": "Literature", "year": "2014", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "If I speak true! If hollowly, invert    What best is boded me to mischief! I,    Beyond all limit of what else i' the world,    Do love, prize, honour you.    (Act III, Scene One, lines 70 - 73)    The setting is", "images": [], "options": {"A": "another part of the island", "B": "in the palace", "C": "on a ship", "D": "before the Prospero's cell"}, "answer": "A", "explanation": "The scene takes place on an island where Prospero, the rightful Duke of Milan, has been living in exile with his daughter, Miranda. Specifically, these lines are spoken in another part of the island, not in the palace, on a ship, or before Prospero's cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>1", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A speech in a play in which a character speaks his or her thoughts alone is", "images": [], "options": {"A": "a monologue", "B": "an aside", "C": "a soliloquy", "D": "an epiloque"}, "answer": "C", "explanation": "Soliloquy is a form of monologue where a character talks to himself when other casts are not around.  An aside refers to when a character leaves other characters on stage to address the audience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>2", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In literature, repetition is used essentially for", "images": [], "options": {"A": "rhyme", "B": "suspense", "C": "allusion", "D": "emphasis"}, "answer": "D", "explanation": "In literature, repetition is a rhetorical device that involves repeating a word or phrase multiple times to make an idea clearer and more memorable. It is used essentially for emphasis. It helps to stress the importance of the idea or theme that the author is trying to convey.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>3", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The pattern of a poem without reference to its content is referred to as the", "images": [], "options": {"A": "limerick", "B": "metre", "C": "free verse", "D": "form"}, "answer": "D", "explanation": "Analysis of poems involves paying attention to the form and content. The content refers to elements such as themes, the subject matter, mood and tone. The form includes the rhyme, metre, language, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>4", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The performers in a play constitute the", "images": [], "options": {"A": "chorus", "B": "characters", "C": "audience", "D": "cast"}, "answer": "D", "explanation": "The performers in a play constitute the 'cast'. The cast of a play are the actors who perform in it. In this context, it is not referring to the 'characters' which are the roles that the actors play, the 'audience' which are the people watching the play, or the 'chorus' which is a group of performers who comment on the main action, typically speaking and moving together.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2015>5", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pan, O great Pan, to thee    Thus do we sing!    Thou who keep'st chaste and free    As the young spring    Ever be thy honour spake    From that place the morn is broke    To the place day doth unyoke.    The stanza is an example of", "images": [], "options": {"A": "appellation", "B": "apostrophe", "C": "euphemism", "D": "elegy"}, "answer": "B", "explanation": "Apostrophe: a figurative device that is deployed when we address a thing that is not present as if it were present and could hear.  Here, pan is directly addressed.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>6", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pan, O great Pan, to thee    Thus do we sing!    Thou who keep'st chaste and free    As the young spring    Ever be thy honour spake    From that place the morn is broke    To the place day doth unyoke.   Pan is used here as", "images": [], "options": {"A": "an allusion", "B": "a symbol", "C": "iron", "D": "metonymy"}, "answer": "B", "explanation": "In this stanza, Pan is used as a symbol. A symbol is a figure of speech where an object, person, or situation has another meaning other than its literal meaning. Here, Pan, the god of the wild, shepherds, and flocks in Greek mythology, is used as a symbol to represent nature or the natural world.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>7", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Pan, O great Pan, to thee    Thus do we sing!    Thou who keep'st chaste and free    As the young spring    Ever be thy honour spake    From that place the morn is broke    To the place day doth unyoke.   The rhyme scheme of the stanza is", "images": [], "options": {"A": "abcabcc", "B": "ababcdd", "C": "babaccc", "D": "bcbccaa"}, "answer": "B", "explanation": "thee - a  sing - b  free - a   spring - b  spake - c   broke - d  unyoke - d", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>8", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A metrical foot in which a stressed syllable is followed by an unstressed syllable is", "images": [], "options": {"A": "iambic", "B": "spondaic", "C": "trochaic", "D": "dactylic"}, "answer": "C", "explanation": "Trochee - Stressed syllable follpowed by an unstressed syllable.  Iambus - Unstressed syllable followed by a stressed syllable  Spondaic - Two stressed syllables in a foot  Dactylic - A stressed syllable followed by two unstressed ones", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>9", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "----------- is the location of the action of the plot.", "images": [], "options": {"A": "setting", "B": "narrative technique", "C": "point of view", "D": "Characterization"}, "answer": "A", "explanation": "The setting refers to the location of the action in a work of art. It can be extend to mersn the time when the action occured.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2015>10", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A ballad is essentially a ------------ poem", "images": [], "options": {"A": "descriptive", "B": "dramatic", "C": "pastoral", "D": "narrative"}, "answer": "D", "explanation": "Ballad narrates the story of unfulfilled love, historic battles, death of loved ones and stories of supernatural beings. It forms part of the oral tradition of the society where it origanated from.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>11", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The first four lines of the Shakespearean sonnet rhyme", "images": [], "options": {"A": "abcd", "B": "abba", "C": "abab", "D": "cdcd"}, "answer": "C", "explanation": "Shakespearean sonnet rhymes abab/cdcd/efef/gg   It is divided into three quatrains and a heroic couplet", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>12", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A story in which characters or actions represent abstract ideas or moral qualities is", "images": [], "options": {"A": "an epic", "B": "a legend", "C": "an allegory", "D": "a satire"}, "answer": "C", "explanation": "Allegory uses abstract or symbols to portray evil and ills in the society. In an allegory, abstract ideas are personified.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>13", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The use of imagery in prose or verse", "images": [], "options": {"A": "appeals to the senses", "B": "develops the plot", "C": "create confusion", "D": "obscures meaning"}, "answer": "A", "explanation": "Imagery is used when poets create mental 'images' in our minds through words.When these words appeal to our sense of sight, the imagery is termed as VISUAL.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>14", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "'Our leaders will not compromise freedom    Nor will our heads give up liberty.'    The lines illustrate", "images": [], "options": {"A": "soliloquy", "B": "parallelism", "C": "dialogue", "D": "contrast"}, "answer": "B", "explanation": "Parallelism occurs when two statements have the same meaning.  'Freedom' and 'Liberty' mean the same thing but has been said in different forms. This is used for repetition and emphasis", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>15", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "'Our leaders will not compromise freedom    Nor will our heads give up liberty.'  \"heads\" in the second lines is an example of", "images": [], "options": {"A": "synecdoche", "B": "inversion", "C": "epithet", "D": "conceit"}, "answer": "A", "explanation": "The synecdoche is a device the uses a part of the body to represent the whole body.  'Head',  a part of the body, is used to represent humans ( the writer and others).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>16", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A character that develops in the course of a novel or play is described as", "images": [], "options": {"A": "flat", "B": "antagonist", "C": "round", "D": "protagonist"}, "answer": "C", "explanation": "A round character plays a prominent role in a literary work. He is dynamic, and he experiences growth and changes.  The flat character on the other hand is static and one-dimensional. This character does not experience any form of change.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>17", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A dirge is a poem sung", "images": [], "options": {"A": "to send a child to sleep", "B": "to make workers happy", "C": "at birthday party", "D": "at funeral"}, "answer": "D", "explanation": "A dirge is a somber song or lament expressing mourning or grief, such as would be appropriate for performance at a funeral.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>18", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In drama, the ---------- creates humour", "images": [], "options": {"A": "hero", "B": "clown", "C": "villain", "D": "chorus"}, "answer": "B", "explanation": "A clown is an entertainer who paints his face or dresses up in a funny way and performs foolish tricks to make people laugh.  The job of the clown is to make people laugh.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>19", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Let me not love thee if I love thee not\" Illustrates", "images": [], "options": {"A": "metaphor", "B": "proverb", "C": "paradox", "D": "meiosis"}, "answer": "C", "explanation": "The statement \"Let me not love thee if I love thee not\" is an example of a paradox. A paradox is a statement that appears to be self-contradictory or silly but may include a latent truth. In this case, the speaker is expressing a contradiction where they do not want to love if they do not love, which is inherently contradictory.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>20", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "---------- is a literary device used to express unpleasant in more acceptable manner.", "images": [], "options": {"A": "Epilogue", "B": "Epigram", "C": "Euphemism", "D": "Eulogy"}, "answer": "C", "explanation": "The euphemism is a figurative device that expresses an unpleasant event in a less offensive manner.  An armed robber is called a gentle man of the high way - to say it more pleasantly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>21", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "A modest two-room hut built of mud and roofed with straw graciously sheltered the Mensahs. One of the rooms advertised itself as a living room. The kind earthenware pot willingly kept company with four ever-smilling stools. The pot eternally contained cool water for guests. The second room was a warm-hearted bedroom without a bed. The poor pair had to sleep on bare straw mats on the polished dirt floor. Some over washed rags deputised for blankets and sheets and pillows. Two strong dry logs, facing each other like bitter rivals burned themselves out at night, not merely to keep the couple warm but mainly to ward off hungry mosquitoes and other hostile pests.    There was no door to ward off the cold night air. Some rude devices, however, were contrived to keep the room quite safe from prying eyes and curious domestic animals. Would any thief be ever tempted to peep into  such a rude room of such a poor pair?      The writer's attitude to the couple is one of", "images": [], "options": {"A": "resignation", "B": "indifference", "C": "patronage", "D": "praise"}, "answer": "A", "explanation": "The writer feels helpless to their situation. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>22", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "A modest two-room hut built of mud and roofed with straw graciously sheltered the Mensahs. One of the rooms advertised itself as a living room. The kind earthenware pot willingly kept company with four ever-smilling stools. The pot eternally contained cool water for guests. The second room was a warm-hearted bedroom without a bed. The poor pair had to sleep on bare straw mats on the polished dirt floor. Some over washed rags deputised for blankets and sheets and pillows. Two strong dry logs, facing each other like bitter rivals burned themselves out at night, not merely to keep the couple warm but mainly to ward off hungry mosquitoes and other hostile pests.    There was no door to ward off the cold night air. Some rude devices, however, were contrived to keep the room quite safe from prying eyes and curious domestic animals. Would any thief be ever tempted to peep into  such a rude room of such a poor pair?    The dominant literary device used in the passage is", "images": [], "options": {"A": "litotes", "B": "personification", "C": "simile", "D": "paradox"}, "answer": "B", "explanation": "Personification: the act of giving human qualities to inanimate objects of nature.  '... rooms advertised itself...  ... pot willingly kept company with four ever smiling stools   ... logs, facing each other ...  ... door to ward off the cold night air  ... such a rude room...", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>23", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "A modest two-room hut built of mud and roofed with straw graciously sheltered the Mensahs. One of the rooms advertised itself as a living room. The kind earthenware pot willingly kept company with four ever-smilling stools. The pot eternally contained cool water for guests. The second room was a warm-hearted bedroom without a bed. The poor pair had to sleep on bare straw mats on the polished dirt floor. Some over washed rags deputised for blankets and sheets and pillows. Two strong dry logs, facing each other like bitter rivals burned themselves out at night, not merely to keep the couple warm but mainly to ward off hungry mosquitoes and other hostile pests.    There was no door to ward off the cold night air. Some rude devices, however, were contrived to keep the room quite safe from prying eyes and curious domestic animals. Would any thief be ever tempted to peep into  such a rude room of such a poor pair?    The rhetorical question that ends the passage stresses the", "images": [], "options": {"A": "wickedness of thieves", "B": "poverty of the couple", "C": "security of the hut", "D": "filthiness of the surrounding"}, "answer": "B", "explanation": "Rhetorical questions are used to place emphasis on information tha has already been established. Here, the rhetorical question is used to emphasised the level of poverty facing the couple.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>24", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "A modest two-room hut built of mud and roofed with straw graciously sheltered the Mensahs. One of the rooms advertised itself as a living room. The kind earthenware pot willingly kept company with four ever-smilling stools. The pot eternally contained cool water for guests. The second room was a warm-hearted bedroom without a bed. The poor pair had to sleep on bare straw mats on the polished dirt floor. Some over washed rags deputised for blankets and sheets and pillows. Two strong dry logs, facing each other like bitter rivals burned themselves out at night, not merely to keep the couple warm but mainly to ward off hungry mosquitoes and other hostile pests.    There was no door to ward off the cold night air. Some rude devices, however, were contrived to keep the room quite safe from prying eyes and curious domestic animals. Would any thief be ever tempted to peep into  such a rude room of such a poor pair?    The expression 'such a rude room of such a poor pair' illustrates", "images": [], "options": {"A": "onomatopoeia", "B": "pun", "C": "rhyme", "D": "alliteration"}, "answer": "D", "explanation": "such a  r ude  r oom of such a  p oor  p air  'r' and 'p' alliterates", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>25", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "A modest two-room hut built of mud and roofed with straw graciously sheltered the Mensahs. One of the rooms advertised itself as a living room. The kind earthenware pot willingly kept company with four ever-smilling stools. The pot eternally contained cool water for guests. The second room was a warm-hearted bedroom without a bed. The poor pair had to sleep on bare straw mats on the polished dirt floor. Some over washed rags deputised for blankets and sheets and pillows. Two strong dry logs, facing each other like bitter rivals burned themselves out at night, not merely to keep the couple warm but mainly to ward off hungry mosquitoes and other hostile pests.    There was no door to ward off the cold night air. Some rude devices, however, were contrived to keep the room quite safe from prying eyes and curious domestic animals. Would any thief be ever tempted to peep into  such a rude room of such a poor pair?    The setting is", "images": [], "options": {"A": "dawn", "B": "sunset", "C": "midday", "D": "night"}, "answer": "D", "explanation": "The time setting is at night.  Words like 'sleep', 'burning logs', 'night' and 'cold night air' indicate that this scene occurred at night", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>26", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Proud mothers of the coming age,    'Tis good to find you now engage    Your minds and time your lives to raise    Above the level of bygone days.      'Tis good to see you play your part    With spirit and undaunted heart,    It gives young Afric's throbbing soul    A glimpse of a bright and glorious goal.      God bless you, mothers of our race,    God cause to shine on you His face,    And give you strength and all you crave    To bring forth sons and daughters brave.      The rhyme scheme is", "images": [], "options": {"A": "aabb ccdd eeff", "B": "abab abab aabb", "C": "abca abbc abab", "D": "abba abca abab"}, "answer": "A", "explanation": "Each stanza has two couplets.    age - a  engage - a  raise - b  days - b    part - c  heart - c  soul - d  goal - d    race - e  face - e  crave - f   brave - f", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>27", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Proud mothers of the coming age,    'Tis good to find you now engage    Your minds and time your lives to raise    Above the level of bygone days.      'Tis good to see you play your part    With spirit and undaunted heart,    It gives young Afric's throbbing soul    A glimpse of a bright and glorious goal.      God bless you, mothers of our race,    God cause to shine on you His face,    And give you strength and all you crave    To bring forth sons and daughters brave.    The theme of the poem is", "images": [], "options": {"A": "the love of mother", "B": "invoking the spirit of womanhood", "C": "admiration for women's hard work", "D": "the suffering of women"}, "answer": "C", "explanation": "The poem centres on the admiration the persona has for women's hard work.   'proud mothers...'  with spirit and undaunted hearts   God bless you, mothers of our race", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>28", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Proud mothers of the coming age,    'Tis good to find you now engage    Your minds and time your lives to raise    Above the level of bygone days.      'Tis good to see you play your part    With spirit and undaunted heart,    It gives young Afric's throbbing soul    A glimpse of a bright and glorious goal.      God bless you, mothers of our race,    God cause to shine on you His face,    And give you strength and all you crave    To bring forth sons and daughters brave.    The literary device used in line 7 is", "images": [], "options": {"A": "conceit", "B": "personification", "C": "hyperbole", "D": "pathos"}, "answer": "B", "explanation": "The literary device used in line 7, 'It gives young Afric's throbbing soul', is personification. Personification is a figure of speech in which a thing, an idea or an animal is given human attributes. In this case, 'Afric's throbbing soul' is personified, as Africa is given the human attribute of having a 'throbbing soul'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>29", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Proud mothers of the coming age,    'Tis good to find you now engage    Your minds and time your lives to raise    Above the level of bygone days.      'Tis good to see you play your part    With spirit and undaunted heart,    It gives young Afric's throbbing soul    A glimpse of a bright and glorious goal.      God bless you, mothers of our race,    God cause to shine on you His face,    And give you strength and all you crave    To bring forth sons and daughters brave.    The poet's tone is one of", "images": [], "options": {"A": "sadness", "B": "joy", "C": "condemnation", "D": "sarcasm"}, "answer": "B", "explanation": "The poet is happy with the work of mothers. He sees mothers are people with a huge role to play in terms of devoloping Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>30", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Proud mothers of the coming age,    'Tis good to find you now engage    Your minds and time your lives to raise    Above the level of bygone days.      'Tis good to see you play your part    With spirit and undaunted heart,    It gives young Afric's throbbing soul    A glimpse of a bright and glorious goal.      God bless you, mothers of our race,    God cause to shine on you His face,    And give you strength and all you crave    To bring forth sons and daughters brave.    \"To bring forth sons and daughters brave\" illustrates", "images": [], "options": {"A": "paradox", "B": "zeugma", "C": "inversion", "D": "epigram"}, "answer": "C", "explanation": "Inversion: This is a change of the natural word order of a sentence or expression.   Here, the extract can be rewritten as 'To bring forth brave sons and daughters'", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2015>31", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: The Tempest    Silence! One word more    Shall make me chide thee, if not hate thee. What!    An advocate for an imposter! Hush!    (Act I, Scene Two, lines 478 - 480)     The speaker is", "images": [], "options": {"A": "Gonzalo", "B": "Antonio", "C": "Prospero", "D": "Alonso"}, "answer": "C", "explanation": "The speaker in the given lines from 'The Tempest' by William Shakespeare is Prospero. Prospero is the rightful Duke of Milan, who, with his daughter Miranda, was sent on a boat to die by his usurping brother Antonio. He is a powerful magician, who uses his abilities to control spirits and manipulate his enemies. In the given lines, Prospero is expressing his anger and frustration.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>32", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: The Tempest    Silence! One word more    Shall make me chide thee, if not hate thee. What!    An advocate for an imposter! Hush!    (Act I, Scene Two, lines 478 - 480)   The addressee is", "images": [], "options": {"A": "Ariel", "B": "Ferdinand", "C": "Caliban", "D": "Miranda"}, "answer": "D", "explanation": "Miranda is being addressed. She asks her father to deal gently with Ferdinand", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>33", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: The Tempest    Silence! One word more    Shall make me chide thee, if not hate thee. What!    An advocate for an imposter! Hush!    (Act I, Scene Two, lines 478 - 480)   The \"impostor\" is", "images": [], "options": {"A": "Sabastin", "B": "Antonio", "C": "Ferdinand", "D": "Alonso"}, "answer": "C", "explanation": "In the context of the play, Prospero, the speaker of these lines, is referring to Ferdinand as an impostor because he does not trust him and suspects him of having ulterior motives.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>34", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: The Tempest    Silence! One word more    Shall make me chide thee, if not hate thee. What!    An advocate for an imposter! Hush!    (Act I, Scene Two, lines 478 - 480)   The \"advocate\" and the \"imposter\" are", "images": [], "options": {"A": "conspirators", "B": "enemies", "C": "suspicious of each other", "D": "attracted to each other"}, "answer": "D", "explanation": "The advocate (Miranda) and the imposter (Ferdinand) fall in love with each.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>35", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: The Tempest    Silence! One word more    Shall make me chide thee, if not hate thee. What!    An advocate for an imposter! Hush!    (Act I, Scene Two, lines 478 - 480)   The speaker's utterance betrays his", "images": [], "options": {"A": "anger", "B": "presence", "C": "hatred", "D": "sorrow"}, "answer": "A", "explanation": "The speaker's utterance in the given lines from 'The Tempest' by William Shakespeare reveals his anger. The speaker threatens to chide, or scold, the listener if they speak another word, and even suggests he might hate them. This strong language and the intensity of the speaker's reaction suggest anger.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>36", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "You cram  these words  into mine ears against    The stomach of my sense. Would I had never    Married my daughter there! For, coming thence,    My son is lost, and in my rate , she too,    (Act II, Scene One, lines 99 - 102)    The speaker is", "images": [], "options": {"A": "Gonzalo", "B": "Antonio", "C": "Sebastian", "D": "Alonso"}, "answer": "D", "explanation": "The speaker in the given lines from 'The Tempest' by William Shakespeare is Alonso. The speaker expresses regret for marrying his daughter off, as it has resulted in his son being lost. Alonso is the only character in the play who has a son and a daughter, making him the speaker of these lines.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>37", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "You cram  these words  into mine ears against    The stomach of my sense. Would I had never    Married my daughter there! For, coming thence,    My son is lost, and in my rate , she too,    (Act II, Scene One, lines 99 - 102)   \"these words\" refers to", "images": [], "options": {"A": "the shipwreck", "B": "the son disappearance", "C": "the daughter's wedding", "D": "Prospero's magic"}, "answer": "B", "explanation": "After the shipwreck, Ferdinand is seen in another part of the Island, away from his father and others.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>38", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "You cram  these words  into mine ears against    The stomach of my sense. Would I had never    Married my daughter there! For, coming thence,    My son is lost, and in my rate , she too,    (Act II, Scene One, lines 99 - 102)   Where did the wedding take place?", "images": [], "options": {"A": "Algiers", "B": "Milan", "C": "Tunis", "D": "Naples"}, "answer": "B", "explanation": "Earlier, Gonzalo speaks of how their garments are fresh when they are at  Tunis at the marriage of Alonso's daughter", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>39", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "You cram  these words  into mine ears against    The stomach of my sense. Would I had never    Married my daughter there! For, coming thence,    My son is lost, and in my rate , she too,    (Act II, Scene One, lines 99 - 102)   The setting is", "images": [], "options": {"A": "outside Prosperos cell", "B": "on a ship", "C": "in front of Prospero cell", "D": "another part of the island"}, "answer": "D", "explanation": "Aafter the tempest, Ferdinand is on a different part of the Island, Alonso and his friend on another part and Trinculo and Stephano are also seen separately on the Island", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>40", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "You cram  these words  into mine ears against    The stomach of my sense. Would I had never    Married my daughter there! For, coming thence,    My son is lost, and in my rate , she too,    (Act II, Scene One, lines 99 - 102)   \"...in my rate\" means", "images": [], "options": {"A": "I am very certain", "B": "so far as I can see", "C": "there is no doubt", "D": "as it appears"}, "answer": "B", "explanation": "Alonso said this ' in his own opinion'. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>41", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Ariel: All hail, great master! Grave sir, hail! I come    To answer the best pleasure; be't to fly    To wim, to dive into the fire, to ride    On the curled clouds, to thys strong bidding task    Ariel and all his quality.    (Act I, Scene Two, lines 189-193)    Ariel has 'come' because", "images": [], "options": {"A": "he has been invited by Prospero", "B": "he wants to make a request", "C": "he desires a meeting", "D": "flying is no problem"}, "answer": "A", "explanation": "In the given excerpt from 'The Tempest' by William Shakespeare, Ariel, a spirit, is speaking to his master, Prospero. Ariel says he has come to 'answer the best pleasure', meaning he has come to do Prospero's bidding or fulfill his commands. Therefore, the correct answer is that Ariel has 'come' because he has been invited by Prospero.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>42", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Ariel: All hail, great master! Grave sir, hail! I come    To answer the best pleasure; be't to fly    To wim, to dive into the fire, to ride    On the curled clouds, to thys strong bidding task    Ariel and all his quality.    (Act I, Scene Two, lines 189-193)  Prospero has actually", "images": [], "options": {"A": "raised a storm at sea", "B": "punished Miranda", "C": "dismissed Ferdinand", "D": "commanded Ariel to disappear"}, "answer": "A", "explanation": "In the context of 'The Tempest', Prospero, a powerful magician, has indeed raised a storm at sea. This is not directly stated in the given excerpt, but it is a significant event in the play. Ariel, who is speaking in the excerpt, is a spirit who serves Prospero and carries out his commands, including creating the storm. Therefore, the correct answer is that Prospero has actually raised a storm at sea.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>43", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Ariel: All hail, great master! Grave sir, hail! I come    To answer the best pleasure; be't to fly    To wim, to dive into the fire, to ride    On the curled clouds, to thys strong bidding task    Ariel and all his quality.    (Act I, Scene Two, lines 189-193)  Before Ariel's entry", "images": [], "options": {"A": "Ferdinand has brought in some wood", "B": "Prospero had put Miranda to sleep", "C": "Caliban had been swearing at Prospero", "D": "Trinculo had discovered caliban's cloak"}, "answer": "B", "explanation": "Before Ariel's entry, Prospero had put Miranda to sleep. In Act I, Scene Two of 'The Tempest', Prospero uses his magical powers to make his daughter Miranda fall asleep because he needs to converse with Ariel, his spirit servant, privately. This is why Ariel hails him as 'great master' and is ready to do his bidding.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>44", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Ariel: All hail, great master! Grave sir, hail! I come    To answer the best pleasure; be't to fly    To wim, to dive into the fire, to ride    On the curled clouds, to thys strong bidding task    Ariel and all his quality.    (Act I, Scene Two, lines 189-193)  'Ariel and all his quality' means Ariel and", "images": [], "options": {"A": "all at his command", "B": "the quality of a spirit", "C": "his band of spirit", "D": "an ability to cause mischief"}, "answer": "C", "explanation": "'Ariel and all his quality' refers to Ariel and his band of spirits. In the context of 'The Tempest', 'quality' refers to Ariel's fellow spirits who, like him, are under Prospero's command. Ariel is a spirit who serves Prospero and he is often accompanied by other spirits who assist him in carrying out Prospero's orders.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>45", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Ariel: All hail, great master! Grave sir, hail! I come    To answer the best pleasure; be't to fly    To wim, to dive into the fire, to ride    On the curled clouds, to thys strong bidding task    Ariel and all his quality.    (Act I, Scene Two, lines 189-193)  Soon after, Ariel", "images": [], "options": {"A": "flies off to do his duty", "B": "recounts the confusion on board the ship", "C": "kneels down to worship prospero", "D": "calls Ceres and another spirit"}, "answer": "B", "explanation": "Prospero just asks the King to sleep so he cab take guard", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>46", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: We two, my lord,    Will guard your person while you take your rest,    And watch your safety.  Y: Thank you- Wondrous heavy.    (Act II, Scene One, lines 184 - 187).    X and Y are", "images": [], "options": {"A": "Antonio and Alonso", "B": "Sebastian and Alonso", "C": "Antonio and Gonzalo", "D": "Sebastian and Gonzalo"}, "answer": "A", "explanation": "Antonio asks the king to sleep so he can take guard", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>47", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: We two, my lord,    Will guard your person while you take your rest,    And watch your safety.  Y: Thank you- Wondrous heavy.    (Act II, Scene One, lines 184 - 187).  \"We two\" are", "images": [], "options": {"A": "Antonio and Adrian", "B": "Sebastian and Adrian", "C": "Sebastian and Franciso", "D": "Antonio and Sebastian"}, "answer": "D", "explanation": "Antonio and Sebastian asks Alonso to sleep, promising to keep watch", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>48", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: We two, my lord,    Will guard your person while you take your rest,    And watch your safety.  Y: Thank you- Wondrous heavy.    (Act II, Scene One, lines 184 - 187).  The situation in the extract is highly", "images": [], "options": {"A": "satirical", "B": "prophetic", "C": "ironical", "D": "comical"}, "answer": "C", "explanation": "The extract is ironical because Antonio and Sebastian plot to kill Alonso in his sleep, so they mean the opposite of what they say. This is a form of verbal irony.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>49", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: We two, my lord,    Will guard your person while you take your rest,    And watch your safety.  Y: Thank you- Wondrous heavy.    (Act II, Scene One, lines 184 - 187).  What has happened to all the other characters in the scene?", "images": [], "options": {"A": "They have been made deaf and dumb", "B": "Ariel has put them all to sleep", "C": "They have been sent away", "D": "Prospero has put them to sleep"}, "answer": "B", "explanation": "In the play 'The Tempest' by William Shakespeare, Ariel, a spirit, has the ability to put people to sleep. In this scene, Ariel has put all the other characters to sleep.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2015>50", "subject": "Literature", "year": "2015", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "X: We two, my lord,    Will guard your person while you take your rest,    And watch your safety.  Y: Thank you- Wondrous heavy.    (Act II, Scene One, lines 184 - 187).  The \"two\" later plot to", "images": [], "options": {"A": "kill all the other characters", "B": "escape from the island", "C": "kill Prospero and Miranda", "D": "Kill Alonso and Gonzalo"}, "answer": "D", "explanation": "Antonio just as he overthrows his brother, ask Sebastian to do the same to Alonso. They also plan to kill Gonzalo in the process.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>1", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": ".............. refers to the structure of  a work of art.", "images": [], "options": {"A": "Form", "B": "Plot", "C": "Settings", "D": "Style"}, "answer": "A", "explanation": "The form of a literary work is basically the structure: things we can see. Examples of elements which fall into this category include: rhyme. number of stanzas, diction, language, figures of speech and sound devices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>2", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Conflict in a literary work begins to unfold with", "images": [], "options": {"A": "climax", "B": "episode", "C": "exposition", "D": "resolution"}, "answer": "D", "explanation": "The reolution is the point where the conflict is settled.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>3", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The character assumed by the author in his writing is", "images": [], "options": {"A": "protagonist", "B": "chorus", "C": "persona", "D": "pseudonym"}, "answer": "C", "explanation": "The character assumed by the author in his writing is referred to as the 'persona'. The persona is the voice or character representing the speaker in a literary work. It is not necessarily the author himself, but it does allow the author to speak in different voices in different works. The protagonist is the main character in a story, while the chorus is a group of characters in Greek tragedy (and in later forms of drama), who comment on the action of a play without participation in it. A pseudonym is a fictitious name, especially one used by an author.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>4", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Oral literature is part of", "images": [], "options": {"A": "drama", "B": "folklore", "C": "poetry", "D": "music"}, "answer": "B", "explanation": "Oral literature includes traditional stories which are transmitted through speech or songs.They include folktales, ballads, chants, prose or verses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2016>5", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Poetry is written in", "images": [], "options": {"A": "chapters", "B": "paragraphs", "C": "scenes", "D": "lines"}, "answer": "D", "explanation": "Lines of a poem makes up a verse. Poetry is written in lines and stanzas. Prose is divided into chapters containing paragraphs. Scenes are found in drama.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2016>6", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Soliloquy is a ........ technique", "images": [], "options": {"A": "descriptive", "B": "dramatic", "C": "narrative", "D": "poetic"}, "answer": "B", "explanation": "Soliloquy is a dramatic technique in which an actor speaks his thought aloud when alone. Other dramatic technique includes mime, flashback, costume, foreshadowing and dialogue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>7", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The ........ produces comic relief in drama", "images": [], "options": {"A": "chorus", "B": "protagonist", "C": "antagonist", "D": "clown"}, "answer": "D", "explanation": "A clown perform as an entertainer and wears funny clothes in order to make people laugh.  Comic relief in a tragedy is a funny scene that is meant to reduce the tragic tension.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>8", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short play is also called a", "images": [], "options": {"A": "farce", "B": "novelette", "C": "playlet", "D": "slapstick"}, "answer": "C", "explanation": "This is a short form of drama popularly known as a short play. A novelette is often used as a synonym for the short story.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2016>9", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the stanza and answer this question.    For days I wept and felt depressed  The one and all I loved had left  But then on me our bill impressed   'Your love is where she looks bereft'    The rhyme scheme is", "images": [], "options": {"A": "abab", "B": "aaba", "C": "abcc", "D": "abbc"}, "answer": "A", "explanation": "depressed - a  left - b  impressed - a  bereft - b    This rhyming pattern is also known as alternate rhymes.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>10", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the stanza and answer this question.    For days I wept and felt depressed  The one and all I loved had left  But then on me our bill impressed   'Your love is where she looks bereft'  The lines are Iambic", "images": [], "options": {"A": "pentameter", "B": "quatrain", "C": "tetrameter", "D": "hexameter"}, "answer": "C", "explanation": "Iambic is a foot of two syllables which starts with an unstressed syllable, then followed by a stressed one. A tetrameter is a line of poetry containing four feet.    In the extact below, the capitalised words or syllables are stressed:  for DAYS/ i WEPT/ and FELT/ dePRESSED/  Here, we have eight syllables that are divided into four iambic feet (Ianbic tetrameter.)", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>11", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the stanza and answer this question.    For days I wept and felt depressed  The one and all I loved had left  But then on me our bill impressed   'Your love is where she looks bereft'  The lines constitute", "images": [], "options": {"A": "an epic", "B": "a quatrain", "C": "an ode", "D": "a sestet"}, "answer": "B", "explanation": "The given stanza is a quatrain. A quatrain is a type of stanza, or a complete poem, consisting of four lines. The stanza provided in the question has four lines, hence it is a quatrain.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>12", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"The sun smiled gently on the scene\" illustrates", "images": [], "options": {"A": "paradox", "B": "euphemism", "C": "hyperbole", "D": "personification"}, "answer": "D", "explanation": "Personification is the transfer of human attribute to inanimate objects.   Here, the sun is attributed with the quality of smiling.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>13", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The major part of the Petrachan sonnet is", "images": [], "options": {"A": "quintet", "B": "sestet", "C": "tercet", "D": "octave"}, "answer": "D", "explanation": "A Petrachan or Italian sonnet is made up of an octave and sestet i.e  8 lines and 6 lines respectively. The octave introduces or a problem, expresses a desire or a conflict within the speaker's soul.. It has a rhyme scheme of abba abba cdc cdc.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>14", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A poem that celebrates an object, person or event is", "images": [], "options": {"A": "a sonnet", "B": "a dirge", "C": "an ode", "D": "a ballad"}, "answer": "C", "explanation": "An ode is a poem that speaks of special events, persons or things. It is a praise poem that is written of the form of an address to the thing it praises.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>15", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"That it will rain is not unlikely\" illustrates the use of", "images": [], "options": {"A": "irony", "B": "litotes", "C": "aside", "D": "inuendo"}, "answer": "B", "explanation": "Litotes or meisosis is a figure of speech an affirmative is expressed by negation of the contrast. It is a deliberate understatement.  It is the use of double negatives to express a positive meaning. Here, \"not unlikely\" = likely", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>16", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An ...... is an indirect an usually unfavourable remark.", "images": [], "options": {"A": "allusion", "B": "irony", "C": "aside", "D": "inuendo"}, "answer": "D", "explanation": "An 'innuendo' is an indirect and usually unfavorable remark. It is a veiled or indirect expression of a derogatory or critical nature, often used to convey criticism, sarcasm, or cleverness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>17", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "'Many hands make light work' illustrates", "images": [], "options": {"A": "zeugma", "B": "hyperbole", "C": "metonymy", "D": "synedoche"}, "answer": "D", "explanation": "Synedoche is the representation of a whole with one of its parts.  Here, \"many hands\" refer to mmany people..", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>18", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Through ...... the ills of the society are criticised with the objectives of having them corrected.", "images": [], "options": {"A": "dramatic irony", "B": "comic relief", "C": "satire", "D": "farce"}, "answer": "C", "explanation": "The literary approach rebukes human errors in humorous way with the aim of correcting them. The satire criticises vices, follies and other societal problems.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>19", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the following lines to answer this question.    The livid waters roared and snarled and flapped   At the poor battered and weeping yatch.    The dominant literary device used in the lines is", "images": [], "options": {"A": "simile", "B": "alliteration", "C": "assonance", "D": "personification"}, "answer": "D", "explanation": "Human attributes, were given to the body of water and yatch. That is, they are roaring, snarling and flapping.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>20", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the following lines to answer this question.    The livid waters roared and snarled and flapped   At the poor battered and weeping yatch.  The picture presented is one of", "images": [], "options": {"A": "quiet sea", "B": "dark sky", "C": "stormy weather", "D": "calm"}, "answer": "C", "explanation": "The visual imagery depicted in the lines show a restless body of water and its effect on the vessel. This shows that there is a storm at sea.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>21", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this question.    He was under the siege of three union executive members. There was the Secretary standing over him; there was the Treasurer puffing away at  a cigarette; there was the organizer longing near the door, a deadpan look  plastered on each of their faces like a death - mask .  Incredulous, he sat in a pensive mood. How could the others do such a thing? His discontent turned to silent anger that simmered.  \"I think it is not right . \"he said just managing not to explode from his growing anger.  \"You sign that sheet, Mr President, \"ordered the secretary in a barely audible but stern voice.  \"Why are you doing this?\" he asked ,his voice was not giving any hint of the boiling cauldron of  screaming anger  in his chest. Will you sign, Mr President?\"   \"All right,\"he said, now seething amiably.  He took his pen, picked up the sheet of paper and looked over the signatures. Then he proceeded to tear up the paper - into shreds.    The attitude of the writer towards the president is one of", "images": [], "options": {"A": "contempt", "B": "disdain", "C": "disinterest", "D": "approval"}, "answer": "D", "explanation": "The writer revealed the inner thoughts of the President, showing justification for rhe President's actions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>22", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this question.    He was under the siege of three union executive members. There was the Secretary standing over him; there was the Treasurer puffing away at  a cigarette; there was the organizer longing near the door, a deadpan look  plastered on each of their faces like a death - mask .  Incredulous, he sat in a pensive mood. How could the others do such a thing? His discontent turned to silent anger that simmered.  \"I think it is not right . \"he said just managing not to explode from his growing anger.  \"You sign that sheet, Mr President, \"ordered the secretary in a barely audible but stern voice.  \"Why are you doing this?\" he asked ,his voice was not giving any hint of the boiling cauldron of  screaming anger  in his chest. Will you sign, Mr President?\"   \"All right,\"he said, now seething amiably.  He took his pen, picked up the sheet of paper and looked over the signatures. Then he proceeded to tear up the paper - into shreds.  The prevailing atmosphere is", "images": [], "options": {"A": "tense", "B": "sad", "C": "cordial", "D": "warm"}, "answer": "A", "explanation": "The atmosphere is tense because there appears to be a standoff between the president and the others.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>23", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this question.    He was under the siege of three union executive members. There was the Secretary standing over him; there was the Treasurer puffing away at  a cigarette; there was the organizer longing near the door, a deadpan look  plastered on each of their faces like a death - mask .  Incredulous, he sat in a pensive mood. How could the others do such a thing? His discontent turned to silent anger that simmered.  \"I think it is not right . \"he said just managing not to explode from his growing anger.  \"You sign that sheet, Mr President, \"ordered the secretary in a barely audible but stern voice.  \"Why are you doing this?\" he asked ,his voice was not giving any hint of the boiling cauldron of  screaming anger  in his chest. Will you sign, Mr President?\"   \"All right,\"he said, now seething amiably.  He took his pen, picked up the sheet of paper and looked over the signatures. Then he proceeded to tear up the paper - into shreds.  The expression \" plastered on each of their faces like a death mask\" illustrates", "images": [], "options": {"A": "alliteration and metaphor", "B": "simile and personification", "C": "personification and alliteration", "D": "metaphor and simile"}, "answer": "D", "explanation": "Metaohor and simile. The metaphor is a direct comparison while the simile is an indirect comparison that makes use of as or like.     'plastered on each of their faces' depicts metaphor because it shows direct comparison.  '... like a death mask' shows simile because 'like' was used to compare their looks and a death mask.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>24", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this question.    He was under the siege of three union executive members. There was the Secretary standing over him; there was the Treasurer puffing away at  a cigarette; there was the organizer longing near the door, a deadpan look  plastered on each of their faces like a death - mask .  Incredulous, he sat in a pensive mood. How could the others do such a thing? His discontent turned to silent anger that simmered.  \"I think it is not right . \"he said just managing not to explode from his growing anger.  \"You sign that sheet, Mr President, \"ordered the secretary in a barely audible but stern voice.  \"Why are you doing this?\" he asked ,his voice was not giving any hint of the boiling cauldron of  screaming anger  in his chest. Will you sign, Mr President?\"   \"All right,\"he said, now seething amiably.  He took his pen, picked up the sheet of paper and looked over the signatures. Then he proceeded to tear up the paper - into shreds.  \"..... screaming anger\" \"is an example of", "images": [], "options": {"A": "allusion", "B": "personification", "C": "simile", "D": "euphemism"}, "answer": "B", "explanation": "Personification: This is an act of giving human attributes to inanimate of abstract objects. Here, \"anger\" is attributed to be \"screaming\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>25", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer this question.    He was under the siege of three union executive members. There was the Secretary standing over him; there was the Treasurer puffing away at  a cigarette; there was the organizer longing near the door, a deadpan look  plastered on each of their faces like a death - mask .  Incredulous, he sat in a pensive mood. How could the others do such a thing? His discontent turned to silent anger that simmered.  \"I think it is not right . \"he said just managing not to explode from his growing anger.  \"You sign that sheet, Mr President, \"ordered the secretary in a barely audible but stern voice.  \"Why are you doing this?\" he asked ,his voice was not giving any hint of the boiling cauldron of  screaming anger  in his chest. Will you sign, Mr President?\"   \"All right,\"he said, now seething amiably.  He took his pen, picked up the sheet of paper and looked over the signatures. Then he proceeded to tear up the paper - into shreds.  The last paragraph illustrates", "images": [], "options": {"A": "foreshadow", "B": "pathos", "C": "bathos", "D": "climax"}, "answer": "D", "explanation": "Climax is the highest point in an ascending series where the forces reach their moment of highest concentration.  He took his pen, picked up the sheet of a paper looked over the signature and tore up the paper. In that sentence, there is an obvious rise in the action.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>26", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this question.    We have come to the crossroads  And I must either leave or come with you  I lingered over the choice  You lifted the lamp of love  And I saw in your face  The road that I should take    The theme of the poem is", "images": [], "options": {"A": "indecision", "B": "separation", "C": "rejected love", "D": "requited love"}, "answer": "A", "explanation": "The theme of the poem is 'indecision'. A theme in literature is the central topic or idea explored in a text. In the given poem, the speaker is at a crossroads and must make a decision - to leave or to come with the other person. The speaker lingers over the choice, indicating uncertainty or indecision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>27", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this question.    We have come to the crossroads  And I must either leave or come with you  I lingered over the choice  You lifted the lamp of love  And I saw in your face  The road that I should take  The speaker is", "images": [], "options": {"A": "decisive", "B": "frustrated", "C": "disappointed", "D": "angry"}, "answer": "B", "explanation": "In line three, poet 'lingered over the choice ' because he feels helpless having to choose when he doesn't even want to.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>28", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this question.    We have come to the crossroads  And I must either leave or come with you  I lingered over the choice  You lifted the lamp of love  And I saw in your face  The road that I should take  The dominant literary device used in the poem is", "images": [], "options": {"A": "paradox", "B": "parody", "C": "metaphor", "D": "oxymoron"}, "answer": "C", "explanation": "The dominant literary device used in the poem is metaphor. This is evident from the lines 'You lifted the lamp of love' and 'I saw in your face The road that I should take'. The 'lamp of love' is a metaphor for guidance or enlightenment, and the 'road' is a metaphor for the path or decision the speaker should take. A metaphor is a figure of speech that makes a comparison between two things that are basically dissimilar.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>29", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this question.    We have come to the crossroads  And I must either leave or come with you  I lingered over the choice  You lifted the lamp of love  And I saw in your face  The road that I should take  The mood of the poem is", "images": [], "options": {"A": "jubilant", "B": "sad", "C": "gloomy", "D": "romantic"}, "answer": "C", "explanation": "The poem starts on a sad not, the mood  gets better towards the end, but still, it isn't good enough.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>30", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer this question.    We have come to the crossroads  And I must either leave or come with you  I lingered over the choice  You lifted the lamp of love  And I saw in your face  The road that I should take  The poem can be described as", "images": [], "options": {"A": "an epitaph", "B": "a lyric", "C": "a lullaby", "D": "an elegy"}, "answer": "B", "explanation": "The poem expresses a strong personal emotion in honour and praise of somebody. The personal feelings and thoughts of the poet are also expressed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2016>31", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Answer all questions in this section   WILLIAMS SHAKESPEARE: Othello    Read the extract and answer the question.    So opposite to marriage that she shunned  The wealthy, curled darlings  of the nation,  Would ever have, t'incur a general mock,   Run from her guardage to the  sooty bosom    Of such a thing as though - to fear, not to delight?    (Act 1, Scene Two , lines 66 - 70)    The speaker is", "images": [], "options": {"A": "Otherllo", "B": "Duke", "C": "Brabantio", "D": "Lago"}, "answer": "C", "explanation": "Brabantio is the speaker. His daughter has just eloped with Othello.  Brabantio accuses Othello of bewitching his daughter for her to marry him.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>32", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Answer all questions in this section   WILLIAMS SHAKESPEARE: Othello    Read the extract and answer the question.    So opposite to marriage that she shunned  The wealthy, curled darlings  of the nation,  Would ever have, t'incur a general mock,   Run from her guardage to the  sooty bosom    Of such a thing as though - to fear, not to delight?    (Act 1, Scene Two , lines 66 - 70)  The speaker is addressing", "images": [], "options": {"A": "Cassio", "B": "Branbantio", "C": "Roderigo", "D": "Othello"}, "answer": "D", "explanation": "Brabantio is addressing Othello. Brabantio does not approve of the marriage between Desdemona and Othello.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>33", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Answer all questions in this section   WILLIAMS SHAKESPEARE: Othello    Read the extract and answer the question.    So opposite to marriage that she shunned  The wealthy, curled darlings  of the nation,  Would ever have, t'incur a general mock,   Run from her guardage to the  sooty bosom    Of such a thing as though - to fear, not to delight?    (Act 1, Scene Two , lines 66 - 70)  \"Sooty bosom\" is a metaphor for", "images": [], "options": {"A": "a black coat", "B": "Othello", "C": "a breastplate", "D": "lago"}, "answer": "B", "explanation": "Brabantio uses the epithet, \"sooty bosom\", to describe Othello.  Brabantio regards Othello as a cheat who is useless and practices black magic.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>34", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Answer all questions in this section   WILLIAMS SHAKESPEARE: Othello    Read the extract and answer the question.    So opposite to marriage that she shunned  The wealthy, curled darlings  of the nation,  Would ever have, t'incur a general mock,   Run from her guardage to the  sooty bosom    Of such a thing as though - to fear, not to delight?    (Act 1, Scene Two , lines 66 - 70)  \"Run from her guardage\" refers to", "images": [], "options": {"A": "Emilia", "B": "Desdemona", "C": "Bianca", "D": "Cassio's mistress"}, "answer": "B", "explanation": "Brabiantio refers to his daughter, Desdemona, whom he believes to be charmed to marry such a man as Othello.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>35", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Answer all questions in this section   WILLIAMS SHAKESPEARE: Othello    Read the extract and answer the question.    So opposite to marriage that she shunned  The wealthy, curled darlings  of the nation,  Would ever have, t'incur a general mock,   Run from her guardage to the  sooty bosom    Of such a thing as though - to fear, not to delight?    (Act 1, Scene Two , lines 66 - 70)  The setting is", "images": [], "options": {"A": "another street outside the saggitary", "B": "a council chamber", "C": "a seaport in cyprus", "D": "the citadel"}, "answer": "A", "explanation": "The setting of the extract is another street outside the saggitary. This is where Othello and Iago are discussing Desdemona's love for Othello. The 'sooty bosom' refers to Othello, who is of Moorish descent and hence, dark-skinned. The 'guardage' refers to the societal expectations and norms that Desdemona is running from to be with Othello.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>36", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.    For when my outward action doth demonstrate  The native act and figure of my heart  In complement extern, 'tis not long after    But I will wear my heart upon my sleeve    For daws to peck at;     (Act one, scene one, lines 58-62)    The speaker is", "images": [], "options": {"A": "Branbantio", "B": "Cassio", "C": "Gratiano", "D": "lago"}, "answer": "D", "explanation": "The speaker of the extract is Iago. This is evident from the line 'But I will wear my heart upon my sleeve'. This is a famous line spoken by Iago in Act one, scene one, where he is expressing his deceitful nature. He is saying that he will pretend to show his true emotions, while in reality, he is hiding his true intentions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>37", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.    For when my outward action doth demonstrate  The native act and figure of my heart  In complement extern, 'tis not long after    But I will wear my heart upon my sleeve    For daws to peck at;     (Act one, scene one, lines 58-62)  The addressee is", "images": [], "options": {"A": "Othello", "B": "Duke", "C": "Roderigo", "D": "Montano"}, "answer": "C", "explanation": "Roderigo, Iago's pawn in the play, helps implement most of his (lago's) devious plans.  Note that Roderigo is unaware of Iago's wicked plans.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>38", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.    For when my outward action doth demonstrate  The native act and figure of my heart  In complement extern, 'tis not long after    But I will wear my heart upon my sleeve    For daws to peck at;     (Act one, scene one, lines 58-62)  What has happened to the speaker?", "images": [], "options": {"A": "He has been fined", "B": "He has fallen out of favour", "C": "He has been denied promotion", "D": "He has lost his job"}, "answer": "C", "explanation": "Iago expected to be promoted ahead of Cassio because he is more experienced than Cassio.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>39", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.    For when my outward action doth demonstrate  The native act and figure of my heart  In complement extern, 'tis not long after    But I will wear my heart upon my sleeve    For daws to peck at;     (Act one, scene one, lines 58-62)  The underlined expression shows that the speaker is", "images": [], "options": {"A": "jovial", "B": "insincere", "C": "polite", "D": "unfriendly"}, "answer": "B", "explanation": "The phrase 'wear my heart upon my sleeve' is a metaphor that means to openly display one's emotions or feelings, rather than keeping them hidden. The phrase 'for daws to peck at' suggests that the speaker is aware that this openness may make him vulnerable to harm or exploitation. This suggests that the speaker is insincere, as he is willing to display false emotions to manipulate others.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>40", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.    For when my outward action doth demonstrate  The native act and figure of my heart  In complement extern, 'tis not long after    But I will wear my heart upon my sleeve    For daws to peck at;     (Act one, scene one, lines 58-62)  The setting is", "images": [], "options": {"A": "a street in Venice", "B": "a street in Cyprus", "C": "outside the citadel", "D": "a court before the citadel"}, "answer": "A", "explanation": "This is the first scene of the play, where Iago expresses his feelings to Roderigo. It is in Venice.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>41", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.  Work on,   My medicine works! Thus credulous fools are caught,  And many worthy and chaste dams even thus,  All quilts, meet approach. What ho! My lord!  My lord, I say!    (Act four, scene one, lines 45-49)    The speaker is", "images": [], "options": {"A": "Othello", "B": "lago", "C": "Lodovico", "D": "Bianca"}, "answer": "B", "explanation": "The speaker of these lines is Iago. He is a character in the play who is known for his deceit and manipulation. He is speaking these lines to himself, expressing his satisfaction that his manipulative plans are working.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>42", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.  Work on,   My medicine works! Thus credulous fools are caught,  And many worthy and chaste dams even thus,  All quilts, meet approach. What ho! My lord!  My lord, I say!    (Act four, scene one, lines 45-49)  The speaker is addressing", "images": [], "options": {"A": "Cassio", "B": "Duke", "C": "herself", "D": "himself"}, "answer": "D", "explanation": "Iago tricks Othello into believing  his wife had an affair with anither man, Othello falls into a trance and Iago makes this comment to himself.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>43", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.  Work on,   My medicine works! Thus credulous fools are caught,  And many worthy and chaste dams even thus,  All quilts, meet approach. What ho! My lord!  My lord, I say!    (Act four, scene one, lines 45-49)  Just before this", "images": [], "options": {"A": "Othello falls into a trance", "B": "Bianca flings a handkerchief at Cassio", "C": "Montano fights with Cassio", "D": "Roderigo"}, "answer": "A", "explanation": "Having heard that Desdomona is having an ( extra-marital affair, Othello shakes with rage and falls into a trance. (Iago: My lord is fallen into an epilepsy.)", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>44", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.  Work on,   My medicine works! Thus credulous fools are caught,  And many worthy and chaste dams even thus,  All quilts, meet approach. What ho! My lord!  My lord, I say!    (Act four, scene one, lines 45-49)  \"Medicine\" in extract refers to the speakers", "images": [], "options": {"A": "hatred", "B": "passion", "C": "lies", "D": "loyalty"}, "answer": "C", "explanation": "In the given extract, the term 'medicine' is used metaphorically by Iago. He refers to his manipulative lies and deceit as 'medicine'. He is saying that his lies (medicine) are working on Othello, making him believe that his wife Desdemona is unfaithful. Therefore, the correct answer is 'lies'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>45", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.  Work on,   My medicine works! Thus credulous fools are caught,  And many worthy and chaste dams even thus,  All quilts, meet approach. What ho! My lord!  My lord, I say!    (Act four, scene one, lines 45-49)  The character that enters immediately after is", "images": [], "options": {"A": "lago", "B": "Emilia", "C": "Othello", "D": "Cassio"}, "answer": "D", "explanation": "Cassio immediately enters and Iago explains that Othello is having a fit of epilepsy", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>46", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.    I am glad I have found this napkin;  This was her first remembrance from the Moor  My wayward husband hath a hundred times  Wooed me to steal it; but she so loved the token   (For he conjured her she should ever keep it )  That she reserves it more about her   To kiss and talk to    (Act three, scene three,lines 289 - 295)    The speaker is", "images": [], "options": {"A": "Bianca", "B": "Emilia", "C": "Clown", "D": "Desdemona"}, "answer": "B", "explanation": "Emilia is the speaker; she is Desdemona's maidservant and Iago's wife. She picks Desdemona's handkerchief and takes it to Iago.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>47", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.    I am glad I have found this napkin;  This was her first remembrance from the Moor  My wayward husband hath a hundred times  Wooed me to steal it; but she so loved the token   (For he conjured her she should ever keep it )  That she reserves it more about her   To kiss and talk to    (Act three, scene three,lines 289 - 295)  The characters that just left the scene are", "images": [], "options": {"A": "Othello and lago", "B": "Montano and Cassio", "C": "Othello and Desdemona", "D": "Gratiano and Desdemona"}, "answer": "C", "explanation": "Othello and Desdomona move out of the scene after Othello complains of headache.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>48", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.    I am glad I have found this napkin;  This was her first remembrance from the Moor  My wayward husband hath a hundred times  Wooed me to steal it; but she so loved the token   (For he conjured her she should ever keep it )  That she reserves it more about her   To kiss and talk to    (Act three, scene three,lines 289 - 295)  'She' in the extract refers to", "images": [], "options": {"A": "Bianca", "B": "Desdemona", "C": "Emilia", "D": "Musician"}, "answer": "B", "explanation": "In the extract, 'she' refers to Desdemona. The napkin or handkerchief mentioned in the extract is a significant symbol in the play 'Othello'. It was given to Desdemona by Othello as a token of his love, and she cherishes it greatly. Iago, Othello's ensign, plots to make Othello believe that Desdemona has been unfaithful to him, and uses this handkerchief as a key piece in his plot.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>49", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.    I am glad I have found this napkin;  This was her first remembrance from the Moor  My wayward husband hath a hundred times  Wooed me to steal it; but she so loved the token   (For he conjured her she should ever keep it )  That she reserves it more about her   To kiss and talk to    (Act three, scene three,lines 289 - 295)  'My wayward husband' refers to", "images": [], "options": {"A": "Othello", "B": "lago", "C": "Cassio", "D": "Roderigo"}, "answer": "B", "explanation": "Iago, the perpetrator of evil in the play, is  the one who asks Emilia to get the hander kerchief  for him.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2016>50", "subject": "Literature", "year": "2016", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question.    I am glad I have found this napkin;  This was her first remembrance from the Moor  My wayward husband hath a hundred times  Wooed me to steal it; but she so loved the token   (For he conjured her she should ever keep it )  That she reserves it more about her   To kiss and talk to    (Act three, scene three,lines 289 - 295)  In the extract \"this napkin\" is \"the token\" of love between", "images": [], "options": {"A": "lago and Emilia", "B": "Cassio and Desdemona", "C": "Bianca and Cassio", "D": "Desdemona and Othello"}, "answer": "D", "explanation": "Desdemona receives the napkin as a gift (token) from Othello and she cherishes it. Th napkin once belonged to Othello's mother.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>1", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A praise poem is", "images": [], "options": {"A": "a ballad", "B": "a panegyric", "C": "an allegory", "D": "an epigram"}, "answer": "B", "explanation": "A praise poem is a panegyric. A panegyric is a public speech or published text in praise of someone or something, often to honour them for their achievements. It is a form of high praise, often delivered in a formal setting. The other options do not fit the definition of a praise poem. A ballad is a narrative poem that often sets to music, an allegory is a story, poem, or picture that can be interpreted to reveal a hidden meaning, typically a moral or political one, and an epigram is a pithy saying or remark expressing an idea in a clever and amusing way.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2017>2", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary work in which the characters are animals is a", "images": [], "options": {"A": "lampoon", "B": "fable", "C": "parody", "D": "pantomine"}, "answer": "B", "explanation": "A literary work in which the characters are animals is a fable. A fable is a short story, typically with animals as characters, conveying a moral. The other options do not fit the definition. A lampoon is a sharp, often virulent satire directed against an individual or institution; a work of literature, art, or the like, ridiculing severely the character or behavior of a person, society, etc. A parody is an imitation of the style of a particular writer, artist, or genre with deliberate exaggeration for comic effect. A pantomime is a dramatic entertainment, originating in Roman mime, in which performers express meaning through gestures accompanied by music.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2017>3", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short single act drama is called", "images": [], "options": {"A": "opera", "B": "allusion", "C": "farce", "D": "playlet"}, "answer": "D", "explanation": "A short single act drama is called a playlet. A playlet is a short play, often one act, that is simpler in structure and smaller in scope than a full-length play.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2017>4", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Use the following lines and answer question below.    Through the trees I'll hear a  single ringing sound ringing loud, a cowbell  jingle   The underlined is an example of _____ rhyme", "images": [], "options": {"A": "end", "B": "feminine", "C": "internal", "D": "masculine"}, "answer": "C", "explanation": "Internal rhyme occurs when two or more words within a line of poetry have the same sounds.  The words, \"single and jingle\" rhyme, and they occur in a line of poetry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>5", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Yet let me flat this bug with gilded wings                                                                                                                                                                                  The painted child of dirt that stinks and stings.\"    The alliteration in stinks and stings effectively conveys", "images": [], "options": {"A": "distaste", "B": "admiration", "C": "indifference", "D": "approval"}, "answer": "A", "explanation": "The words 'stink' and 'strings' have negative meanings; therefore. they show distate, repulsion and irritation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>6", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Yet let me flat this bug with gilded wings                                                                                                                                                                                  The painted child of dirt that stinks and stings.\"    The poet's intension is to", "images": [], "options": {"A": "create humour", "B": "arouse sympathy", "C": "create fun", "D": "show contempt"}, "answer": "D", "explanation": "The poet's intention in this excerpt is to express contempt or strong disapproval. The use of negative imagery such as 'bug with gilded wings' and 'painted child of dirt that stinks and stings' shows the poet's disdain or contempt for the subject.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>7", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"Yet let me flat this bug with gilded wings                                                                                                                                                                                  The painted child of dirt that stinks and stings.\"    The lines illustrates", "images": [], "options": {"A": "bank verse", "B": "end rhyme", "C": "internal rhyme", "D": "free verse"}, "answer": "B", "explanation": "An internal rhyme is the rhyming of two words within the same line. In this case 'sting' and 'wing' rhyme.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>8", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A play on words for literary effect is", "images": [], "options": {"A": "a paradox", "B": "a pun", "C": "a satire", "D": "an elegy"}, "answer": "B", "explanation": "Pun is a play upon words. It is also known as paronomasia.   In \"I will jog to pick up the jug,\" the two words 'jog' and 'jug' are played upon", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2017>9", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "\"It is better of sad joy\" illustrates", "images": [], "options": {"A": "metonymy", "B": "oxymoron", "C": "euphemism", "D": "irony"}, "answer": "B", "explanation": "Oxymoron is the placement of two words side by side in a sentence.   In this case, two opposite words \"sad\" and \"joy\" are placed side by side", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2017>10", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The leading character in a literary work is the", "images": [], "options": {"A": "foil", "B": "villain", "C": "antagonist", "D": "protagonist"}, "answer": "D", "explanation": "The protagonist is the major and leading character in a work of art. Such a character can also be referred to as the hero.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2017>11", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A long narrative poem that relates heroic exploits is an", "images": [], "options": {"A": "epilogue", "B": "epitaph", "C": "epic", "D": "epigram"}, "answer": "C", "explanation": "The epic is a long narrative poem that talks about the heroic deeds of great warriors.  The epitaph is an inscription on a tomb.  The epigram is a short witty statement.  The epilogue is the tail-piece of a work of art.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>12", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Over the cobbles it clattered and crashed is an example of", "images": [], "options": {"A": "oxymoron", "B": "pun", "C": "onomatopoeia", "D": "paradox"}, "answer": "C", "explanation": "Onomatopoeia is a word that sounds like what is described. Here; 'clattered' and 'crashed' are examples  It has to do with naming an object poetically; that is, using how objects sound to identify the object.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>13", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An essential feture of drama is", "images": [], "options": {"A": "soliloguy", "B": "conflict", "C": "irony", "D": "aside"}, "answer": "B", "explanation": "Conflict means a disagreement between/among two or more characters in a drama, usually the antagonist and the protagonist. It is an essential feature of drama", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>14", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A humorous peom with five lines, the first two rhyming with the last is", "images": [], "options": {"A": "an ode", "B": "sestet", "C": "octave", "D": "a limerick"}, "answer": "D", "explanation": "A humorous poem with five lines, the first two rhyming with the last is a limerick. A limerick is a form of verse, usually humorous and frequently rude, in five-line, predominantly anapestic meter with a strict rhyme scheme of AABBA, in which the first, second and fifth line rhyme, while the third and fourth lines are shorter and share a different rhyme.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>15", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Death be not proud, though some have called thee mighty and dreadful is an example of", "images": [], "options": {"A": "euphemism", "B": "metaphor", "C": "apostrophe", "D": "alliteration"}, "answer": "C", "explanation": "Apostrophe is an address to an absent person as if they were present .  Here, death is addressed as if it were alive and could hear.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>16", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An essential part of the plot is", "images": [], "options": {"A": "characterization", "B": "exposition", "C": "atmosphere", "D": "foreshadow"}, "answer": "B", "explanation": "Exposition is the part of the plot where we are introduced to the characters and event. the five stages of the plot structure are as follows: EXPOSTION -- RISING ACTION -- CLIMAX -- FALLING ACTION -- RESOLUTION.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>17", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The climax in a literary work is the", "images": [], "options": {"A": "middle", "B": "beginning", "C": "central part of the dialogue", "D": "peak of the conflict"}, "answer": "D", "explanation": "The climax in a literary work is the peak of the conflict. This is the point in the story where the tension or action reaches its highest part. It's the moment the readers have been led up to by the events of the story. It's not the middle, beginning, or central part of the dialogue.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>18", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Dramatis personae is the same as", "images": [], "options": {"A": "chorus", "B": "prompter", "C": "foil", "D": "cast"}, "answer": "D", "explanation": "Dramatis personae refers to all the characters in a literary work: cast. The singular form iof personae is persona.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>19", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Ten thousand saw I at a glance ... illustrate", "images": [], "options": {"A": "caesura", "B": "climax", "C": "bathos", "D": "hyperbole"}, "answer": "D", "explanation": "Hyperbole means exaggeration. The speaker here claims to have seen ten thousand people at a glance. Of course, this is an excessive exaggeration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>20", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Catharsis is normally associated with", "images": [], "options": {"A": "pantomine", "B": "tragedy", "C": "comedy", "D": "farce"}, "answer": "B", "explanation": "Catharsis is the purgation of emotions. It is the feeling of pity and great fear that the objects are subjected to when they see the hardship faced by the characters. According to Aristotle, the main aim of a tragedy is to bring about a catharsis of the spectators.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>21", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "PART II  UNSEEN PROSE AND POETRY   Read the passage and answer Questions 21 - 25We did not go to school on that Friday morning. The night before had been rough. It was turbulent and scary. The strange cry \"non-indigenes must go\" rent the air. Little did I know what it meant. That cry all the same haunted me in my sleep. My dreams were horrible. Why was Mum so troubled? Why was Dad suddenly so pale and sticky? That night Mum and Dad had a foreboding silence. They looked at each other, they did not smile. They were utterly silent.  Their silence spoke millions.  Fear ruled the night.  When the family bell summoned us  to the family altar, it seemed that it toiled its last for the humans. Death smelled in the air, death was in the eyes... But why? We were not told. Yes, during the prayer at the family altar, Dad had told use there was trouble in town. No one who was a non-indigenes was safe    The dominant feeling in the passage is that of", "images": [], "options": {"A": "hostility", "B": "anger", "C": "anxiety", "D": "bitterness"}, "answer": "C", "explanation": "Anxiety pervades this passage. The speaker and his family are part of the non-indigenes and the people town want to expel every non-indigene.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>22", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "We did not go to school on that Friday morning. The night before had been rough. It was turbulent and scary. The strange cry \"non-indigenes must go\" rent the air. Little did I know what it meant. That cry all the same haunted me in my sleep. My dreams were horrible. Why was Mum so troubled? Why was Dad suddenly so pale and sticky? That night Mum and Dad had a foreboding silence. They looked at each other, they did not smile. They were utterly silent.  Their silence spoke millions.  Fear ruled the night.  When the family bell summoned us  to the family altar, it seemed that it toiled its last for the humans. Death smelled in the air, death was in the eyes... But why? We were not told. Yes, during the prayer at the family altar, Dad had told use there was trouble in town. No one who was a non-indigenes was safe   This feeling is conveyed by the use of", "images": [], "options": {"A": "long sentences", "B": "visual images", "C": "tactile images", "D": "short sentences"}, "answer": "B", "explanation": "The first fourteen sentences in the passage are simple sentences. Thus, they are used to convey the feeling of anxiety.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>23", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "We did not go to school on that Friday morning. The night before had been rough. It was turbulent and scary. The strange cry \"non-indigenes must go\" rent the air. Little did I know what it meant. That cry all the same haunted me in my sleep. My dreams were horrible. Why was Mum so troubled? Why was Dad suddenly so pale and sticky? That night Mum and Dad had a foreboding silence. They looked at each other, they did not smile. They were utterly silent.  Their silence spoke millions.  Fear ruled the night.  When the family bell summoned us  to the family altar, it seemed that it toiled its last for the humans. Death smelled in the air, death was in the eyes... But why? We were not told. Yes, during the prayer at the family altar, Dad had told use there was trouble in town. No one who was a non-indigenes was safe   Their silence spoke millions illustrates", "images": [], "options": {"A": "oxymoron", "B": "litotes", "C": "antithesis", "D": "assonance"}, "answer": "A", "explanation": "Oxymoron means the placement of two contrasting words side by side. Here, two contrasting words, 'silence' and \"spoke\" are juxtaposed by placing them side by side.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>24", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Their family bell summoned us in an example of", "images": [], "options": {"A": "apostrophe", "B": "personification", "C": "allusion", "D": "euphemism"}, "answer": "B", "explanation": "Personification the practice of giving lifeless objects attributes of living things. Here, a bell is said to have summoned people. thus,. the bell is giving a human quality: that is, the ability to call (summon) people.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>25", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "The passage is", "images": [], "options": {"A": "in first person", "B": "in third person", "C": "a dialogue", "D": "a monologue"}, "answer": "A", "explanation": "The passage is written in the first person narrative technique. The use of first-person pronouns such as we and our proves this.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2017>26", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem and answer question  26 to  30 I know not, Amina   When again on your brightness of smile   My eyes will rest awhile     Nor when again of your softness of voice    My ears will drink by eager choice     When again into the silver moonshine   You early at night or late venture   As is your wont in weather fine  Astute, awake in bed as doters may, I'll lie   Dreaming of grasping your velvety texture    The first stanza is a", "images": [], "options": {"A": "tercet", "B": "couplet", "C": "quatrain", "D": "Sestet"}, "answer": "A", "explanation": "A tercet is a three-line poem . The first stanza has three lines.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>27", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I know not, Amina   When again on your brightness of smile   My eyes will rest awhile     Nor when again of your softness of voice    My ears will drink by eager choice     When again into the silver moonshine   You early at night or late venture   As is your wont in weather fine  Astute, awake in bed as doters may, I'll lie   Dreaming of grasping your velvety texture   The poem evokes the senses of", "images": [], "options": {"A": "smell and sight", "B": "smell and hearing", "C": "sight and hearing", "D": "touch and smell"}, "answer": "C", "explanation": "The poem evokes the senses of sight and hearing. Sight is evoked in the lines 'When again on your brightness of smile / My eyes will rest awhile' and 'When again into the silver moonshine'. Hearing is evoked in the line 'Nor when again of your softness of voice / My ears will drink by eager choice'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>28", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I know not, Amina   When again on your brightness of smile   My eyes will rest awhile     Nor when again of your softness of voice    My ears will drink by eager choice     When again into the silver moonshine   You early at night or late venture   As is your wont in weather fine  Astute, awake in bed as doters may, I'll lie   Dreaming of grasping your velvety texture   The dominant literary device used in the poem is", "images": [], "options": {"A": "allusion", "B": "repetition", "C": "allegory", "D": "metonymy"}, "answer": "B", "explanation": "The dominant literary device used in the poem is repetition. This is evident in the repeated use of the phrase 'When again' at the beginning of several lines, which creates a rhythmic pattern and emphasizes the speaker's longing and anticipation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>29", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I know not, Amina   When again on your brightness of smile   My eyes will rest awhile     Nor when again of your softness of voice    My ears will drink by eager choice     When again into the silver moonshine   You early at night or late venture   As is your wont in weather fine  Astute, awake in bed as doters may, I'll lie   Dreaming of grasping your velvety texture   The poem's tone is one of", "images": [], "options": {"A": "anxiety", "B": "defiance", "C": "nostalgia", "D": "regret"}, "answer": "C", "explanation": "The speaker has a mixed of sadness and happiness. Sadness about being unsure of when next he will meet his lover and happiness about remembering the good past times they had spent together. Thus, it can be deciphered that the speaker is feeling nostalgic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2017>30", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "I know not, Amina   When again on your brightness of smile   My eyes will rest awhile     Nor when again of your softness of voice    My ears will drink by eager choice     When again into the silver moonshine   You early at night or late venture   As is your wont in weather fine  Astute, awake in bed as doters may, I'll lie   Dreaming of grasping your velvety texture   My ears will drink by eager choice illustrates", "images": [], "options": {"A": "oxymoron", "B": "onomatopoeia", "C": "synecdoche", "D": "meiosis"}, "answer": "C", "explanation": "By saying 'my ears will drink by eager choice' , the speaker means his whole self will listen with enthusiasm, not just his ears alone. so, ear is used to represent the entire body.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>31", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "SECTION B    Answer all the questions in this section    WILLIAM SHAKESPEARE:   Othello   Read the extract and answer question 31 to 35Speaker: I think this tale would win my daughter too,   Good Brabantio,  take up this mangled matter at the best   Men do their broken weapons rather use   Than their bare hands   (Act I, Scene Three, lines 171 - 174)    The speaker is", "images": [], "options": {"A": "Duke", "B": "Othello", "C": "Brabantio", "D": "Cassio"}, "answer": "A", "explanation": "The speaker is the Duke. othello has just told the duke and the members of the council how he was able to woo Desdemona.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>32", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker: I think this tale would win my daughter too,   Good Brabantio,  take up this mangled matter at the best   Men do their broken weapons rather use   Than their bare hands   (Act I, Scene Three, lines 171 - 174)  The tale being referred to is", "images": [], "options": {"A": "Duke's war exploit", "B": "Brabanito's rejection of the Othello and Desdemona relationship", "C": "Othello's war exploits", "D": "Cassio's promotion as Othello's lieutenant"}, "answer": "C", "explanation": "The 'tale' being referred to in the extract is Othello's war exploits. In Act I, Scene Three, Othello is asked to recount the story of his courtship with Desdemona, which includes tales of his adventures and war exploits. The Duke is suggesting that such a tale would also win his own daughter, showing his admiration for Othello's storytelling and experiences.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>33", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker: I think this tale would win my daughter too,   Good Brabantio,  take up this mangled matter at the best   Men do their broken weapons rather use   Than their bare hands   (Act I, Scene Three, lines 171 - 174)  ... this tale justifies", "images": [], "options": {"A": "Roderigo's unrequited love for Desdemona", "B": "Cassio's promotion above lago", "C": "Desdemona's attraction to Othello", "D": "Brabantio's rejection of Othello's love for his daughter"}, "answer": "C", "explanation": "The speaker in the given lines is Othello, and he is speaking to Brabantio about his love for Desdemona. The 'tale' he refers to is the story of his life, his adventures, and the dangers he has faced, which he had shared with Desdemona. He believes that this tale, which fascinated Desdemona, justifies her attraction to him. Therefore, the correct answer is 'Desdemona's attraction to Othello'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>34", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker: I think this tale would win my daughter too,   Good Brabantio,  take up this mangled matter at the best   Men do their broken weapons rather use   Than their bare hands   (Act I, Scene Three, lines 171 - 174)  The underlined expression means", "images": [], "options": {"A": "seek counsel elsewhere", "B": "wait till the war is ended", "C": "take your revenge", "D": "make the best out of this"}, "answer": "D", "explanation": "The underlined expression 'take up this mangled matter at the best' is a metaphorical way of saying 'make the best out of this situation'. Othello is suggesting that Brabantio should accept the situation (his daughter's marriage to Othello) and try to see it in the best possible light. Therefore, the correct answer is 'make the best out of this'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>35", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker: I think this tale would win my daughter too,   Good Brabantio,  take up this mangled matter at the best   Men do their broken weapons rather use   Than their bare hands   (Act I, Scene Three, lines 171 - 174)  According to the speaker,", "images": [], "options": {"A": "the tale was good enough to win a woman's heart", "B": "the fight was necessary", "C": "the charges were a waste of time", "D": "there were other matters demanding the attention of the Senate"}, "answer": "A", "explanation": "In the given extract, the speaker is saying that the tale he is about to tell is so compelling that it would even win his daughter's heart. This implies that the tale is good enough to win a woman's heart. Therefore, the correct answer is option 1.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>36", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer Question  36 to  40 Othello:   So please your grace, my ancient;  A man he is of honest and trust,  With what else needful your good grace shall think   To be sent after me   (Act I, Scene Three, lines 279-283)    Othello is speaking to", "images": [], "options": {"A": "Brabantio", "B": "Duke", "C": "Montano", "D": "Roderigo"}, "answer": "B", "explanation": "In the given extract, Othello is addressing someone with the title 'your grace', which is a form of address for dukes and duchesses. Therefore, Othello is speaking to the Duke. Hence, the correct answer is option 2.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>37", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Othello:   So please your grace, my ancient;  A man he is of honest and trust,  With what else needful your good grace shall think   To be sent after me   (Act I, Scene Three, lines 279-283)  The speech illustrates the use of", "images": [], "options": {"A": "irony", "B": "litotes", "C": "paradox", "D": "comic relief"}, "answer": "A", "explanation": "The speech is ironical because Othello addresses Iagos as honesty and trust, howbeit he is in the true sense he is not", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>38", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Othello:   So please your grace, my ancient;  A man he is of honest and trust,  With what else needful your good grace shall think   To be sent after me   (Act I, Scene Three, lines 279-283)  A man he is of honest and trust refers to", "images": [], "options": {"A": "Cassio", "B": "Lodovico", "C": "Gratiano", "D": "lago"}, "answer": "D", "explanation": "A man he is of honest and trust refers to Iago. In the play 'Othello' by William Shakespeare, Othello refers to Iago as a man of honesty and trust. This is ironic because Iago is the villain of the play who betrays Othello's trust.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>39", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Othello:   So please your grace, my ancient;  A man he is of honest and trust,  With what else needful your good grace shall think   To be sent after me   (Act I, Scene Three, lines 279-283)  Othello is leaving to", "images": [], "options": {"A": "fight in Rhodes", "B": "make peace with the Turks", "C": "meet the Governor of Cyrus", "D": "take over the government"}, "answer": "A", "explanation": "Othello is leaving to fight in Rhodes. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>40", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Othello:   So please your grace, my ancient;  A man he is of honest and trust,  With what else needful your good grace shall think   To be sent after me   (Act I, Scene Three, lines 279-283)  Othello then", "images": [], "options": {"A": "leaves with Desdemona", "B": "entrusts Desdemona to lago's care", "C": "calls his lieutenant", "D": "confers with the Duke"}, "answer": "B", "explanation": "Othello then enthrusts Desdemona to lago's care, not knowing Iago is an unfriendly friend. This is an irony of situation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>41", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer Questions 41 to 45lago: Mere prattle without practice   Is all his soldiership, But he, sir had th'election;  And I, of whom  his eyes  had seen the proof   At Rhodes, at Cyprus, and on other grounds   ... must be belee'd and calmed   By debitor and creditor.  (Act I, Scene One, line 23-28)    His soldiership refers to", "images": [], "options": {"A": "Roderigo", "B": "Montano", "C": "Cassio", "D": "Brabantio"}, "answer": "C", "explanation": "In the given extract, Iago is expressing his resentment over the fact that Cassio, despite his lack of practical experience in warfare (as Iago sees it), was chosen over him for a military position. Therefore, 'his soldiership' refers to Cassio.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>42", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "lago: Mere prattle without practice   Is all his soldiership, But he, sir had th'election;  And I, of whom  his eyes  had seen the proof   At Rhodes, at Cyprus, and on other grounds   ... must be belee'd and calmed   By debitor and creditor.  (Act I, Scene One, line 23-28)  Sir refers to", "images": [], "options": {"A": "Cassio", "B": "Roderigo", "C": "Othello", "D": "Duke"}, "answer": "B", "explanation": "In the given extract, Iago is speaking to Roderigo about his resentment over Cassio's promotion. Therefore, 'sir' refers to Roderigo.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>43", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "lago: Mere prattle without practice   Is all his soldiership, But he, sir had th'election;  And I, of whom  his eyes  had seen the proof   At Rhodes, at Cyprus, and on other grounds   ... must be belee'd and calmed   By debitor and creditor.  (Act I, Scene One, line 23-28)  lago", "images": [], "options": {"A": "wants to go to Cyrus with Othello", "B": "does not regard Roderigo as a good soldier", "C": "is bitter about Cassio's appointment as lieutenant", "D": "has been placed in charge of Desdemona"}, "answer": "C", "explanation": "Iago is bitter because Cassio has been appointed lieutenant, and is making a scathing and condescending remark against Cassio because he believes Cassio does not have enough experience.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>44", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "lago: Mere prattle without practice   Is all his soldiership, But he, sir had th'election;  And I, of whom  his eyes  had seen the proof   At Rhodes, at Cyprus, and on other grounds   ... must be belee'd and calmed   By debitor and creditor.  (Act I, Scene One, line 23-28)  His eyes refers to", "images": [], "options": {"A": "Lodovico", "B": "Cassio", "C": "Othello", "D": "Duke"}, "answer": "C", "explanation": "In the context of the excerpt, 'his eyes' refers to the person who had the power to make the election, the person who overlooked Iago and chose Cassio. This person is Othello. Therefore, 'his eyes' refers to Othello.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>45", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "lago: Mere prattle without practice   Is all his soldiership, But he, sir had th'election;  And I, of whom  his eyes  had seen the proof   At Rhodes, at Cyprus, and on other grounds   ... must be belee'd and calmed   By debitor and creditor.  (Act I, Scene One, line 23-28)  The setting is", "images": [], "options": {"A": "the castle", "B": "Cyprus", "C": "a sea-port", "D": "Venice"}, "answer": "C", "explanation": "The setting is a sea-port. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>46", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer Questions 46 to 50Speaker: My wife! My wife! What wife!  Methinks it should be now a huge   eclipse of sun and moon and that   th' affrighted globe  Should yawn at alteration (Act V, Scene Two, lines 97-101)    The speaker is", "images": [], "options": {"A": "lago", "B": "Othello", "C": "Brabantio", "D": "Duke"}, "answer": "B", "explanation": "The speaker of the extract is Othello. This is inferred from the line 'My wife! My wife! What wife!'. In the play, Othello is the character who is married and is often in distress about his wife, Desdemona. The lines express his despair and disbelief, which are emotions Othello frequently experiences in the play.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>47", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker: My wife! My wife! What wife!  Methinks it should be now a huge   eclipse of sun and moon and that   th' affrighted globe  Should yawn at alteration (Act V, Scene Two, lines 97-101)  The first two lines express the speaker's", "images": [], "options": {"A": "loneliness", "B": "fear", "C": "confusion", "D": "regret"}, "answer": "D", "explanation": "Othello regrets murdering his wife. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>48", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker: My wife! My wife! What wife!  Methinks it should be now a huge   eclipse of sun and moon and that   th' affrighted globe  Should yawn at alteration (Act V, Scene Two, lines 97-101)  The speaker has just", "images": [], "options": {"A": "divorced his wife", "B": "arrived home from war", "C": "had a nightmare", "D": "smothered his wife"}, "answer": "D", "explanation": "The phrase 'smothered his wife' is a reference to the play 'Othello' by William Shakespeare, where the character Othello smothers his wife Desdemona out of jealousy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>49", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker: My wife! My wife! What wife!  Methinks it should be now a huge   eclipse of sun and moon and that   th' affrighted globe  Should yawn at alteration (Act V, Scene Two, lines 97-101)  The speech is provoked by", "images": [], "options": {"A": "Emilia's call", "B": "lago's treachery", "C": "Cassio's confession", "D": "Desdemona's plea"}, "answer": "A", "explanation": "The speech is provoked by Emilia's call. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2017>50", "subject": "Literature", "year": "2017", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker: My wife! My wife! What wife!  Methinks it should be now a huge   eclipse of sun and moon and that   th' affrighted globe  Should yawn at alteration (Act V, Scene Two, lines 97-101)  The underlined expression suggests that", "images": [], "options": {"A": "there is an imminent eclipse", "B": "life will never be the same again for the speaker", "C": "nothing will change", "D": "there is an impending danger for the speaker"}, "answer": "B", "explanation": "The expression suggests that the speakers hope has been dimmed and life will remain the same for him again.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>1", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS", "question": "The main character in a play or novel is the", "images": [], "options": {"A": "protagonist", "B": "narrator", "C": "villain", "D": "antagonist"}, "answer": "A", "explanation": "The protagonist is the principal character in a play or novel; he is the character in which the whole story revolves around.\\  The antagonist is the character that contends against the protagonist.  A villain is an extremely wicked character.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2018>2", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "AFRICAN DRAMA", "question": "A dramatic performance with only bodily movements and no speech is a", "images": [], "options": {"A": "farce", "B": "mime", "C": "slapstick", "D": "burlesque"}, "answer": "B", "explanation": "Mime is a type of drama which involves bodily movements or gesculation with no speech been made.   In a mime, dialogue is substituted for gestures and body movements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>3", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "AFRICAN POETRY", "question": "Before a play is performed, it is", "images": [], "options": {"A": "auditioned", "B": "applauded", "C": "rehearsed", "D": "recited"}, "answer": "C", "explanation": "Rehearsal is a stage in the performance of a play to ensure perfection before real stage performance.  For a stage to be well performed, it must be rehearsed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2018>4", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "AFRICAN PROSE", "question": "A play that moves the audience to pity and fear is a", "images": [], "options": {"A": "comedy", "B": "farce", "C": "pantomime", "D": "tragedy"}, "answer": "D", "explanation": "Tragedy is a type of drama in which the protagonist faces and suffers some difficulties which eventually leads to his downfall. It is a type of drama that ends on a sad note. Because the tragedy ends on a sad note, it usually instigates pity and fear from the audience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>5", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS", "question": "A sonnet has a final couplet when it has", "images": [], "options": {"A": "a sestet", "B": "an octave", "C": "two sestets", "D": "three quatrains"}, "answer": "D", "explanation": "Shakespearean Sonnet  Here, three quatrains and a couplet follow this rhyme scheme: abab, cdcd, efef, gg. The couplet plays a pivotal role, usually arriving in the form of a conclusion, amplification, or even refutation of the previous three stanzas, often creating an epiphanic quality to the end.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>6", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "He is my most beloved enemy illustrates", "images": [], "options": {"A": "synecdoche", "B": "oxymoron", "C": "metonymy", "D": "litotes"}, "answer": "B", "explanation": "Oxymoron is the placement of two contrasting words side by side. In the above expression, \"beloved\" and \"enemy\" are juxtaposed because they are placed side by side", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>7", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "AFRICAN PROSE", "question": "The cast appears at the end of a play for the", "images": [], "options": {"A": "musical", "B": "curtain call", "C": "intermission", "D": "introduction"}, "answer": "B", "explanation": "The cast appears at the end of a play for the 'curtain call'. A curtain call is a tradition where the cast of a theatrical production appears on stage after the performance to acknowledge the audience's applause. This is not related to a musical, intermission, or introduction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2018>8", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "AFRICAN POETRY", "question": "Diction is a writer's choice of", "images": [], "options": {"A": "style", "B": "syntax", "C": "rhythm", "D": "words"}, "answer": "D", "explanation": "Diction refers to a writer's choice of 'words'. It is the style of speaking or writing determined by the choice of words by a speaker or a writer. It is not directly related to style, syntax, or rhythm, although these elements can be influenced by diction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2018>9", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "AFRICAN DRAMA", "question": "A poem which celebrates simple country life is", "images": [], "options": {"A": "a pastoral", "B": "a dirge", "C": "an ode", "D": "an epic"}, "answer": "A", "explanation": "Pastoral is a type of poem that praises and celebrates the lives of those living in the country (rural) area. Most times, it revolves around shepherds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>10", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN POETRY", "question": "Hamartia, in a literary work refers to a hero's", "images": [], "options": {"A": "tragic flaw", "B": "inordinate ambition", "C": "strength of character", "D": "good works"}, "answer": "A", "explanation": "Hamartia, in a literary work, refers to the hero's tragic flaw.  Tragic flaw refers to the mistake made by the tragic hero. This mistake will lead to his downfall.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>11", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the lines and answer question 10  Who lied in the chapel  Now lies in the Abbey.    The dominant device used is", "images": [], "options": {"A": "paradox", "B": "pun", "C": "chiasmus", "D": "zeugma"}, "answer": "B", "explanation": "Pun simply means a play on words.  Here, the word, LIE, is played on. In the first instance, lied means telling lies (untruths) while lie, in the second line. means dead.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>12", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short play performed during the pause between the acts of a longer play is", "images": [], "options": {"A": "an interlude", "B": "an epilogue", "C": "a proloque", "D": "an interval"}, "answer": "A", "explanation": "An interlude is a brief presentation at the middle of a work of art. This presentation can be in the form of musical or drammatic performance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2018>13", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "AFRICAN DRAMA", "question": "Weeping willow illustrates", "images": [], "options": {"A": "dramatic monologue", "B": "pathetic fallacy", "C": "transferred epithet", "D": "dramatic irony"}, "answer": "B", "explanation": "The pathetic fallacy is a form of personification whereby human expression are expressed through inanimate objects of nature.  Here, a willow (tree) is said to be weeping.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>14", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the lines and answer question 15 to 17  But the towering earth was tired of sitting in one position.  She moved suddenly and the houses crumbled, the mountains heaved horribly, and the work of a million years was lost.    The predominant of figure of speech in the extract is", "images": [], "options": {"A": "oxymoron", "B": "personification", "C": "contrast", "D": "paradox"}, "answer": "B", "explanation": "Personification is a figure of speech that centres on giving living things or lifeful things attributes to a non-living thing or a lifeless object. In the above, the earth was given the features of a living thing.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>15", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "AFRICAN POETRY", "question": "Read the lines and answer question 15 to 17  But the towering earth was tired of sitting in one position.  She moved suddenly and the houses crumbled, the mountains heaved horribly, and the work of a million years was lost.The extract is about", "images": [], "options": {"A": "an earthquake", "B": "a flood", "C": "an explosion", "D": "a storm"}, "answer": "A", "explanation": "The whole extract is all about earthquake: \"She moved suddenly and the house crumbled, the mount heaved horribly, and the work of a million years was lost\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>16", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "AFRICAN POETRY", "question": "Read the lines and answer question 15 to 17  But the towering earth was tired of sitting in one position.  She moved suddenly and the houses crumbled, the mountains heaved horribly, and the work of a million years was lost.The effect of the extract is conveyed through the use of", "images": [], "options": {"A": "antithesis", "B": "parallelism", "C": "conceit", "D": "climax"}, "answer": "D", "explanation": "The effect of the extract is conveyed through the use of climax. Climax is the arrangement of an event from the less important to the most important one i.e the chronological arrangement of an event in ascending order. This arrangement can be seen in the extract below:    She moved suddenly and the houses crumbled, the mountains heaved horribly, and the work of a million years was lostcomes before mountain and after the mountain the work of a million years.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>17", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS", "question": "Beware her faintly failing health. And gentle garlands around her speech illustrates", "images": [], "options": {"A": "oxymoron", "B": "alliteration", "C": "synecdoche", "D": "repetition"}, "answer": "B", "explanation": "Alliteration is the repetition of a particular consonant sound at the beginning of words. The sound. /f/ alliterates in \"faintly failing\" while /g/ alliterates in \"gentle garlands\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>18", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS", "question": "The eight - line part of a Petrarchan sonnet is the", "images": [], "options": {"A": "quatrain", "B": "octave", "C": "octasmeter", "D": "quartet"}, "answer": "B", "explanation": "A Pertrarchan sonnet is divided into two: an octave and a sestet. The octave has eight lines while the sestet has six lines. It has a rhyme scheme of abba abba cdc cdc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>19", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS", "question": "The merical beat in The splendor falls on castle walls is", "images": [], "options": {"A": "anapaestic", "B": "dactylic", "C": "trochaic", "D": "iambic"}, "answer": "D", "explanation": "The metrical beat in The splendour falls on castle wall is iambic.  Iambic metre occurs when an unstressed syllable is immediately followed by a stressed syllable. In the extract below, the streesed syllables have been capitalised:  the SPLENdor FALLS on CAStle WALLS  we have the iambic tetrameter (four groups of iambic feet).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>20", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer questions 21 to 25   James heart beat badly as he and Alice approached the beeping metal detector at the entrance. The oblivious swinging  door hugged the couple  with inviting, outstretched arms and ushered them into the lobby in genial welcome. The receptionist asked James to surrender any valuable items he had; If they got lost, management would not be liable.  James looked at Alice, his wife returned his guilt-stricken, dubious look with an innocent, trusting smile. What would he do if jewels went missing?  How would he explain it to himself?  What would he have gained by his mischief? What had come over James so shamelessly to decide to rob his own wife? The swindled woman stood innocently beside her unrepentant husband as he took the key to their room with hands that shook slightly.    The expression door hugged the couple illustrates", "images": [], "options": {"A": "euphemism", "B": "personification", "C": "litotes", "D": "onomatopoeia"}, "answer": "B", "explanation": "Personification is the giving of human attributes to a non living object.  Here, the door is given the ability to perform the action, HUG.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>21", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer questions 21 to 25   James heart beat badly as he and Alice approached the beeping metal detector at the entrance. The oblivious swinging  door hugged the couple  with inviting, outstretched arms and ushered them into the lobby in genial welcome. The receptionist asked James to surrender any valuable items he had; If they got lost, management would not be liable.  James looked at Alice, his wife returned his guilt-stricken, dubious look with an innocent, trusting smile. What would he do if jewels went missing?  How would he explain it to himself?  What would he have gained by his mischief? What had come over James so shamelessly to decide to rob his own wife? The swindled woman stood innocently beside her unrepentant husband as he took the key to their room with hands that shook slightly.The narrative technique is", "images": [], "options": {"A": "first person", "B": "stream of consciousness", "C": "third person", "D": "interior monoloque"}, "answer": "C", "explanation": "The narrative technique used in the passage is third person. This is because the narrator is not a character in the story, but someone who stands outside the story and describes the characters and events. The narrator uses pronouns like 'he', 'she', 'it', or 'they' to refer to the characters. In this passage, the narrator describes the actions and thoughts of James, a character in the story, using 'he' and 'his'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>22", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer questions 21 to 25   James heart beat badly as he and Alice approached the beeping metal detector at the entrance. The oblivious swinging  door hugged the couple  with inviting, outstretched arms and ushered them into the lobby in genial welcome. The receptionist asked James to surrender any valuable items he had; If they got lost, management would not be liable.  James looked at Alice, his wife returned his guilt-stricken, dubious look with an innocent, trusting smile. What would he do if jewels went missing?  How would he explain it to himself?  What would he have gained by his mischief? What had come over James so shamelessly to decide to rob his own wife? The swindled woman stood innocently beside her unrepentant husband as he took the key to their room with hands that shook slightly.How would he explain it to himself? exemplifies", "images": [], "options": {"A": "hyperbole", "B": "paralleism", "C": "rhetorical question", "D": "understatement"}, "answer": "C", "explanation": "The phrase 'How would he explain it to himself?' exemplifies a rhetorical question. A rhetorical question is a figure of speech in the form of a question that is asked to make a point rather than to elicit an answer. In this context, the question is not meant to be answered, but to emphasize the dilemma James is facing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>23", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer questions 21 to 25   James heart beat badly as he and Alice approached the beeping metal detector at the entrance. The oblivious swinging  door hugged the couple  with inviting, outstretched arms and ushered them into the lobby in genial welcome. The receptionist asked James to surrender any valuable items he had; If they got lost, management would not be liable.  James looked at Alice, his wife returned his guilt-stricken, dubious look with an innocent, trusting smile. What would he do if jewels went missing?  How would he explain it to himself?  What would he have gained by his mischief? What had come over James so shamelessly to decide to rob his own wife? The swindled woman stood innocently beside her unrepentant husband as he took the key to their room with hands that shook slightly.The writer's attitude towards James is one of", "images": [], "options": {"A": "sympathy", "B": "distrust", "C": "support", "D": "disapproval"}, "answer": "B", "explanation": "The attitude of the writer towards James is one of distrust. This is evinced through expressions such as \"dubious\" and \"guilt-stricken\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>24", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "AFRICAN POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer questions 21 to 25   James heart beat badly as he and Alice approached the beeping metal detector at the entrance. The oblivious swinging  door hugged the couple  with inviting, outstretched arms and ushered them into the lobby in genial welcome. The receptionist asked James to surrender any valuable items he had; If they got lost, management would not be liable.  James looked at Alice, his wife returned his guilt-stricken, dubious look with an innocent, trusting smile. What would he do if jewels went missing?  How would he explain it to himself?  What would he have gained by his mischief? What had come over James so shamelessly to decide to rob his own wife? The swindled woman stood innocently beside her unrepentant husband as he took the key to their room with hands that shook slightly.The setting is", "images": [], "options": {"A": "the couple's home", "B": "a modern hotel", "C": "the airport", "D": "a school"}, "answer": "B", "explanation": "According to the plot analysis, it can be deduce that the setting is a modern hotel. The extract below proves it:  \"...he took the key to their room with hands that shook slightly.\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>25", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN POETRY", "question": "Read the Poem and answer questions 26 to 30  Poison ivy came up like a rose  in red and thorny garb   I look, liked and did dare touch.  My pals my avid touch espied  with green and frosty eyes  I should've only looked, and not leapt,  For away and over my rising moon she flew  on clipped wings of my dream   now a song-filled air pocket of serenades.  A love's wretch, my dream is a hornbill  flightless and tottering.  My dream remains a dream still  Now my dream is a locked-up serenade.    The mood of the persona is one of", "images": [], "options": {"A": "contempt", "B": "hilarity", "C": "despondency", "D": "hopefulness"}, "answer": "C", "explanation": "The mood of the persona in the poem is one of despondency. This is evident from the lines 'A love's wretch, my dream is a hornbill flightless and tottering. My dream remains a dream still Now my dream is a locked-up serenade.' These lines suggest a sense of despair and sadness, as the persona's dreams remain unfulfilled and locked up, like a flightless bird.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>26", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS", "question": "Read the Poem and answer questions 26 to 30  Poison ivy came up like a rose  in red and thorny garb   I look, liked and did dare touch.  My pals my avid touch espied  with green and frosty eyes  I should've only looked, and not leapt,  For away and over my rising moon she flew  on clipped wings of my dream   now a song-filled air pocket of serenades.  A love's wretch, my dream is a hornbill  flightless and tottering.  My dream remains a dream still  Now my dream is a locked-up serenade.The theme of the poem is a", "images": [], "options": {"A": "love in the garden", "B": "the acceptance", "C": "the rising room", "D": "unrequited"}, "answer": "D", "explanation": "The theme of the poem is unrequited love. This is evident from the lines 'Poison ivy came up like a rose in red and thorny garb I look, liked and did dare touch. My pals my avid touch espied with green and frosty eyes I should've only looked, and not leapt, For away and over my rising moon she flew on clipped wings of my dream now a song-filled air pocket of serenades.' These lines suggest a love that is not returned or rewarded, hence the theme of unrequited love.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>27", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN POETRY", "question": "Read the Poem and answer questions 26 to 30  Poison ivy came up like a rose  in red and thorny garb   I look, liked and did dare touch.  My pals my avid touch espied  with green and frosty eyes  I should've only looked, and not leapt,  For away and over my rising moon she flew  on clipped wings of my dream   now a song-filled air pocket of serenades.  A love's wretch, my dream is a hornbill  flightless and tottering.  My dream remains a dream still  Now my dream is a locked-up serenade.The envy of the persona's friends is expressed in the", "images": [], "options": {"A": "avid touched", "B": "clipped wings", "C": "green and frosty eyes", "D": "song-filled air pocket"}, "answer": "C", "explanation": "The envy of the persona's friend is expressed in the green and frosty eyes.    \"My pals, my avid touch espred with green and frosty eyes\"  This is a reference to the saying, \"Green with envy.\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>28", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS", "question": "Read the Poem and answer questions 26 to 30  Poison ivy came up like a rose  in red and thorny garb   I look, liked and did dare touch.  My pals my avid touch espied  with green and frosty eyes  I should've only looked, and not leapt,  For away and over my rising moon she flew  on clipped wings of my dream   now a song-filled air pocket of serenades.  A love's wretch, my dream is a hornbill  flightless and tottering.  My dream remains a dream still  Now my dream is a locked-up serenade.Line 2 is in iambic", "images": [], "options": {"A": "trimether", "B": "tetrmeter", "C": "pentameter", "D": "hexameter"}, "answer": "A", "explanation": "Line two is composed in iambic trimeter.   The iambic meter is a combination of two syllables. The first syllable is unstressed while the second syllable is stressed. The stressed syllables are in capital letters in the extract below:  \"in RED/ and THOR/ny GARB/  We have three iambic feet - iambic trimeter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>29", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "LITERARY TERMS", "question": "Read the Poem and answer questions 26 to 30  Poison ivy came up like a rose  in red and thorny garb   I look, liked and did dare touch.  My pals my avid touch espied  with green and frosty eyes  I should've only looked, and not leapt,  For away and over my rising moon she flew  on clipped wings of my dream   now a song-filled air pocket of serenades.  A love's wretch, my dream is a hornbill  flightless and tottering.  My dream remains a dream still  Now my dream is a locked-up serenade.The last line illustrates", "images": [], "options": {"A": "parallelism", "B": "contrast", "C": "hyperbole", "D": "metaphor"}, "answer": "D", "explanation": "The last line of the poem, 'Now my dream is a locked-up serenade' is a metaphor. A metaphor is a figure of speech that makes a comparison between two things that are basically dissimilar. In this case, the speaker's dream is compared to a 'locked-up serenade', suggesting that it is something beautiful and musical that is, unfortunately, inaccessible or unattainable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>30", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 35 to 40    Othello: Not I, I must be found.  My parts, my title, and my perfect soul  Shall manifest me rightly. Is it they?    Iago: By Janus, I think no.    Othello: The servants of the duke? And my lieutenants?  The goodness of the night upon you, friends.  What is the news?  (Act One, Scene Two, Lines 23 - 34)    Question: Just before this, Iago advises Othello to", "images": [], "options": {"A": "stay there", "B": "go in", "C": "show concern", "D": "be fair"}, "answer": "B", "explanation": "Just before this extract, Iago advises Othello to 'go in'. In the context of the play, Iago is advising Othello to go inside to avoid the people who are coming to look for him. This is evident from Othello's response, 'Not I, I must be found.' which suggests that he is not afraid of being found and does not intend to hide.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>31", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 30 to 34    Othello: Not I, I must be found.  My parts, my title, and my perfect soul  Shall manifest me rightly. Is it they?    Iago: By Janus, I think no.    Othello: The servants of the duke? And my lieutenants?  The goodness of the night upon you, friends.  What is the news?  (Act One, Scene Two, Lines 23 - 34)      By Janus is", "images": [], "options": {"A": "flashback", "B": "foregrounding", "C": "an allusion", "D": "euphenism"}, "answer": "C", "explanation": "In the given extract, 'By Janus' is an allusion. An allusion is a figure of speech that refers to a well-known story, event, person, or object in order to make a comparison in the readers' minds. In this case, 'By Janus' is an allusion to the Roman god Janus, who is the god of beginnings, gates, transitions, time, duality, doorways, passages, and endings. Iago uses this allusion to express his thoughts.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>32", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 30 to 34    Othello: Not I, I must be found.  My parts, my title, and my perfect soul  Shall manifest me rightly. Is it they?    Iago: By Janus, I think no.    Othello: The servants of the duke? And my lieutenants?  The goodness of the night upon you, friends.  What is the news?  (Act One, Scene Two, Lines 23 - 34)      The news Othello receives is that he must", "images": [], "options": {"A": "set sail for cyprus", "B": "reconcile brabantio", "C": "prepare a military strategy", "D": "appear before the council"}, "answer": "D", "explanation": "The news Othello receives is that he must appear before the council to meet the duke and other members of the council.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>33", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 30 to 34    Othello: Not I, I must be found.  My parts, my title, and my perfect soul  Shall manifest me rightly. Is it they?    Iago: By Janus, I think no.    Othello: The servants of the duke? And my lieutenants?  The goodness of the night upon you, friends.  What is the news?  (Act One, Scene Two, Lines 23 - 34)          Duke is in council that night because of", "images": [], "options": {"A": "Brabantio's complaint", "B": "Iago's demotion", "C": "the Turkish threat", "D": "Cassio's dismissal as lieutenant"}, "answer": "C", "explanation": "In the play 'Othello' by William Shakespeare, the Duke is in council that night because of the Turkish threat. The Turkish threat refers to the imminent attack by the Turkish fleet on Cyprus. This is a significant plot point in the play as it sets the stage for Othello's appointment as the general to lead the defense against the Turks, and the subsequent events that unfold.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>34", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 30 to 34    Othello: Not I, I must be found.  My parts, my title, and my perfect soul  Shall manifest me rightly. Is it they?    Iago: By Janus, I think no.    Othello: The servants of the duke? And my lieutenants?  The goodness of the night upon you, friends.  What is the news?  (Act One, Scene Two, Lines 23 - 34)          Later on, Brabantio accuses Othello of", "images": [], "options": {"A": "being unfair to iago", "B": "instigating a brawl", "C": "stealing his daughter", "D": "being a knave"}, "answer": "C", "explanation": "Later on in the play, Brabantio, Desdemona's father, accuses Othello of stealing his daughter. Brabantio believes that Othello has used witchcraft or some other form of trickery to make Desdemona fall in love with him, as he cannot believe that she would willingly choose to be with Othello. This accusation sets the stage for the tragic events that follow in the play.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>35", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 35 to 40  Speaker:  Let me speak like yourself and    lay a sentence   Which, as a grise or step, may help  these lovers. When   remedies are past, the griefs are   ended  By seeing the worst, whch late on   hopes depended.  (Act I, scene Three, lines 198-201)    The speaker is", "images": [], "options": {"A": "Brabantio", "B": "Duke", "C": "Montano", "D": "Lodovico"}, "answer": "B", "explanation": "The speaker in the extract is the Duke of Venice. He is the highest authority in Venice and he is speaking in the council chamber trying to mediate the situation between Brabantio and Othello.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>36", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 35 to 40  Speaker:  Let me speak like yourself and    lay a sentence   Which, as a grise or step, may help  these lovers. When   remedies are past, the griefs are   ended  By seeing the worst, whch late on   hopes depended.  (Act I, scene Three, lines 198-201) He is responding to", "images": [], "options": {"A": "Montano", "B": "Iago", "C": "Roderigo", "D": "Brabantio"}, "answer": "D", "explanation": "The Duke is responding to Brabantio's accusations against Othello. Brabantio has accused Othello of bewitching his daughter, Desdemona. The Duke is trying to calm the situation and provide a fair judgement.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>37", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 35 to 40  Speaker:  Let me speak like yourself and    lay a sentence   Which, as a grise or step, may help  these lovers. When   remedies are past, the griefs are   ended  By seeing the worst, whch late on   hopes depended.  (Act I, scene Three, lines 198-201) The setting is", "images": [], "options": {"A": "a council chamber", "B": "venice a street", "C": "another street outside sagittary", "D": "the citadel of cyprus"}, "answer": "A", "explanation": "The extract is from Shakespeare's play 'Othello'. The setting of Act I, Scene Three is a council chamber in Venice. The speaker is the Duke of Venice, who is trying to mediate between Brabantio and Othello over Desdemona's elopement. Therefore, the correct answer is 'a council chamber'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>38", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 35 to 40  Speaker:  Let me speak like yourself and    lay a sentence   Which, as a grise or step, may help  these lovers. When   remedies are past, the griefs are   ended  By seeing the worst, whch late on   hopes depended.  (Act I, scene Three, lines 198-201) These lovers refers to", "images": [], "options": {"A": "Iago and Emiia", "B": "Cassio and Bianca", "C": "Roderigo and Desdemona", "D": "Othello and Desdemona"}, "answer": "D", "explanation": "In the given extract, the 'lovers' being referred to are Othello and Desdemona. The speaker is the Duke of Venice, who is trying to mediate between Brabantio (Desdemona's father) and Othello over Desdemona's elopement. The Duke is suggesting that they should move on from the past and focus on the future. Therefore, the correct answer is 'Othello and Desdemona'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>39", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 35 to 40  Speaker:  Let me speak like yourself and    lay a sentence   Which, as a grise or step, may help  these lovers. When   remedies are past, the griefs are   ended  By seeing the worst, whch late on   hopes depended.  (Act I, scene Three, lines 198-201) The expression lay a sentence means", "images": [], "options": {"A": "decide who is guilty", "B": "offer criticism", "C": "give advice", "D": "speak politely"}, "answer": "C", "explanation": "In the context of the extract, 'lay a sentence' means to give advice. The speaker is expressing a desire to provide some guidance or advice that might help the lovers in their situation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2018>40", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Oh Spite! Oh hell! I see you are all bent  To set against me for your merriment    The lines illustrate", "images": [], "options": {"A": "epitaph", "B": "epigram", "C": "apostrophe", "D": "allusion"}, "answer": "C", "explanation": "Apostrophe is a figure of speech which address an abstract object as if it is present. In the above expressed expression, \"spite and hell\" are being refer to as if they are present.  \"Oh spite !\" , \"Oh hell! \"  Here, Hell is directly addressed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>41", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 41 to 45.  Othello:  \"Why, how now, ho! From whence ariseth this?  Are we turned Turks? And to ourselves do that  Which  heaven hath forbid the Ottomites?   For Christian shame, put by this barbarous brawl.  He that stirs next to carve for his own rage  Holds his soul light, he dies upon his motion.  Silence that dreadful bell, it frights the isle  From her propriety. What is the matter, masters?—  Honest Iago, that looks dead with grieving,  Speak, who began this? On thy love, I charge thee.  Iago:  I do not know  (Act II, Scene Three, line 155 - 165)    Othello is brought to the scene because", "images": [], "options": {"A": "Iago is drunk", "B": "a bell has been rung", "C": "people are fighting", "D": "Cassio has stabbed Montano"}, "answer": "D", "explanation": "Othello is brought to the scene because Cassio, who is drunk, has stabbed Montano", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>42", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 41 to 45.  Othello:  \"Why, how now, ho! From whence ariseth this?  Are we turned Turks? And to ourselves do that  Which  heaven hath forbid the Ottomites?   For Christian shame, put by this barbarous brawl.  He that stirs next to carve for his own rage  Holds his soul light, he dies upon his motion.  Silence that dreadful bell, it frights the isle  From her propriety. What is the matter, masters?—  Honest Iago, that looks dead with grieving,  Speak, who began this? On thy love, I charge thee.  Iago:  I do not know  (Act II, Scene Three, line 155 - 165)The underlined expression refers to the", "images": [], "options": {"A": "intervention of the storm in the war", "B": "return of the victorious army to cyprus", "C": "killing of roderigo by iago", "D": "stabbing of montano by cassio"}, "answer": "A", "explanation": "\"heaven hath forbid the Ottomites\" refers to the intervention of the storm in the war. The Turkish fleet was destroyed in the war.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>43", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 41 to 45.  Othello:  \"Why, how now, ho! From whence ariseth this?  Are we turned Turks? And to ourselves do that  Which  heaven hath forbid the Ottomites?   For Christian shame, put by this barbarous brawl.  He that stirs next to carve for his own rage  Holds his soul light, he dies upon his motion.  Silence that dreadful bell, it frights the isle  From her propriety. What is the matter, masters?—  Honest Iago, that looks dead with grieving,  Speak, who began this? On thy love, I charge thee.  Iago:  I do not know  (Act II, Scene Three, line 155 - 165)In \"Who began  this \" this refers to the", "images": [], "options": {"A": "theft", "B": "war", "C": "bell", "D": "brawl"}, "answer": "D", "explanation": "In the given extract, Othello is trying to stop a fight or 'brawl'. When he asks 'Who began this?', he is referring to the brawl. Therefore, 'this' refers to the 'brawl'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>44", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 41 to 45.  Othello:  \"Why, how now, ho! From whence ariseth this?  Are we turned Turks? And to ourselves do that  Which  heaven hath forbid the Ottomites?   For Christian shame, put by this barbarous brawl.  He that stirs next to carve for his own rage  Holds his soul light, he dies upon his motion.  Silence that dreadful bell, it frights the isle  From her propriety. What is the matter, masters?—  Honest Iago, that looks dead with grieving,  Speak, who began this? On thy love, I charge thee.  Iago:  I do not know  (Act II, Scene Three, line 155 - 165)To Othello, Iago is", "images": [], "options": {"A": "sincere", "B": "a negligent guard", "C": "untrustworthy", "D": "a loyal senator"}, "answer": "A", "explanation": "In the given extract, Othello refers to Iago as 'Honest Iago', indicating that he trusts Iago and believes him to be sincere. Therefore, to Othello, Iago is 'sincere'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>45", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 41 to 45.  Othello:  \"Why, how now, ho! From whence ariseth this?  Are we turned Turks? And to ourselves do that  Which  heaven hath forbid the Ottomites?   For Christian shame, put by this barbarous brawl.  He that stirs next to carve for his own rage  Holds his soul light, he dies upon his motion.  Silence that dreadful bell, it frights the isle  From her propriety. What is the matter, masters?—  Honest Iago, that looks dead with grieving,  Speak, who began this? On thy love, I charge thee.  Iago:  I do not know  (Act II, Scene Three, line 155 - 165)The major consequence of the brawl is that", "images": [], "options": {"A": "montano is killed", "B": "roderigo demands his money back", "C": "Cassio is dismissed as Othello's lieutenant", "D": "iago is given charge of the city"}, "answer": "C", "explanation": "The major consequence of the brawl is that Cassio is dismissed as Othello's liuetenant. Cassio is demoted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>46", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 45 to 50.   I durst, my lord, to wager she is honest,  Lay down my soul at stake. If you think other,   Remove your thought. It doth abuse your bosom.   If any wretch have put this in your head,  Let heaven requite it with the serpent's curse,  For if she be not honest, chaste, and true,  There's no man happy. The purest of their wives  Is foul as slander.   (Act IV, Scene Two, lines 12-19 )    The speaker is", "images": [], "options": {"A": "Iago", "B": "Desdemona", "C": "Cassio", "D": "Emilia"}, "answer": "D", "explanation": "Emilia said this while talking to Othello when he thinks Cassio and Desdemona are having love affairs", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>47", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 45 to 50.   I durst, my lord, to wager she is honest,  Lay down my soul at stake. If you think other,   Remove your thought. It doth abuse your bosom.   If any wretch have put this in your head,  Let heaven requite it with the serpent's curse,  For if she be not honest, chaste, and true,  There's no man happy. The purest of their wives  Is foul as slander.   (Act IV, Scene Two, lines 12-19 )The speaker is addressing", "images": [], "options": {"A": "Othello", "B": "Montano", "C": "duke", "D": "Roderigo"}, "answer": "A", "explanation": "The speaker in the extract is addressing Othello. This can be inferred from the context of the extract. The speaker is defending the honesty of a woman (presumably Desdemona), and the only character who doubts Desdemona's honesty in the play 'Othello' is Othello himself. Therefore, the speaker must be addressing Othello.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>48", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 45 to 50.   I durst, my lord, to wager she is honest,  Lay down my soul at stake. If you think other,   Remove your thought. It doth abuse your bosom.   If any wretch have put this in your head,  Let heaven requite it with the serpent's curse,  For if she be not honest, chaste, and true,  There's no man happy. The purest of their wives  Is foul as slander.   (Act IV, Scene Two, lines 12-19 )The speech is in response to", "images": [], "options": {"A": "the allegation that the speaker has lied about desdemona", "B": "Iago's disdain for othello", "C": "Othello's suspicion that cassio and desdemona are lovers", "D": "Brabantio's rejection of his daughter"}, "answer": "C", "explanation": "The speech is in response to Othello's suspicion that Cassio and Desdemona are lovers. This can be inferred from the extract where the speaker is defending the honesty of a woman (presumably Desdemona) and is trying to convince the listener (presumably Othello) that if she is not honest, then no man can be happy. This suggests that the speaker is responding to accusations or suspicions of infidelity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>49", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 45 to 50.   I durst, my lord, to wager she is honest,  Lay down my soul at stake. If you think other,   Remove your thought. It doth abuse your bosom.   If any wretch have put this in your head,  Let heaven requite it with the serpent's curse,  For if she be not honest, chaste, and true,  There's no man happy. The purest of their wives  Is foul as slander.   (Act IV, Scene Two, lines 12-19 )The line: Remove your thought. It doth abuse your bosom is best paraphrased", "images": [], "options": {"A": "you are not wise", "B": "do not kill yourself", "C": "you are ungrateful", "D": "you demean yourself by thinking so"}, "answer": "D", "explanation": "The line 'Remove your thought. It doth abuse your bosom' is best paraphrased as 'you demean yourself by thinking so'. The speaker is telling the listener to remove the negative thought from their mind as it is causing harm to their heart or spirit. The term 'abuse your bosom' is a metaphorical way of saying that the thought is causing emotional or spiritual harm.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2018>50", "subject": "Literature", "year": "2018", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer questions 45 to 50.   I durst, my lord, to wager she is honest,  Lay down my soul at stake. If you think other,   Remove your thought. It doth abuse your bosom.   If any wretch have put this in your head,  Let heaven requite it with the serpent's curse,  For if she be not honest, chaste, and true,  There's no man happy. The purest of their wives  Is foul as slander.   (Act IV, Scene Two, lines 12-19 )The character being spoken of is described as", "images": [], "options": {"A": "unhappy", "B": "virtuous", "C": "generous", "D": "wretched"}, "answer": "B", "explanation": "The character being spoken of is described as 'virtuous'. The speaker is defending the character's honesty and chastity, stating that if she is not honest, chaste, and true, then no man can be happy. This implies that the character is virtuous, as virtue is associated with honesty and chastity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>1", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary work which is intended to teach a moral lesson is", "images": [], "options": {"A": "romantic", "B": "didactic", "C": "mimetic", "D": "moralistic"}, "answer": "B", "explanation": "A work of art is termed as didactic if it teaches moral lessons.  Romance in poetry has to do with nature. In prose, it means unrealistic fiction.  Mimeticism has to do with the imitation of life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>2", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A short account of an interesting event is", "images": [], "options": {"A": "a tale", "B": "an anecdote", "C": "an episode", "D": "a story"}, "answer": "B", "explanation": "An anecdote is a short account of an interesting or humorous incident, often intended to illustrate or support some point. It is typically used to capture the audience's attention and prepare them for the topic that will be covered. The other options, while they can be short and interesting, do not specifically denote a short account of an interesting event.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2019>3", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "He is a citizen of no mean city illustrates", "images": [], "options": {"A": "bathos", "B": "euphemism", "C": "an episode", "D": "litotes"}, "answer": "D", "explanation": "Litotes: This is a form of understatement. It is the use of two negative words to express a positive meaning. E.g., I an not ungrateful.  \"Not ungrateful\" means grateful.  In the question, \"no' and \"mean\" are two negative words. Together, they mean \"good\" or \"great\": \"He is a citizen of a great city.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>4", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The introductory part of a play, a novel or a poem is the", "images": [], "options": {"A": "epilogue", "B": "plot", "C": "setting", "D": "prologue"}, "answer": "D", "explanation": "The prologue is the introductory section of a literary work of art. It is a part that comes at the beginning of a play, story or long narratives to give certain useful information about events in literary work.  On the other hand, the epilogue comes at the end of a work of art. It is known as the tail-piece.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2019>5", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "An elegy is a poem of", "images": [], "options": {"A": "mourning", "B": "complaint", "C": "hope", "D": "joy"}, "answer": "A", "explanation": "An elegy is a form of poetry that typically expresses sorrow or lamentation, usually for someone who has died. Therefore, it is a poem of mourning. This eliminates the other options which suggest that an elegy is a poem of complaint, hope, or joy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>6", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The trees bowed their heads in shame illustrates", "images": [], "options": {"A": "personification", "B": "alliteration", "C": "assonance", "D": "paradox"}, "answer": "A", "explanation": "Personification: This is a literary device or figure of speech that gives human features, attributes, behaviour to inanimate objects.  Here, the trees are given the ability to perform a human action: \"to bow their heads.\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>7", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A character whose actions are predictable in a literary work is", "images": [], "options": {"A": "a round character", "B": "a flat character", "C": "the hero", "D": "the villain"}, "answer": "B", "explanation": "The flat character is easy to predict because such character is one dimensional; that is, a flat character has just one dominant trait, and this makes it easy for people to easily identify a flat character.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>8", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A scene in fiction enacting past events is", "images": [], "options": {"A": "allusion", "B": "foreshadow", "C": "flashback", "D": "interlude"}, "answer": "C", "explanation": "The flashback is a device that is used to bring past events to the present; that is, these past events must have great significance to the present events.  To foreshadow means to predict future events.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>9", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Poetic license is a  term applied to a poet's", "images": [], "options": {"A": "choice of words", "B": "choice of characters", "C": "restrictions in the use of language", "D": "freedom in the use of language"}, "answer": "D", "explanation": "Poetic licence refers to the freedom given to poets to use words as they like. here, the poets are allowed to depart from the rules of grammar and even spelling.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>10", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Milton! thou should'st be living at this hour  The literary device used in the line above is", "images": [], "options": {"A": "aside", "B": "apostrophe", "C": "soliloquy", "D": "suspense"}, "answer": "B", "explanation": "The apostrophe is a figurative device in which something that is absent is directly addressed as if it were present and could hear.  Here, Milton is addressed as if he were alive.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>11", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Here lie I, Martin Eliginbrodde  Have mercy on my soul, Lord God.    The extract above illustrates", "images": [], "options": {"A": "epitaph", "B": "elegy", "C": "ballad", "D": "dirge"}, "answer": "A", "explanation": "An epitaph is a short poem that is written on a tomb or grave stone.   Here lie I, Martin Eliginbrodde  Have mercy on my soul, Lord God.    The above is written on the tomb of Martin Eliginbrodde.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>12", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "We live to die, we die to live is an example of", "images": [], "options": {"A": "paradox", "B": "hyperbole", "C": "inversion", "D": "oxymoron"}, "answer": "C", "explanation": "Inversion occurs when we change the word order of a sentence or expression. In the expression above, \"live to die\" is inverted to become \"die to live.\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>13", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the poem and answer this question    Here she lies, a pretty bud,  Lately made of flesh and blood,  Who as soon fell fast asleep  As her little eyes did peep.  Give her strewings, but not stir  The earth that lightly covers her.    The poem is about a/an", "images": [], "options": {"A": "flower", "B": "old woman", "C": "little child", "D": "traveller"}, "answer": "A", "explanation": "Theb poem is about a flower: \"Pretty bud\". This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>14", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the poem and answer this question    Here she lies, a pretty bud,  Lately made of flesh and blood,  Who as soon fell fast asleep  As her little eyes did peep.  Give her strewings, but not stir  The earth that lightly covers her.  The persona's mood is one of", "images": [], "options": {"A": "anger", "B": "admiration", "C": "indifference", "D": "joy"}, "answer": "B", "explanation": "The poet is filled with admiration. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>15", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the poem and answer this question    Here she lies, a pretty bud,  Lately made of flesh and blood,  Who as soon fell fast asleep  As her little eyes did peep.  Give her strewings, but not stir  The earth that lightly covers her.  The rhyme pattern is", "images": [], "options": {"A": "abc abc", "B": "aa bb cc", "C": "ab ab cc", "D": "aa bc bc"}, "answer": "B", "explanation": "The rhyme pattern of the poem is 'aa bb cc'. This is because the first two lines rhyme (bud and blood), the next two lines rhyme (asleep and peep), and the last two lines rhyme (stir and her).", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>16", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A play in which characters act through gestures and facial expressions is a", "images": [], "options": {"A": "pantomime", "B": "buriesque", "C": "farce", "D": "melodrama"}, "answer": "A", "explanation": "Pantomime: This is a form of dramatic performance with scenes played by body movement or gestures but without words.  It is a dramatic presentation where dialogue is substituted for body movement and gestures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>17", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Characterisation refers to", "images": [], "options": {"A": "how characters are grouped", "B": "the readers' opinions of the characters", "C": "how characters are depicted", "D": "the roles played by the character"}, "answer": "C", "explanation": "Characterization: is the act of creating or constructing fictional character . It includes both the description of a characters physical attributes as well as the character's personality. The way the characters think and speak.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2019>18", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "In a literary work, the foil is one who", "images": [], "options": {"A": "complements another character", "B": "contrasts with another character", "C": "introduces the conflict", "D": "resolves the conflict"}, "answer": "B", "explanation": "In fiction, a foil is a character who contrasts with another character, usually the protagonist, to highlight qualities of the other character.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>19", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Dramatis personae refers to", "images": [], "options": {"A": "audience", "B": "characters", "C": "chorus", "D": "cast"}, "answer": "D", "explanation": "Dramatis personae refers to all the characters (cast). The singular form is persona.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2019>20", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "A literary device used to enhance sound effect in poetry is", "images": [], "options": {"A": "imagery", "B": "alliteration", "C": "refrain", "D": "symbol"}, "answer": "B", "explanation": "Alliteration: This is the conspicuous repetition of identical initial consonant sound in a successive or closely associated syllables within a group of words even among those spelled differently. It helps to enhance sound effect in poetry. Examples   i. She Sells Seashells by the SeaShore.  ii. Peter pipers picked a picked peppers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>21", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage and answer this question  &nbsp &nbsp &nbsp Mark lies sleepless, his supine eyes rolling as he counts the rafters vertically, horizontally, diagonally-over and over. There is continual rumbling in his belly, Lying so still, whom can be blame now? Is't it his own fault to be like this?  &nbsp &nbsp &nbsp Three months ago, Atongo and Agbenya said they were leaving town because \"things have become too hard\", as they put it. They asked Mark to come along. He declined saying that he would have to prepare. Of course, he simply could not go-dare not. He had a pact with Akwele who sells kenkey downtown: neither could leave town without the other. At the time Mark's friends were ready, Akwele had travelled to Accra and would, unknown to anyone, not return in a hurry.  This is why Mark is lying dejected on his bed, a hungry man. Anyhow, he is not an angry man.    ...supine eyes ... illustrates", "images": [], "options": {"A": "oxymoron", "B": "paradox", "C": "verbal irony", "D": "synecdoche"}, "answer": "A", "explanation": "Oxymoron.  Here, supine which means lazy is juxtaposed with \"sleepless\" eyes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>22", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage and answer this question  &nbsp &nbsp &nbsp Mark lies sleepless, his supine eyes rolling as he counts the rafters vertically, horizontally, diagonally-over and over. There is continual rumbling in his belly, Lying so still, whom can be blame now? Is't it his own fault to be like this?  &nbsp &nbsp &nbsp Three months ago, Atongo and Agbenya said they were leaving town because \"things have become too hard\", as they put it. They asked Mark to come along. He declined saying that he would have to prepare. Of course, he simply could not go-dare not. He had a pact with Akwele who sells kenkey downtown: neither could leave town without the other. At the time Mark's friends were ready, Akwele had travelled to Accra and would, unknown to anyone, not return in a hurry.  This is why Mark is lying dejected on his bed, a hungry man. Anyhow, he is not an angry man.    Rumbling as used in the 1st paragraph is", "images": [], "options": {"A": "onomatopoeic", "B": "metaphoric", "C": "ironic", "D": "alliterative"}, "answer": "A", "explanation": "Onomatopoeic: This is a device in literary work in which sound suggest the meaning of words or expressions. It also means the act of forming words by imitating the actual sounds associated with the thing concerned.    Rumbling, as used in the passage, means HUNGRY. Hence, it is a sound that is used to describe hunger.    More examples: (i) Tick tack syas the clock  (ii) The mewing of the cat  (iii) The roaring of a lion", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>23", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage and answer this question  &nbsp &nbsp &nbsp Mark lies sleepless, his supine eyes rolling as he counts the rafters vertically, horizontally, diagonally-over and over. There is continual rumbling in his belly, Lying so still, whom can be blame now? Is't it his own fault to be like this?  &nbsp &nbsp &nbsp Three months ago, Atongo and Agbenya said they were leaving town because \"things have become too hard\", as they put it. They asked Mark to come along. He declined saying that he would have to prepare. Of course, he simply could not go-dare not. He had a pact with Akwele who sells kenkey downtown: neither could leave town without the other. At the time Mark's friends were ready, Akwele had travelled to Accra and would, unknown to anyone, not return in a hurry.  This is why Mark is lying dejected on his bed, a hungry man. Anyhow, he is not an angry man.    The dominant theme is", "images": [], "options": {"A": "unrequited love", "B": "loss of opportunity", "C": "lack of trust", "D": "insatiable hunger"}, "answer": "B", "explanation": "The extract revolves aroun loss of opportunity. Mark had an opportunity to leave town with Atongo and Agbenya but he refused to.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>24", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage and answer this question  &nbsp &nbsp &nbsp Mark lies sleepless, his supine eyes rolling as he counts the rafters vertically, horizontally, diagonally-over and over. There is continual rumbling in his belly, Lying so still, whom can be blame now? Is't it his own fault to be like this?  &nbsp &nbsp &nbsp Three months ago, Atongo and Agbenya said they were leaving town because \"things have become too hard\", as they put it. They asked Mark to come along. He declined saying that he would have to prepare. Of course, he simply could not go-dare not. He had a pact with Akwele who sells kenkey downtown: neither could leave town without the other. At the time Mark's friends were ready, Akwele had travelled to Accra and would, unknown to anyone, not return in a hurry.  This is why Mark is lying dejected on his bed, a hungry man. Anyhow, he is not an angry man.    The narrative technique is", "images": [], "options": {"A": "third person", "B": "first person", "C": "interior-monologue", "D": "multiple narration"}, "answer": "A", "explanation": "Third person: This is associated to prose as a genre of literature. It is a kind of point of view and it occurs when the writer does not connect himself with other cast in the novel but describes what the character does. The narrator often describes the characters by their name or by the used of third-person pronouns.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>25", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage and answer this question  &nbsp &nbsp &nbsp Mark lies sleepless, his supine eyes rolling as he counts the rafters vertically, horizontally, diagonally-over and over. There is continual rumbling in his belly, Lying so still, whom can be blame now? Is't it his own fault to be like this?  &nbsp &nbsp &nbsp Three months ago, Atongo and Agbenya said they were leaving town because \"things have become too hard\", as they put it. They asked Mark to come along. He declined saying that he would have to prepare. Of course, he simply could not go-dare not. He had a pact with Akwele who sells kenkey downtown: neither could leave town without the other. At the time Mark's friends were ready, Akwele had travelled to Accra and would, unknown to anyone, not return in a hurry.  This is why Mark is lying dejected on his bed, a hungry man. Anyhow, he is not an angry man.    The writer's attitude is one of", "images": [], "options": {"A": "anger", "B": "indifference", "C": "sympathy", "D": "mockery"}, "answer": "D", "explanation": "The tone is replete with mockery as the narrator shows no pity to Mark.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>26", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the Poem and answer this question  Walker, stop and let me move and check you  My sneaky, fleeting moon of reckless birth  The light of hope you flashed at dawn has dimmed   And flickers weakly, so you squint at Earth.    Walker, stand and let me sit and quiz you  Will foes and friends be irked if Mum you tell  The bitter tale of woe behind your flu?  The trickling tears unseen announce your age.    Walker, stay and let me come and tell you  My fleeting moon, I own you dim my light  Your sparkling blouse has turned a darker hue   You must, I guess, have done a steeplechase.    The stanzas are written in", "images": [], "options": {"A": "quintets", "B": "quatrains", "C": "sestets", "D": "tercets"}, "answer": "B", "explanation": "Quatrains: a quatrain refers to a poem or stanza of four lines.   Quintets refer to five lines.  Sestets are stanzas of six lines,  Tercets refer to stanzas of three lines.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>27", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the Poem and answer this question  Walker, stop and let me move and check you  My sneaky, fleeting moon of reckless birth  The light of hope you flashed at dawn has dimmed   And flickers weakly, so you squint at Earth.    Walker, stand and let me sit and quiz you  Will foes and friends be irked if Mum you tell  The bitter tale of woe behind your flu?  The trickling tears unseen announce your age.    Walker, stay and let me come and tell you  My fleeting moon, I own you dim my light  Your sparkling blouse has turned a darker hue   You must, I guess, have done a steeplechase.  The recurrent device used is", "images": [], "options": {"A": "synecdoche", "B": "apostrophe", "C": "metonymy", "D": "paradox"}, "answer": "B", "explanation": "The recurrent device used in the poem is apostrophe. Apostrophe is a figure of speech in which the poet addresses an absent person, an abstract idea, or a thing. In this poem, the poet is addressing 'Walker', who is not present.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>28", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the Poem and answer this question  Walker, stop and let me move and check you  My sneaky, fleeting moon of reckless birth  The light of hope you flashed at dawn has dimmed   And flickers weakly, so you squint at Earth.    Walker, stand and let me sit and quiz you  Will foes and friends be irked if Mum you tell  The bitter tale of woe behind your flu?  The trickling tears unseen announce your age.    Walker, stay and let me come and tell you  My fleeting moon, I own you dim my light  Your sparkling blouse has turned a darker hue   You must, I guess, have done a steeplechase.  The mood of the poet is", "images": [], "options": {"A": "derisive", "B": "ecstatic", "C": "regretful", "D": "melancholic"}, "answer": "D", "explanation": "The mood is melancholic, for the speaker appears to be sad. His sadness is betrayed by the third and fourth lines of each stanza.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>29", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the Poem and answer this question  Walker, stop and let me move and check you  My sneaky, fleeting moon of reckless birth  The light of hope you flashed at dawn has dimmed   And flickers weakly, so you squint at Earth.    Walker, stand and let me sit and quiz you  Will foes and friends be irked if Mum you tell  The bitter tale of woe behind your flu?  The trickling tears unseen announce your age.    Walker, stay and let me come and tell you  My fleeting moon, I own you dim my light  Your sparkling blouse has turned a darker hue   You must, I guess, have done a steeplechase.  The opening lines of the stanzas are", "images": [], "options": {"A": "trochaic", "B": "iambic", "C": "anapaestic", "D": "dactylic"}, "answer": "A", "explanation": "The first line is written in trochaic pentameter: that is, five feet of trochaic meter.  The trochee is a combination of two syllables. In this combination, the first syllable is stressed while the second is unstressed. In the extract below, the stressed syllables are all capitalised.  WALker/ STOP and/ LET me/ MOVE and/ CHECK you/    Therefore, we have the pattern: Stressed + Unstessed/ Stressed + Unstessed/ Stressed + Unstessed/ Stressed + Unstessed/ Stressed + Unstessed/", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>30", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the Poem and answer this question  Walker, stop and let me move and check you  My sneaky, fleeting moon of reckless birth  The light of hope you flashed at dawn has dimmed   And flickers weakly, so you squint at Earth.    Walker, stand and let me sit and quiz you  Will foes and friends be irked if Mum you tell  The bitter tale of woe behind your flu?  The trickling tears unseen announce your age.    Walker, stay and let me come and tell you  My fleeting moon, I own you dim my light  Your sparkling blouse has turned a darker hue   You must, I guess, have done a steeplechase.  The first stanza rhymes", "images": [], "options": {"A": "ab ac", "B": "ab ab", "C": "abcb", "D": "abba"}, "answer": "C", "explanation": "The first stanza rhymes abcb. In poetry, rhyme scheme refers to the pattern of end rhymes in stanzas or poems. An 'abcb' rhyme scheme means that the second and fourth lines of a stanza or between stanzas rhyme.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2019>31", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Othello  Read the extract and answer this question    When remedies are past, griefs are ended  By seeing the worst, which late on hopes depended.  To mourn a mischief that is past and gone   Is the next way to draw new mischief on.  What cannot be preserved when fortune takes,  Patience her injury a mock'ry makes.  The robbed that smiles, steals something from the thief;  He robs himself that spends a bootless grief.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp  (Act I, Scene Three, lines 200 - 207)    The speaker is", "images": [], "options": {"A": "Gratiano", "B": "Duke", "C": "Lodovico", "D": "Montano"}, "answer": "B", "explanation": "The speaker of these lines is the Duke of Venice. In Act I, Scene Three of Othello, the Duke is trying to console Brabantio, who is upset about his daughter Desdemona's marriage to Othello. The Duke is advising Brabantio to accept what has happened and move on, rather than dwelling on his grief. The Duke is a character who represents law and order in the play, and his words often carry wisdom and advice.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>32", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Othello  Read the extract and answer this question    When remedies are past, griefs are ended  By seeing the worst, which late on hopes depended.  To mourn a mischief that is past and gone   Is the next way to draw new mischief on.  What cannot be preserved when fortune takes,  Patience her injury a mock'ry makes.  The robbed that smiles, steals something from the thief;  He robs himself that spends a bootless grief.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp  (Act I, Scene Three, lines 200 - 207)  The speech is directly addressed to", "images": [], "options": {"A": "Cassio", "B": "Brabantio", "C": "Othello", "D": "2nd Senator"}, "answer": "B", "explanation": "The duke is addressing Brabantio. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>33", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Othello  Read the extract and answer this question    When remedies are past, griefs are ended  By seeing the worst, which late on hopes depended.  To mourn a mischief that is past and gone   Is the next way to draw new mischief on.  What cannot be preserved when fortune takes,  Patience her injury a mock'ry makes.  The robbed that smiles, steals something from the thief;  He robs himself that spends a bootless grief.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp  (Act I, Scene Three, lines 200 - 207)  The speech is about", "images": [], "options": {"A": "Brabantio's complaint about Othello.", "B": "Othello's loss of his handkerchief.", "C": "Brabantio's loss of his daughter.", "D": "the fight between Cassio and Roderigo."}, "answer": "A", "explanation": "The speech is about Brabantio's complaint about Othello and Desdemona's marriage.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>34", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Othello  Read the extract and answer this question    When remedies are past, griefs are ended  By seeing the worst, which late on hopes depended.  To mourn a mischief that is past and gone   Is the next way to draw new mischief on.  What cannot be preserved when fortune takes,  Patience her injury a mock'ry makes.  The robbed that smiles, steals something from the thief;  He robs himself that spends a bootless grief.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp  (Act I, Scene Three, lines 200 - 207)  By the speech, the speaker attempts to", "images": [], "options": {"A": "instigate the addressee", "B": "console the addressee", "C": "prevent a war", "D": "settle a fight"}, "answer": "B", "explanation": "By the speech, the speaker attempts to console the addressee. The speaker is trying to provide comfort and counsel to the person he is addressing, suggesting that they should not dwell on their loss or misfortune, but rather find a way to move forward. This is evident in lines such as 'When remedies are past, griefs are ended' and 'To mourn a mischief that is past and gone Is the next way to draw new mischief on.'", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>35", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "WILLIAM SHAKESPEARE: Othello  Read the extract and answer this question    When remedies are past, griefs are ended  By seeing the worst, which late on hopes depended.  To mourn a mischief that is past and gone   Is the next way to draw new mischief on.  What cannot be preserved when fortune takes,  Patience her injury a mock'ry makes.  The robbed that smiles, steals something from the thief;  He robs himself that spends a bootless grief.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp  (Act I, Scene Three, lines 200 - 207)  The underlined expression means", "images": [], "options": {"A": "one is bound to lose something in life", "B": "keep smiling even while being robbed", "C": "it is useful not to bemoan one's loss", "D": "the thief loses either way"}, "answer": "C", "explanation": "The underlined expression 'The robbed that smiles, steals something from the thief' in the context of the passage means that if a person who is robbed can manage to smile, they take something away from the thief. This 'something' is the satisfaction or joy the thief might derive from seeing their victim distressed. Therefore, the closest meaning to this is 'it is useful not to bemoan one's loss' which is option 3.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>36", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  Thou art sure of me. Go, make money. I have told thee Often, and I retell thee again and again, I hate the Moor. My cause is hearted; thine has no less reason. Let us be conjuctive in our revenge against him. If thou canst Cuckold him, thou dost thyself a pleasure, me a sport. There are many events in the womb of time, which will be delivered. Traverse, go, provide thy money! We will have more of this tomorrow. Adieu.    (Act I Scene Three, lines 355 - 362)    The speaker and the addressee are", "images": [], "options": {"A": "Lodovico and Roderigo", "B": "Clown and Lodovico", "C": "lago and Roderigo", "D": "lago and Clown"}, "answer": "C", "explanation": "lago and Roderigo.    Iago: He is a villian in the play, he is young and treachenous. He is inimoral but very perceptive, keen, and able to manipulate people into falling into his deception. His hatred for the moor, Othello has no bound and he achieve his revenge on him when he successfully manipulated him into killing his wife and himself too.    Roderigo: He is young venetian who lusts after Desdemona and for this reason he became a tool in iago's plots against Othello. lago promises Roderigo that he shall have Desdemona's love in return for his help (See Act 1 scene III, lines 355 - 362). He ended up receiving nothing as promised but a disgraceful death for his attempt on Cassio's life.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>37", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  Thou art sure of me. Go, make money. I have told thee Often, and I retell thee again and again, I hate the Moor. My cause is hearted; thine has no less reason. Let us be conjuctive in our revenge against him. If thou canst Cuckold him, thou dost thyself a pleasure, me a sport. There are many events in the womb of time, which will be delivered. Traverse, go, provide thy money! We will have more of this tomorrow. Adieu.    (Act I Scene Three, lines 355 - 362)  What binds the speaker and addressee together is their", "images": [], "options": {"A": "hatred for Othello", "B": "fear of Cassio", "C": "fear of Duke", "D": "hatred for Brabantio"}, "answer": "A", "explanation": "The speaker in the extract is Iago and the addressee is Roderigo. The extract is from Shakespeare's play 'Othello'. In this extract, Iago is expressing his hatred for Othello and is trying to convince Roderigo to join him in his revenge against Othello. Therefore, what binds the speaker and the addressee together is their 'hatred for Othello'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>38", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  Thou art sure of me. Go, make money. I have told thee Often, and I retell thee again and again, I hate the Moor. My cause is hearted; thine has no less reason. Let us be conjuctive in our revenge against him. If thou canst Cuckold him, thou dost thyself a pleasure, me a sport. There are many events in the womb of time, which will be delivered. Traverse, go, provide thy money! We will have more of this tomorrow. Adieu.    (Act I Scene Three, lines 355 - 362)  The addressee is enjoined to Go, make money for", "images": [], "options": {"A": "wooing Desdemona", "B": "enriching lago", "C": "placating Brabantio", "D": "rewarding Bianca"}, "answer": "A", "explanation": "Iago orders Roderigo to go and make more money in order to woo Desdoma through the giving of gift items.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>39", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  Thou art sure of me. Go, make money. I have told thee Often, and I retell thee again and again, I hate the Moor. My cause is hearted; thine has no less reason. Let us be conjuctive in our revenge against him. If thou canst Cuckold him, thou dost thyself a pleasure, me a sport. There are many events in the womb of time, which will be delivered. Traverse, go, provide thy money! We will have more of this tomorrow. Adieu.    (Act I Scene Three, lines 355 - 362)  The underlined expression means", "images": [], "options": {"A": "you have your way by making him angry", "B": "you gain by making his wife cheat on him", "C": "you will not be delighted at the result", "D": "you will have succeeded in seducing her"}, "answer": "B", "explanation": "To cuckhold means to have an affair with a married person in a bid to spite the spouse. here, Roderigo is advised to try to start up an affair with the newly-married Desdemona.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>40", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  Thou art sure of me. Go, make money. I have told thee Often, and I retell thee again and again, I hate the Moor. My cause is hearted; thine has no less reason. Let us be conjuctive in our revenge against him. If thou canst Cuckold him, thou dost thyself a pleasure, me a sport. There are many events in the womb of time, which will be delivered. Traverse, go, provide thy money! We will have more of this tomorrow. Adieu.    (Act I Scene Three, lines 355 - 362)  The speaker's attitude to the addressee is one of", "images": [], "options": {"A": "spite", "B": "envy", "C": "friendliness", "D": "intolerance"}, "answer": "A", "explanation": "Iago's attitude is one of spite. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>41", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  I have done the state some service, and they know't.  No more of that. I pray you, in your letters,  When you shall these unlucky deeds relate,  Speak of me as I am. Nothing extenuate,  Nor set down aught in malice. Then must you speaker  Of one that loved not wisely, but too well;  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act V, Scene Two, lines 336 - 341)    The speaker is", "images": [], "options": {"A": "Othello", "B": "Gratiano", "C": "lago", "D": "Cassio"}, "answer": "A", "explanation": "The speaker in the given extract is Othello. This is a part of Othello's final speech in Act V, Scene Two of the play 'Othello' by William Shakespeare. In this speech, Othello is speaking to Lodovico and Gratiano, expressing his guilt and regret over his actions and asking them to remember him as he truly was.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>42", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  I have done the state some service, and they know't.  No more of that. I pray you, in your letters,  When you shall these unlucky deeds relate,  Speak of me as I am. Nothing extenuate,  Nor set down aught in malice. Then must you speaker  Of one that loved not wisely, but too well;  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act V, Scene Two, lines 336 - 341)  The setting is", "images": [], "options": {"A": "a street in front of the citadel", "B": "a street", "C": "the citadel", "D": "Desdemonia's chamber"}, "answer": "D", "explanation": "The setting of the action is Desdemonia's chamber.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>43", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  I have done the state some service, and they know't.  No more of that. I pray you, in your letters,  When you shall these unlucky deeds relate,  Speak of me as I am. Nothing extenuate,  Nor set down aught in malice. Then must you speaker  Of one that loved not wisely, but too well;  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act V, Scene Two, lines 336 - 341)  The speaker is addressing", "images": [], "options": {"A": "Duke and others", "B": "Emilia", "C": "the Senate", "D": "Lodovico and others"}, "answer": "D", "explanation": "Lodovico and others   Lodovico: He is a noble of Venetia and a relation of Othello's wife: Desdemona. First he reprimaded Othello when he physically assults Desdemona and he also is to take news of the tragedy that trucks back to Venice to the officials of the city", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>44", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  I have done the state some service, and they know't.  No more of that. I pray you, in your letters,  When you shall these unlucky deeds relate,  Speak of me as I am. Nothing extenuate,  Nor set down aught in malice. Then must you speaker  Of one that loved not wisely, but too well;  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act V, Scene Two, lines 336 - 341)  The speech is intended to", "images": [], "options": {"A": "preserve the speaker's reputation", "B": "express the speaker's remorse", "C": "express the speaker's acceptance of guilt", "D": "denounce the speaker's enemies"}, "answer": "A", "explanation": "In the extract, Othello is asking those present to speak of him as he is when they relate his deeds. He does not want them to exaggerate or diminish his actions. This indicates that he wants to preserve his reputation, even if it is tarnished by his actions. Therefore, the correct answer is 'preserve the speaker's reputation'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>45", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  I have done the state some service, and they know't.  No more of that. I pray you, in your letters,  When you shall these unlucky deeds relate,  Speak of me as I am. Nothing extenuate,  Nor set down aught in malice. Then must you speaker  Of one that loved not wisely, but too well;  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act V, Scene Two, lines 336 - 341)  Among these unlucky deeds, the immediate one is", "images": [], "options": {"A": "the killing of Desdemona", "B": "declaring Desdemona as unfaithful", "C": "refusing to listen to Emilia", "D": "the sacking of Cassio"}, "answer": "A", "explanation": "The extract is from Shakespeare's play 'Othello'. In this scene, Othello is speaking to Lodovico, after he has killed Desdemona. He is asking Lodovico to write about him as he is, and not to exaggerate or downplay his actions. The 'unlucky deeds' he refers to are his actions that led to the tragic events, the immediate one being the killing of Desdemona. Therefore, the correct answer is 'the killing of Desdemona'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>46", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  If after every tempest come such calms,  May the winds blow till they have wakened death,  And let the labouring bark climb hills of seas  Olympus-high, and duck again as low  As hell's from heaven. If it were now to die,  T were now to be most happy; for I fear  My soul hath her content so absolute  That not another comfort like to this   Succeeds in unknown fate.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II, Scene One, lines 179 - 187)    The speaker is", "images": [], "options": {"A": "Brabantio", "B": "Othello", "C": "Duke", "D": "Montano"}, "answer": "B", "explanation": "The extract is from Shakespeare's play 'Othello'. In this scene, Othello is speaking to Desdemona after they have been reunited following a dangerous storm at sea. He is expressing his happiness and contentment at being with Desdemona, to the point where he feels that if he were to die at that moment, he would be most happy. Therefore, the speaker is Othello.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>47", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  If after every tempest come such calms,  May the winds blow till they have wakened death,  And let the labouring bark climb hills of seas  Olympus-high, and duck again as low  As hell's from heaven. If it were now to die,  T were now to be most happy; for I fear  My soul hath her content so absolute  That not another comfort like to this   Succeeds in unknown fate.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II, Scene One, lines 179 - 187)  The occasion is", "images": [], "options": {"A": "Othello's return from war", "B": "Othello's departure for Cyprus", "C": "Montano expressing his delight after the tempest", "D": "the defeat of the Turks"}, "answer": "A", "explanation": "The occasion is Othello's return from war. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>48", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  If after every tempest come such calms,  May the winds blow till they have wakened death,  And let the labouring bark climb hills of seas  Olympus-high, and duck again as low  As hell's from heaven. If it were now to die,  T were now to be most happy; for I fear  My soul hath her content so absolute  That not another comfort like to this   Succeeds in unknown fate.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II, Scene One, lines 179 - 187)  The dominant images are associated with", "images": [], "options": {"A": "love", "B": "nature", "C": "sailing", "D": "war"}, "answer": "C", "explanation": "Words like \"tempest\", \"calms\", \"winds\" and \"seas\" prove that the dominant images are drawn from sailing.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>49", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  If after every tempest come such calms,  May the winds blow till they have wakened death,  And let the labouring bark climb hills of seas  Olympus-high, and duck again as low  As hell's from heaven. If it were now to die,  T were now to be most happy; for I fear  My soul hath her content so absolute  That not another comfort like to this   Succeeds in unknown fate.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II, Scene One, lines 179 - 187)  The scene reveals the speaker's", "images": [], "options": {"A": "fear of adventure", "B": "affection for his wife", "C": "suspicion of his wife", "D": "fulfilment as a warrior"}, "answer": "B", "explanation": "The speaker in the extract is expressing a deep sense of contentment and happiness, suggesting that he is at a peak of happiness that he fears will not be matched by any future event. This happiness is derived from his relationship with his wife, hence the correct answer is 'affection for his wife'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2019>50", "subject": "Literature", "year": "2019", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract and answer this question  If after every tempest come such calms,  May the winds blow till they have wakened death,  And let the labouring bark climb hills of seas  Olympus-high, and duck again as low  As hell's from heaven. If it were now to die,  T were now to be most happy; for I fear  My soul hath her content so absolute  That not another comfort like to this   Succeeds in unknown fate.  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp (Act II, Scene One, lines 179 - 187)  The language of the extract is best described as", "images": [], "options": {"A": "ironical", "B": "humorous", "C": "hyperbolical", "D": "sarcastic"}, "answer": "C", "explanation": "Hyperbolical:  The speaker exaggerates as he attempts to show his affection. In the extract below, this exaggeration is seen.    And let the labouring bark climb hills of seas Olympus-high, and duck again   as low As hell's from heaven", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>1", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "A situtation when a audience is aware of an action a character is ignorant of is", "images": [], "options": {"A": "Dramatic irony", "B": "comic relief", "C": "aside", "D": "satire"}, "answer": "A", "explanation": "Dramatic irony occurs when the audience know something that is unkjnown to a character.  An aside is a form of monologue that is used when an actor directly addresses the audience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>2", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "A ficitional prose which is neither a novel nor a short story is a/an", "images": [], "options": {"A": "Allegory", "B": "fable", "C": "Novella", "D": "novellette"}, "answer": "C", "explanation": "A novella is a written, fictional, prose narrative that is longer than a novelette but shorter than a novel. While there is some disagreement as to what length defines a novella, the Science Fiction and Fantasy Writers of America Nebula Awards for science fiction define the novella as having a word count between 17,500 and 40,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>3", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Condensed use of language is a dominant feature of", "images": [], "options": {"A": "Comedy", "B": "poetry", "C": "prose", "D": "tragedy"}, "answer": "B", "explanation": "The condensed us of language is associated with poetry. Poetry says a lot by using few words. That is, poetry can present in few lines what will take prose many chapters to present.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2020>4", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "The sudden reversal of a charater's fortune in a literary work is", "images": [], "options": {"A": "Denouement", "B": "Hamartia", "C": "Hubris", "D": "Peripetria"}, "answer": "D", "explanation": "Peripeteia refers to the sudden change in the fortunes of a character. This change is often irreversible. Peripeteia occurs mainly in a tragedy.  Hamartia is another name for tragic flaw. It is the mistake made by the protagonist that leads to his downfall.  Hubris has to do with excessive pride.  Denouement means resolution: the point where the conflict is settled.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>5", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "With the pen, he wrote kings into reality  With his words, Kingdom arose   The same words, slaves inhaled   Their hands building walls, their feet tromping territories   His pen was like the breath of life    The underlined words illustrate", "images": [], "options": {"A": "Hyperbole", "B": "irony", "C": "Metonymy", "D": "paradox"}, "answer": "A", "explanation": "The pen is presented to be something magical; one that produce kings and even kingdoms. therefore, it suffices to say that the ability of the poem has been excessively exaggerated.  This illustrates hyperbole.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>6", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "With the pen, he wrote kings into reality  With his words, Kingdom arose   The same words, slaves inhaled   Their hands building walls, their feet tromping territories   His pen was like the breath of life   Hands and feet  in line 4 illustrate", "images": [], "options": {"A": "Contrast", "B": "litotes", "C": "personification", "D": "synecdoche"}, "answer": "D", "explanation": "The synecdoche is a device that is deployed when we use a part of a body to represent the entire body.  Here, hands and feet are used to represent the entire body of the slaves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>7", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "His pen is like the breath of life exemplifies", "images": [], "options": {"A": "Bathos", "B": "pathox", "C": "satire", "D": "simile"}, "answer": "D", "explanation": "The simile is a figure of speech that makes an indirect comparison, using as or like.  Here, \"his pen\" is comoared to \"breath of life\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>8", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Comic reliefs occurs in", "images": [], "options": {"A": "comedies", "B": "pastorals", "C": "Romance", "D": "Tragedies"}, "answer": "D", "explanation": "Comic relief is a humorous scene that is infused into a tragedy in order to reduce the tragic tension.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2020>9", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "One week of fasting makes weak is an example of", "images": [], "options": {"A": "Apostrophe", "B": "Paradox", "C": "pun", "D": "sarcasm"}, "answer": "C", "explanation": "Pun means the humorous use of a word or phrase so as to emphasize or suggest its different meanings or applications, or the use of words that are alike or nearly alike in sound but different in meaning. It is also known as play on words (paronomasia).  In the question, there is a play on the words - week and week - because they sound alike.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>10", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Students rarely read Julius Caesar these days illustrates", "images": [], "options": {"A": "Caesura", "B": "eponym", "C": "Oxymoron", "D": "Zeugma"}, "answer": "B", "explanation": "An eponymous text is a type of book whereby the name of the main character is also the name of the book. Some examples are Charles Dickens' Oliver Twist, Mark Twain's Huckleberry Finn and William Shakespearw's Hamlet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>11", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "In literature the terms  poetic justice  applies to", "images": [], "options": {"A": "A story that ends well.", "B": "character that are spared death", "C": "The development of a good plot", "D": "The rewarding of good character and the purnishing of bad ones."}, "answer": "D", "explanation": "Poetic justice simply means the fact of experiencing a fitting or deserved retribution for one's actions. I.e. the rewarding of good characters and the punishing of the bad ones. It is also referred to as nemesis.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>12", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Ascribing human moods to nature, as in a  playful breeze  illustrates", "images": [], "options": {"A": "Humour", "B": "Pathetic fallacy", "C": "Symbolism", "D": "Transferred epithet"}, "answer": "B", "explanation": "Thye pathetic fallacy is a form of oxymoron whereby human emotions are projected through the elements of nature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>13", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "The ends of performance is followed by", "images": [], "options": {"A": "A curtain call", "B": "A curtain raiser", "C": "Epilogue", "D": "Interlude"}, "answer": "A", "explanation": "Curtain call refers to when the actors come to stage at the end of their performance to receive the applause of the audience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>14", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Marching  along  fifty score   Great hearted gentlemen singing this  song     The underlined words illustrate", "images": [], "options": {"A": "Assonance", "B": "consonance", "C": "Onomatopeia", "D": "repetition"}, "answer": "A", "explanation": "Assonance is a resemblance of sound between syllables of nearby words, arising particularly from the rhyming of two or more stressed vowels, also from the use of identical consonants with different vowels.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>15", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "A short poem with a witty or sarcastic ending is a/an", "images": [], "options": {"A": "Ballad", "B": "Allegory", "C": "Epigram", "D": "panegyric"}, "answer": "C", "explanation": "An epigram is a brief, interesting, memorable, and sometimes surprising or satirical statement. It originates from the Greek: επίγραμμα epigramma 'inscription' and is often in the form of a short poem with a witty or sarcastic ending.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>16", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "The Big boulder blasted the house  illustrates", "images": [], "options": {"A": "alliteration", "B": "contrast", "C": "irony", "D": "Paradox"}, "answer": "A", "explanation": "Alliteration is deployed when a particular consonant sound is repeated at the beginning of a group of words. Here, the sound /b/ alliterates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>17", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "I find no peace and all my war is done  I fear and hope, i burn and freeze like ice    The dominant literary device used in the lines is", "images": [], "options": {"A": "Euphemism", "B": "Hyperbole", "C": "Paradox", "D": "understatement"}, "answer": "C", "explanation": "Paradox is a seemingly absurd or contradictory statement or proposition which when investigated may prove to be well founded or true.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>18", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "I find no peace and all my war is done  I fear and hope, i burn and freeze like ice  The feeling of the narrator in the extract is one of", "images": [], "options": {"A": "confusion", "B": "fatigue", "C": "love", "D": "Joy"}, "answer": "A", "explanation": "Confusion is a state of uncertainty about what is happening, intended, or required. That is, a state of being bewildered or unclear in one's mind about something.   In the extract the persona is unsure of a lot; hence, he FEARS and HOPES at the same time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>19", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "AFRICAN DRAMA", "question": "Which of the following is written by an African playwright?", "images": [], "options": {"A": "She stoops to conquer", "B": "A Raising in the sun", "C": "Lonely days", "D": "The Blood of a stranger"}, "answer": "D", "explanation": "\"The Blood of a Stranger\" is a play written by an African playwright, Dele Charley. The play is set in Sierra Leone and explores the themes of greed and deception.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2020>20", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN POETRY", "question": "Which of the following is written by a Non-African poet", "images": [], "options": {"A": "\"Piano and drums\"", "B": "\"The Dinning Table\"", "C": "\"The Schoolboy\"", "D": "\"The Panic of Growing Older\""}, "answer": "C", "explanation": "\"The Schoolboy\" is a poem by William Blake, an English poet. The poem is a critique of the formal education system of his time, which he believed stifled children's natural joy and curiosity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2020>21", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "On, on, on, over the countless miles of angry space roll the long heaving billows, mountains and caves are here; for what is now the other. Then all is but a boiling heap of rushing water. Pursuit and flight and mad return of wave and savage struggle, ending up in a spouting up of foam that whitens the black night, incessant change of place and form and hue, constancy in nothing but eternal strife.         On, on, on, they roll and darker grows the night and louder howls the wind and more clamorous and fierce become the  million voices  in the sea , when the wild cry goes forth upon the storm ' A ship '.    The most suituable title for the passage is", "images": [], "options": {"A": "A Savage Struggle at  Night.", "B": "At Sea a Stormy Night", "C": "The Long Heaving Waves", "D": "The Million Voice in the Sea"}, "answer": "B", "explanation": "The passage describes a stormy night at sea with the waves rolling on and on, the night growing darker, the wind howling louder, and the sea voices becoming more clamorous and fierce. The title 'At Sea a Stormy Night' best captures the essence of the passage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>22", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "On, on, on, over the countless miles of angry space roll the long heaving billows, mountains and caves are here; for what is now the other. Then all is but a boiling heap of rushing water. Pursuit and flight and mad return of wave and savage struggle, ending up in a spouting up of foam that whitens the black night, incessant change of place and form and hue, constancy in nothing but eternal strife.         On, on, on, they roll and darker grows the night and louder howls the wind and more clamorous and fierce become the  million voices  in the sea , when the wild cry goes forth upon the storm ' A ship '.  The predominant use of long vowels in the first sentence heightens the ..... of the waves.", "images": [], "options": {"A": "Anger", "B": "Expanse", "C": "Great noise", "D": "Endless movement"}, "answer": "B", "explanation": "Expanse refers to something that is wide and open: endless. The use of long vowels shows the expanse of the sea.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>23", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "On, on, on, over the countless miles of angry space roll the long heaving billows, mountains and caves are here; for what is now the other. Then all is but a boiling heap of rushing water. Pursuit and flight and mad return of wave and savage struggle, ending up in a spouting up of foam that whitens the black night, incessant change of place and form and hue, constancy in nothing but eternal strife.         On, on, on, they roll and darker grows the night and louder howls the wind and more clamorous and fierce become the  million voices  in the sea , when the wild cry goes forth upon the storm ' A ship '.  The Writer's attitude to the scene is one of ...", "images": [], "options": {"A": "Anxiety", "B": "Awe", "C": "Contempt", "D": "indifference"}, "answer": "A", "explanation": "The writer's attitude is one of anxiety because the sea appears to be uncontrollable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>24", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "On, on, on, over the countless miles of angry space roll the long heaving billows, mountains and caves are here; for what is now the other. Then all is but a boiling heap of rushing water. Pursuit and flight and mad return of wave and savage struggle, ending up in a spouting up of foam that whitens the black night, incessant change of place and form and hue, constancy in nothing but eternal strife.         On, on, on, they roll and darker grows the night and louder howls the wind and more clamorous and fierce become the  million voices  in the sea , when the wild cry goes forth upon the storm ' A ship '.  The expression  million voices  is used as", "images": [], "options": {"A": "Conceit", "B": "Euphemism", "C": "Hyberbole", "D": "Metonymy"}, "answer": "C", "explanation": "Hyperbole is an exaggerated statements or claims not meant to be taken literally.  The expression, \"a million voices\", is an exaggeration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>25", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "On, on, on, over the countless miles of angry space roll the long heaving billows, mountains and caves are here; for what is now the other. Then all is but a boiling heap of rushing water. Pursuit and flight and mad return of wave and savage struggle, ending up in a spouting up of foam that whitens the black night, incessant change of place and form and hue, constancy in nothing but eternal strife.         On, on, on, they roll and darker grows the night and louder howls the wind and more clamorous and fierce become the  million voices  in the sea , when the wild cry goes forth upon the storm ' A ship '.   A ship  in the last line symbolises", "images": [], "options": {"A": "Desipair", "B": "Hope", "C": "Pirates.", "D": "sailors"}, "answer": "B", "explanation": "The presence of a ship symbolises HOPE; that is, those at sea will finally be rescued.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>26", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Oft in the stilly night   Ere slumber's chain has bound me   Fond memory brings the light   of other days around me:  The smiles, the tears   of the boyhood years   The words of the loves then spoken  The eyes that shone  How dimm'd and gone  The cheerful hearts now broken !  Thus in the stilly night   Ere slumber's chain has me    Sad memory brings the light  of the days around me.    The Theme is about the poet", "images": [], "options": {"A": "Broken love affairs", "B": "fear of the stilly night", "C": "Sleepless night", "D": "Yearning for happier times gone by."}, "answer": "D", "explanation": "The poem is about the poet reminiscing about the past. The poet talks about the smiles, tears, and words of love from his boyhood years, and how those cheerful hearts are now broken. He also mentions how sad memory brings the light of those days around him. This suggests that the poet is yearning for the happier times that have gone by.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>27", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Oft in the stilly night   Ere slumber's chain has bound me   Fond memory brings the light   of other days around me:  The smiles, the tears   of the boyhood years   The words of the loves then spoken  The eyes that shone  How dimm'd and gone  The cheerful hearts now broken !  Thus in the stilly night   Ere slumber's chain has me    Sad memory brings the light  of the days around me.  The theme of the poem is presented essentially through", "images": [], "options": {"A": "Assonance", "B": "Contrast", "C": "paradox", "D": "Repetition"}, "answer": "D", "explanation": "The theme of the poem is presented essentially through repetition. The poet repeats certain phrases and ideas to emphasize the theme of the poem. Repetition is a literary device that repeats the same words or phrases a few times to make an idea clearer and more memorable. In this poem, phrases like 'stilly night', 'Ere slumber's chain has bound me', 'brings the light', 'around me' are repeated to emphasize the theme of the poem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>28", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Oft in the stilly night   Ere slumber's chain has bound me   Fond memory brings the light   of other days around me:  The smiles, the tears   of the boyhood years   The words of the loves then spoken  The eyes that shone  How dimm'd and gone  The cheerful hearts now broken !  Thus in the stilly night   Ere slumber's chain has me    Sad memory brings the light  of the days around me.  The two words that give hint of the poet's unhappiness are", "images": [], "options": {"A": "Light and night", "B": "Light amd shone", "C": "Night and Dimm'd", "D": "Shone and Dimm'd"}, "answer": "C", "explanation": "The poet's unhappiness is shown through his use of words like \"night\" and \"dimm'd\". These words suggest aging.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>29", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Oft in the stilly night   Ere slumber's chain has bound me   Fond memory brings the light   of other days around me:  The smiles, the tears   of the boyhood years   The words of the loves then spoken  The eyes that shone  How dimm'd and gone  The cheerful hearts now broken !  Thus in the stilly night   Ere slumber's chain has me    Sad memory brings the light  of the days around me.  The poet refers to memory as being 'fond' and 'sad' because it brings", "images": [], "options": {"A": "Cheers and smiles", "B": "love and joy", "C": "sorrow and pity", "D": "Since i cannot sleep"}, "answer": "B", "explanation": "The memories bring back both \"Smiles and tears\". This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>30", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Oft in the stilly night   Ere slumber's chain has bound me   Fond memory brings the light   of other days around me:  The smiles, the tears   of the boyhood years   The words of the loves then spoken  The eyes that shone  How dimm'd and gone  The cheerful hearts now broken !  Thus in the stilly night   Ere slumber's chain has me    Sad memory brings the light  of the days around me.  The meaning of the expression,  Ere Slumber's chain his bound me  is", "images": [], "options": {"A": "After i wake up", "B": "Before i sleep", "C": "before i dream", "D": "since i cannot sleep"}, "answer": "D", "explanation": "It means the persona is unable to sleep. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2020>31", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Zounds, sir, y' are robbed! For shame , put on your gown!   Your heart is burst, you have lost half your soul.  Even now, very now,  an old black ram    Is tripping your white ewe , Arise, arise !  Awake the snorting citizen with the bell,  Or else the devil will make a grandsire of you  Arise i say !  (Act 1, Scene one, line  83 - 89)    The speaker is", "images": [], "options": {"A": "Cassio", "B": "Iago", "C": "Lodovico", "D": "Roderigo"}, "answer": "B", "explanation": "Iago is the speaker. He is informing Brabantio about his daughter's elopement with Othello.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>32", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Zounds, sir, y' are robbed! For shame , put on your gown!   Your heart is burst, you have lost half your soul.  Even now, very now,  an old black ram    Is tripping your white ewe , Arise, arise !  Awake the snorting citizen with the bell,  Or else the devil will make a grandsire of you  Arise i say !  (Act 1, Scene one, line  83 - 89)  The underlined expression implies an attitude of", "images": [], "options": {"A": "Callousness", "B": "Hypocrisy", "C": "Racism", "D": "Tribalism"}, "answer": "C", "explanation": "The underlined implies racism. Othello is being regarded as an old black ram; that is, he is considered as unfit to marry Desdemona, a white lady.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>33", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Zounds, sir, y' are robbed! For shame , put on your gown!   Your heart is burst, you have lost half your soul.  Even now, very now,  an old black ram    Is tripping your white ewe , Arise, arise !  Awake the snorting citizen with the bell,  Or else the devil will make a grandsire of you  Arise i say !  (Act 1, Scene one, line  83 - 89)  ...y' are robbed! refers to", "images": [], "options": {"A": "Brabanito's rejection of othello", "B": "Desdemona's stout defence of othello", "C": "Iago's stealin of Roderigo purse", "D": "Othella elopment with Desdemona"}, "answer": "D", "explanation": "The phrase 'y' are robbed!' in this context refers to Othello's elopement with Desdemona. The speaker, Iago, is informing Brabantio (Desdemona's father) that Othello has 'stolen' his daughter. The term 'robbed' is used metaphorically to indicate that Desdemona has been taken away without Brabantio's knowledge or consent.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>34", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Zounds, sir, y' are robbed! For shame , put on your gown!   Your heart is burst, you have lost half your soul.  Even now, very now,  an old black ram    Is tripping your white ewe , Arise, arise !  Awake the snorting citizen with the bell,  Or else the devil will make a grandsire of you  Arise i say !  (Act 1, Scene one, line  83 - 89)  Th speaker is", "images": [], "options": {"A": "at the citadel of Cyprus", "B": "In the front of Brabantio's house", "C": "In the the council chamber", "D": "Outside the sagittary."}, "answer": "B", "explanation": "The speaker of these lines is Iago, and he is speaking in front of Brabantio's house. Iago and Roderigo have come to inform Brabantio of Desdemona's elopement with Othello. The location is inferred from the context of the scene and the urgency with which Iago and Roderigo are trying to wake Brabantio.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>35", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Zounds, sir, y' are robbed! For shame , put on your gown!   Your heart is burst, you have lost half your soul.  Even now, very now,  an old black ram    Is tripping your white ewe , Arise, arise !  Awake the snorting citizen with the bell,  Or else the devil will make a grandsire of you  Arise i say !  (Act 1, Scene one, line  83 - 89)  The speaker is", "images": [], "options": {"A": "at the citadel of Cyprus", "B": "in front of Brabantio's house", "C": "In the council chamber", "D": "Outside the sagittary."}, "answer": "B", "explanation": "The speaker is in front of Brabantio's house. This is evident from the context of the quote. The speaker is Iago, who is trying to wake up Brabantio to tell him that his daughter, Desdemona, has eloped with Othello. The 'old black ram' is a reference to Othello, and the 'white ewe' is a reference to Desdemona. The speaker is trying to create a sense of urgency and alarm, hence the repeated calls for Brabantio to 'arise'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>36", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "I will rather sue to be despised than to be decievd so good a commander with so slight, drunken an so indiscreet an officer. Drunk! And speak parrot! And squabble! swagger ! swear! And discouse fustian with one's own shadow !  O thou invisible spirit of wine  , if thou hast no name to be name to be known by, let us call thee devil !   (Act II, scene three, lines 262-267)    The speaker is", "images": [], "options": {"A": "Cassio", "B": "Iago.", "C": "Duke", "D": "Roderigo"}, "answer": "A", "explanation": "Michael Cassio is the speaker. He is ashamed to have lost his reputation due to his part in a drunken brawl. He is demoted by Othello.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>37", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "I will rather sue to be despised than to be decievd so good a commander with so slight, drunken an so indiscreet an officer. Drunk! And speak parrot! And squabble! swagger ! swear! And discouse fustian with one's own shadow !  O thou invisible spirit of wine  , if thou hast no name to be name to be known by, let us call thee devil !   (Act II, scene three, lines 262-267)  The speaker is addressing", "images": [], "options": {"A": "Cassio.", "B": "Iago", "C": "Othello", "D": "Roderigo"}, "answer": "B", "explanation": "Cassio is addressing Iago. Cassio is unaware that Iago is the cause of everything.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>38", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "I will rather sue to be despised than to be decievd so good a commander with so slight, drunken an so indiscreet an officer. Drunk! And speak parrot! And squabble! swagger ! swear! And discouse fustian with one's own shadow !  O thou invisible spirit of wine  , if thou hast no name to be name to be known by, let us call thee devil !   (Act II, scene three, lines 262-267)  The mood is that of", "images": [], "options": {"A": "Deceit", "B": "Envy", "C": "Hatred", "D": "regret"}, "answer": "D", "explanation": "The mood in this excerpt is one of regret. The speaker, Iago, is expressing his disdain for Cassio's drunken behavior. He is regretful that such a good commander could be so indiscreet and irresponsible. The use of strong, negative language ('drunk', 'squabble', 'swagger', 'swear', 'devil') further emphasizes this mood of regret.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>39", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "I will rather sue to be despised than to be decievd so good a commander with so slight, drunken an so indiscreet an officer. Drunk! And speak parrot! And squabble! swagger ! swear! And discouse fustian with one's own shadow !  O thou invisible spirit of wine  , if thou hast no name to be name to be known by, let us call thee devil !   (Act II, scene three, lines 262-267)  ... So good a commander refers to", "images": [], "options": {"A": "Brabantio", "B": "Duke", "C": "Othello", "D": "Roderigo"}, "answer": "C", "explanation": "In the context of the play, 'so good a commander' refers to Othello who is the commander of the Venetian army.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>40", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "I will rather sue to be despised than to be decievd so good a commander with so slight, drunken an so indiscreet an officer. Drunk! And speak parrot! And squabble! swagger ! swear! And discouse fustian with one's own shadow !  O thou invisible spirit of wine  , if thou hast no name to be name to be known by, let us call thee devil !   (Act II, scene three, lines 262-267)  The underlined expression exemplifies", "images": [], "options": {"A": "Antithesis", "B": "Apostrophe", "C": "Chiamus", "D": "Euphemism"}, "answer": "B", "explanation": "Apostrophe as a literary device refers to a speech, address to a person who is not present, or to a personified object.  Here, WINE is directly addressed.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>41", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker X : ...did he lives now,   This sight would make him do a desperate turn;   Yea, curse his better angel from his side ,  And fall to reprobation    Speaker Y : 'T is pitiful; but yet Iago knows that she with Cassio hath the act of shame  A thousand times committed. Cassio confessed it;  And she gratify his amorous works .  (Act V, scene Two, lines 204 - 211)    ...e... referred to the speaker X, is", "images": [], "options": {"A": "Brabantio", "B": "Gratiano", "C": "Montano", "D": "Lodovico"}, "answer": "B", "explanation": "Gratiano Brabantio's relative who accompanies Lodovico to Cyprus. Amidst the chaos of the final scene, Graziano mentions that Desdemona's father has died.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>42", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker X : ...did he lives now,   This sight would make him do a desperate turn;   Yea, curse his better angel from his side ,  And fall to reprobation    Speaker Y : 'T is pitiful; but yet Iago knows that she with Cassio hath the act of shame  A thousand times committed. Cassio confessed it;  And she gratify his amorous works .  (Act V, scene Two, lines 204 - 211)  ....do a desperate turns means", "images": [], "options": {"A": "commit suicide", "B": "Confront Duke", "C": "Disown Desdemona", "D": "Kill Othello"}, "answer": "A", "explanation": "'Do a desperate turn' in this context means to take a drastic or extreme action due to despair or desperation. In the context of the play 'Othello', this phrase is used to refer to the act of committing suicide. Othello, in his despair and feeling of betrayal, kills himself. Therefore, the phrase 'do a desperate turn' means to commit suicide.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>43", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker X : ...did he lives now,   This sight would make him do a desperate turn;   Yea, curse his better angel from his side ,  And fall to reprobation    Speaker Y : 'T is pitiful; but yet Iago knows that she with Cassio hath the act of shame  A thousand times committed. Cassio confessed it;  And she gratify his amorous works .  (Act V, scene Two, lines 204 - 211)  Speaker Y's spech shows that", "images": [], "options": {"A": "Cassio is to blame", "B": "Emillia is to blame", "C": "He is unrepentant", "D": "She is regretful"}, "answer": "C", "explanation": "Othello is trying to justify his killing of Desdemona.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>44", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker X : ...did he lives now,   This sight would make him do a desperate turn;   Yea, curse his better angel from his side ,  And fall to reprobation    Speaker Y : 'T is pitiful; but yet Iago knows that she with Cassio hath the act of shame  A thousand times committed. Cassio confessed it;  And she gratify his amorous works .  (Act V, scene Two, lines 204 - 211)  Speaker Y has just", "images": [], "options": {"A": "Discovered Iagos plan", "B": "Killed Desdemona", "C": "ordered the arrest  of Iago", "D": "Promoed cassio"}, "answer": "B", "explanation": "Othello has just killed Desdemona. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>45", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Speaker X : ...did he lives now,   This sight would make him do a desperate turn;   Yea, curse his better angel from his side ,  And fall to reprobation    Speaker Y : 'T is pitiful; but yet Iago knows that she with Cassio hath the act of shame  A thousand times committed. Cassio confessed it;  And she gratify his amorous works .  (Act V, scene Two, lines 204 - 211)  Just after this dialogue", "images": [], "options": {"A": "Cassio is killed", "B": "Emilia realises her culpability", "C": "Iago gloats over his success", "D": "Roderigo fight cassio"}, "answer": "B", "explanation": "Emilia realises that she had unwittingly played a part in making Othello think that Desdemona was unfaithful.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>46", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "O thou dull moor, the handkerchief thou speak'st of   i found by fortune and did give mu husband;  For often with solemn earnestness-  More than indeed belonged to such a trifle-  He begged of me to steal 't.  (Act V, scene Two, lines 223-227)    The speaker is", "images": [], "options": {"A": "Bianca", "B": "Cassio", "C": "Desdemona", "D": "Emilia"}, "answer": "D", "explanation": "The speaker of the given lines is Emilia. In this part of the play, Emilia reveals that she found the handkerchief that Othello had given to Desdemona, and she gave it to her husband Iago. She also mentions that Iago had often, with 'solemn earnestness', asked her to steal it. This revelation is a crucial turning point in the play, as it exposes Iago's manipulation and deceit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>47", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "O thou dull moor, the handkerchief thou speak'st of   i found by fortune and did give mu husband;  For often with solemn earnestness-  More than indeed belonged to such a trifle-  He begged of me to steal 't.  (Act V, scene Two, lines 223-227)  The speaker has just been threatened by", "images": [], "options": {"A": "Cassio", "B": "Iago", "C": "Lodovico", "D": "Othello"}, "answer": "B", "explanation": "When Emilia begins to speak, Iago attempts to run her through with his sword. He later succeeds.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>48", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "O thou dull moor, the handkerchief thou speak'st of   i found by fortune and did give mu husband;  For often with solemn earnestness-  More than indeed belonged to such a trifle-  He begged of me to steal 't.  (Act V, scene Two, lines 223-227)  What has just happened is that", "images": [], "options": {"A": "Emilia has confirmed her mistress's guilt", "B": "Iago has openly confessed his crime", "C": "Othello has murdered his wife", "D": "Roderigo has realised Iago is a fraud"}, "answer": "C", "explanation": "The given lines are from the play 'Othello' by William Shakespeare. In this scene, Emilia, Desdemona's maid and Iago's wife, is speaking to Othello. She has just discovered that Othello has killed Desdemona. Emilia is revealing the truth about the handkerchief, which was a significant symbol in the play. Othello had been manipulated by Iago into believing that Desdemona gave the handkerchief to Cassio as a token of love, which led to Othello's jealousy and ultimately, Desdemona's death. Therefore, what has just happened is that Othello has murdered his wife.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>49", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "O thou dull moor, the handkerchief thou speak'st of   i found by fortune and did give mu husband;  For often with solemn earnestness-  More than indeed belonged to such a trifle-  He begged of me to steal 't.  (Act V, scene Two, lines 223-227)  Soon after this, the speaker", "images": [], "options": {"A": "Attempts to run away", "B": "is arrested by Lodovico", "C": "is killed by Iago.", "D": "show remorse"}, "answer": "C", "explanation": "The speaker in the quoted lines is Emilia from Shakespeare's play 'Othello'. After these lines, Emilia is killed by Iago. Therefore, the correct answer is 'is killed by Iago.'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2020>50", "subject": "Literature", "year": "2020", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "O thou dull moor, the handkerchief thou speak'st of   i found by fortune and did give mu husband;  For often with solemn earnestness-  More than indeed belonged to such a trifle-  He begged of me to steal 't.  (Act V, scene Two, lines 223-227)  This stage of the play is known as the", "images": [], "options": {"A": "Climax", "B": "conflict", "C": "denoucment", "D": "exposition"}, "answer": "C", "explanation": "Denouement is the final part of a play, film, or narrative in which the strands of the plot are drawn together and matters are explained or resolved.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2021>1", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Something a character says on stage that is meant for the audience alone is ____.", "images": [], "options": {"A": "an epilogue", "B": "a mime", "C": "a soliloquy", "D": "an aside"}, "answer": "D", "explanation": "An aside is a speech made by a character without the knowledge of other characters. Such speech is addressed to the audience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>2", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "A pause within a line of poetry is ____.", "images": [], "options": {"A": "an alliteration", "B": "a caesura", "C": "a metre", "D": "an assonance"}, "answer": "B", "explanation": "A caesura refers to a pause in a line of poetry. It is often marked by pauses instigated by punctuation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>3", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "A recurring idea, image, or a group of images that unifies a work of literature is ____.", "images": [], "options": {"A": "motif", "B": "allusion", "C": "legend", "D": "anecdote"}, "answer": "A", "explanation": "A motif is a recurring idea, image, or group of images that unifies a work of literature. It is a distinctive feature or dominant idea in an artistic or literary composition. It helps in developing the themes and mood of the work and often symbolizes something important.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>4", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "When you are old and grey and full of sleep  The rhythmic pattern of the above line is ____.", "images": [], "options": {"A": "anapestic", "B": "dactylic", "C": "trochaic", "D": "iambic"}, "answer": "D", "explanation": "Iambic meter is made up of two syllables following the pattern: unstressed + stressed. That is, the first syllable us unstressed while the second is stressed. In the extract below, the stressed syllables or words are capitalised:    when YOU are OLD and GREY and FULL of SLEEP", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2021>5", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "An inscription on a tombstone is an ____.", "images": [], "options": {"A": "epitaph", "B": "epistle", "C": "epigram", "D": "ode"}, "answer": "A", "explanation": "An inscription on a tomb is known as an epitaph.  Thus, any poem that is written on the gravestone of a person can be called an epitaph.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>6", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "A three-line stanza, rhymed ABA, BCB, CDC is a ____.", "images": [], "options": {"A": "couplet", "B": "haiku", "C": "terza rima", "D": "heroic couplet"}, "answer": "C", "explanation": "The terza rima is a type of poem with stanzas of three lines. It has a rhyming pattern that goes thus: aba bcb cdc ded...", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2021>7", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "The chorus normally features prominently in ____.", "images": [], "options": {"A": "poetry", "B": "the epic", "C": "the novel", "D": "drama"}, "answer": "D", "explanation": "The chorus can be used in all genres, but it features predominantly in drama. In ancient Greek drama, for instance, the chorus was used to give commentary on issues as well as to link the various scenes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>8", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "A story which explains a natural phenomenon or justifies the beliefs of a society is ____.", "images": [], "options": {"A": "myth", "B": "legend", "C": "motif", "D": "fable"}, "answer": "A", "explanation": "A myth is a story that was once believed to be true by a particular society. This story served to explain the origin of a natural phenomenon. On the other hand, the legend refers to true stories that might have been exaggerated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>9", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "/Read the extract below and answer questions below.*/    What happened to a dream deferred?  Does it dry up  Like a raisin in the sun?  Or fester like a sore  And then run?  Does it stink like rotten meat?    The dominant literary device is ____.", "images": [], "options": {"A": "the epithet", "B": "the rhetorical question", "C": "verbal irony", "D": "paradox"}, "answer": "B", "explanation": "The rhetorical question dominates in this extract because several questions which do not require answers are asked.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2021>10", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "/Read the extract below and answer questions below.    What happened to a dream deferred?  Does it dry up  Like a raisin in the sun?  Or fester like a sore  And then run?  Does it stink like rotten meat?  Does it stink like rotten meat?*/ makes use of the sense of ____.", "images": [], "options": {"A": "taste", "B": "touch", "C": "sight", "D": "smell"}, "answer": "D", "explanation": "\"Stink\" as used in the line suggests a bad smell; hence, the extract makes an impression to the sense of smell: olfactory imagery.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2021>11", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "/Read the extract below and answer questions below.*/    What happened to a dream deferred?  Does it dry up  Like a raisin in the sun?  Or fester like a sore  And then run?  Does it stink like rotten meat?  The mood of the poem is one of ____.", "images": [], "options": {"A": "joy", "B": "doubt", "C": "anger", "D": "certainty"}, "answer": "B", "explanation": "The mood is that of doubt. This is reinforced through the rhetorical questions which suggest that there is no definitive answer to the persona's questions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>12", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "A short play play performed in the pause between the act of a longer play is ____.", "images": [], "options": {"A": "denouement", "B": "interlude", "C": "prologue", "D": "epilogue"}, "answer": "B", "explanation": "An Interlude refers to a brief presentation that comes in the middle of a larger performance or play. This presentation can be in the form of music, dance, verse or even a short play.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2021>13", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "The most intense part of a conflict is the ____.", "images": [], "options": {"A": "resolution", "B": "climax", "C": "denouement", "D": "deus ex machina"}, "answer": "B", "explanation": "The climax is the most intense part of a conflict in a story. It is the turning point, where the tension and uncertainty reach their peak. It's the point where the protagonist confronts the conflict directly and it becomes clear who will win. The resolution and denouement are the parts of the story that wrap up loose ends and resolve any remaining issues after the climax. Deus ex machina is a plot device where an unsolvable problem is suddenly resolved by an unexpected intervention.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>14", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "I feel a million times better than I felt yesterday is ____.", "images": [], "options": {"A": "an apostrophe", "B": "a euphemism", "C": "an irony", "D": "a hyperbole"}, "answer": "D", "explanation": "The hyperbole is an excessive exaggeration that is used to emphasize a point. Here, \"a million times\" is used to point out that the speaker is much better than he or she was the previous day.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2021>15", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Identify the odd item:", "images": [], "options": {"A": "third person narrative", "B": "literary appreciation", "C": "first person narrative", "D": "epistolary technique"}, "answer": "B", "explanation": "Literary appreciation is the odd item in the list. The other options refer to modes of storytelling or narration while literary appreciation refers to the analysis or appraisal of a literary work.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>16", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "A dramatists is someone who ____ plays.", "images": [], "options": {"A": "writes", "B": "directs", "C": "commissions", "D": "promotes"}, "answer": "A", "explanation": "A dramatist is a person who writes plays. The term 'dramatist' comes from the Greek word 'drama', which means 'action', and the suffix '-ist', which denotes a person who practices or is concerned with something. Therefore, a dramatist is someone who creates action through their writing, i.e., they write plays. The other options, 'directs', 'commissions', and 'promotes', are roles that may be associated with a play but are not specifically related to the role of a dramatist.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2021>17", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Nando's family lives within the lower income bracket illustrates ____.", "images": [], "options": {"A": "sarcasm", "B": "allusion", "C": "climax", "D": "euphemism"}, "answer": "D", "explanation": "The euphemism is a milder way of making unpleasant statements. In the extract, instead of calling Nando's family poor, the speaker refers to them as \"living within the lower income bracket\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>18", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "A dramatic performance without words is ____.", "images": [], "options": {"A": "a mime", "B": "an aside", "C": "a monologue", "D": "a soliloquy"}, "answer": "A", "explanation": "A dramatic performance without words is a mime. Mime is a form of performance where the story is told through body movements and facial expressions without the use of speech. The other options, an aside, a monologue, and a soliloquy, all involve spoken words and therefore do not fit the description.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2021>19", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Utopia is a term used to describe ____.", "images": [], "options": {"A": "strange circumstances", "B": "difficult conditions", "C": "pleasant feelings", "D": "ideal societies"}, "answer": "D", "explanation": "Utopia is used to describe a place or society where everything is perfect. The opposite is dystopia.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>20", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "The lawyer addressed the bench illustrates ____.", "images": [], "options": {"A": "simile", "B": "oxymoron", "C": "alliteration", "D": "metonymy"}, "answer": "D", "explanation": "Metonymy is used when we use something closely related to refer to a thing. Here, the bench is used to refer to the jury.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>21", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage below and answer questions below     When he was little, he would ask his mother sometimes, as he lay in the cold little room and looked up at her as she sat beside his bed stroking his hair, why two boys from his class had thrown stones at a dog; or why on another occasion a gang of them had broken into an empty house, smashing the thick door which had curved mouldings on the front which had been turned by carpenters years before; or why he had ended up in a fight which had begun when a little girl had shouted names at him which made no sense about his house and his mother and others joined in and he had rushed at them, scattering them as some shrieked and some laughed and he flailed about with his hard little fists and tears in his eyes. His mother would smile, say 'shhh' and he would drift to sleep with the heart shape of her face imprinted on his mind.    The dominant feeling in the passage is that of ____.", "images": [], "options": {"A": "nostalgia", "B": "anger", "C": "expectancy", "D": "fear"}, "answer": "A", "explanation": "Nostalgia refers to a sad feeling mixed with pleasure when you think of happy times in the past. In the extract, the first clause - \"When he was little\" - shows that the person is no longer little. That is, a time in the past is being remembered.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>22", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage below and answer questions below     When he was little, he would ask his mother sometimes, as he lay in the cold little room and looked up at her as she sat beside his bed stroking his hair, why two boys from his class had thrown stones at a dog; or why on another occasion a gang of them had broken into an empty house, smashing the thick door which had curved mouldings on the front which had been turned by carpenters years before; or why he had ended up in a fight which had begun when a little girl had shouted names at him which made no sense about his house and his mother and others joined in and he had rushed at them, scattering them as some shrieked and some laughed and he flailed about with his hard little fists and tears in his eyes. His mother would smile, say 'shhh' and he would drift to sleep with the heart shape of her face imprinted on his mind.  The feeling is conveyed by the ____.", "images": [], "options": {"A": "mouldings on the door", "B": "boys' actions", "C": "tender care of his mother", "D": "little girl's taunts"}, "answer": "C", "explanation": "The feeling is conveyed by the tender care of his mother. The boy recalls all these past events alongside his mother's love and affections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>23", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage below and answer questions below     When he was little, he would ask his mother sometimes, as he lay in the cold little room and looked up at her as she sat beside his bed stroking his hair, why two boys from his class had thrown stones at a dog; or why on another occasion a gang of them had broken into an empty house, smashing the thick door which had curved mouldings on the front which had been turned by carpenters years before; or why he had ended up in a fight which had begun when a little girl had shouted names at him which made no sense about his house and his mother and others joined in and he had rushed at them, scattering them as some shrieked and some laughed and he flailed about with his hard little fists and tears in his eyes. His mother would smile, say 'shhh' and he would drift to sleep with the heart shape of her face imprinted on his mind.  The dominant literary device in the passage is ____.", "images": [], "options": {"A": "personification", "B": "antithesis", "C": "litotes", "D": "parallelism"}, "answer": "D", "explanation": "Parallelism is a device that is used when two different statements have the same meaning or are constructed in similar fashion. Most of the statements begin with \"why\" or \"or why\".", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2021>24", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage below and answer questions below     When he was little, he would ask his mother sometimes, as he lay in the cold little room and looked up at her as she sat beside his bed stroking his hair, why two boys from his class had thrown stones at a dog; or why on another occasion a gang of them had broken into an empty house, smashing the thick door which had curved mouldings on the front which had been turned by carpenters years before; or why he had ended up in a fight which had begun when a little girl had shouted names at him which made no sense about his house and his mother and others joined in and he had rushed at them, scattering them as some shrieked and some laughed and he flailed about with his hard little fists and tears in his eyes. His mother would smile, say 'shhh' and he would drift to sleep with the heart shape of her face imprinted on his mind.  ... and he had rushed at them, scattering them as some shrieked and some laughed illustrates ____.", "images": [], "options": {"A": "onomatopoeia", "B": "climax", "C": "metaphor", "D": "metonymy"}, "answer": "A", "explanation": "Words like \"scattering\" and \"shrieked\" are onomatopoeias.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2021>25", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the passage below and answer questions below     When he was little, he would ask his mother sometimes, as he lay in the cold little room and looked up at her as she sat beside his bed stroking his hair, why two boys from his class had thrown stones at a dog; or why on another occasion a gang of them had broken into an empty house, smashing the thick door which had curved mouldings on the front which had been turned by carpenters years before; or why he had ended up in a fight which had begun when a little girl had shouted names at him which made no sense about his house and his mother and others joined in and he had rushed at them, scattering them as some shrieked and some laughed and he flailed about with his hard little fists and tears in his eyes. His mother would smile, say 'shhh' and he would drift to sleep with the heart shape of her face imprinted on his mind.  The main character is ____.", "images": [], "options": {"A": "playful", "B": "inquisitive", "C": "sad", "D": "humorous"}, "answer": "B", "explanation": "The main character can be described as inquisitive because he asks a lot of questions about things he does not understand. That is, he wants to why why certain things happened.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>26", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem below and answer questions 26 to 30.    We wear the mask that grins and lies,  It hides our cheeks and shades our eyes,  This debt we pay to human guile;  With torn and bleeding hearts we smile  And mouths with myriad subtleties,    Why should the world be over-wise,  In counting all our tears and sighs?  Nay, let them only see us, while  We wear the mask.    We smile but O great God, our cries  To thee from tortured souls arise.  We sing, but oh the clay is vile  Beneath our feet and long the mile,  But let the world dream otherwise,  We wear the mask!    The poem is about ____.", "images": [], "options": {"A": "debtors", "B": "dreams", "C": "costumes", "D": "appearances"}, "answer": "D", "explanation": "The poem talks about wearing a mask that hides true emotions and presents a different appearance to the world. This indicates that the poem is about 'appearances'. The term 'appearances' in this context refers to the act of presenting oneself in a certain way to the outside world, often hiding true feelings or situations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>27", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem below and answer questions 26 to 30.    We wear the mask that grins and lies,  It hides our cheeks and shades our eyes,  This debt we pay to human guile;  With torn and bleeding hearts we smile  And mouths with myriad subtleties,    Why should the world be over-wise,  In counting all our tears and sighs?  Nay, let them only see us, while  We wear the mask.    We smile but O great God, our cries  To thee from tortured souls arise.  We sing, but oh the clay is vile  Beneath our feet and long the mile,  But let the world dream otherwise,  We wear the mask!  The poet's tone is ____.", "images": [], "options": {"A": "supplicatory", "B": "defiant", "C": "conciliatory", "D": "compliant"}, "answer": "B", "explanation": "The tone is defiant. This defiance is marked by the way the speaker refuses to allow people know about his inner struggles. Rather, people are only allowed the see the mask.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>28", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem below and answer questions 26 to 30.    We wear the mask that grins and lies,  It hides our cheeks and shades our eyes,  This debt we pay to human guile;  With torn and bleeding hearts we smile  And mouths with myriad subtleties,    Why should the world be over-wise,  In counting all our tears and sighs?  Nay, let them only see us, while  We wear the mask.    We smile but O great God, our cries  To thee from tortured souls arise.  We sing, but oh the clay is vile  Beneath our feet and long the mile,  But let the world dream otherwise,  We wear the mask!  The rhyme scheme of the first stanza is ____.", "images": [], "options": {"A": "aabcc", "B": "ababa", "C": "aabbc", "D": "abbac"}, "answer": "C", "explanation": "The rhyme scheme of the first stanza is aabbc. This can be determined by assigning a letter to each end word in the stanza based on its sound. The words 'lies', 'eyes', 'guile', 'smile', and 'subtleties' correspond to the rhyme scheme aabbc.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2021>29", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem below and answer questions 26 to 30.    We wear the mask that grins and lies,  It hides our cheeks and shades our eyes,  This debt we pay to human guile;  With torn and bleeding hearts we smile  And mouths with myriad subtleties,    Why should the world be over-wise,  In counting all our tears and sighs?  Nay, let them only see us, while  We wear the mask.    We smile but O great God, our cries  To thee from tortured souls arise.  We sing, but oh the clay is vile  Beneath our feet and long the mile,  But let the world dream otherwise,  We wear the mask!  The dominant mood is one of ____.", "images": [], "options": {"A": "sadness", "B": "fear", "C": "joy", "D": "optimism"}, "answer": "A", "explanation": "The dominant mood is one of sadness. The speaker talks about how he makes an effort to hide this feeling by wearing a mask of happiness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>30", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the poem below and answer questions 26 to 30.    We wear the mask that grins and lies,  It hides our cheeks and shades our eyes,  This debt we pay to human guile;  With torn and bleeding hearts we smile  And mouths with myriad subtleties,    Why should the world be over-wise,  In counting all our tears and sighs?  Nay, let them only see us, while  We wear the mask.    We smile but O great God, our cries  To thee from tortured souls arise.  We sing, but oh the clay is vile  Beneath our feet and long the mile,  But let the world dream otherwise,  We wear the mask!  We wear the mask that grins and lies illustrates ____.", "images": [], "options": {"A": "irony", "B": "personification", "C": "synecdoche", "D": "alliteration"}, "answer": "B", "explanation": "Here, an inanimate object - \"mask\" - is given the human ability to grin and lie.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2021>31", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions 31 to 35.    X: You do impeach your modesty too much,  To leave the city and commit yourself  Into the hands of one that loves you not;  To trust the opportunity of night  And the ill counsel of a desert place.  With the rich worth of your virginity.    Y: Your virtue is my privilege: for that  It is not night when I do see your face,  Therefore I think I am not in this night;    (Act II, Scene One, Lines 214 - 222)    Speaker X is ____.", "images": [], "options": {"A": "Hermia", "B": "Philostrate", "C": "Demetrius", "D": "Lysander"}, "answer": "C", "explanation": "Speaker X is Demetrius. In the context of the play, he is speaking to Helena, trying to dissuade her from following him into the woods at night. He does not love her and is concerned for her safety and virtue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>32", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions 31 to 35.    X: You do impeach your modesty too much,  To leave the city and commit yourself  Into the hands of one that loves you not;  To trust the opportunity of night  And the ill counsel of a desert place.  With the rich worth of your virginity.    Y: Your virtue is my privilege: for that  It is not night when I do see your face,  Therefore I think I am not in this night;    (Act II, Scene One, Lines 214 - 222)  Speaker Y is ____.", "images": [], "options": {"A": "Titania", "B": "Peaseblossom", "C": "Hippolyta", "D": "Helena"}, "answer": "D", "explanation": "Speaker Y is Helena. She is in love with Demetrius and is following him into the woods. She is trying to convince him that her virtue is safe with him, even though he does not love her.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>33", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions 31 to 35.    X: You do impeach your modesty too much,  To leave the city and commit yourself  Into the hands of one that loves you not;  To trust the opportunity of night  And the ill counsel of a desert place.  With the rich worth of your virginity.    Y: Your virtue is my privilege: for that  It is not night when I do see your face,  Therefore I think I am not in this night;    (Act II, Scene One, Lines 214 - 222)  Speaker X sees Speaker Y ____.", "images": [], "options": {"A": "as a pretender", "B": "as a past lover", "C": "for the first time", "D": "for the last time"}, "answer": "A", "explanation": "In the given extract, Speaker X is cautioning Speaker Y about the dangers of leaving the city and entrusting herself to someone who does not love her. This suggests that Speaker X sees Speaker Y as someone who is naive or misguided, rather than any of the options provided. However, the closest option to this interpretation is 'as a pretender', as Speaker X may see Speaker Y as pretending or deluding herself about the reality of her situation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>34", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions 31 to 35.    X: You do impeach your modesty too much,  To leave the city and commit yourself  Into the hands of one that loves you not;  To trust the opportunity of night  And the ill counsel of a desert place.  With the rich worth of your virginity.    Y: Your virtue is my privilege: for that  It is not night when I do see your face,  Therefore I think I am not in this night;    (Act II, Scene One, Lines 214 - 222)  Both speakers are in the woods ____.", "images": [], "options": {"A": "to hide from each other", "B": "to spy on each other", "C": "for different reasons", "D": "for the same reason"}, "answer": "C", "explanation": "Demetrius is in the woods to fight Lysander and woo Hermia while Helena followed Demetrius because she loves him.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>35", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions 31 to 35.    X: You do impeach your modesty too much,  To leave the city and commit yourself  Into the hands of one that loves you not;  To trust the opportunity of night  And the ill counsel of a desert place.  With the rich worth of your virginity.    Y: Your virtue is my privilege: for that  It is not night when I do see your face,  Therefore I think I am not in this night;    (Act II, Scene One, Lines 214 - 222)  Night evolves in the speakers' ____.", "images": [], "options": {"A": "huge responsibilities", "B": "contrasting feelings", "C": "despairing thoughts", "D": "erotic feelings"}, "answer": "D", "explanation": "Helena uses the word night metaphorically because of her erotic feelings for Demetrius.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>36", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below .    But, masters, here are our parts, and I am  to entreat you, request you, and desire you, to con them by  to-morrow night; and meet me in the place wood, a mile  without the town, by moonlight. There will we rehearse: for  if we meet in the city, we shall be dogged with company, and our devices known.                  (Act I, Scene Two Lines 79 - 84)    The speaker is ____.", "images": [], "options": {"A": "Bottom", "B": "Peaseblossom", "C": "Quince", "D": "Puck"}, "answer": "C", "explanation": "The speaker in the extract is giving instructions to a group of people about rehearsing a play in a secluded place outside the town. This is a role that Quince plays in the play 'A Midsummer Night's Dream' by William Shakespeare. Quince is the director of the play that the Mechanicals are putting on for Theseus' wedding and he often finds himself correcting or managing the other performers. Therefore, the correct answer is 'Quince'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>37", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below .    But, masters, here are our parts, and I am  to entreat you, request you, and desire you, to con them by  to-morrow night; and meet me in the place wood, a mile  without the town, by moonlight. There will we rehearse: for  if we meet in the city, we shall be dogged with company, and our devices known.                  (Act I, Scene Two Lines 79 - 84)  The speaker is addressing ____.", "images": [], "options": {"A": "artists", "B": "painters", "C": "actors", "D": "writers"}, "answer": "C", "explanation": "The speaker is addressing a group of people who are supposed to rehearse their parts for a play. The term 'parts' in this context refers to the roles or characters that the individuals are supposed to play. Therefore, the speaker is addressing actors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>38", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below .    But, masters, here are our parts, and I am  to entreat you, request you, and desire you, to con them by  to-morrow night; and meet me in the place wood, a mile  without the town, by moonlight. There will we rehearse: for  if we meet in the city, we shall be dogged with company, and our devices known.                  (Act I, Scene Two Lines 79 - 84)  They intend to rehearse the play, ____.", "images": [], "options": {"A": "A Midsummer Night's Dream", "B": "Pyramus and Thisby", "C": "The Tragedy of Lovers", "D": "The Battle Royal"}, "answer": "B", "explanation": "Quince: Marry, our play is, The most lamentable comedy, and most cruel death of Pyramus and Thisby. (Act 1, Scene II)", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>39", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below .    But, masters, here are our parts, and I am  to entreat you, request you, and desire you, to con them by  to-morrow night; and meet me in the place wood, a mile  without the town, by moonlight. There will we rehearse: for  if we meet in the city, we shall be dogged with company, and our devices known.                  (Act I, Scene Two Lines 79 - 84)  The rehearsal is in preparation for ____.", "images": [], "options": {"A": "Egeus' acceptance of Lysander", "B": "the dance of the fairies", "C": "Theseus' wedding", "D": "Titania waking up from a dream"}, "answer": "C", "explanation": "The extract is from Shakespeare's 'A Midsummer Night's Dream'. The speaker is Peter Quince, who is organizing a rehearsal for a play that is to be performed at the wedding of Theseus, the Duke of Athens. Therefore, the rehearsal is in preparation for Theseus' wedding.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>40", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below .    But, masters, here are our parts, and I am  to entreat you, request you, and desire you, to con them by  to-morrow night; and meet me in the place wood, a mile  without the town, by moonlight. There will we rehearse: for  if we meet in the city, we shall be dogged with company, and our devices known.                  (Act I, Scene Two Lines 79 - 84)  The main actors will be ____.", "images": [], "options": {"A": "Snug and Snout", "B": "Philostrate and Starveling", "C": "Puck and Mustardseed", "D": "Quince and Bottom"}, "answer": "D", "explanation": "In the play 'A Midsummer Night's Dream', the main actors in the play that Peter Quince is organizing are Quince himself and Nick Bottom. Quince is the director and Bottom is the lead actor, playing the role of Pyramus in the play within the play. Therefore, the main actors will be Quince and Bottom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>41", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below.    X: I pray thee, gentle mortal, sing again;  Mine ear is much enamoured of thy note;  So is mine eye enthralled to thy shape;  And thy fair virtue's force perforce doth move me  On the first view, to say, to swear, I love thee.    Y: Methinks, mistress, you should have little reason for that ...    (Act III, Scene One, Lines 116 - 121)    Speaker X is ____.", "images": [], "options": {"A": "Titania", "B": "Hippolyta", "C": "Snout", "D": "Oberon"}, "answer": "A", "explanation": "The extract is from William Shakespeare's 'A Midsummer Night's Dream'. In this scene, the fairy queen Titania has fallen in love with a mortal named Bottom due to a love potion. She is enchanted by his singing and his appearance, which is why she says 'I pray thee, gentle mortal, sing again; Mine ear is much enamoured of thy note; So is mine eye enthralled to thy shape; And thy fair virtue's force perforce doth move me On the first view, to say, to swear, I love thee.' Therefore, Speaker X is Titania.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>42", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below.    X: I pray thee, gentle mortal, sing again;  Mine ear is much enamoured of thy note;  So is mine eye enthralled to thy shape;  And thy fair virtue's force perforce doth move me  On the first view, to say, to swear, I love thee.    Y: Methinks, mistress, you should have little reason for that ...    (Act III, Scene One, Lines 116 - 121)  Speaker X has just ____.", "images": [], "options": {"A": "escaped from the city", "B": "fallen into a world of dreams", "C": "woken up from an induced sleep", "D": "abandoned a love one"}, "answer": "C", "explanation": "In the given extract, Titania has just woken up from an induced sleep. Oberon, the king of the fairies, had instructed Puck to apply a love potion to Titania's eyes while she was sleeping. This potion causes the person affected to fall in love with the first creature they see upon waking. In this case, Titania wakes up to see Bottom (who has been transformed to have a donkey's head) and immediately falls in love with him. Therefore, Speaker X has just woken up from an induced sleep.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>43", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below.    X: I pray thee, gentle mortal, sing again;  Mine ear is much enamoured of thy note;  So is mine eye enthralled to thy shape;  And thy fair virtue's force perforce doth move me  On the first view, to say, to swear, I love thee.    Y: Methinks, mistress, you should have little reason for that ...    (Act III, Scene One, Lines 116 - 121)  Speaker Y is ____.", "images": [], "options": {"A": "Quince", "B": "Lysander", "C": "Demetrius", "D": "Bottom"}, "answer": "D", "explanation": "In Act III, Scene One of 'A Midsummer Night's Dream', Bottom is the character who interacts with Titania after she has been enchanted to fall in love with the first creature she sees, which happens to be Bottom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>44", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below.    X: I pray thee, gentle mortal, sing again;  Mine ear is much enamoured of thy note;  So is mine eye enthralled to thy shape;  And thy fair virtue's force perforce doth move me  On the first view, to say, to swear, I love thee.    Y: Methinks, mistress, you should have little reason for that ...    (Act III, Scene One, Lines 116 - 121)  Speaker Y is a member of ____.", "images": [], "options": {"A": "Theseus' retinue", "B": "Titania's retinue", "C": "the group of actors", "D": "the group of lovers"}, "answer": "C", "explanation": "Bottom is a member of the group of amateur actors who are preparing a play for the Duke Theseus' wedding in 'A Midsummer Night's Dream'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>45", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below.    X: I pray thee, gentle mortal, sing again;  Mine ear is much enamoured of thy note;  So is mine eye enthralled to thy shape;  And thy fair virtue's force perforce doth move me  On the first view, to say, to swear, I love thee.    Y: Methinks, mistress, you should have little reason for that ...    (Act III, Scene One, Lines 116 - 121)  Speaker X's speech can be described as a ____.", "images": [], "options": {"A": "satire", "B": "conceit", "C": "paradox", "D": "parody"}, "answer": "A", "explanation": "The speech is satirical because it contains elements of irony which criticises the concept of love as held by the English society then.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>46", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below.    If we offend, it is with our good will,  That you should think, we come not to offend,  But with good will. To show our simple skill,  That is the true beginning of our end.  Consider then, we come but in despite.  We do not come, as minding to content you,  Our true intent is.  (Act V, Scene One, Lines 108 - 114)    46. The speaker is ____.", "images": [], "options": {"A": "Flute", "B": "Quince", "C": "Bottom", "D": "Philostrate"}, "answer": "B", "explanation": "The speaker is Quince. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>47", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below.    If we offend, it is with our good will,  That you should think, we come not to offend,  But with good will. To show our simple skill,  That is the true beginning of our end.  Consider then, we come but in despite.  We do not come, as minding to content you,  Our true intent is.  (Act V, Scene One, Lines 108 - 114)  The speech is part of the ____.", "images": [], "options": {"A": "prologue", "B": "epilogue", "C": "exposition", "D": "lyric"}, "answer": "A", "explanation": "The extract is part of the prologue of a play. A prologue is an opening to a story that establishes the context and gives background details, often some earlier story that ties into the main one, and other miscellaneous information. The speaker in the extract is setting the stage for the play, explaining their intentions and asking for the audience's understanding, which is a common function of a prologue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>48", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below.    If we offend, it is with our good will,  That you should think, we come not to offend,  But with good will. To show our simple skill,  That is the true beginning of our end.  Consider then, we come but in despite.  We do not come, as minding to content you,  Our true intent is.  (Act V, Scene One, Lines 108 - 114)  The speaker is involved in putting on ____.", "images": [], "options": {"A": "a scene", "B": "a skit", "C": "an act", "D": "a play"}, "answer": "D", "explanation": "The speaker is involved in putting on a play. The extract is a speech from a character in a play, and the references to 'we come not to offend' and 'our true intent' suggest that the speaker is part of a group of actors performing a play. A play is a form of literature written by a playwright, usually consisting of dialogue or musical performances between characters, intended for theatrical performance rather than just reading.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>49", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below.    If we offend, it is with our good will,  That you should think, we come not to offend,  But with good will. To show our simple skill,  That is the true beginning of our end.  Consider then, we come but in despite.  We do not come, as minding to content you,  Our true intent is.  (Act V, Scene One, Lines 108 - 114)  The occasion is ____.", "images": [], "options": {"A": "the celebration of a royal marriage", "B": "the king's decision to banish Hermia", "C": "Oberon's threat to punish Titania", "D": "Titania falling in love with Bottom"}, "answer": "A", "explanation": "The speech is part of the play within the play performed by the mechanicals for the celebration of the royal marriage in 'A Midsummer Night's Dream'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2021>50", "subject": "Literature", "year": "2021", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer questions below.    If we offend, it is with our good will,  That you should think, we come not to offend,  But with good will. To show our simple skill,  That is the true beginning of our end.  Consider then, we come but in despite.  We do not come, as minding to content you,  Our true intent is.  (Act V, Scene One, Lines 108 - 114)  The speech is ____.", "images": [], "options": {"A": "romantic", "B": "satiric", "C": "comic", "D": "tragic"}, "answer": "D", "explanation": "The speech is tragic. Quince introduces a tragic play.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>1", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS", "question": "A novel that features spiritual apparitions as major character is", "images": [], "options": {"A": "Epistolary", "B": "Gothic", "C": "Historical", "D": "Sociological"}, "answer": "B", "explanation": "Much of Gothic literature's allure comes from the genre's suggestion of supernatural or inexplicable events, such as inanimate objects coming to life, ghosts, spirits, and vampires. An epistolary is a novel written in form of a letter. An historial novel retells history while a sociological novel relates with issues that affect our society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>2", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS", "question": "The literary term describing individuals in a work of literature is", "images": [], "options": {"A": "characters", "B": "protagonist", "C": "narrator", "D": "villain"}, "answer": "A", "explanation": "The term 'characters' is used to describe individuals in a work of literature. They can be humans, animals, or any other creatures that take part in the action of a story. A protagonist is the main character of a story, while a narrator is the person who tells the story. A villain is a character whose evil actions or motives are important to the plot. Therefore, the correct answer is 'characters'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2022>3", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Several hands stretched out for free meals at the refugee camp  illustrates", "images": [], "options": {"A": "Antithesis", "B": "Euphemism", "C": "Litotes", "D": "Synecdoche"}, "answer": "D", "explanation": "Synecdoche is a figure of speech in which a part of something is used to represent the whole. Antithesis means placing opposing ideas or statements side by side; euphemism means presenting an unpleasant event in  a milder way while litotes means a deliberate understatement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>4", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS", "question": "A short play performed between the acts of a bigger play for entertainment is", "images": [], "options": {"A": "an in media res", "B": "an interlude", "C": "an incantation", "D": "a deux ex machina"}, "answer": "B", "explanation": "The word \"interlude\" directly translates to \"between play\" meaning, it is a break from the flow of a piece (whether music, a story, or a play).    A musical interlude, for example, which can also be referred to as a \"bridge\" is a part of the song that seems to deviate...", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>5", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS", "question": "In literature, the two components of diction are", "images": [], "options": {"A": "sentence construction and punctuation", "B": "vocabulary and punctuation", "C": "syntax and sentence construction", "D": "vocabulary and syntax"}, "answer": "D", "explanation": "Diction is the speaker's (or author's) word choice. This term may also refer to the general type or character of language used in speech or in a work of literature. Diction is typically divided into two components: vocabulary and syntax. By vocabulary, we mean the degree of difficulty, complexity, abstractness, formality as well as the origin of words chosen. Syntax  refers to the arrangement – the ordering, grouping and placement of words within a sentence. The meaning of this term can also extend to encompass such things as the degree of complexity or fragmentation within these arrangements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>6", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS", "question": "A story with elements that have both literal and figurative meanings is", "images": [], "options": {"A": "an allegory", "B": "a fable", "C": "a novella", "D": "an epistle"}, "answer": "A", "explanation": "Allegory is a narration or description in which events, actions, characters, settings or objects represent specific abstractions or ideas. Allegory generally operates on two levels as a literary device. The overt or surface narrative/description is meant to have enough literary elements to be a standalone work that is interesting and/or entertaining by itself. However, the emphasis of allegory is typically placed on the abstract ideals represented or symbolized by the work's literary elements. In other words, the meaning behind the surface narrative has even greater value as a literary work. Though many allegories are intended to be didactic in providing a moral, ethical, or religious lesson, not all allegories set out to achieve this goal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>7", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "My bounty is as boundless as the sea my love as deep     The above lines illustrate", "images": [], "options": {"A": "apostrophe", "B": "epigram", "C": "hyperbole", "D": "euphemism"}, "answer": "C", "explanation": "Hyperbole is a rhetorical and literary technique where an author or speaker intentionally uses exaggeration and overstatement for emphasis and effect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>8", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS", "question": "In drama, catharsis is the", "images": [], "options": {"A": "change of setting", "B": "conflict between two characters", "C": "resolution of conflict", "D": "purgation of emotion from tension"}, "answer": "D", "explanation": "Catharsis is a literary device used to depict a release of emotions. Catharsis can be applied to any literature that makes audiences feel intense emotions such as pain or sadness, but ultimately leads to a feeling of release.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2022>9", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the extract below and answer the following questions    A little learning is a dangerous thing:  Drink deep, or taste not the Pierian Spring   The shallow droughts intoxicate the brain  And drinking largely sobers us again    The poem is", "images": [], "options": {"A": "allegoric", "B": "didactic", "C": "metaphysical", "D": "romantic"}, "answer": "B", "explanation": "This highlights that as soon as we start having a little knowledge, it intoxicates us with pride and arrogance. However, as soon as a person becomes more knowledgeable, he becomes sober. The poet has beautifully used metaphors to convey that when a person does not get more knowledge and does not become an expert, he often becomes haughty and mislead others. Didacticism is defined as the type of literature that is meant to instruct or teach something.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>10", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the extract below and answer the following questions    A little learning is a dangerous thing:  Drink deep, or taste not the Pierian Spring   The shallow droughts intoxicate the brain  And drinking largely sobers us again  The tone of the poet is", "images": [], "options": {"A": "jocular", "B": "harsh", "C": "mournful", "D": "sombre"}, "answer": "D", "explanation": "Sombre means to convey a deep feeling of seriousness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>11", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the extract below and answer the following questions    A little learning is a dangerous thing:  Drink deep, or taste not the Pierian Spring   The shallow droughts intoxicate the brain  And drinking largely sobers us again  Lines 3 and 4 illustrate", "images": [], "options": {"A": "antithesis", "B": "oxymoron", "C": "anti-climax", "D": "metonymy"}, "answer": "A", "explanation": "In lines 3 and 4, two contrasting ideas were placed side by side and this is a vivid feature of antithesis.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2022>12", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS", "question": "A word or a phrase that is repeated at regular intervals in a poem or a play is a", "images": [], "options": {"A": "dirge", "B": "refrain", "C": "lullaby", "D": "verse"}, "answer": "B", "explanation": "In poetry, a refrain is a repeated word, line, or group of lines that appears at the end of a stanza. Refrain is a poetic device that uses repetition to place emphasis on a set of words or an idea within a poem. Refrains appear at regular intervals throughout a poem to create a unique rhyme scheme and give the poem its particular rhythm.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>13", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS", "question": "The warriors conquered my men and my country  illustrates the use of", "images": [], "options": {"A": "Paradox", "B": "Litotes", "C": "Parallelism", "D": "Zeugma"}, "answer": "D", "explanation": "Zeugma is when you use a word in a sentence once, while conveying two different meanings at the same time. Sometimes, the word is literal in one part of the sentence, but figurative in another; other times, it's just two completely separate meanings for the word.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2022>14", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Disguise in drama mostly portrays the theme of", "images": [], "options": {"A": "known identity", "B": "plain identity", "C": "unknown identity", "D": "mistaken identity"}, "answer": "D", "explanation": "Disguise in drama mostly portrays the theme of 'mistaken identity'. This is because when characters disguise themselves, it often leads to other characters misidentifying them, leading to a series of misunderstandings and complications, which is a common theme in many dramas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>15", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Men swift to see things done , do not  run their commanding.    The underlined words exemplify", "images": [], "options": {"A": "pun", "B": "end rhyme", "C": "internal rhyme", "D": "paradox"}, "answer": "B", "explanation": "Internal rhymes are defined by the position of the rhyme within the line of poetry. The placement of rhymes in the middle of lines is what distinguishes internal rhymes from end rhymes, in which rhyming words occur at the ends of lines.  Internal rhyme is also sometimes referred to as \"middle rhyme.\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>16", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS", "question": "An aside in drama is used mostly to create a sense of", "images": [], "options": {"A": "admiration", "B": "conspiracy", "C": "greatness", "D": "superiority"}, "answer": "B", "explanation": "As most realistic characters will not share secret plans with others onstage, asides are a way to share these thoughts with the audience without allowing any other character to hear or understand them. Asides are used by all sorts of characters, but they are often used by villains in plays to reveal their dark intentions or secret plans to the audience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>17", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "More haste, less speed  illustrates the use of", "images": [], "options": {"A": "anaphora", "B": "paradox", "C": "litotes", "D": "synecdoche"}, "answer": "B", "explanation": "In literature, a paradox is a device used to force the reader to consider a statement or idea more deeply or critically than at face value. It is a statement or idea that seems illogical, but upon further analysis, does make sense.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>18", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Poetry gets bored of being alone   It wants to go outdoors to chew the winds.     The mental picture evoked in the above lines is that of", "images": [], "options": {"A": "smell and touch", "B": "sight and hearing", "C": "taste and touch", "D": "sight and taste"}, "answer": "D", "explanation": "Outdoors reflects the sense of sight while chew reflects the sense of taste.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2022>19", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS", "question": "A novel that recounts the adventures of a likeable rogue is", "images": [], "options": {"A": "panegyric", "B": "gothic", "C": "picaresque", "D": "grotesque"}, "answer": "C", "explanation": "Picaresque refers to fiction that follows the adventures of a rogue character, a picaro who rambles along, relating the shady details of his everyday experiences in autobiographical form.  The picaro's tales often come across with humour, although tragedy of circumstances usually travels with the storytelling. Even as he's a rascal, the picaresque hero can be quite likable in the realism he portrays.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>20", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "LITERARY TERMS", "question": "At the fall of their house, the widow lost her husband, her sewing machine and her ear-rings  illustrates", "images": [], "options": {"A": "bathos", "B": "epigram", "C": "pathos", "D": "oxymoron"}, "answer": "A", "explanation": "Bathos is a literary device where a serious or important subject is suddenly turned into a ridiculous or ordinary one. It is an anticlimax that surprises the reader and disrupts their thoughts and emotions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2022>21", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Unseen Prose and Poetry      Read the passage below and answer the following questions     Marooned, Akpatse felt imprisoned. It was fifteen days since the storm. The flood waters were not receding; neither did Akpatse see any sign of help coming. Akpatse could not swim the expanse of flood waters. He meditated: when one looks upon the mountain for help and help comes from the Lord ... where does the Lord sit - in the cloud or on the mountain, or in the valley?    Well, Akpatse looked for salvation in the distance, far across the ocean of flood - the intimidating expense of his great gaoler - up to where the sky and the lips of the flood waters met in a mocking kiss. He had forgotten the feeling of hunger but knew he did not have any energy. What a foolish thing to think! He had not had any food for days. True. But hunger never said hello from the hollow of his 'person-tree' as they say in his language. Akpatse saw no help coming.    The narrative technique used is", "images": [], "options": {"A": "1st person", "B": "Dialogue", "C": "3rd person", "D": "stream of consciousness"}, "answer": "C", "explanation": "In third-person point of view, the author is narrating a story about the characters, referring to them by name, or using the third-person pronouns \"he,\" \"she,\" and \"they.\"  A third-person narrator can be all-knowing (aware of every character's thoughts and feelings) or limited (focused on a single character, or aware only what certain characters say and do).", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>22", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Unseen Prose and Poetry      Read the passage below and answer the following questions     Marooned, Akpatse felt imprisoned. It was fifteen days since the storm. The flood waters were not receding; neither did Akpatse see any sign of help coming. Akpatse could not swim the expanse of flood waters. He meditated: when one looks upon the mountain for help and help comes from the Lord ... where does the Lord sit - in the cloud or on the mountain, or in the valley?    Well, Akpatse looked for salvation in the distance, far across the ocean of flood - the intimidating expense of his great gaoler - up to where the sky and the lips of the flood waters met in a mocking kiss. He had forgotten the feeling of hunger but knew he did not have any energy. What a foolish thing to think! He had not had any food for days. True. But hunger never said hello from the hollow of his 'person-tree' as they say in his language. Akpatse saw no help coming.  The reference to mountain illustrates", "images": [], "options": {"A": "allusion", "B": "irony", "C": "parallelism", "D": "antithesis"}, "answer": "A", "explanation": "An allusion is a reference, typically brief, to a person, place, thing, event, or other literary work with which the reader is presumably familiar. As a literary device, allusion allows a writer to compress a great deal of meaning and significance into a word or phrase. However, allusions are only effective to the extent that they are recognized and understood by the reader, and that they are properly inferred and interpreted by the reader.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>23", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Unseen Prose and Poetry      Read the passage below and answer the following questions     Marooned, Akpatse felt imprisoned. It was fifteen days since the storm. The flood waters were not receding; neither did Akpatse see any sign of help coming. Akpatse could not swim the expanse of flood waters. He meditated: when one looks upon the mountain for help and help comes from the Lord ... where does the Lord sit - in the cloud or on the mountain, or in the valley?    Well, Akpatse looked for salvation in the distance, far across the ocean of flood - the intimidating expense of his great gaoler - up to where the sky and the lips of the flood waters met in a mocking kiss. He had forgotten the feeling of hunger but knew he did not have any energy. What a foolish thing to think! He had not had any food for days. True. But hunger never said hello from the hollow of his 'person-tree' as they say in his language. Akpatse saw no help coming.   Flood waters met in a mocking kiss illustrates", "images": [], "options": {"A": "contrast", "B": "euphemism", "C": "personification", "D": "Litotes"}, "answer": "C", "explanation": "Personification is a literary device that uses the non-literal use of language to convey concepts in a relatable way. Writers use personification to give human characteristics, such as emotions and behaviors, to non-human things, animals, and ideas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>24", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Unseen Prose and Poetry      Read the passage below and answer the following questions     Marooned, Akpatse felt imprisoned. It was fifteen days since the storm. The flood waters were not receding; neither did Akpatse see any sign of help coming. Akpatse could not swim the expanse of flood waters. He meditated: when one looks upon the mountain for help and help comes from the Lord ... where does the Lord sit - in the cloud or on the mountain, or in the valley?    Well, Akpatse looked for salvation in the distance, far across the ocean of flood - the intimidating expense of his great gaoler - up to where the sky and the lips of the flood waters met in a mocking kiss. He had forgotten the feeling of hunger but knew he did not have any energy. What a foolish thing to think! He had not had any food for days. True. But hunger never said hello from the hollow of his 'person-tree' as they say in his language. Akpatse saw no help coming.  The overall feeling evoked by the passage is one of", "images": [], "options": {"A": "anger", "B": "empathy", "C": "love", "D": "relief"}, "answer": "B", "explanation": "The overall feeling evoked by the passage is one of empathy. The passage describes the plight of Akpatse who is marooned and feels imprisoned with no sign of help coming. He is hungry and has no energy. The reader is likely to feel empathy for Akpatse's situation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>25", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Unseen Prose and Poetry      Read the passage below and answer the following questions     Marooned, Akpatse felt imprisoned. It was fifteen days since the storm. The flood waters were not receding; neither did Akpatse see any sign of help coming. Akpatse could not swim the expanse of flood waters. He meditated: when one looks upon the mountain for help and help comes from the Lord ... where does the Lord sit - in the cloud or on the mountain, or in the valley?    Well, Akpatse looked for salvation in the distance, far across the ocean of flood - the intimidating expense of his great gaoler - up to where the sky and the lips of the flood waters met in a mocking kiss. He had forgotten the feeling of hunger but knew he did not have any energy. What a foolish thing to think! He had not had any food for days. True. But hunger never said hello from the hollow of his 'person-tree' as they say in his language. Akpatse saw no help coming.  The last sentence conveys the mood of", "images": [], "options": {"A": "anxiety", "B": "despondency", "C": "excitement", "D": "nonchalance"}, "answer": "B", "explanation": "The mood conveyed in the last sentence of the passage is despondency. Despondency refers to a state of low spirits caused by loss of hope or courage. In the passage, Akpatse is described as seeing no sign of help coming after being marooned for fifteen days. This creates a mood of despondency as Akpatse is losing hope of being rescued.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>26", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the following questions     Your lies are the withering strokes still, they come from the inner recesses of your dungeoned heart.   And though venomous than the venom, they inspire our once dociled  minds to disorders   even as your angels of death pass us by with messages of hopeless hope.     Did you read our mind in your lies?   We know the seat of power in a castle of your evil heart; where your lies are imprisoned to be released again and again; they are never in rain!  but they have soothed us calmly , your lies; the war is not of you anymore, it is of the angels who pass us by with messages of peace.    The main theme of the poem is", "images": [], "options": {"A": "evil of lying", "B": "hopeless hope", "C": "message of peace", "D": "message of war"}, "answer": "A", "explanation": "The main theme of the poem is the 'evil of lying'. The poem repeatedly refers to 'lies' and the negative effects they have, such as inspiring 'disorders' and being 'venomous'. The poem also mentions the 'evil heart' where the lies are imprisoned. This suggests that the main theme of the poem is the harm and evil that lies can cause.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>27", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the following questions     Your lies are the withering strokes still, they come from the inner recesses of your dungeoned heart.   And though venomous than the venom, they inspire our once dociled  minds to disorders   even as your angels of death pass us by with messages of hopeless hope.     Did you read our mind in your lies?   We know the seat of power in a castle of your evil heart; where your lies are imprisoned to be released again and again; they are never in rain!  but they have soothed us calmly , your lies; the war is not of you anymore, it is of the angels who pass us by with messages of peace.  The tone of the speaker shows", "images": [], "options": {"A": "contentment", "B": "helplessness", "C": "patience", "D": "resilience"}, "answer": "B", "explanation": "From the poem, we can deduce that the persona is helpless.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>28", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the following questions     Your lies are the withering strokes still, they come from the inner recesses of your dungeoned heart.   And though venomous than the venom, they inspire our once dociled  minds to disorders   even as your angels of death pass us by with messages of hopeless hope.     Did you read our mind in your lies?   We know the seat of power in a castle of your evil heart; where your lies are imprisoned to be released again and again; they are never in rain!  but they have soothed us calmly , your lies; the war is not of you anymore, it is of the angels who pass us by with messages of peace.   Did your read our minds in your lies?  exemplifies", "images": [], "options": {"A": "personification", "B": "oxymoron", "C": "pathetic fallacy", "D": "rhetorical question"}, "answer": "D", "explanation": "In literature, a rhetorical question is self-evident and used for style as an impressive persuasive device. Broadly speaking, a rhetorical question is asked when the questioner himself knows the answer already, or an answer is not actually demanded. So, an answer is not expected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>29", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the following questions     Your lies are the withering strokes still, they come from the inner recesses of your dungeoned heart.   And though venomous than the venom, they inspire our once dociled  minds to disorders   even as your angels of death pass us by with messages of hopeless hope.     Did you read our mind in your lies?   We know the seat of power in a castle of your evil heart; where your lies are imprisoned to be released again and again; they are never in rain!  but they have soothed us calmly , your lies; the war is not of you anymore, it is of the angels who pass us by with messages of peace.   But they have soothed us calmly, your lies  illustrates", "images": [], "options": {"A": "paradox", "B": "irony", "C": "synecdoche", "D": "zeugma"}, "answer": "B", "explanation": "The definition of irony as a literary device is a situation in which there is a contrast between expectation and reality. For example, the difference between what something appears to mean versus its literal meaning. Irony is associated with both tragedy and humor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>30", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "UNSEEN PROSE AND UNSEEN POETRY", "question": "Read the poem below and answer the following questions     Your lies are the withering strokes still, they come from the inner recesses of your dungeoned heart.   And though venomous than the venom, they inspire our once dociled  minds to disorders   even as your angels of death pass us by with messages of hopeless hope.     Did you read our mind in your lies?   We know the seat of power in a castle of your evil heart; where your lies are imprisoned to be released again and again; they are never in rain!  but they have soothed us calmly , your lies; the war is not of you anymore, it is of the angels who pass us by with messages of peace.  The last lines both stanza present", "images": [], "options": {"A": "Negative but similar ideas", "B": "opposite ideas", "C": "Positive but opposite ideas", "D": "Similar ideas"}, "answer": "D", "explanation": "Both ideas are similar. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>31", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "William Shakespeare: A Midsummer Night's Dream     Read the extract below and answer the following questions     Go, Philostrate,   Sir up the Athenian youth to merriments;  Awake the pert and nimble spirit of mirth;  Turn melancholy forth to funerals:   The pale companion is not our pomp    Hippolyta, I wooed thee with my sword,  And won thy love doing thee injuries;  But I will wed thee in another key,  With pomp with triumph, and with reveling ( Act 1, Scene One, Lines 12-20)    Who is the speaker?", "images": [], "options": {"A": "Demetrius", "B": "Egeus", "C": "Hermia", "D": "Theseus"}, "answer": "D", "explanation": "The speaker in the given extract is Theseus. This is evident from the lines where he is speaking to Hippolyta, whom he is about to marry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>32", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "William Shakespeare: A Midsummer Night's Dream     Read the extract below and answer the following questions     Go, Philostrate,   Sir up the Athenian youth to merriments;  Awake the pert and nimble spirit of mirth;  Turn melancholy forth to funerals:   The pale companion is not our pomp    Hippolyta, I wooed thee with my sword,  And won thy love doing thee injuries;  But I will wed thee in another key,  With pomp with triumph, and with reveling ( Act 1, Scene One, Lines 12-20)  Philostrate is", "images": [], "options": {"A": "Clown of Hippolyta", "B": "Duke's entertainer", "C": "Fairy king's cuckold", "D": "Rival of Puck"}, "answer": "B", "explanation": "Philostrate is Duke Theseus's party planner. His official title is \"Master of the Revels,\" which happened to be a court-appointed position in Shakespeare's day. Basically, the Master of the Revels organized courtly entertainments and also determined which plays could be performed at court and on public stages.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>33", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "William Shakespeare: A Midsummer Night's Dream     Read the extract below and answer the following questions     Go, Philostrate,   Sir up the Athenian youth to merriments;  Awake the pert and nimble spirit of mirth;  Turn melancholy forth to funerals:   The pale companion is not our pomp    Hippolyta, I wooed thee with my sword,  And won thy love doing thee injuries;  But I will wed thee in another key,  With pomp with triumph, and with reveling ( Act 1, Scene One, Lines 12-20)  The speaker's attitude towards  melancholy is", "images": [], "options": {"A": "adoration", "B": "dislike", "C": "intolerance", "D": "tolerance"}, "answer": "C", "explanation": "In the given extract from 'A Midsummer Night's Dream', the speaker expresses a desire to 'Turn melancholy forth to funerals'. This suggests that the speaker does not want melancholy to be a part of the celebrations, indicating an attitude of intolerance towards it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>34", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "William Shakespeare: A Midsummer Night's Dream     Read the extract below and answer the following questions     Go, Philostrate,   Sir up the Athenian youth to merriments;  Awake the pert and nimble spirit of mirth;  Turn melancholy forth to funerals:   The pale companion is not our pomp    Hippolyta, I wooed thee with my sword,  And won thy love doing thee injuries;  But I will wed thee in another key,  With pomp with triumph, and with reveling ( Act 1, Scene One, Lines 12-20)  While the speaker is talking", "images": [], "options": {"A": "Egeus departs", "B": "Flute arrives", "C": "the fairies sing", "D": "Philostrate departs"}, "answer": "D", "explanation": "Philostrate departs while the speaker is speaking.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>35", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "William Shakespeare: A Midsummer Night's Dream     Read the extract below and answer the following questions     Go, Philostrate,   Sir up the Athenian youth to merriments;  Awake the pert and nimble spirit of mirth;  Turn melancholy forth to funerals:   The pale companion is not our pomp    Hippolyta, I wooed thee with my sword,  And won thy love doing thee injuries;  But I will wed thee in another key,  With pomp with triumph, and with reveling ( Act 1, Scene One, Lines 12-20)  To win Hippolyta's love, the speaker", "images": [], "options": {"A": "disowned his friends", "B": "had to fight against her", "C": "killed his father", "D": "sent Puck away"}, "answer": "B", "explanation": "In the given extract from 'A Midsummer Night's Dream', the speaker is Theseus, the Duke of Athens. He is speaking to Hippolyta, the Queen of the Amazons, whom he is about to marry. He mentions that he 'wooed thee with my sword, And won thy love doing thee injuries'. This implies that he had to fight against her to win her love. Therefore, the correct answer is 'had to fight against her'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>36", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions     Speaker X: Thou runaway, thou coward,                       art thou fled?                      Speak! In some bush? Where dost thou hide thy head?    Speaker Y: Thou coward, art thou bragging to the stars,                      Telling the bushes that thou look'st for wars,                      And wilt not come? Come, recreant, come, thou child;                      I'll whip thee with a rod. He is defiled                      That draws a sword on thee.                               (Act III, Scene Two, Lines 405 - 411)    Speakers X and Y are", "images": [], "options": {"A": "Demetrious and Puck", "B": "Lysander and Demetrius", "C": "Hermia and Helen", "D": "Lysander and Puck"}, "answer": "A", "explanation": "Speakers X and Y are Demetrious and Puck. This is the accurate answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>37", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions     Speaker X: Thou runaway, thou coward,                       art thou fled?                      Speak! In some bush? Where dost thou hide thy head?    Speaker Y: Thou coward, art thou bragging to the stars,                      Telling the bushes that thou look'st for wars,                      And wilt not come? Come, recreant, come, thou child;                      I'll whip thee with a rod. He is defiled                      That draws a sword on thee.                               (Act III, Scene Two, Lines 405 - 411)  Speaker Y speaks in the voice of", "images": [], "options": {"A": "Bottom", "B": "Demetrius", "C": "Oberon", "D": "Lysander"}, "answer": "D", "explanation": "Puck(Robin Goodfellow) was speaking as Lysander in this scene.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>38", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions     Speaker X: Thou runaway, thou coward,                       art thou fled?                      Speak! In some bush? Where dost thou hide thy head?    Speaker Y: Thou coward, art thou bragging to the stars,                      Telling the bushes that thou look'st for wars,                      And wilt not come? Come, recreant, come, thou child;                      I'll whip thee with a rod. He is defiled                      That draws a sword on thee.                               (Act III, Scene Two, Lines 405 - 411)  Speaker Y's intention is to stop", "images": [], "options": {"A": "plan", "B": "fight", "C": "plot", "D": "flight"}, "answer": "B", "explanation": "The lines 'I'll whip thee with a rod. He is defiled That draws a sword on thee.' indicate that Speaker Y is trying to prevent a fight from happening. Therefore, Speaker Y's intention is to stop the fight.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>39", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions     Speaker X: Thou runaway, thou coward,                       art thou fled?                      Speak! In some bush? Where dost thou hide thy head?    Speaker Y: Thou coward, art thou bragging to the stars,                      Telling the bushes that thou look'st for wars,                      And wilt not come? Come, recreant, come, thou child;                      I'll whip thee with a rod. He is defiled                      That draws a sword on thee.                               (Act III, Scene Two, Lines 405 - 411)  The wars are over.", "images": [], "options": {"A": "Helena", "B": "Titania", "C": "Hermia", "D": "Hippolyta"}, "answer": "A", "explanation": "Helena is the cause of the rift between Lysander and Demetrius.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>40", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions     Speaker X: Thou runaway, thou coward,                       art thou fled?                      Speak! In some bush? Where dost thou hide thy head?    Speaker Y: Thou coward, art thou bragging to the stars,                      Telling the bushes that thou look'st for wars,                      And wilt not come? Come, recreant, come, thou child;                      I'll whip thee with a rod. He is defiled                      That draws a sword on thee.                               (Act III, Scene Two, Lines 405 - 411)  Speaker Y's speech can be described as", "images": [], "options": {"A": "cowardly", "B": "solemn", "C": "taunting", "D": "silly"}, "answer": "C", "explanation": "In the extract, Speaker Y (Helena) is responding to Speaker X's (Hermia's) accusations and threats with mockery and derision. She is not showing fear or solemnity, and her speech is not silly or nonsensical. Instead, she is taunting Speaker X, making light of her threats and challenging her to follow through. Therefore, the correct answer is 'taunting'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>41", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions   ... seest thou this sweet sight?  Her dotage now I do begin to pity;  For meeting her of late behind the wood,  Seeking sweet favours for this hateful fool,  I did upbraid her, and fall out with her.  For she his hairy temples then had rounded   With coronet of fresh and fragrant flowers;  (Act IV, Scene One, Lines 42 - 28)    The speaker is", "images": [], "options": {"A": "Egeus", "B": "Oberon", "C": "Puke", "D": "Theseus"}, "answer": "B", "explanation": "The speaker in the extract is Oberon, the king of the fairies in the play 'A Midsummer Night's Dream'. He is speaking to Puck about Titania, his queen, who has fallen in love with a 'hateful fool' due to a spell Oberon had Puck cast on her.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>42", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions   ... seest thou this sweet sight?  Her dotage now I do begin to pity;  For meeting her of late behind the wood,  Seeking sweet favours for this hateful fool,  I did upbraid her, and fall out with her.  For she his hairy temples then had rounded   With coronet of fresh and fragrant flowers;  (Act IV, Scene One, Lines 42 - 28)  The relationship between the speaker and thou in the first line is one of", "images": [], "options": {"A": "companionship", "B": "friendship", "C": "king and courtier", "D": "master and errand boy"}, "answer": "C", "explanation": "Puck, also called Robin Goodfellow, the vivacious fairy, henchman for Oberon, and narrator in Shakespeare's A Midsummer Night's Dream.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>43", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions   ... seest thou this sweet sight?  Her dotage now I do begin to pity;  For meeting her of late behind the wood,  Seeking sweet favours for this hateful fool,  I did upbraid her, and fall out with her.  For she his hairy temples then had rounded   With coronet of fresh and fragrant flowers;  (Act IV, Scene One, Lines 42 - 28)   This sweet sight refers to", "images": [], "options": {"A": "Bottom and Titania", "B": "Demetrius and Helena", "C": "Lysander and Hermia", "D": "Pyramus and Thisbe"}, "answer": "A", "explanation": "The extract is from Shakespeare's 'A Midsummer Night's Dream'. The 'sweet sight' referred to in the extract is the sight of Bottom and Titania. Bottom has been transformed to have the head of a donkey, and Titania, the queen of the fairies, has been enchanted to fall in love with him. The speaker is expressing pity for Titania's infatuation with Bottom, whom he refers to as a 'hateful fool'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>44", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions   ... seest thou this sweet sight?  Her dotage now I do begin to pity;  For meeting her of late behind the wood,  Seeking sweet favours for this hateful fool,  I did upbraid her, and fall out with her.  For she his hairy temples then had rounded   With coronet of fresh and fragrant flowers;  (Act IV, Scene One, Lines 42 - 28)  The pair are lovers by", "images": [], "options": {"A": "accident", "B": "fate", "C": "design", "D": "fortune"}, "answer": "C", "explanation": "Titania, Queen of the Fairies, is under the influence of a love potion, given to her by her husband Oberon to punish her for her pride. The potion has made her fall in love with the weaver Nick Bottom, who in turn is under a spell which has transformed his head into that of an ass.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>45", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions   ... seest thou this sweet sight?  Her dotage now I do begin to pity;  For meeting her of late behind the wood,  Seeking sweet favours for this hateful fool,  I did upbraid her, and fall out with her.  For she his hairy temples then had rounded   With coronet of fresh and fragrant flowers;  (Act IV, Scene One, Lines 42 - 28)  The speaker appears to be", "images": [], "options": {"A": "blaming himself", "B": "commending the addressee", "C": "enjoying himself", "D": "lamenting the sight"}, "answer": "C", "explanation": "The speaker is enjoying himself. This is the accurate answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>46", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions     ... Man is but an ass if he go about to   expound this dream. Methought I was - there   is no man can tell  what. Methought I was, and methought I had -   but man is   But a patched fool, if he will offer  To say what methought I   had. The eye of man hath not heard, the ear of   man hath not  seen, man's hand is not able to taste, his   tongue to conceive, nor  his heart to report, what my dream was                (Act IV, Scene One, Lines 201 - 207)    The speaker is", "images": [], "options": {"A": "Bottom", "B": "Puck", "C": "Quince", "D": "Peaseblossom"}, "answer": "A", "explanation": "Bottom makes this speech after he wakes up from his adventure with Titania; his human head restored, he believes that his experience as an ass-headed monster beloved by the beautiful fairy queen was merely a bizarre dream", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>47", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions     ... Man is but an ass if he go about to   expound this dream. Methought I was - there   is no man can tell  what. Methought I was, and methought I had -   but man is   But a patched fool, if he will offer  To say what methought I   had. The eye of man hath not heard, the ear of   man hath not  seen, man's hand is not able to taste, his   tongue to conceive, nor  his heart to report, what my dream was                (Act IV, Scene One, Lines 201 - 207)  The speaker has just come out of", "images": [], "options": {"A": "an appalling experience", "B": "a nightmare", "C": "an induced sleep", "D": "a rehearsal"}, "answer": "A", "explanation": "Bottom makes this speech after he wakes up from his adventure with Titania; his human head restored, he believes that his experience as an ass-headed monster beloved by the beautiful fairy queen was merely a bizarre dream", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>48", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions     ... Man is but an ass if he go about to   expound this dream. Methought I was - there   is no man can tell  what. Methought I was, and methought I had -   but man is   But a patched fool, if he will offer  To say what methought I   had. The eye of man hath not heard, the ear of   man hath not  seen, man's hand is not able to taste, his   tongue to conceive, nor  his heart to report, what my dream was                (Act IV, Scene One, Lines 201 - 207)  The architect of the speaker's current state is", "images": [], "options": {"A": "Hippolyta", "B": "Oberon", "C": "Titania", "D": "Theseus"}, "answer": "B", "explanation": "Titania, Queen of the Fairies, is under the influence of a love potion, given to her by her husband Oberon to punish her for her pride. The potion has made her fall in love with the weaver Nick Bottom, who in turn is under a spell which has transformed his head into that of an ass.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>49", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions     ... Man is but an ass if he go about to   expound this dream. Methought I was - there   is no man can tell  what. Methought I was, and methought I had -   but man is   But a patched fool, if he will offer  To say what methought I   had. The eye of man hath not heard, the ear of   man hath not  seen, man's hand is not able to taste, his   tongue to conceive, nor  his heart to report, what my dream was                (Act IV, Scene One, Lines 201 - 207)  It is a state of", "images": [], "options": {"A": "deception", "B": "ignorance", "C": "illusion", "D": "innocence"}, "answer": "C", "explanation": "His overabundant self-confidence burbles out in his grandiose idea that although no one could possibly understand his dream, it is worthy of being immortalized in a poem. This shows his illusion of the experience being a dream.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2022>50", "subject": "Literature", "year": "2022", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the following questions     ... Man is but an ass if he go about to   expound this dream. Methought I was - there   is no man can tell  what. Methought I was, and methought I had -   but man is   But a patched fool, if he will offer  To say what methought I   had. The eye of man hath not heard, the ear of   man hath not  seen, man's hand is not able to taste, his   tongue to conceive, nor  his heart to report, what my dream was                (Act IV, Scene One, Lines 201 - 207)  The speaker's language is best described as", "images": [], "options": {"A": "comic", "B": "satiric", "C": "conceit", "D": "metaphoric"}, "answer": "A", "explanation": "Bottom's tendency to make melodramatic rhetorical mistakes manifests itself plentifully, particularly in his comically mixed-up association of body parts and senses: he suggests that eyes can hear, ears see, hands taste, tongues think, and hearts speak.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>1", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS", "question": "Letters, journals and diaries arc examples of", "images": [], "options": {"A": "fiction", "B": "meta-fiction", "C": "faction", "D": "non-fiction"}, "answer": "D", "explanation": "Letters, journals, and diaries are examples of non-fiction. Non-fiction refers to literature based on facts, real events, and real people, such as biography or history.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>2", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "That girl is too young to be put in the family  way illustrates", "images": [], "options": {"A": "euphemism", "B": "hyperbole", "C": "oxymoron", "D": "paradox"}, "answer": "A", "explanation": "The phrase 'That girl is too young to be put in the family way' is an example of euphemism. Euphemism is a polite or mild word or expression used to refer to something embarrassing, taboo, or unpleasant.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2023>3", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS", "question": "A character that is built around a single idea or  quality is a _______ character.", "images": [], "options": {"A": "choral", "B": "flat", "C": "heroic", "D": "sound"}, "answer": "B", "explanation": "A character that is built around a single idea or quality is a flat character. Flat characters are two-dimensional in that they are relatively uncomplicated and do not change throughout the course of a work.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2023>4", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS", "question": "Seven metrical feet in a line of a stanza is", "images": [], "options": {"A": "heptametre", "B": "triolet", "C": "hexametre", "D": "septet"}, "answer": "A", "explanation": "Seven metrical feet in a line of a stanza is heptametre. Heptametre is a line of verse consisting of seven metrical feet.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2023>5", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS", "question": "A dead metaphor is", "images": [], "options": {"A": "implied and underused", "B": "overused and ineffective", "C": "implied and not funny", "D": "overused and funny"}, "answer": "B", "explanation": "A dead metaphor is overused and ineffective. A dead metaphor is a figure of speech which has lost the original imagery of its meaning due to extensive, repetitive, and popular usage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>6", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract below and answer the following Questions.    (In the Town Hall)  Jonsey: (By himself, centre right, looking skulky) How does anyone keep faith with himself In such an ill made place?               Bassy, Ba-a-ssy!  Bassy: Here. Anything the matter?  Jonsey: (Moves front stage centre right)  Your  mayoral hopeful.    Jonsey's opening speech illustrates", "images": [], "options": {"A": "aside", "B": "epilogue", "C": "mime", "D": "soliloquy"}, "answer": "D", "explanation": "Jonsey's opening speech illustrates a soliloquy. A soliloquy is a dramatic device where a character speaks to themselves, expressing their thoughts or feelings aloud. In this case, Jonsey is speaking to himself, expressing his thoughts about the place and his mayoral hopes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>7", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract below and answer the following Questions.    (In the Town Hall)  Jonsey: (By himself, centre right, looking skulky) How does anyone keep faith with himself In such an ill made place?               Bassy, Ba-a-ssy!  Bassy: Here. Anything the matter?  Jonsey: (Moves front stage centre right)  Your  mayoral hopeful.   In the Town hall is the", "images": [], "options": {"A": "atmosphere", "B": "location", "C": "setting", "D": "stage"}, "answer": "C", "explanation": "'In the Town Hall' is the setting of the scene. The setting in literature refers to the time and place in which the events of a narrative occur. In this case, the events are taking place in the Town Hall.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>8", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract below and answer the following Questions.    (In the Town Hall)  Jonsey: (By himself, centre right, looking skulky) How does anyone keep faith with himself In such an ill made place?               Bassy, Ba-a-ssy!  Bassy: Here. Anything the matter?  Jonsey: (Moves front stage centre right)  Your  mayoral hopeful.  Bassy is a ____ in the play.", "images": [], "options": {"A": "character", "B": "director", "C": "narrator", "D": "producer"}, "answer": "A", "explanation": "Bassy is a character in the play. A character in literature is a person, animal, being, creature, or thing in a story. In this case, Bassy is a person in the story who interacts with Jonsey.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>9", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract below and answer the following Questions.    (In the Town Hall)  Jonsey: (By himself, centre right, looking skulky) How does anyone keep faith with himself In such an ill made place?               Bassy, Ba-a-ssy!  Bassy: Here. Anything the matter?  Jonsey: (Moves front stage centre right)  Your  mayoral hopeful.  Jonsey's speech  Your mayoral hopeful is addressed to", "images": [], "options": {"A": "the audience", "B": "Bassy", "C": "himself", "D": "no one"}, "answer": "B", "explanation": "Jonsey's speech 'Your mayoral hopeful' is addressed to Bassy. This is evident from the dialogue where Jonsey calls out to Bassy and then makes the statement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>10", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "Read the extract below and answer the following Questions.    (In the Town Hall)  Jonsey: (By himself, centre right, looking skulky) How does anyone keep faith with himself In such an ill made place?               Bassy, Ba-a-ssy!  Bassy: Here. Anything the matter?  Jonsey: (Moves front stage centre right)  Your  mayoral hopeful.  The speeches of Jonsey and Bassy illustrate", "images": [], "options": {"A": "dialogue", "B": "epilogue", "C": "monologue", "D": "prologue"}, "answer": "A", "explanation": "The speeches of Jonsey and Bassy illustrate a dialogue. A dialogue is a conversation between two or more characters in a narrative. In this case, Jonsey and Bassy are having a conversation, which makes it a dialogue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>11", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS", "question": "Resolution in a literary work is also referred to as", "images": [], "options": {"A": "events that increase action", "B": "the complication", "C": "events that increase tension", "D": "final outcome"}, "answer": "D", "explanation": "The resolution in a literary work refers to the final outcome of the story, where the conflicts are resolved and the story concludes. It is the part of the story's plot line in which the problem of the story is resolved or worked out. This occurs after the falling action and is typically where the story ends.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>12", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "The moon looked on the massacre in horror ! illustrates", "images": [], "options": {"A": "epilogue", "B": "pathetic fallacy", "C": "prologue", "D": "transferred epithet"}, "answer": "B", "explanation": "The phrase 'The moon looked on the massacre in horror' is an example of pathetic fallacy. Pathetic fallacy is a literary device that attributes human feelings and responses to inanimate things or animals, especially in art and literature. In this case, the moon is given the human ability to look on in horror.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>13", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "A dramatic performance with scenes played by body movements or gestures without words known as", "images": [], "options": {"A": "comedy", "B": "panygeric", "C": "melodrama", "D": "pantomime"}, "answer": "D", "explanation": "A dramatic performance with scenes played by body movements or gestures without words is known as pantomime. Pantomime is a theatrical performance in which the actors express meaning through gestures accompanied by music.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>14", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "NON-AFRICAN POETRY", "question": "A short poem lamenting the death of someone is", "images": [], "options": {"A": "an epic", "B": "a sonnet", "C": "an ode", "D": "a threnody"}, "answer": "D", "explanation": "A short poem lamenting the death of someone is known as a threnody. A threnody is a song, hymn or poem of mourning composed or performed as a memorial to a dead person.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>15", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "The third stanza of the Shakespearean sonnet is", "images": [], "options": {"A": "couplet", "B": "octave", "C": "quatrain", "D": "sextet"}, "answer": "C", "explanation": "The third stanza of the Shakespearean sonnet is a quatrain. A Shakespearean sonnet consists of three quatrains (four lines each) and a final rhymed couplet. The quatrain presents a separate idea or example, and the couplet provides a summary or a different take on the previous lines.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2023>16", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer Questions 16 and 17    The boat nodded in timing with the gentle   Bobbing of the float on the unhurrying   Tide as the angler awaited the bite and   Pull of a salmon    The extract presents the image of a", "images": [], "options": {"A": "bright day", "B": "dark night", "C": "calm weather", "D": "eough time"}, "answer": "C", "explanation": "The extract describes a peaceful scene of a boat gently bobbing on the tide as an angler waits for a bite. This suggests calm weather, not necessarily a bright day or a dark night. The term 'unhurrying tide' further emphasizes the calmness of the weather.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>17", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the extract below and answer Questions 16 and 17    The boat nodded in timing with the gentle   Bobbing of the float on the unhurrying   Tide as the angler awaited the bite and   Pull of a salmon  The dominant literary device used in the extract is", "images": [], "options": {"A": "apostrophe", "B": "parallelism", "C": "antithesis", "D": "personification"}, "answer": "D", "explanation": "The dominant literary device used in the extract is personification. Personification is a figure of speech in which a thing, an idea or an animal is given human attributes. In the extract, the boat is personified as 'nodding' in time with the tide, a human action.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>18", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS", "question": "A fable is also known as", "images": [], "options": {"A": "an apologue", "B": "a farce", "C": "an epigram", "D": "a parody"}, "answer": "A", "explanation": "A fable is also known as an apologue. Both terms refer to a short story, typically with animals as characters, conveying a moral.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2023>19", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "Exaggerating one's personal features for comic effect is", "images": [], "options": {"A": "contrast", "B": "lampoon", "C": "caricature", "D": "satire"}, "answer": "C", "explanation": "Exaggerating one's personal features for comic effect is known as caricature. A caricature is a rendered image showing the features of its subject in a simplified or exaggerated way.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>20", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "At the last head count, the population of the school was three thousand is an example of", "images": [], "options": {"A": "hyperbole", "B": "metonymy", "C": "pun", "D": "synecdoche"}, "answer": "D", "explanation": "Synecdoche is a figure of speech in which a part of something is used to represent the whole or the whole is used to represent a part.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>21", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "PART II  UNSEEN PROSE AND POETRY  Read the passage below and answer Questions 21 to 25.  Along marched the crowd, determined not to be distracted from its cause and the course it had charted. If anyone could intimidate the chief, it was Sasu, who led the crowd. The chief nurtured unruffled restraint. He knew Sasu, knew that Sasu would not waste the trust between them on renegades.  One way to divert a mob from its goal is to join in with it, lead it on, but, finally, veer it from the course of its cause. Onward, towards the chief's palace marched the crowd, singing war songs.  The sun frowned as the palace guards, rattling like leaves in a storm - fear branded on their faces, came out to survey the threatening crowd and prepare for a siege. Just then, Sasu turned about, heading away from the palace - with the crowd, and the war songs.    The prevailing atmosphere is", "images": [], "options": {"A": "drab", "B": "pleasant", "C": "serene", "D": "tense"}, "answer": "D", "explanation": "The prevailing atmosphere in the passage is tense. This is evident from the description of the crowd marching determinedly, the palace guards preparing for a siege, and the crowd singing war songs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>22", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS", "question": "PART II  UNSEEN PROSE AND POETRY  Read the passage below and answer Questions 21 to 25.  Along marched the crowd, determined not to be distracted from its cause and the course it had charted. If anyone could intimidate the chief, it was Sasu, who led the crowd. The chief nurtured unruffled restraint. He knew Sasu, knew that Sasu would not waste the trust between them on renegades.  One way to divert a mob from its goal is to join in with it, lead it on, but, finally, veer it from the course of its cause. Onward, towards the chief's palace marched the crowd, singing war songs.  The sun frowned as the palace guards, rattling like leaves in a storm - fear branded on their faces, came out to survey the threatening crowd and prepare for a siege. Just then, Sasu turned about, heading away from the palace - with the crowd, and the war songs.   join in with it, lead it on, but, finally,veer it from  illustrates", "images": [], "options": {"A": "allusion", "B": "parallelism", "C": "simile", "D": "personification"}, "answer": "B", "explanation": "The phrase 'join in with it, lead it on, but, finally, veer it from' illustrates parallelism. Parallelism is a rhetorical device that compounds words or phrases that have equivalent meanings so as to create a definite pattern. This pattern helps to highlight the similarities or contrasts between different ideas.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2023>23", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "PART II  UNSEEN PROSE AND POETRY  Read the passage below and answer Questions 21 to 25.  Along marched the crowd, determined not to be distracted from its cause and the course it had charted. If anyone could intimidate the chief, it was Sasu, who led the crowd. The chief nurtured unruffled restraint. He knew Sasu, knew that Sasu would not waste the trust between them on renegades.  One way to divert a mob from its goal is to join in with it, lead it on, but, finally, veer it from the course of its cause. Onward, towards the chief's palace marched the crowd, singing war songs.  The sun frowned as the palace guards, rattling like leaves in a storm - fear branded on their faces, came out to survey the threatening crowd and prepare for a siege. Just then, Sasu turned about, heading away from the palace - with the crowd, and the war songs.  The attitude of the writer towards Sasu is one of", "images": [], "options": {"A": "anger", "B": "disdain", "C": "approval", "D": "surprise"}, "answer": "C", "explanation": "The attitude of the writer towards Sasu is one of approval. This is evident from the writer's description of Sasu as someone who would not waste the trust between him and the chief on renegades, and his ability to lead and divert the crowd.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>24", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "PART II  UNSEEN PROSE AND POETRY  Read the passage below and answer Questions 21 to 25.  Along marched the crowd, determined not to be distracted from its cause and the course it had charted. If anyone could intimidate the chief, it was Sasu, who led the crowd. The chief nurtured unruffled restraint. He knew Sasu, knew that Sasu would not waste the trust between them on renegades.  One way to divert a mob from its goal is to join in with it, lead it on, but, finally, veer it from the course of its cause. Onward, towards the chief's palace marched the crowd, singing war songs.  The sun frowned as the palace guards, rattling like leaves in a storm - fear branded on their faces, came out to survey the threatening crowd and prepare for a siege. Just then, Sasu turned about, heading away from the palace - with the crowd, and the war songs.   rattling like leaves in a storm, fear branded on their faces illustrates", "images": [], "options": {"A": "assonance and simile", "B": "personification and metaphor", "C": "simile and metaphor", "D": "personification and simile"}, "answer": "D", "explanation": "'Rattling like leaves in a storm, fear branded on their faces' illustrates personification and simile. Personification is a figure of speech in which an idea or thing is given human attributes and/or feelings or is spoken of as if it were human. Simile is a figure of speech that makes a comparison, showing similarities between two different things.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2023>25", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "PART II  UNSEEN PROSE AND POETRY  Read the passage below and answer Questions 21 to 25.  Along marched the crowd, determined not to be distracted from its cause and the course it had charted. If anyone could intimidate the chief, it was Sasu, who led the crowd. The chief nurtured unruffled restraint. He knew Sasu, knew that Sasu would not waste the trust between them on renegades.  One way to divert a mob from its goal is to join in with it, lead it on, but, finally, veer it from the course of its cause. Onward, towards the chief's palace marched the crowd, singing war songs.  The sun frowned as the palace guards, rattling like leaves in a storm - fear branded on their faces, came out to survey the threatening crowd and prepare for a siege. Just then, Sasu turned about, heading away from the palace - with the crowd, and the war songs.  The last paragraph illustrates", "images": [], "options": {"A": "anti climax", "B": "foreshadow", "C": "rising action", "D": "suspense"}, "answer": "A", "explanation": "The last paragraph illustrates anti-climax. Anti-climax is a rhetorical device which can be defined as a disappointing situation or a sudden transition in discourse from an important idea to a ludicrous or trivial one. It is when at a specific point, expectations are raised, everything is built-up and then suddenly something boring or disappointing happens. In the passage, the crowd is marching towards the palace, singing war songs, creating a build-up, but then Sasu turns away from the palace, leading the crowd away, which is an anti-climax.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2023>26", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "NON-AFRICAN POETRY~~LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the poem below and answer Questions 26 to 30    Miniver Cheevy, child of scorn,  Grew lean while he assailed the season; He wept that he was ever born,  And he had reasons.  Miniver loved the days of old  When swords were bright and steeds prancing; The vision of a warrior bold  Would set him dancing.     child of scorn illustrates", "images": [], "options": {"A": "contrast", "B": "euphemism", "C": "metaphor", "D": "metonymy"}, "answer": "C", "explanation": "The phrase 'child of scorn' is a metaphor. A metaphor is a figure of speech that makes a comparison between two things that are basically dissimilar. In this case, 'child of scorn' is used to describe Miniver Cheevy's character, implying that he is a person who is often scorned or looked down upon.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>27", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "NON-AFRICAN POETRY~~LITERARY TERMS", "question": "Read the poem below and answer Questions 26 to 30    Miniver Cheevy, child of scorn,  Grew lean while he assailed the season; He wept that he was ever born,  And he had reasons.  Miniver loved the days of old  When swords were bright and steeds prancing; The vision of a warrior bold  Would set him dancing.  The metrical structure is predominantly", "images": [], "options": {"A": "dactylic", "B": "iambic", "C": "spondaic", "D": "trochaic"}, "answer": "B", "explanation": "The metrical structure of the poem is predominantly iambic. An iambic meter is one of the most common metrical forms in English poetry and is characterized by an unstressed syllable followed by a stressed syllable.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2023>28", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "NON-AFRICAN POETRY~~LITERARY TERMS AND FIGURES OF SPEECH", "question": "Read the poem below and answer Questions 26 to 30    Miniver Cheevy, child of scorn,  Grew lean while he assailed the season; He wept that he was ever born,  And he had reasons.  Miniver loved the days of old  When swords were bright and steeds prancing; The vision of a warrior bold  Would set him dancing.  Reading the poem, one notices that the poet is being", "images": [], "options": {"A": "euphemistic", "B": "Hyperbolic", "C": "ironic", "D": "sarcastic"}, "answer": "C", "explanation": "The poet is being ironic in the poem. Irony is a figure of speech in which the intended meaning is the opposite of what is stated, often implying a form of humor. The poet's description of Miniver Cheevy's love for the 'days of old' and his dissatisfaction with the present is ironic because it highlights the impracticality of his longing for a time he never experienced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>29", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "NON-AFRICAN POETRY", "question": "Read the poem below and answer Questions 26 to 30    Miniver Cheevy, child of scorn,  Grew lean while he assailed the season; He wept that he was ever born,  And he had reasons.  Miniver loved the days of old  When swords were bright and steeds prancing; The vision of a warrior bold  Would set him dancing.  In the last stanza, the persona is", "images": [], "options": {"A": "angry", "B": "fantasizing", "C": "malnourished", "D": "pretending"}, "answer": "B", "explanation": "In the last stanza, the persona is fantasizing. This is evident from the lines 'Miniver loved the days of old' and 'The vision of a warrior bold Would set him dancing.' These lines suggest that Miniver Cheevy is imagining or fantasizing about the past.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>30", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "NON-AFRICAN POETRY~~LITERARY TERMS", "question": "Read the poem below and answer Questions 26 to 30    Miniver Cheevy, child of scorn,  Grew lean while he assailed the season; He wept that he was ever born,  And he had reasons.  Miniver loved the days of old  When swords were bright and steeds prancing; The vision of a warrior bold  Would set him dancing.  The two stanzas are built on", "images": [], "options": {"A": "alternate rhyme", "B": "couplets", "C": "identical rhyme", "D": "run on lines"}, "answer": "A", "explanation": "The two stanzas are built on alternate rhyme. An alternate rhyme, also known as an ABAB rhyme scheme, is a rhyme pattern where the first and third lines rhyme, and the second and fourth lines rhyme.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2023>31", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "WILLIAM SHAKESPEARE: A Midsummer Night's Dream   Read the extract and answer Questions 31 to 35.    As wagish boys in a game themselves forswear;  So the boy Love is perjured everywhere;  For ere Demetrius looked on Hermia's eyne,  He hailed down oaths that he was only mine;  And when this hail some heat from Hermia felt,  So he dissolved and showers of oaths did melt    The speaker is", "images": [], "options": {"A": "Demetrius", "B": "Egeus", "C": "Helena", "D": "Hermia"}, "answer": "C", "explanation": "The speaker in the extract is Helena. This is evident from the context of the extract where the speaker talks about Demetrius' oaths of love to her before he fell in love with Hermia. In the play 'A Midsummer Night's Dream', Helena is the one who is in love with Demetrius and is hurt by his love for Hermia.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>32", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "WILLIAM SHAKESPEARE: A Midsummer Night's Dream   Read the extract and answer Questions 31 to 35.    As wagish boys in a game themselves forswear;  So the boy Love is perjured everywhere;  For ere Demetrius looked on Hermia's eyne,  He hailed down oaths that he was only mine;  And when this hail some heat from Hermia felt,  So he dissolved and showers of oaths did melt  The speech shows that the speaker is", "images": [], "options": {"A": "in a bad mood", "B": "excited", "C": "high spirits", "D": "disappointed"}, "answer": "D", "explanation": "The speech shows that the speaker is disappointed. The speaker talks about how Demetrius broke his oaths of love to her and fell in love with Hermia instead. This shows that the speaker is disappointed with Demetrius' actions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>33", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "WILLIAM SHAKESPEARE: A Midsummer Night's Dream   Read the extract and answer Questions 31 to 35.    As wagish boys in a game themselves forswear;  So the boy Love is perjured everywhere;  For ere Demetrius looked on Hermia's eyne,  He hailed down oaths that he was only mine;  And when this hail some heat from Hermia felt,  So he dissolved and showers of oaths did melt  The speaker's mood stems from", "images": [], "options": {"A": "being rejected by the lover", "B": "having to go into the forest", "C": "meeting with Hermia", "D": "wanting to punish Hermia"}, "answer": "A", "explanation": "The speaker's mood stems from being rejected by the lover. The speaker talks about how Demetrius broke his oaths of love to her and fell in love with Hermia instead. This shows that the speaker is hurt and disappointed by Demetrius' rejection.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>34", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "WILLIAM SHAKESPEARE: A Midsummer Night's Dream   Read the extract and answer Questions 31 to 35.    As wagish boys in a game themselves forswear;  So the boy Love is perjured everywhere;  For ere Demetrius looked on Hermia's eyne,  He hailed down oaths that he was only mine;  And when this hail some heat from Hermia felt,  So he dissolved and showers of oaths did melt  The speaker has just said farewell to", "images": [], "options": {"A": "Demetrius", "B": "Hermia", "C": "Lysander", "D": "Helena"}, "answer": "B", "explanation": "The speaker has  just said farewell to Hermia. This is the accurate answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>35", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "WILLIAM SHAKESPEARE: A Midsummer Night's Dream   Read the extract and answer Questions 31 to 35.    As wagish boys in a game themselves forswear;  So the boy Love is perjured everywhere;  For ere Demetrius looked on Hermia's eyne,  He hailed down oaths that he was only mine;  And when this hail some heat from Hermia felt,  So he dissolved and showers of oaths did melt  The speaker resolves to tell", "images": [], "options": {"A": "Demetrius of Hermia's flight", "B": "Egeus of Hermia's flight", "C": "Lysander of Hermia's infidelity", "D": "Theseus of Hermia's infidelity"}, "answer": "A", "explanation": "This was because he was being abandoned. This is the accurate answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>36", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer Questions 36 to 40.    Lysander riddles very prettily;  Now much beshrew my manners and my pride, If Hermia meant to say Lysander lied.  But, gentle friend, for love and courtesy Lie further off, in human modesty;  Such separation as may well be said  Becomes a virtuous bachelor and a maid;  So far be distant, and good night, sweet friend: Thy love ne'er alter, till thy sweet life end!    The speaker is", "images": [], "options": {"A": "Helena", "B": "Hermia", "C": "Hippolyta", "D": "Titania"}, "answer": "B", "explanation": "The speaker in the extract is Hermia. She is speaking to Lysander, asking him to sleep a little further away from her to maintain modesty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>37", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer Questions 36 to 40.    Lysander riddles very prettily;  Now much beshrew my manners and my pride, If Hermia meant to say Lysander lied.  But, gentle friend, for love and courtesy Lie further off, in human modesty;  Such separation as may well be said  Becomes a virtuous bachelor and a maid;  So far be distant, and good night, sweet friend: Thy love ne'er alter, till thy sweet life end!  The speech is made in", "images": [], "options": {"A": "the woods", "B": "the Queen's palace", "C": "Oberon's place", "D": "Theseus' palace"}, "answer": "A", "explanation": "The speech is made in the woods. Hermia and Lysander have run away from Athens and are in the woods when this conversation takes place.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>38", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer Questions 36 to 40.    Lysander riddles very prettily;  Now much beshrew my manners and my pride, If Hermia meant to say Lysander lied.  But, gentle friend, for love and courtesy Lie further off, in human modesty;  Such separation as may well be said  Becomes a virtuous bachelor and a maid;  So far be distant, and good night, sweet friend: Thy love ne'er alter, till thy sweet life end!  The speaker and the addressee are", "images": [], "options": {"A": "father and daughter", "B": "lovers", "C": "master and servant", "D": "friends"}, "answer": "B", "explanation": "The speaker and the addressee are lovers. Hermia and Lysander are in love and have run away to get married.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>39", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS", "question": "Read the extract below and answer Questions 36 to 40.    Lysander riddles very prettily;  Now much beshrew my manners and my pride, If Hermia meant to say Lysander lied.  But, gentle friend, for love and courtesy Lie further off, in human modesty;  Such separation as may well be said  Becomes a virtuous bachelor and a maid;  So far be distant, and good night, sweet friend: Thy love ne'er alter, till thy sweet life end!   Now much beshrew my manners and my pride, illustrates the use of", "images": [], "options": {"A": "assonance", "B": "alliteration", "C": "onomatopoeia", "D": "personification"}, "answer": "B", "explanation": "'Now much beshrew my manners and my pride' illustrates the use of alliteration. Alliteration is a literary device where words in quick succession begin with the same letter or sound. Here, the 'm' sound in 'much', 'my', 'manners', and 'my' is repeated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>40", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer Questions 36 to 40.    Lysander riddles very prettily;  Now much beshrew my manners and my pride, If Hermia meant to say Lysander lied.  But, gentle friend, for love and courtesy Lie further off, in human modesty;  Such separation as may well be said  Becomes a virtuous bachelor and a maid;  So far be distant, and good night, sweet friend: Thy love ne'er alter, till thy sweet life end!   Thy love ne'er alter, till thy sweet life end.' implies", "images": [], "options": {"A": "an enduring love", "B": "a family love", "C": "an undying love", "D": "a fickle love"}, "answer": "A", "explanation": "'Thy love ne'er alter, till thy sweet life end' implies an enduring love. Hermia is expressing her wish for Lysander's love for her to remain constant until the end of his life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>41", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer Questions 41 to 45.  That fallen am I in dark uneven way,   \tCome, thou gentle day;  For if but once thou show me thy grey light,  I'll find \t, and revenge this spite.    The speaker is", "images": [], "options": {"A": "Egeus", "B": "Titania", "C": "Lysander", "D": "Thisbe"}, "answer": "C", "explanation": "The speaker in the extract is Lysander, a character from 'A Midsummer Night's Dream' by William Shakespeare. Lysander is lost in the woods and is expressing his desire for the day to come so he can find his way.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>42", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer Questions 41 to 45.  That fallen am I in dark uneven way,   \tCome, thou gentle day;  For if but once thou show me thy grey light,  I'll find \t, and revenge this spite.  The speaker is addressing", "images": [], "options": {"A": "Helena", "B": "Demetrius", "C": "Hermia", "D": "himself"}, "answer": "D", "explanation": "In the extract, Lysander is speaking to himself. He is expressing his frustration and his desire for the day to come so he can find his way out of the woods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>43", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer Questions 41 to 45.  That fallen am I in dark uneven way,   \tCome, thou gentle day;  For if but once thou show me thy grey light,  I'll find \t, and revenge this spite.  The speaker is in", "images": [], "options": {"A": "an apartment", "B": "the woods", "C": "a street", "D": "the palace"}, "answer": "B", "explanation": "In the extract, Lysander is in the woods. He is lost and is expressing his desire for the day to come so he can find his way.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>44", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS", "question": "Read the extract below and answer Questions 41 to 45.  That fallen am I in dark uneven way,   \tCome, thou gentle day;  For if but once thou show me thy grey light,  I'll find \t, and revenge this spite.   Come, thou gentle day illustrates", "images": [], "options": {"A": "apostrophe", "B": "euphemism", "C": "irony", "D": "paradox"}, "answer": "A", "explanation": "The phrase 'Come, thou gentle day' is an example of apostrophe, a figure of speech in which the speaker addresses an absent person, an abstract idea, or a thing. Here, Lysander is addressing the day, which is not a person and is not present.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2023>45", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer Questions 41 to 45.  That fallen am I in dark uneven way,   \tCome, thou gentle day;  For if but once thou show me thy grey light,  I'll find \t, and revenge this spite.  After the speech, the speaker", "images": [], "options": {"A": "begins to dance", "B": "falls asleep", "C": "laughs uncontrollably", "D": "starts crying"}, "answer": "B", "explanation": "After the speech, Lysander falls asleep. This is a part of the plot in 'A Midsummer Night's Dream' where characters in the woods fall asleep and experience dreams.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>46", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract and answer Questions 46 to 50.  lie bath rid his prologue like a rough colt: he knows not the stop. A good moral, my lord: it is not enough to speak, but to speak true.    The speaker is", "images": [], "options": {"A": "Bottom", "B": "Hippolyta", "C": "Pyramus", "D": "Lysander"}, "answer": "B", "explanation": "The speaker in the extract is Hippolyta. She is the one who comments on the prologue delivered by another character, saying that it's not enough to speak, but to speak true. This is a reflection of her character as a wise and discerning individual.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>47", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract and answer Questions 46 to 50.  lie bath rid his prologue like a rough colt: he knows not the stop. A good moral, my lord: it is not enough to speak, but to speak true.  The character that speaks before the speaker", "images": [], "options": {"A": "Demetrius", "B": "Hippolyta", "C": "Pyramus", "D": "Theseus"}, "answer": "D", "explanation": "The character that speaks before Hippolyta is Theseus. In the play, Theseus and Hippolyta are often together and engage in conversation about the events happening around them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>48", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "LITERARY TERMS", "question": "Read the extract and answer Questions 46 to 50.  lie bath rid his prologue like a rough colt: he knows not the stop. A good moral, my lord: it is not enough to speak, but to speak true.   it is not enough to speak, but to speak true  illustrates", "images": [], "options": {"A": "epigram", "B": "parable", "C": "epitaph", "D": "wisecrack"}, "answer": "A", "explanation": "The phrase 'it is not enough to speak, but to speak true' illustrates an epigram. An epigram is a brief, interesting, memorable, and sometimes surprising or satirical statement.", "marks": "1", "difficulty": "3"}, {"id": "objective>Literature>2023>49", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract and answer Questions 46 to 50.  lie bath rid his prologue like a rough colt: he knows not the stop. A good moral, my lord: it is not enough to speak, but to speak true.  The character that speaks after the speaker is", "images": [], "options": {"A": "Demetrius", "B": "Hippolyta", "C": "Lysander", "D": "Titania"}, "answer": "C", "explanation": "The character that speaks after Hippolyta is Lysander.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2023>50", "subject": "Literature", "year": "2023", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract and answer Questions 46 to 50.  lie bath rid his prologue like a rough colt: he knows not the stop. A good moral, my lord: it is not enough to speak, but to speak true.  The character that delivers the prologue is", "images": [], "options": {"A": "Quince", "B": "Snout", "C": "Starveling", "D": "Snug"}, "answer": "A", "explanation": "The character that delivers the prologue is Quince. In the play, Quince is the one who directs the play within the play and often delivers prologues.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>1", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "A poem that is shaped in the image of the object it talks about is", "images": [], "options": {"A": "concrete", "B": "lyrical", "C": "metaphysical", "D": "romantic"}, "answer": "A", "explanation": "A poem that is shaped in the image of the object it talks about is known as a 'concrete' poem. Concrete poetry uses visual layout to enhance the meaning of the words.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>2", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "The choir is on wheels to a convention Illustrates", "images": [], "options": {"A": "allusion", "B": "hyperbolic", "C": "metonymy", "D": "personification"}, "answer": "D", "explanation": "The phrase 'The choir is on wheels to a convention' illustrates 'personification'. Personification is a literary device where human qualities are given to animals, objects, or ideas. Here, the choir is given the human ability to be 'on wheels'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>3", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "Which of the following helps best to create and sustain interest in a literary work?", "images": [], "options": {"A": "Plot", "B": "Rhyme", "C": "Rhythm", "D": "Suspense"}, "answer": "D", "explanation": "Suspense helps best to create and sustain interest in a literary work. Suspense keeps the reader engaged and eager to know what happens next.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>4", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "'The dominant device used in Macheth doth murder sleep; the innocent sleep is", "images": [], "options": {"A": "alliteration", "B": "conceit", "C": "metonymy", "D": "personification"}, "answer": "D", "explanation": "The dominant device used in 'Macbeth doth murder sleep; the innocent sleep' is 'personification'. Personification is used here as sleep is given the human attribute of being 'murdered'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>5", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "GENERAL KNOWLEDGE OF LITERATURE", "question": "A narrative that extols the deeds of a heroic figure is a", "images": [], "options": {"A": "ballad", "B": "folktale", "C": "panegyric", "D": "pastoral"}, "answer": "C", "explanation": "A narrative that extols the deeds of a heroic figure is a 'panegyric'. A panegyric is a public speech or text in praise of someone or something, often used to extol heroic deeds.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>6", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "She is a woman of great virtue  She is a woman of great vice  illustrate", "images": [], "options": {"A": "antithesis", "B": "alliteration", "C": "paradox", "D": "pathos"}, "answer": "A", "explanation": "The statement 'She is a woman of great virtue, She is a woman of great vice' is an example of antithesis. Antithesis is a rhetorical device in which two opposite ideas are put together in a sentence to achieve a contrasting effect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>7", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "The overwhelming confidence and pride that lead to the fall of the protagonist is", "images": [], "options": {"A": "catharsis", "B": "ego", "C": "hamartia", "D": "hubris"}, "answer": "D", "explanation": "The overwhelming confidence and pride that lead to the fall of the protagonist is known as hubris. Hubris is excessive pride or self-confidence, often leading to the downfall of the character in literature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>8", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "Those you have loved and respected mock you to your face  illustrates", "images": [], "options": {"A": "hyperbole", "B": "irony", "C": "oxymoron", "D": "paradox"}, "answer": "B", "explanation": "The statement 'Those you have loved and respected mock you to your face' illustrates irony. Irony is a literary device where the intended meaning is opposite to the literal meaning, often highlighting a discrepancy between expectation and reality.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>9", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "NON-AFRICAN DRAMA", "question": "The major divisions in a play are", "images": [], "options": {"A": "acts", "B": "chapters", "C": "scenes", "D": "stanzas"}, "answer": "A", "explanation": "The major divisions in a play are called acts. An act is a part of a play defined by elements such as rising action, climax, and resolution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>10", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "Read the lines below and answer the questions.  My heart aches, and a drowsy numbness pains   My sense, as though of hemlock I have drunk    The metrical pattern is", "images": [], "options": {"A": "anapestic", "B": "dactylic", "C": "iambic", "D": "trochaic"}, "answer": "C", "explanation": "The metrical pattern in the lines 'My heart aches, and a drowsy numbness pains / My sense, as though of hemlock I have drunk' is iambic. Iambic meter consists of lines of poetry with a pattern of an unstressed syllable followed by a stressed syllable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>11", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "NON-AFRICAN POETRY", "question": "Read the lines below and answer the questions.  My heart aches, and a drowsy numbness pains   My sense, as though of hemlock I have drunk  The mood of the poet is that of", "images": [], "options": {"A": "anger", "B": "apathy", "C": "drunkenness", "D": "sadness"}, "answer": "D", "explanation": "The lines 'My heart aches, and a drowsy numbness pains / My sense, as though of hemlock I have drunk' suggest a feeling of sadness and lethargy. The poet's mood is one of sadness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>12", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "NON-AFRICAN PROSE", "question": "A narrative composed in the form of a letter is", "images": [], "options": {"A": "an eponymous novel", "B": "an epistolary novel", "C": "a novella", "D": "a panegyric"}, "answer": "B", "explanation": "A narrative composed in the form of a letter is called an epistolary novel. The term 'epistolary' refers to the writing of letters.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>13", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "The device used in  she gave him lots of cash and lender attention is", "images": [], "options": {"A": "bathos", "B": "pathos", "C": "suspense", "D": "zeugma"}, "answer": "D", "explanation": "The device used in 'she gave him lots of cash and lender attention' is zeugma. Zeugma is a figure of speech in which a word applies to multiple parts of the sentence, often in different senses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>14", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "The Shakespearean sonnet differs from the Petrarchan sonnet by ending with a", "images": [], "options": {"A": "couplet", "B": "quatrain", "C": "sestet", "D": "tercet"}, "answer": "A", "explanation": "The Shakespearean sonnet, also known as the English sonnet, ends with a couplet. This is a pair of rhyming lines.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>15", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "Read the lines below and answer the question.   The closing of the day  Is the beginning of the day   The lines", "images": [], "options": {"A": "are alliterated", "B": "are repeated", "C": "end stop.", "D": "run on."}, "answer": "D", "explanation": "The lines 'The closing of the day / Is the beginning of the day' are run-on lines, also known as enjambment. This means the sentence or phrase continues beyond the end of the line without a pause.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>16", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "One of the important means available to a writer of a literary work is", "images": [], "options": {"A": "diction", "B": "fiction", "C": "stage", "D": "Stanza"}, "answer": "A", "explanation": "Diction refers to the choice of words and style of expression that an author uses in a literary work. It is one of the most important means available to a writer to convey tone, mood, and meaning.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>17", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "Read the line below and answer the questions.  The curl of my lips, the swing of my waist, the ride of my breast, the stride of my steps, the flash of my teeth and the palm of my hand    The line is an example of", "images": [], "options": {"A": "euphemism", "B": "parallelism", "C": "personification", "D": "synecdoche"}, "answer": "B", "explanation": "Parallelism is the use of components in a sentence that are grammatically the same or similar in their construction, sound, meaning, or meter. The line provided uses parallel structure in the repetition of phrases like 'the curl of my lips, the swing of my waist,' etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>18", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "Read the line below and answer the questions.  The curl of my lips, the swing of my waist, the ride of my breast, the stride of my steps, the flash of my teeth and the palm of my hand  The image created in the line appeals to the sense of", "images": [], "options": {"A": "sight", "B": "taste", "C": "smell", "D": "touch"}, "answer": "A", "explanation": "The imagery in the line appeals to the sense of sight. It describes visual elements such as 'the curl of my lips,' 'the swing of my waist,' and 'the flash of my teeth,' which are all things that can be seen.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>19", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "AFRICAN DRAMA", "question": "Characters in a play that the author uses as vehicle for commentary is", "images": [], "options": {"A": "chorus", "B": "dancers", "C": "drummers", "D": "singers"}, "answer": "A", "explanation": "In classical Greek drama, the chorus is a group of characters who comment on the action of a play without participating in it. They are used by the author as a vehicle for commentary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>20", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS", "question": "The ...... comes after the loose ends of the plot have been tied up.", "images": [], "options": {"A": "climax", "B": "denouement", "C": "epilogue", "D": "prologue"}, "answer": "B", "explanation": "Denouement is the final part of a play, movie, or narrative in which the strands of the plot are drawn together and matters are explained or resolved. It comes after the loose ends of the plot have been tied up.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2024>21", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer the Questions.  The message was unambiguous: her John was on his way back. For how long had he been gone? Jenny wondered. She wrung her hands in silent expectation. She stood, turned about, and sat, motionless.  She was listening to the silence of the room and looking into the gloom of the unlit room.  She seemed to pull herself together as she rose to her full height, switched on the light and turned on the TV, to no station in particular, selecting no programme at all. She sat in front of the TV, not watching. Her heart was pounding. Slowly, she hoisted herself from the arm chair and moved towards the kitchen. like one sleepwalking.  She must get some food ready for the sojourner. Her rapid heartbeat did not show in her slow motion actions. Her cooking done.  Jenny was carrying the dish on a tray to the dining table when the doorbell rang. Jenny dropped the tray.    The passage is about", "images": [], "options": {"A": "a meeting place", "B": "Jenny's expert cooking", "C": "the disappointments of love", "D": "the passion of love"}, "answer": "D", "explanation": "The passage describes Jenny's emotional state as she anticipates John's return. Her actions and feelings, such as her heart pounding and her slow, deliberate movements, indicate a deep emotional connection and passion for John. Therefore, the passage is about the passion of love.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>22", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer the Questions.  The message was unambiguous: her John was on his way back. For how long had he been gone? Jenny wondered. She wrung her hands in silent expectation. She stood, turned about, and sat, motionless.  She was listening to the silence of the room and looking into the gloom of the unlit room.  She seemed to pull herself together as she rose to her full height, switched on the light and turned on the TV, to no station in particular, selecting no programme at all. She sat in front of the TV, not watching. Her heart was pounding. Slowly, she hoisted herself from the arm chair and moved towards the kitchen. like one sleepwalking.  She must get some food ready for the sojourner. Her rapid heartbeat did not show in her slow motion actions. Her cooking done.  Jenny was carrying the dish on a tray to the dining table when the doorbell rang. Jenny dropped the tray.  The figure of speech used in  She was listening to the silence of the room is", "images": [], "options": {"A": "conceit", "B": "irony", "C": "Oxymoron", "D": "zeugma"}, "answer": "C", "explanation": "The phrase 'listening to the silence of the room' is an oxymoron because it combines contradictory terms (listening and silence) to create a paradoxical effect. An oxymoron is a figure of speech in which apparently contradictory terms appear in conjunction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>23", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer the Questions.  The message was unambiguous: her John was on his way back. For how long had he been gone? Jenny wondered. She wrung her hands in silent expectation. She stood, turned about, and sat, motionless.  She was listening to the silence of the room and looking into the gloom of the unlit room.  She seemed to pull herself together as she rose to her full height, switched on the light and turned on the TV, to no station in particular, selecting no programme at all. She sat in front of the TV, not watching. Her heart was pounding. Slowly, she hoisted herself from the arm chair and moved towards the kitchen. like one sleepwalking.  She must get some food ready for the sojourner. Her rapid heartbeat did not show in her slow motion actions. Her cooking done.  Jenny was carrying the dish on a tray to the dining table when the doorbell rang. Jenny dropped the tray.  The technique of narration is", "images": [], "options": {"A": "first person", "B": "second person", "C": "third person", "D": "stream of consciousness"}, "answer": "C", "explanation": "The passage is narrated from a third-person perspective, as it describes Jenny's actions and feelings from an outside viewpoint without using 'I' or 'you'. The third person narrative technique uses pronouns like 'he', 'she', and 'they'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>24", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "LITERARY TERMS AND FIGURES OF SPEECH", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer the Questions.  The message was unambiguous: her John was on his way back. For how long had he been gone? Jenny wondered. She wrung her hands in silent expectation. She stood, turned about, and sat, motionless.  She was listening to the silence of the room and looking into the gloom of the unlit room.  She seemed to pull herself together as she rose to her full height, switched on the light and turned on the TV, to no station in particular, selecting no programme at all. She sat in front of the TV, not watching. Her heart was pounding. Slowly, she hoisted herself from the arm chair and moved towards the kitchen. like one sleepwalking.  She must get some food ready for the sojourner. Her rapid heartbeat did not show in her slow motion actions. Her cooking done.  Jenny was carrying the dish on a tray to the dining table when the doorbell rang. Jenny dropped the tray.  In ... and moved towards the kitchen, like one sleepwalking , the simile portrays one who is", "images": [], "options": {"A": "absent minded", "B": "disappointed", "C": "passion driven", "D": "morose"}, "answer": "A", "explanation": "The simile 'like one sleepwalking' suggests that Jenny is moving in a dazed or absent-minded manner, not fully aware of her surroundings or actions. This indicates that she is preoccupied with her thoughts and emotions, making her appear absent-minded.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>25", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "UNSEEN PROSE AND POETRY  Read the passage and answer the Questions.  The message was unambiguous: her John was on his way back. For how long had he been gone? Jenny wondered. She wrung her hands in silent expectation. She stood, turned about, and sat, motionless.  She was listening to the silence of the room and looking into the gloom of the unlit room.  She seemed to pull herself together as she rose to her full height, switched on the light and turned on the TV, to no station in particular, selecting no programme at all. She sat in front of the TV, not watching. Her heart was pounding. Slowly, she hoisted herself from the arm chair and moved towards the kitchen. like one sleepwalking.  She must get some food ready for the sojourner. Her rapid heartbeat did not show in her slow motion actions. Her cooking done.  Jenny was carrying the dish on a tray to the dining table when the doorbell rang. Jenny dropped the tray.  The mood is one of", "images": [], "options": {"A": "anxiety", "B": "despondency", "C": "sorrow", "D": "regret"}, "answer": "A", "explanation": "The mood of the passage is one of anxiety. Jenny's actions, such as her heart pounding and her slow, deliberate movements, along with her dropping the tray when the doorbell rings, all indicate a state of nervous anticipation and anxiety about John's return.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>26", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN POETRY", "question": "Read the poem and answer the questions.  My heart was in fearful flight  Pursued by Cupid, arrow poised  Waiting for my flight's end  When I'd turn about  5  Or I'd fall supine  My fleeing heart to pierce  Enslave or enthrall and ravish hopeless  So I'm pining and pining away  For you high up there have perched  10 Out of reach of my now yearning  Which was why my heart'd been fleeing     From Cupid's poised arrow    The poem is about __________ love.", "images": [], "options": {"A": "unforgettable", "B": "unrequited", "C": "sacrificial", "D": "selfish"}, "answer": "B", "explanation": "The poem describes a situation where the speaker's heart is fleeing from Cupid's arrow, indicating that the love is not reciprocated. This is characteristic of unrequited love.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>27", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN POETRY", "question": "Read the poem and answer the questions.  My heart was in fearful flight  Pursued by Cupid, arrow poised  Waiting for my flight's end  When I'd turn about  5  Or I'd fall supine  My fleeing heart to pierce  Enslave or enthrall and ravish hopeless  So I'm pining and pining away  For you high up there have perched  10 Out of reach of my now yearning  Which was why my heart'd been fleeing     From Cupid's poised arrow  The lines that provide the evidence for the of the poem are", "images": [], "options": {"A": "2 and 3", "B": "7 and 8", "C": "9 and 10", "D": "11 and 12"}, "answer": "C", "explanation": "Lines 9 and 10 ('For you high up there have perched / Out of reach of my now yearning') indicate that the speaker's love is not returned, supporting the idea of unrequited love.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>28", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN POETRY", "question": "Read the poem and answer the questions.  My heart was in fearful flight  Pursued by Cupid, arrow poised  Waiting for my flight's end  When I'd turn about  5  Or I'd fall supine  My fleeing heart to pierce  Enslave or enthrall and ravish hopeless  So I'm pining and pining away  For you high up there have perched  10 Out of reach of my now yearning  Which was why my heart'd been fleeing     From Cupid's poised arrow  The poem is a", "images": [], "options": {"A": "haiku", "B": "kenning", "C": "limerick", "D": "lyric"}, "answer": "D", "explanation": "The poem is a lyric because it expresses personal emotions and thoughts, particularly about love, in a musical and rhythmic manner.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>29", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN POETRY", "question": "Read the poem and answer the questions.  My heart was in fearful flight  Pursued by Cupid, arrow poised  Waiting for my flight's end  When I'd turn about  5  Or I'd fall supine  My fleeing heart to pierce  Enslave or enthrall and ravish hopeless  So I'm pining and pining away  For you high up there have perched  10 Out of reach of my now yearning  Which was why my heart'd been fleeing     From Cupid's poised arrow  The dominant image is one of", "images": [], "options": {"A": "begging", "B": "flying", "C": "running", "D": "waiting"}, "answer": "B", "explanation": "The dominant image in the poem is one of 'flying,' as the speaker's heart is described as being in 'fearful flight' and fleeing from Cupid's arrow.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>30", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN POETRY", "question": "Read the poem and answer the questions.  My heart was in fearful flight  Pursued by Cupid, arrow poised  Waiting for my flight's end  When I'd turn about  5  Or I'd fall supine  My fleeing heart to pierce  Enslave or enthrall and ravish hopeless  So I'm pining and pining away  For you high up there have perched  10 Out of reach of my now yearning  Which was why my heart'd been fleeing     From Cupid's poised arrow  In the poem, Cupid is", "images": [], "options": {"A": "an allusion", "B": "a metonymy", "C": "the persona's mistress", "D": "the persona's rival"}, "answer": "A", "explanation": "Cupid is an allusion in the poem, referring to the Roman god of love, which is a common literary device used to symbolize love and desire.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>31", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Answer all the questions in this section.  WILLIAM, SHAKESPEARE; A Midsummer Night's Dream  Read the extract below and answer the questions.  Where I have come, great clerks have purposed To greet me with premeditated welcomes;  Where I have seen them shiver and look pale, Make periods in the midst of sentences, Throttle their practised accent in their fears, And in conclusion, dumbly have broken off,  Not paying me a welcome...    The speaker is", "images": [], "options": {"A": "Helena", "B": "Hermia", "C": "Philostrate", "D": "Theseus"}, "answer": "D", "explanation": "The speaker in the extract is Theseus. Theseus is the Duke of Athens in the play 'A Midsummer Night's Dream' by William Shakespeare. The lines describe how people have reacted to his presence, which aligns with the character of Theseus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>32", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Answer all the questions in this section.  WILLIAM, SHAKESPEARE; A Midsummer Night's Dream  Read the extract below and answer the questions.  Where I have come, great clerks have purposed To greet me with premeditated welcomes;  Where I have seen them shiver and look pale, Make periods in the midst of sentences, Throttle their practised accent in their fears, And in conclusion, dumbly have broken off,  Not paying me a welcome...  The speaker is addressing", "images": [], "options": {"A": "Hippolyta", "B": "Lysander", "C": "Philostrate", "D": "Quince"}, "answer": "A", "explanation": "The speaker is addressing Hippolyta. Hippolyta is the Queen of the Amazons and Theseus' betrothed in the play. The context of the lines suggests that the speaker is referring to someone of high status, which fits Hippolyta's character.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>33", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Answer all the questions in this section.  WILLIAM, SHAKESPEARE; A Midsummer Night's Dream  Read the extract below and answer the questions.  Where I have come, great clerks have purposed To greet me with premeditated welcomes;  Where I have seen them shiver and look pale, Make periods in the midst of sentences, Throttle their practised accent in their fears, And in conclusion, dumbly have broken off,  Not paying me a welcome...  The speech is in reaction to", "images": [], "options": {"A": "Hippolyta's rejection of the burden the poor bear", "B": "Philostrate's rejection of the play-within-the play", "C": "the address of the chorus", "D": "the arrival of the players"}, "answer": "C", "explanation": "It is more about the speaker's observation of people's reactions to him which is seen in the chorus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>34", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Answer all the questions in this section.  WILLIAM, SHAKESPEARE; A Midsummer Night's Dream  Read the extract below and answer the questions.  Where I have come, great clerks have purposed To greet me with premeditated welcomes;  Where I have seen them shiver and look pale, Make periods in the midst of sentences, Throttle their practised accent in their fears, And in conclusion, dumbly have broken off,  Not paying me a welcome...  The speaker's experience is that", "images": [], "options": {"A": "the poor are eloquent", "B": "even the eloquent can falter in their speech", "C": "the poor are inhibited", "D": "even the poor can be tongue-tied"}, "answer": "B", "explanation": "The speaker's experience is that even the eloquent can falter in their speech. The lines describe how even skilled speakers have struggled to welcome the speaker properly, indicating that eloquence does not guarantee flawless speech.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>35", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Answer all the questions in this section.  WILLIAM, SHAKESPEARE; A Midsummer Night's Dream  Read the extract below and answer the questions.  Where I have come, great clerks have purposed To greet me with premeditated welcomes;  Where I have seen them shiver and look pale, Make periods in the midst of sentences, Throttle their practised accent in their fears, And in conclusion, dumbly have broken off,  Not paying me a welcome...  At the end of the speech,", "images": [], "options": {"A": "Hippolyta storms out of the place", "B": "Philostrate announces the prologue", "C": "the ladies settle down", "D": "the curtain is drawn"}, "answer": "D", "explanation": "At the end of the speech, the curtain is drawn. This action signifies the end of the speech or performance, which is a common theatrical practice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>36", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer the questions.  So should the murdered look; and so should I,  Pierced through the heart with your stern cruelty:   Yet you, the murderer. look as bright, as clear   As yonder Venus in her glimmering sphere.     The speaker and the addressee are", "images": [], "options": {"A": "Demetrius and Lysander", "B": "Hermia and Lysander", "C": "Demetrius and Hermia", "D": "Lysander and Helena"}, "answer": "C", "explanation": "The speaker is accusing the addressee of being the murderer, which is evident from the line 'Yet you, the murderer, look as bright, as clear'. Therefore, the correct answer is 'Demetrius and Hermia'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>37", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer the questions.  So should the murdered look; and so should I,  Pierced through the heart with your stern cruelty:   Yet you, the murderer. look as bright, as clear   As yonder Venus in her glimmering sphere. Earlier, the addressee has accused the speaker of", "images": [], "options": {"A": "disloyalty", "B": "infidelity", "C": "murder", "D": "theft"}, "answer": "A", "explanation": "The addressee has accused the speaker of disloyalty, as indicated by the speaker being 'pierced through the heart with your stern cruelty'. Therefore, the correct answer is 'disloyalty'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>38", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer the questions.  So should the murdered look; and so should I,  Pierced through the heart with your stern cruelty:   Yet you, the murderer. look as bright, as clear   As yonder Venus in her glimmering sphere. In turn, the speaker accuses the addressee of", "images": [], "options": {"A": "cruelty", "B": "discrimination", "C": "deceit", "D": "indiscretion"}, "answer": "A", "explanation": "In turn, the speaker accuses the addressee of cruelty, which is evident from the line 'Pierced through the heart with your stern cruelty'. Therefore, the correct answer is 'cruelty'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>39", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer the questions.  So should the murdered look; and so should I,  Pierced through the heart with your stern cruelty:   Yet you, the murderer. look as bright, as clear   As yonder Venus in her glimmering sphere. The underlined lines portray the addressee as a", "images": [], "options": {"A": "coward", "B": "hunter", "C": "painter", "D": "traitor"}, "answer": "D", "explanation": "The underlined lines in the excerpt portray the addressee as a beautiful yet cruel figure. The speaker compares the addressee to Venus, the Roman goddess of love and beauty, suggesting that the addressee has an outward appearance of brightness and beauty (\"as bright, as clear as yonder Venus\"). However, this beauty contrasts sharply with the cruelty the addressee has inflicted, as the speaker feels \"pierced through the heart\" by their \"stern cruelty.\" This depicts a traitor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>40", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "UNSEEN PROSE AND POETRY", "question": "Read the extract below and answer the questions.  So should the murdered look; and so should I,  Pierced through the heart with your stern cruelty:   Yet you, the murderer. look as bright, as clear   As yonder Venus in her glimmering sphere. The setting of the extract is", "images": [], "options": {"A": "another part of the wood", "B": "Helena's place", "C": "the wood", "D": "Theseus's palace"}, "answer": "A", "explanation": "The setting of the extract is indicated by the line 'another part of the wood'. Therefore, the correct answer is 'another part of the wood'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>41", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the questions.   The wildest hath not such a heart as you.  Run when you will, the story shall be changed:  Apollo flies, and Daphne holds the chase;  The dove pursues the griffin, the mild hind Makes speed to catch the tiger; bootless speed, When cowardice pursues, and valour flies.    The speaker is", "images": [], "options": {"A": "Egeus", "B": "Helena", "C": "Lysander", "D": "Titania"}, "answer": "D", "explanation": "The speaker in the extract is Titania. In Shakespeare's play 'A Midsummer Night's Dream', Titania is a fairy queen who is known for her poetic and romantic language. The reference to Apollo, Daphne, dove, griffin, hind, and tiger alludes to the fantastical and mythological elements present in the play, which align with Titania's character.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>42", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the questions.   The wildest hath not such a heart as you.  Run when you will, the story shall be changed:  Apollo flies, and Daphne holds the chase;  The dove pursues the griffin, the mild hind Makes speed to catch the tiger; bootless speed, When cowardice pursues, and valour flies.  The addressee is", "images": [], "options": {"A": "Demetrius", "B": "Hermia", "C": "Oberon", "D": "Puck"}, "answer": "C", "explanation": "The addressee in the extract is Oberon. Oberon is the king of the fairies in 'A Midsummer Night's Dream' and is known for his involvement in the romantic entanglements and magical occurrences in the play. The language used in the extract, with references to Apollo, Daphne, dove, griffin, hind, and tiger, reflects the magical and whimsical nature of Oberon's character.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>43", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the questions.   The wildest hath not such a heart as you.  Run when you will, the story shall be changed:  Apollo flies, and Daphne holds the chase;  The dove pursues the griffin, the mild hind Makes speed to catch the tiger; bootless speed, When cowardice pursues, and valour flies.  The wildest refers to", "images": [], "options": {"A": "good people", "B": "the least cruel man", "C": "wild beasts", "D": "the most deceptive spirit"}, "answer": "C", "explanation": "The term 'wildest' in the extract refers to wild beasts. The comparison made in the lines between various creatures like the dove, griffin, hind, and tiger suggests a wild and untamed nature, which aligns with the characteristics of wild animals. This interpretation is supported by the context of the lines and the imagery used.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>44", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the questions.   The wildest hath not such a heart as you.  Run when you will, the story shall be changed:  Apollo flies, and Daphne holds the chase;  The dove pursues the griffin, the mild hind Makes speed to catch the tiger; bootless speed, When cowardice pursues, and valour flies.  The speech is intended to _____ addressee.", "images": [], "options": {"A": "confuse", "B": "pacify", "C": "provoke", "D": "reclaim"}, "answer": "C", "explanation": "The speech is intended to mock and chastise the addressee. The speaker reverses natural roles, using ironic comparisons (e.g., Apollo fleeing from Daphne, the dove pursuing the griffin, and the mild hind chasing the tiger) to highlight the absurdity of the situation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>45", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract below and answer the questions.   The wildest hath not such a heart as you.  Run when you will, the story shall be changed:  Apollo flies, and Daphne holds the chase;  The dove pursues the griffin, the mild hind Makes speed to catch the tiger; bootless speed, When cowardice pursues, and valour flies.  Another character present at the scene is", "images": [], "options": {"A": "Egeus", "B": "Lysander", "C": "Oberon", "D": "Theseus"}, "answer": "C", "explanation": "Another character present at the scene in the extract is Oberon. Oberon's presence is significant as he plays a central role in the magical events and romantic entanglements that unfold in 'A Midsummer Night's Dream'. The reference to Oberon being present is supported by the context of the play and the interactions between characters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>46", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract and answer the questions.  And in the wood, where often you and I   Upon faint primrose-beds were wont to lie,    Emptying our bosoms of their counsel sweet ,   There, my Lysander and myself shall meet,   And thence from Athens turn away our yes   To seek new friends and stranger companies.  Farewell, sweet playfellow;     .. you and I  in the first line refer to", "images": [], "options": {"A": "Demetrius and Helena", "B": "Hermia and Lysander", "C": "Hippolyta and Lysander", "D": "Oberon and Titania"}, "answer": "B", "explanation": "The phrase 'you and I' in the first line refers to Hermia and Lysander. This can be inferred from the context of the extract where the speaker mentions meeting 'my Lysander' in the subsequent lines.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>47", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract and answer the questions.  And in the wood, where often you and I   Upon faint primrose-beds were wont to lie,    Emptying our bosoms of their counsel sweet ,   There, my Lysander and myself shall meet,   And thence from Athens turn away our yes   To seek new friends and stranger companies.  Farewell, sweet playfellow;  The couple are going to the wood because", "images": [], "options": {"A": "it is their favourite spot", "B": "they are running away from the Athenian law", "C": "they want to have their peace", "D": "the wood is romantic"}, "answer": "B", "explanation": "The couple is going to the wood to run away from the Athenian law. This is evident from the line 'And thence from Athens turn away our yes' which indicates their intention to leave Athens to avoid the law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>48", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract and answer the questions.  And in the wood, where often you and I   Upon faint primrose-beds were wont to lie,    Emptying our bosoms of their counsel sweet ,   There, my Lysander and myself shall meet,   And thence from Athens turn away our yes   To seek new friends and stranger companies.  Farewell, sweet playfellow;  The underlined means being", "images": [], "options": {"A": "careful", "B": "faithful", "C": "flirtatious", "D": "reckless"}, "answer": "B", "explanation": "The underlined phrase 'Emptying our bosoms of their counsel sweet' implies being faithful. In this context, it suggests sharing intimate thoughts and feelings, rather than being flirtatious or reckless.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>49", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract and answer the questions.  And in the wood, where often you and I   Upon faint primrose-beds were wont to lie,    Emptying our bosoms of their counsel sweet ,   There, my Lysander and myself shall meet,   And thence from Athens turn away our yes   To seek new friends and stranger companies.  Farewell, sweet playfellow;  Farewell, sweet playfellow refers to", "images": [], "options": {"A": "Demetrius", "B": "Hermia", "C": "Helena", "D": "Lysander"}, "answer": "D", "explanation": "The phrase 'Farewell, sweet playfellow' refers to Lysander. This is because the speaker mentions 'my Lysander' earlier in the extract, indicating a close relationship between them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2024>50", "subject": "Literature", "year": "2024", "type": "Objective", "topic": "WILLIAM SHAKESPEARE: A MIDSUMMER NIGHT'S DREAM", "question": "Read the extract and answer the questions.  And in the wood, where often you and I   Upon faint primrose-beds were wont to lie,    Emptying our bosoms of their counsel sweet ,   There, my Lysander and myself shall meet,   And thence from Athens turn away our yes   To seek new friends and stranger companies.  Farewell, sweet playfellow;  Soon after, sweet playfellow decides to", "images": [], "options": {"A": "betray Hermia", "B": "go into exile", "C": "go to the nunnery", "D": "reconcile with Demetrius"}, "answer": "A", "explanation": "In the extract, the speaker (Hermia from A Midsummer Night's Dream by William Shakespeare) is bidding farewell to Helena, her \"sweet playfellow.\" Hermia has made a plan to elope with Lysander, meeting him in the woods, and leaving Athens to start a new life elsewhere, away from their familiar surroundings.    Soon after this, Helena, the \"sweet playfellow,\" decides to betray Hermia's plan. Helena reveals Hermia and Lysander's secret elopement to Demetrius in an attempt to gain his favor, as she is in love with him.    So, soon after the farewell, the \"sweet playfellow\" decides to inform Demetrius of Hermia's plan to run away with Lysander.", "marks": "1", "difficulty": "2"}, {"id": "objective>Literature>2025>1", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Literary Devices", "question": "The dominant theme of an opus is:", "images": [], "options": {"A": "cowardice", "B": "heroism", "C": "sorrow", "D": "victory"}, "answer": "B", "explanation": "The word opus typically refers to a major artistic or literary work. Such works often focus on grand, noble, or heroic subjects. Therefore, heroism is the dominant theme commonly associated with an opus.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>2", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Literary Devices", "question": "The repetition of vowel sounds in poetry is:", "images": [], "options": {"A": "alliteration", "B": "assonance", "C": "onomatopoeia", "D": "pun"}, "answer": "B", "explanation": "Assonance is the repetition of vowel sounds within nearby words, especially in poetry, to create internal rhyming. For example: \"Hear the mellow wedding bells.\" In contrast, alliteration is the repetition of consonant sounds.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>3", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Literary Devices", "question": "\"The cat attempted to kill the mouse by stepping on my mouse\" is an example of:", "images": [], "options": {"A": "chiasmus", "B": "oxymoron", "C": "enigma", "D": "pun"}, "answer": "D", "explanation": "A pun is a humorous or clever play on words that have multiple meanings or sound similar. Here, mouse refers both to a rodent and a computer device, making it a pun.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>4", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Literary Devices", "question": "In a literary work, the speaker's attitude toward the subject is inferred from the:", "images": [], "options": {"A": "plot", "B": "rhythm", "C": "setting", "D": "tone"}, "answer": "D", "explanation": "Tone reflects the author's or speaker's attitude toward the subject or audience. It can be serious, sarcastic, joyful, etc., and helps readers interpret the intended meaning of the text.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>5", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "The part of the theatre in front of the curtain is the:", "images": [], "options": {"A": "backstage", "B": "balcony", "C": "centre stage", "D": "proscenium"}, "answer": "D", "explanation": "The proscenium is the area of the stage located in front of the curtain. It frames the stage and separates it from the audience. This is where much of the visible action occurs in traditional theatres.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>6", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Literary Devices", "question": "\"When the king was murdered, the wind rose with great violence\" exemplifies:", "images": [], "options": {"A": "pathetic fallacy", "B": "hyperbole", "C": "synecdoche", "D": "transferred epithet"}, "answer": "A", "explanation": "Pathetic fallacy is a literary device where human emotions or traits are attributed to nature or inanimate objects. Here, the wind reacting violently to the king's murder reflects the mood of the scene.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>7", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions.  Ampomah's residence   Kwaku: Adwoa,  A-dwo-aas! Where are you that you are not answering, Adwoa? (Pants for breath)  Adwoa: Right here, just a minute and I'll be with you! (Muttering to herself) I wonder why the man doesn't drop dead.    Ampomah's residence is the", "images": [], "options": {"A": "Curtain raiser", "B": "Dramatic monologue", "C": "Interlude", "D": "Props"}, "answer": "A", "explanation": "In theatre and drama, a curtain raiser is a short introductory scene or act that precedes the main event. Ampomah's residence being the setting of the first scene serves this purpose.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>8", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions.  Ampomah's residence   Kwaku: Adwoa,  A-dwo-aas! Where are you that you are not answering, Adwoa? (Pants for breath)  Adwoa: Right here, just a minute and I'll be with you! (Muttering to herself) I wonder why the man doesn't drop dead.Kwaku and Acheon are in the extract", "images": [], "options": {"A": "Actors", "B": "Characters", "C": "Directors", "D": "Props"}, "answer": "B", "explanation": "The names Kwaku and Acheon refer to individuals within the story, making them characters, not actors or stage elements.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>9", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions.  Ampomah's residence   Kwaku: Adwoa,  A-dwo-aas! Where are you that you are not answering, Adwoa? (Pants for breath)  Adwoa: Right here, just a minute and I'll be with you! (Muttering to herself) I wonder why the man doesn't drop dead.\"I wonder why the man doesn't drop dead\" exemplifies a/an", "images": [], "options": {"A": "Dialogue", "B": "Ode", "C": "Soliloquy", "D": "Monologue"}, "answer": "C", "explanation": "This statement is an internal thought spoken aloud, making it a soliloquy, where the speaker reveals their feelings to the audience.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>10", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions.  Ampomah's residence   Kwaku: Adwoa,  A-dwo-aas! Where are you that you are not answering, Adwoa? (Pants for breath)  Adwoa: Right here, just a minute and I'll be with you! (Muttering to herself) I wonder why the man doesn't drop dead.Muttering to herself is a", "images": [], "options": {"A": "Curtain call", "B": "Dress rehearsal", "C": "Musical interlude", "D": "Stage direction"}, "answer": "D", "explanation": "Muttering to herself is a directive to the actor, hence it's a stage direction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>11", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Literary Devices", "question": "A character who serves as a contrast to another character in a literary work is known as the", "images": [], "options": {"A": "Antagonist", "B": "Clown", "C": "Foil", "D": "Protagonist"}, "answer": "C", "explanation": "A foil is used to contrast another character, often highlighting the protagonist's traits.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>12", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Literary Devices", "question": "The weather is not unpleasant illustrates", "images": [], "options": {"A": "Limerick", "B": "Litotes", "C": "Parados", "D": "Parody"}, "answer": "B", "explanation": "Litotes is a figure of speech using double negatives to express a positive. Here, 'not unpleasant' means pleasant. It can also be seen as an understatement.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>13", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Literary Terms", "question": "A collection of literary works which are widely accepted is considered as a", "images": [], "options": {"A": "Canon", "B": "Compilation", "C": "Database", "D": "Period"}, "answer": "A", "explanation": "A canon is a recognised collection of literary or cultural works.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>14", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Poetry", "question": "Read the passage and answer the questions:  She stepped into the hall, her shoulders square, her chin tilted just slightly upward. Her eyes scanned the room, calm and unbothered, just as cool as you please. A hush followed her like a shadow, but she only smiled — slow, deliberate, unshaken. She wasn't here to prove anything; her presence was proof enough.    The speaker (in the extract)", "images": [], "options": {"A": "Adores men", "B": "Disrespects men", "C": "Exhibits impunity", "D": "Exudes self-confidence"}, "answer": "D", "explanation": "The speaker's composed entrance shows calm confidence.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>15", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Poetry", "question": "Read the passage and answer the questions:  She stepped into the hall, her shoulders square, her chin tilted just slightly upward. Her eyes scanned the room, calm and unbothered, just as cool as you please. A hush followed her like a shadow, but she only smiled — slow, deliberate, unshaken. She wasn't here to prove anything; her presence was proof enough. \"Just as cool as you please\" illustrates", "images": [], "options": {"A": "Exaggeration", "B": "Metaphor", "C": "Personification", "D": "Smile"}, "answer": "A", "explanation": "The phrase exaggerates the speaker's calmness, hence it's exaggeration. There is no simile as no two objects are compared; even though there is the use of 'as'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>16", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Poetry", "question": "Read the passage and answer the questions:  She stepped into the hall, her shoulders square, her chin tilted just slightly upward. Her eyes scanned the room, calm and unbothered, just as cool as you please. A hush followed her like a shadow, but she only smiled — slow, deliberate, unshaken. She wasn't here to prove anything; her presence was proof enough. \"The fellows stand or fall down on their knees\" exemplifies", "images": [], "options": {"A": "Apostrophe", "B": "Contrast", "C": "Metonymy", "D": "Parallelism"}, "answer": "D", "explanation": "The structure shows balance in construction, which is parallelism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>17", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Literary Devices", "question": "Chapter is to prose as _______ is to poetry.", "images": [], "options": {"A": "act", "B": "line", "C": "scene", "D": "stanza"}, "answer": "D", "explanation": "A chapter is a structural unit in prose. In poetry, the equivalent is a stanza—a grouped set of lines.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>18", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Poetry", "question": "Read the extract below and answer questions:  Oh Peter, why?  Why have you left so soon?  You should have waited,  For, we love you.    The lines \"Oh Peter, why?...For, we love you\" exemplify", "images": [], "options": {"A": "apostrophe", "B": "ballad", "C": "epistle", "D": "panegyric"}, "answer": "A", "explanation": "Apostrophe is a direct address to an absent or dead person. The speaker addresses Peter as if he were present.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>19", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Poetry", "question": "Read the extract below and answer questions:  Oh Peter, why?  Why have you left so soon?  You should have waited,  For, we love you.    The extract evokes the feeling of", "images": [], "options": {"A": "excitement", "B": "hope", "C": "inspiration", "D": "sorrow"}, "answer": "D", "explanation": "The tone of mourning and loss in addressing Peter reflects sorrow.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>20", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Poetry", "question": "\"The Sea Eats the Land at Home\" illustrates", "images": [], "options": {"A": "chiasmus", "B": "epithet", "C": "fallacy", "D": "personification"}, "answer": "C", "explanation": "The sea is given the human action of eating, a classic case of personification. However, the correct answer is 'fallacy'. This is so because 'sea' is nature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>21", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Prose", "question": "Read the passage and answer the questions:  Our lives are miserable, laborious and short...  Man is the only real enemy that we have.  Remove man from the scene and the root cause of hunger and overwork is abolished forever.    The tone shows that the narrator is", "images": [], "options": {"A": "abusive", "B": "angry", "C": "moralistic", "D": "guilty"}, "answer": "B", "explanation": "The narrator expresses intense frustration and blame towards humans.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>22", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Literary Devices", "question": "Read the passage and answer the questions:  Our lives are miserable, laborious and short...  Man is the only real enemy that we have.  Remove man from the scene and the root cause of hunger and overwork is abolished forever.  \"To work to the last atom of our strength\" illustrates", "images": [], "options": {"A": "antithesis", "B": "hyperbole", "C": "irony", "D": "metonymy"}, "answer": "B", "explanation": "The phrase is an exaggerated expression of total exhaustion, hence hyperbole.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>23", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Prose", "question": "Read the passage and answer the questions:  Our lives are miserable, laborious and short...  Man is the only real enemy that we have.  Remove man from the scene and the root cause of hunger and overwork is abolished forever.  \"Why then do we continue in these miserable conditions?\" is", "images": [], "options": {"A": "an adage", "B": "an inference question", "C": "a rhetorical question", "D": "sarcasm"}, "answer": "C", "explanation": "This question is rhetorical—meant to provoke thought, not to get a literal answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>24", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Prose", "question": "Read the passage and answer the questions:  Our lives are miserable, laborious and short...  Man is the only real enemy that we have.  Remove man from the scene and the root cause of hunger and overwork is abolished forever.  The narrator's speaking voice is", "images": [], "options": {"A": "colloquial", "B": "comical", "C": "didactic", "D": "metaphoric"}, "answer": "C", "explanation": "The voice seeks to instruct and educate on injustice, which is didactic.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>25", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "POETRY", "question": "Read the passage and answer the questions:  Our lives are miserable, laborious and short...  Man is the only real enemy that we have.  Remove man from the scene and the root cause of hunger and overwork is abolished forever.  The subject matter of the poem is__", "images": [], "options": {"A": "Man as a friend", "B": "Man as an enemy", "C": "Man's inhumanity", "D": "The negative impacts of man"}, "answer": "D", "explanation": "The poem points out that man is the root cause of hunger and overwork.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>26", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Poetry", "question": "Read the poem and answer questions.  I know not, my Alberta,  When again on your brightness of smile  My eyes will rest awhile,  Nor when again of your sultriness of voice  My ears will drink by eager choice,  When again into the silver moonshine  You early tonight or late venture  As is your wont in weather fine,  Awake in bed as late as lovers are ill,  Dreaming, hold and fondle the delusions  Of your velvety texture's mirage.    The poem is best described as:", "images": [], "options": {"A": "A dirge", "B": "An epic", "C": "A lyric", "D": "An ode"}, "answer": "C", "explanation": "The poem expresses personal emotions and longing, which characterises a lyric.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>27", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Poetry", "question": "Read the poem and answer questions.  I know not, my Alberta,  When again on your brightness of smile  My eyes will rest awhile,  Nor when again of your sultriness of voice  My ears will drink by eager choice,  When again into the silver moonshine  You early tonight or late venture  As is your wont in weather fine,  Awake in bed as late as lovers are ill,  Dreaming, hold and fondle the delusions  Of your velvety texture's mirage. The intense emotion expressed in the poem is one of:", "images": [], "options": {"A": "Anger", "B": "Desire", "C": "Devotion", "D": "Gratitude"}, "answer": "B", "explanation": "The speaker's yearning shows strong desire, especially for reunion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>28", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Poetry", "question": "Read the poem and answer questions.  I know not, my Alberta,  When again on your brightness of smile  My eyes will rest awhile,  Nor when again of your sultriness of voice  My ears will drink by eager choice,  When again into the silver moonshine  You early tonight or late venture  As is your wont in weather fine,  Awake in bed as late as lovers are ill,  Dreaming, hold and fondle the delusions  Of your velvety texture's mirage. \"My eyes will rest / My ears will drink\" illustrates:", "images": [], "options": {"A": "Alliteration", "B": "Metaphor", "C": "Parallelism", "D": "Simile"}, "answer": "C", "explanation": "These two clauses have the same grammatical structure, hence parallelism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>29", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Poetry", "question": "Read the poem and answer questions.  I know not, my Alberta,  When again on your brightness of smile  My eyes will rest awhile,  Nor when again of your sultriness of voice  My ears will drink by eager choice,  When again into the silver moonshine  You early tonight or late venture  As is your wont in weather fine,  Awake in bed as late as lovers are ill,  Dreaming, hold and fondle the delusions  Of your velvety texture's mirage. The poem is dominated by images associated with:", "images": [], "options": {"A": "Hearing", "B": "Sight", "C": "Smell", "D": "Taste"}, "answer": "B", "explanation": "References like 'brightness of smile' and 'silver moonshine' point to vision.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>30", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Poetry", "question": "Read the poem and answer questions.  I know not, my Alberta,  When again on your brightness of smile  My eyes will rest awhile,  Nor when again of your sultriness of voice  My ears will drink by eager choice,  When again into the silver moonshine  You early tonight or late venture  As is your wont in weather fine,  Awake in bed as late as lovers are ill,  Dreaming, hold and fondle the delusions  Of your velvety texture's mirage. \"Dreaming, hold and fondle the delusions...\" reflects which tone?", "images": [], "options": {"A": "Didactic", "B": "Dramatic", "C": "Pedantic", "D": "Pessimistic"}, "answer": "B", "explanation": "The language used conveys intense emotion and longing—hence, dramatic.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>31", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions.  A Midsummer Night's Dream by William Shakespeare  Extract:    \"I am, my Lord, as well derived as he,  As well possessed, my love is more than his,  My fortunes every way as fairly ranked,  If not with vantage, as -  And, which is more than all these boasts can be,  I am beloved of beauteous -  Why should not I then prosecute my right?  I'll avouch it to his head,  Made love to Nedar's daughter,  And won her soul and she, sweet lady, dotes,  Devoutly dotes, dotes in idolatry,  Upon this spotted and inconstant man.\"    The speaker and the addressee are:", "images": [], "options": {"A": "Egeus and Helena", "B": "Lysander and Theseus", "C": "Theseus and Egeus", "D": "Demetrius and Hermia"}, "answer": "B", "explanation": "Lysander is addressing Theseus to argue his right to marry Hermia.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>32", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions.  A Midsummer Night's Dream by William Shakespeare  Extract:    \"I am, my Lord, as well derived as he,  As well possessed, my love is more than his,  My fortunes every way as fairly ranked,  If not with vantage, as -  And, which is more than all these boasts can be,  I am beloved of beauteous -  Why should not I then prosecute my right?  I'll avouch it to his head,  Made love to Nedar's daughter,  And won her soul and she, sweet lady, dotes,  Devoutly dotes, dotes in idolatry,  Upon this spotted and inconstant man.\"    In \"I am my Lord, as well derived as he\", 'he' refers to:", "images": [], "options": {"A": "Demetrius", "B": "Egeus", "C": "Lysander", "D": "Theseus"}, "answer": "A", "explanation": "Lysander compares himself to Demetrius, Hermia's other suitor.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>33", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions.  A Midsummer Night's Dream by William Shakespeare  Extract:    \"I am, my Lord, as well derived as he,  As well possessed, my love is more than his,  My fortunes every way as fairly ranked,  If not with vantage, as -  And, which is more than all these boasts can be,  I am beloved of beauteous -  Why should not I then prosecute my right?  I'll avouch it to his head,  Made love to Nedar's daughter,  And won her soul and she, sweet lady, dotes,  Devoutly dotes, dotes in idolatry,  Upon this spotted and inconstant man.\"    The setting is:", "images": [], "options": {"A": "another part of the wood", "B": "Athens", "C": "a wood near Athens", "D": "the wood"}, "answer": "B", "explanation": "This part of the play is set in Athens, where the court proceedings occur.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>34", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions.  A Midsummer Night's Dream by William Shakespeare  Extract:    \"I am, my Lord, as well derived as he,  As well possessed, my love is more than his,  My fortunes every way as fairly ranked,  If not with vantage, as -  And, which is more than all these boasts can be,  I am beloved of beauteous -  Why should not I then prosecute my right?  I'll avouch it to his head,  Made love to Nedar's daughter,  And won her soul and she, sweet lady, dotes,  Devoutly dotes, dotes in idolatry,  Upon this spotted and inconstant man.\"    In the speech, the speaker is:", "images": [], "options": {"A": "accepting blame", "B": "defending his right", "C": "resisting arrest", "D": "seeking reconciliation"}, "answer": "B", "explanation": "Lysander defends his qualifications and love for Hermia.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>35", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions.  A Midsummer Night's Dream by William Shakespeare  Extract:    \"I am, my Lord, as well derived as he,  As well possessed, my love is more than his,  My fortunes every way as fairly ranked,  If not with vantage, as -  And, which is more than all these boasts can be,  I am beloved of beauteous -  Why should not I then prosecute my right?  I'll avouch it to his head,  Made love to Nedar's daughter,  And won her soul and she, sweet lady, dotes,  Devoutly dotes, dotes in idolatry,  Upon this spotted and inconstant man.\"    Nedar's daughter is:", "images": [], "options": {"A": "Helena", "B": "Hermia", "C": "Hippolyta", "D": "Titania"}, "answer": "A", "explanation": "Helena is the daughter of Nedar, referenced in Lysander's speech.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>36", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer questions:  \"What thou seest when thou dost wake,  Do it for thy true love take;  Love and languish for his sake.  Be it ounce, or cat, or bear,  Pard, or boar with bristled hair,  In thy eye that shall appear,  When thou wak'st, it is thy dear.  Wake when some vile thing is near.\"    The speaker is:", "images": [], "options": {"A": "First Fairy", "B": "Oberon", "C": "Puck", "D": "Second Fairy"}, "answer": "C", "explanation": "These lines are spoken by Puck as he casts a spell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>37", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer questions:  \"What thou seest when thou dost wake,  Do it for thy true love take;  Love and languish for his sake.  Be it ounce, or cat, or bear,  Pard, or boar with bristled hair,  In thy eye that shall appear,  When thou wak'st, it is thy dear.  Wake when some vile thing is near.\"  The speaker is in the act of:", "images": [], "options": {"A": "picking herbs", "B": "pouring the potion", "C": "proposing to Helena", "D": "reversing his mistake"}, "answer": "B", "explanation": "The lines describe Puck casting the love potion spell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>38", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer questions:  \"What thou seest when thou dost wake,  Do it for thy true love take;  Love and languish for his sake.  Be it ounce, or cat, or bear,  Pard, or boar with bristled hair,  In thy eye that shall appear,  When thou wak'st, it is thy dear.  Wake when some vile thing is near.\"  The speaker is motivated by:", "images": [], "options": {"A": "the desire to please", "B": "the desire to punish", "C": "the need to forgive", "D": "the need to love"}, "answer": "B", "explanation": "Puck is motivated by Oberon's order to punish Titania.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>39", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer questions:  \"What thou seest when thou dost wake,  Do it for thy true love take;  Love and languish for his sake.  Be it ounce, or cat, or bear,  Pard, or boar with bristled hair,  In thy eye that shall appear,  When thou wak'st, it is thy dear.  Wake when some vile thing is near.\"  The action of the speaker is directed at:", "images": [], "options": {"A": "Demetrius", "B": "Helena", "C": "Lysander", "D": "Titania"}, "answer": "D", "explanation": "Puck mistakenly enchants Titania to fall in love with a beast.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>40", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Oberon and Titania are:", "images": [], "options": {"A": "courtiers", "B": "enemies", "C": "friends", "D": "lovers"}, "answer": "D", "explanation": "Titania and Oberon are lovers, though momentarily in conflict.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>41", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions:  \"Out, dog! out, cur! thou drivest me past the bounds  Of maiden's patience. Hast thou slain him, then?  Henceforth be never numbered among men!  O, once tell true; tell true, even for my sake;  Durst thou have looked upon him, being awake?  And hast thou killed him sleeping? O brave touch!  Could not a worm, an adder do so much?  An adder did it: for with doubler tongue  Than thine, thou serpent, never adder stung.\"    The speaker is:", "images": [], "options": {"A": "Helena", "B": "Hermia", "C": "Hippolyta", "D": "Titania"}, "answer": "B", "explanation": "Hermia accuses Demetrius, thinking he killed Lysander.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>42", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions:  \"Out, dog! out, cur! thou drivest me past the bounds  Of maiden's patience. Hast thou slain him, then?  Henceforth be never numbered among men!  O, once tell true; tell true, even for my sake;  Durst thou have looked upon him, being awake?  And hast thou killed him sleeping? O brave touch!  Could not a worm, an adder do so much?  An adder did it: for with doubler tongue  Than thine, thou serpent, never adder stung.\"  The addressee is:", "images": [], "options": {"A": "Demetrius", "B": "Egeus", "C": "Oberon", "D": "Lysander"}, "answer": "A", "explanation": "Hermia speaks to Demetrius in anger. She believes Demetrius had slained her lover, Lysander.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>43", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions:  \"Out, dog! out, cur! thou drivest me past the bounds  Of maiden's patience. Hast thou slain him, then?  Henceforth be never numbered among men!  O, once tell true; tell true, even for my sake;  Durst thou have looked upon him, being awake?  And hast thou killed him sleeping? O brave touch!  Could not a worm, an adder do so much?  An adder did it: for with doubler tongue  Than thine, thou serpent, never adder stung.\"  The character supposedly slain is:", "images": [], "options": {"A": "Demetrius", "B": "Bottom", "C": "Lysander", "D": "Thisby"}, "answer": "C", "explanation": "Hermia believes Lysander is dead and that Demetrius is responsible for his death.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>44", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Literary Devices", "question": "Read the extract below and answer the questions:  \"Out, dog! out, cur! thou drivest me past the bounds  Of maiden's patience. Hast thou slain him, then?  Henceforth be never numbered among men!  O, once tell true; tell true, even for my sake;  Durst thou have looked upon him, being awake?  And hast thou killed him sleeping? O brave touch!  Could not a worm, an adder do so much?  An adder did it: for with doubler tongue  Than thine, thou serpent, never adder stung.\"  \"Thou serpent, never adder stung\" illustrates:", "images": [], "options": {"A": "apostrophe", "B": "conceit", "C": "metaphor", "D": "synecdoche"}, "answer": "C", "explanation": "The phrase is a metaphor comparing the man to a serpent.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>45", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract below and answer the questions:  \"Out, dog! out, cur! thou drivest me past the bounds  Of maiden's patience. Hast thou slain him, then?  Henceforth be never numbered among men!  O, once tell true; tell true, even for my sake;  Durst thou have looked upon him, being awake?  And hast thou killed him sleeping? O brave touch!  Could not a worm, an adder do so much?  An adder did it: for with doubler tongue  Than thine, thou serpent, never adder stung.\"  The speaker accuses the addressee of:", "images": [], "options": {"A": "being unfair", "B": "being unfaithful", "C": "killing Bottom", "D": "killing Lysander"}, "answer": "D", "explanation": "Hermia is furious with Demetrius, whom she believes killed Lysander.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>46", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract and answer questions:  QUINCE:  \"But wonder on, till truth make all things plain.  This man is Pyramus, if you would know;  This beauteous lady Thisby is certain.  This man with lime and rough-cast doth present  Wall, that vile Wall, which did these lovers sunder:  And through Wall's chink, poor souls, they are content  To whisper: at the which, let no man wonder.  This man, with lantern, dog, and bush of thorn,  Presenteth Moonshine;\"    Quince acts as:", "images": [], "options": {"A": "Wall", "B": "Lion", "C": "Moonshine", "D": "Prologue"}, "answer": "D", "explanation": "Quince explains the play within a play, acting as the Prologue.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>47", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract and answer questions:  QUINCE:  \"But wonder on, till truth make all things plain.  This man is Pyramus, if you would know;  This beauteous lady Thisby is certain.  This man with lime and rough-cast doth present  Wall, that vile Wall, which did these lovers sunder:  And through Wall's chink, poor souls, they are content  To whisper: at the which, let no man wonder.  This man, with lantern, dog, and bush of thorn,  Presenteth Moonshine;\"    Who speaks after Quince's speech?", "images": [], "options": {"A": "Demetrius", "B": "Lysander", "C": "Snout", "D": "Theseus"}, "answer": "D", "explanation": "Theseus, the Duke, comments on the amateur nature of the play.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>48", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract and answer questions:  QUINCE:  \"But wonder on, till truth make all things plain.  This man is Pyramus, if you would know;  This beauteous lady Thisby is certain.  This man with lime and rough-cast doth present  Wall, that vile Wall, which did these lovers sunder:  And through Wall's chink, poor souls, they are content  To whisper: at the which, let no man wonder.  This man, with lantern, dog, and bush of thorn,  Presenteth Moonshine;\"    Pyramus is acted by:", "images": [], "options": {"A": "Bottom", "B": "Flute", "C": "Snout", "D": "Starveling"}, "answer": "A", "explanation": "Bottom, the weaver, plays Pyramus in the play within a play.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>49", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract and answer questions:  QUINCE:  \"But wonder on, till truth make all things plain.  This man is Pyramus, if you would know;  This beauteous lady Thisby is certain.  This man with lime and rough-cast doth present  Wall, that vile Wall, which did these lovers sunder:  And through Wall's chink, poor souls, they are content  To whisper: at the which, let no man wonder.  This man, with lantern, dog, and bush of thorn,  Presenteth Moonshine;\"    \"This man with lime and rough-cast...\" is:", "images": [], "options": {"A": "Bottom", "B": "Flute", "C": "Snout", "D": "Starveling"}, "answer": "C", "explanation": "Snout plays the Wall using lime and rough-cast as props.", "marks": "1", "difficulty": "1"}, {"id": "objective>Literature>2025>50", "subject": "Literature", "year": "2025", "type": "Objective", "topic": "Drama", "question": "Read the extract and answer questions:  QUINCE:  \"But wonder on, till truth make all things plain.  This man is Pyramus, if you would know;  This beauteous lady Thisby is certain.  This man with lime and rough-cast doth present  Wall, that vile Wall, which did these lovers sunder:  And through Wall's chink, poor souls, they are content  To whisper: at the which, let no man wonder.  This man, with lantern, dog, and bush of thorn,  Presenteth Moonshine;\"    \"This man, with lantern, dog, and bush of thorn\" acts as:", "images": [], "options": {"A": "Lion", "B": "Moonshine", "C": "Prologue", "D": "Wall"}, "answer": "B", "explanation": "The character with lantern and bush plays Moonshine in the mini-play.", "marks": "1", "difficulty": "1"}];